# --- OG: vectorized draw-volatility modifier (no per-row apply) -------------
if "_compute_draw_modifier_vectorized" not in globals():
    def _compute_draw_modifier_vectorized(df: pd.DataFrame, ref_profile: dict | None = None) -> pd.Series:
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return _pd.Series(0.0, index=getattr(df, 'index', []))
        ref = ref_profile or {}
        # Safe numeric getters (return 0-series if missing)
        def col(name: str, default: float = 0.0) -> _pd.Series:
            s = _pd.to_numeric(df.get(name), errors="coerce")
            if s is None:
                return _pd.Series(default, index=df.index)
            return s.fillna(default)

        press_diff      = col("rolling5_press_z_diff", 0.0)
        home_card_ratio = col("rolling5_home_card_ratio", 0.0)
        away_card_ratio = col("rolling5_away_card_ratio", 0.0)
        home_sot_ratio  = col("rolling5_home_sot_ratio", 0.0)
        away_sot_ratio  = col("rolling5_away_sot_ratio", 0.0)

        # Scales (conservative defaults; ref_profile keys optional)
        p_scale = float(ref.get("press_scale", 0.05))
        c_scale = float(ref.get("card_scale",  0.02))
        s_scale = float(ref.get("sot_scale",   0.02))
        cap     = float(ref.get("cap",         0.80))

        # Simple volatility proxy, bounded
        base = (press_diff.abs()*p_scale
               + (home_card_ratio + away_card_ratio)*c_scale
               + (home_sot_ratio - away_sot_ratio).abs()*s_scale)
        try:
            out = base.clip(lower=0.0, upper=cap)
        except Exception:
            out = base
            try: out[out < 0.0] = 0.0
            except Exception: pass
            try: out[out > cap] = cap
            except Exception: pass
        return out.astype(float)

