# Safe fallback: cap draw probability share; supports (p_draw, cap) or (df, p_draw, cap)
if "_apply_draw_share_cap" not in globals():
    def _apply_draw_share_cap(*args, **kwargs):
        import numpy as _np
        # Accept either (p_draw, cap) or (df, p_draw, cap)
        if len(args) >= 3:
            _, p_draw, cap = args[:3]
        elif len(args) >= 2:
            p_draw, cap = args[:2]
        else:
            p_draw = kwargs.get("p_draw")
            cap = kwargs.get("cap")
        if p_draw is None:
            return None
        arr = _np.asarray(p_draw, dtype=float)
        try:
            c = float(cap) if cap is not None else None
        except Exception:
            c = None
        if c is None:
            return arr
        if c <= 0.0:
            return _np.zeros_like(arr)
        return _np.minimum(arr, c)
