# --- SMOTE guard & helper ----------------------------------------------------
if "_use_smote" not in globals():
    def _use_smote() -> bool:
        """Return True iff SMOTE should be used (env-enabled and importable)."""
        import os as _os
        if _os.getenv("DISABLE_SMOTE", "0") == "1":
            return False
        try:
            from imblearn.over_sampling import SMOTE  # noqa: F401
            return True
        except Exception:
            return False

# --- SMOTE helper -----------------------------------------------------------
if "_smote_fit_resample" not in globals():
    def _smote_fit_resample(X, y, tag: str = ""):
        """Apply SMOTE if enabled/importable; otherwise return (X, y) unchanged.
        Prints a small status line when VERBOSE_QUICK=1.
        """
        # ---- optional class-balancing (env/availability guarded) ----
        # This is a helper; actual resampling is handled elsewhere.
        import os as _os
        try:
            if _use_smote():
                from imblearn.over_sampling import SMOTE
                sampler = SMOTE(random_state=42, k_neighbors=3)
                Xr, yr = sampler.fit_resample(X, y)
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    try:
                        import numpy as _np
                        print(f"🔄  SMOTE applied – new positive ratio = {float(_np.mean(yr)):.3f} | {tag}")
                    except Exception:
                        pass
                return Xr, yr
            else:
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    try:
                        print("⏭️  SMOTE disabled via DISABLE_SMOTE=1")
                    except Exception:
                        pass
                return X, y
        except Exception:
            # On any failure, just pass data through unchanged
            return X, y

# --- Monkey-patch imblearn.SMOTE to respect DISABLE_SMOTE=1 -----------------
try:
    import os as _os
    import imblearn.over_sampling as _im_overs
    if not getattr(_im_overs, "_OG_SMOTE_WRAPPED", False):
        _RealSMOTE = _im_overs.SMOTE
        class _OG_SMOTEWrapper(_RealSMOTE):
            def fit_resample(self, X, y):
                # Honor env guard; if disabled, no-op and return original data
                if _os.getenv("DISABLE_SMOTE", "0") == "1" or ("_use_smote" in globals() and not _use_smote()):
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        try:
                            print("⏭️  SMOTE disabled via DISABLE_SMOTE=1 [monkeypatch]")
                        except Exception:
                            pass
                    return X, y
                # Otherwise call through and emit a compact status line
                outX, outY = super().fit_resample(X, y)
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    try:
                        import numpy as _np
                        print(f"🔄  SMOTE applied – new positive ratio = {float(_np.mean(outY)):.3f}")
                    except Exception:
                        pass
                return outX, outY
        _im_overs.SMOTE = _OG_SMOTEWrapper
        _im_overs._OG_SMOTE_WRAPPED = True
except Exception:
    # If imblearn is not available or patching fails, ignore silently
    pass

# --- Robust calibrator (sklearn >=1.5) -------------------------------------
if "_make_calibrator" not in globals():
    def _make_calibrator(base_estimator, method: str = "isotonic", cv: int = 3):
        """Return CalibratedClassifierCV using modern signature (estimator=...)."""
        try:
            from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
            base_estimator = _Freeze(base_estimator)
        except Exception:
            pass
        from sklearn.calibration import CalibratedClassifierCV
        return CalibratedClassifierCV(estimator=base_estimator, method=method, cv=cv)


# === OG patch: Auto-balanced CalibratedClassifierCV.fit (inverse-frequency weights) ===
# Applies when callers forget to pass sample_weight. Disable via DISABLE_AUTO_CLASS_WEIGHT=1.
try:
    import sklearn.calibration as _skcal
    if not getattr(_skcal, "_OG_CALCV_WEIGHTED_PATCH", False):
        _CalCV_Orig = _skcal.CalibratedClassifierCV
        class _OG_CalCV_Weighted(_CalCV_Orig):
            def __init__(self, estimator=None, method: str = "sigmoid", cv: int | None = 3):
                # Call parent init with explicit params only (avoid varargs for sklearn compatibility)
                super().__init__(estimator=estimator, method=method, cv=cv)
                # Attach OG debug/introspection attributes so probes/reports can read them
                try:
                    import os as _os
                    est = getattr(self, "estimator", None) or getattr(self, "base_estimator", None)
                    try:
                        self._og_estimator_name = type(est).__name__ if est is not None else "unknown"
                    except Exception:
                        pass
                    try:
                        mode = getattr(self, "method", None)
                        mode = str(mode).lower() if mode is not None else "none"
                        if mode not in ("sigmoid", "isotonic"):
                            mode = "none"
                        self._og_cal_mode = mode
                    except Exception:
                        pass
                    try:
                        # Best-effort flag: true when enforcement would have forced sigmoid
                        self._og_enforced = (
                            str(_os.getenv("FTR_ENFORCE_CAL", "1")).strip() == "1"
                            and str(_os.getenv("FTR_CAL_MODE", "")).strip().lower() not in ("sigmoid", "isotonic")
                            and getattr(self, "_og_cal_mode", "none") == "sigmoid"
                        )
                    except Exception:
                        pass
                    if _os.getenv("VERBOSE_QUICK", "0") == "1":
                        try:
                            print(f"🧪 CalCV init: base={getattr(self,'_og_estimator_name','?')} method={getattr(self,'_og_cal_mode','?')}")
                        except Exception:
                            pass
                except Exception:
                    pass
            def fit(self, X, y, sample_weight=None, **kwargs):
                import numpy as _np, os as _os
                # === NEW: coerce dtypes for sklearn’s sigmoid calibrator ===
                # Keep a raw view of y for weighting, then prepare float32 copies for fit.
                y_raw = _np.asarray(y)
                X_fit  = _np.asarray(X, dtype=_np.float32, order="C")
                y_fit  = _np.asarray(y_raw, dtype=_np.float32)
                sw_fit = None if sample_weight is None else _np.asarray(sample_weight, dtype=_np.float32)

                # Optional auto class-weighting (unchanged logic, uses y_raw)
                use_auto = _os.getenv("DISABLE_AUTO_CLASS_WEIGHT", "0") != "1"
                if sw_fit is None and use_auto:
                    try:
                        cls, cnt = _np.unique(y_raw, return_counts=True)
                        k   = max(1, len(cls))
                        tot = int(getattr(y_raw, "shape", [len(y_raw)])[0])
                        wmap = {c: (tot / (k * float(n))) for c, n in zip(cls, cnt) if n > 0}
                        sw_fit = _np.array([wmap.get(yy, 1.0) for yy in y_raw], dtype=_np.float32)
                        if _os.getenv("VERBOSE_QUICK", "0") == "1":
                            try:
                                print(f"🧪 CalCV auto-balanced weights: {wmap}")
                            except Exception:
                                pass
                    except Exception:
                        # leave sw_fit as None
                        pass

                # === NEW: call parent fit with float32-coerced inputs ===
                return super().fit(X_fit, y_fit, sample_weight=sw_fit, **kwargs)
        _skcal.CalibratedClassifierCV = _OG_CalCV_Weighted
        _skcal._OG_CALCV_WEIGHTED_PATCH = True
except Exception:
    # If sklearn isn't available or patching fails, do nothing
    pass

# === OG patch: Hardened FTR estimator factory (calibrated & introspectable) ===
# Builds the 3-way FTR classifier and wraps with controlled calibration.
# Honors env vars and enforces a sane default when requested.
#
#  Env knobs:
#    FTR_ESTIMATOR   = xgb | lgbm | logreg (default: xgb)
#    FTR_CAL_MODE    = sigmoid | isotonic | none (default: sigmoid)
#    FTR_ENFORCE_CAL = 1|0  (default: 1 → enforce sigmoid if mode missing/invalid)
#    SKLEARN_JOBS    = int (n_jobs for estimators)
#    XGBoost knobs:  FTR_XGB_N, FTR_XGB_LR, FTR_XGB_MAX_DEPTH, FTR_XGB_SUBSAMPLE,
#                    FTR_XGB_COLSAMPLE, FTR_XGB_LAMBDA, FTR_XGB_ALPHA, XGB_TREE_METHOD
#    LightGBM knobs: FTR_LGBM_N, FTR_LGBM_LR, FTR_LGBM_LEAVES, FTR_LGBM_MAX_DEPTH,
#                    FTR_LGBM_SUBSAMPLE, FTR_LGBM_COLSAMPLE, FTR_LGBM_LAMBDA, FTR_LGBM_ALPHA
#
#  The returned estimator is tagged so reports can print truthfully:
#    ._og_cal_mode, ._og_enforced, ._og_estimator_name

def _make_calibrated_ftr_estimator(league=None):
    import os as _os
    # Resolve estimator & calibration mode
    est_name = str(_os.getenv("FTR_ESTIMATOR", "xgb")).strip().lower()
    mode_env = str(_os.getenv("FTR_CAL_MODE", "sigmoid")).strip().lower()
    enforce  = (str(_os.getenv("FTR_ENFORCE_CAL", "1")).strip() == "1")

    # Normalize mode
    mode = mode_env if mode_env in ("sigmoid", "isotonic", "none") else None
    enforced = False

    # ---- Build base estimator ----
    base = None
    if est_name in ("xgb", "xgboost"):
        try:
            from xgboost import XGBClassifier as _XGB

            # accept both new & legacy env names
            def _env(name, default, *alts):
                for k in (name,) + alts:
                    v = _os.getenv(k)
                    if v is not None:
                        return v
                return default

            _xgb_params = dict(
                # stronger defaults — all env-overridable
                n_estimators      = int(float(_env("FTR_XGB_N_EST",   "1200", "FTR_XGB_N"))),
                max_depth         = int(float(_env("FTR_XGB_MAX_DEPTH","6"))),
                learning_rate     = float(_env("FTR_XGB_LR",          "0.05")),
                subsample         = float(_env("FTR_XGB_SUBSAMPLE",   "0.80")),
                colsample_bytree  = float(_env("FTR_XGB_COLSAMPLE",   "0.80")),
                min_child_weight  = float(_env("FTR_XGB_MIN_CHILD",   "2.0")),
                reg_lambda        = float(_env("FTR_XGB_L2",          "1.0", "FTR_XGB_LAMBDA")),
                reg_alpha         = float(_env("FTR_XGB_L1",          "0.0", "FTR_XGB_ALPHA")),
                gamma             = float(_env("FTR_XGB_GAMMA",       "0.0")),
                objective         = "multi:softprob",
                tree_method       = _env("FTR_XGB_TREE", _env("XGB_TREE_METHOD", "hist")),
                n_jobs            = int(float(_env("FTR_XGB_NJOBS", _env("SKLEARN_JOBS", "4")))),
                random_state      = 42,
                eval_metric       = "mlogloss",
            )
            base = _XGB(**_xgb_params)
        except Exception:
            base = None

    if base is None and est_name in ("lgbm", "lightgbm", "lgb"):
        try:
            from lightgbm import LGBMClassifier
            base = LGBMClassifier(
                n_estimators=int(float(_os.getenv("FTR_LGBM_N", "1200"))),
                learning_rate=float(_os.getenv("FTR_LGBM_LR", "0.05")),
                num_leaves=int(float(_os.getenv("FTR_LGBM_LEAVES", "63"))),
                max_depth=int(float(_os.getenv("FTR_LGBM_MAX_DEPTH", "-1"))),
                subsample=float(_os.getenv("FTR_LGBM_SUBSAMPLE", "0.9")),
                colsample_bytree=float(_os.getenv("FTR_LGBM_COLSAMPLE", "0.8")),
                reg_lambda=float(_os.getenv("FTR_LGBM_LAMBDA", "1.0")),
                reg_alpha=float(_os.getenv("FTR_LGBM_ALPHA", "0.0")),
                objective="multiclass",
                n_jobs=int(float(_os.getenv("SKLEARN_JOBS", "1"))),
                random_state=42,
            )
        except Exception:
            base = None

    if base is None:
        # Deterministic, always-available fallback
        from sklearn.linear_model import LogisticRegression
        base = LogisticRegression(max_iter=int(float(_os.getenv("FTR_LOGREG_MAXITER", "1000"))), solver="lbfgs")

    # ---- Decide calibration ----
    if (mode is None or mode == "none") and enforce:
        mode = "sigmoid"  # enforce a sane default when requested
        enforced = True

    if mode in ("sigmoid", "isotonic"):
        # Use our robust calibrator wrapper
        clf = _make_calibrator(base, method=mode, cv=3)
        # Tag for report introspection
        try:
            clf._og_cal_mode = mode
            clf._og_enforced = enforced
            clf._og_estimator_name = type(base).__name__
        except Exception:
            pass
        return clf

    # No calibration
    try:
        base._og_cal_mode = "none"
        base._og_enforced = False
        base._og_estimator_name = type(base).__name__
    except Exception:
        pass
    return base

