# --- OG: league path resolver (underscores/spaces + directory scan) ---
import re, os
from pathlib import Path

def _slug(s: str) -> str:
    return re.sub(r"[^a-z0-9]+", "_", str(s).lower()).strip("_") or "unknown_league"

def _resolve_league_data_dir(league: str, user_path: str | None = None) -> tuple[Path | None, list[str]]:
    """
    Return the best-matching directory for this league under Matches/.
    If user_path is provided and exists, prefer it.
    Also tries both 'with spaces' and 'with underscores', then scans Matches/.
    Returns (path_or_None, tried_paths_list).
    """
    tried: list[str] = []
    # 1) Honor user-supplied path
    if user_path:
        p = Path(user_path)
        tried.append(str(p))
        if p.exists():
            return p, tried

    root = Path(__file__).resolve().parent
    matches = root / "Matches"
    name = str(league)
    slug = _slug(name)
    space_name = name
    underscore_name = name.replace(" ", "_")

    # 2) Candidate list (direct guesses)
    candidates = [
        matches / underscore_name,
        matches / space_name,
        matches / underscore_name / underscore_name,
        matches / underscore_name / space_name,
        matches / space_name / underscore_name,
        matches / space_name / space_name,
    ]
    for c in candidates:
        tried.append(str(c))
        if c.exists():
            return c, tried

    # 3) Scan Matches/ for best overlap
    best = None
    best_score = -1
    if matches.exists():
        for d in matches.iterdir():
            if not d.is_dir():
                continue
            nm = d.name.lower()
            score = 0
            # token overlap (spaces/underscores invariant)
            def toks(s: str) -> set[str]:
                return set(re.split(r"[^a-z0-9]+", s.lower()))
            t_name = toks(name)
            t_slug = toks(slug)
            t_nm   = toks(nm)
            score += len(t_name & t_nm) + len(t_slug & t_nm)
            # substring hints
            if slug in nm.replace(" ", "_"):
                score += 2
            if name.lower() in nm:
                score += 2
            if score > best_score:
                best, best_score = d, score
        if best is not None and best_score > 0:
            tried.append(str(best))
            return best, tried

    return None, tried
# --- Players path resolver (underscores/spaces + directory scan) ---
def _resolve_player_data_dir(league: str, user_path: str | None = None) -> tuple[Path | None, list[str]]:
    """Return best-matching directory for this league under Players/.
    If user_path is provided and exists, prefer it. Tries 'with spaces' and 'with underscores', then scans Players/.
    Returns (path_or_None, tried_paths_list).
    """
    from pathlib import Path as _P
    import re as _re
    tried: list[str] = []
    if not league:
        return None, tried
    # 1) Honor user-supplied path
    if user_path:
        p = _P(user_path); tried.append(str(p))
        if p.exists():
            return p, tried

    root = _P(__file__).resolve().parent
    players = root / "Players"
    name = str(league)
    slug = _re.sub(r"[^a-z0-9]+","_", name.lower()).strip("_") or "unknown_league"
    space_name = name
    underscore_name = name.replace(" ", "_")

    # 2) Candidate list (direct guesses)
    candidates = [
        players / underscore_name,
        players / space_name,
        players / underscore_name / underscore_name,
        players / underscore_name / space_name,
        players / space_name / underscore_name,
        players / space_name / space_name,
    ]
    for c in candidates:
        tried.append(str(c))
        if c.exists():
            return c, tried

    # 3) Scan Players/ for best overlap
    best = None; best_score = -1
    if players.exists():
        for d in players.iterdir():
            if not d.is_dir():
                continue
            nm = d.name.lower()
            score = 0
            def toks(s: str) -> set[str]:
                import re as _re
                return set(_re.split(r"[^a-z0-9]+", s.lower()))
            t_name = toks(name); t_slug = toks(slug); t_nm = toks(nm)
            score += len(t_name & t_nm) + len(t_slug & t_nm)
            if slug in nm.replace(" ", "_"): score += 2
            if name.lower() in nm: score += 2
            if score > best_score:
                best, best_score = d, score
        if best is not None and best_score > 0:
            tried.append(str(best))
            return best, tried

    return None, tried

# --- Teams path resolver (underscores/spaces + directory scan) --------------
def _resolve_teams_data_dir(league: str, user_path: str | None = None) -> tuple[Path | None, list[str]]:
    """Return best-matching directory for this league under Teams/.
    If user_path is provided and exists, prefer it. Tries 'with spaces' and
    'with underscores', then scans Teams/ for overlap (case-insensitive).
    Returns (path_or_None, tried_paths_list).
    """
    from pathlib import Path as _P
    import re as _re
    tried: list[str] = []
    if not league:
        return None, tried

    root = _P(__file__).resolve().parent
    teams = root / "Teams"
    # 1) Honor user-supplied path as Teams root override (still scan under it)
    if user_path:
        p = _P(user_path); tried.append(str(p))
        if p.exists() and p.is_dir():
            teams = p  # treat as root for scanning/candidates; do not return early
    name  = str(league)
    slug  = _re.sub(r"[^a-z0-9]+","_", name.lower()).strip("_") or "unknown_league"
    space = name
    under = name.replace(" ", "_")

    # 2) Candidate list (direct guesses, case variants)
    candidates = [
        teams / under,
        teams / space,
        teams / slug,
        teams / space.lower(), teams / space.upper(), teams / space.title(),
        teams / under.lower(), teams / under.upper(), teams / under.title(),
    ]
    for c in candidates:
        tried.append(str(c))
        if c.exists() and c.is_dir():
            return c, tried

    # 3) Scan Teams/ for best overlap
    best = None; best_score = -1
    if teams.exists():
        def toks(s: str) -> set[str]:
            return set(_re.split(r"[^a-z0-9]+", s.lower()))
        t_name = toks(name); t_slug = toks(slug)
        needle = under.lower()
        for d in teams.iterdir():
            if not d.is_dir():
                continue
            nm = d.name.lower(); t_nm = toks(nm)
            score = len(t_name & t_nm) + len(t_slug & t_nm)
            if needle in nm.replace(" ", "_"):
                score += 2
            if score > best_score:
                best, best_score = d, score
        if best is not None and best_score > 0:
            tried.append(str(best))
            return best, tried

    return None, tried
