if "_resolve_per_league_env" not in globals():
    def _resolve_per_league_env(name: str, league: object, default: float | str) -> float:
        """Resolve a float-valued env var with optional per-league override.
        Example: FTR_PRIOR_WEIGHT_ENGLAND_PREMIER_LEAGUE overrides FTR_PRIOR_WEIGHT.
        """
        import os as _os, re as _re
        try:
            base = float(_os.getenv(name, str(default)))
        except Exception:
            base = float(default) if isinstance(default, (int, float)) else 0.0
        try:
            tag = _re.sub(r"[^A-Za-z0-9_]+", "_", str(league).upper()).strip("_")
            key = f"{name}_{tag}"
            return float(_os.getenv(key, str(base)))
        except Exception:
            return base

# --- EV-aware threshold tuner (optional; env-guarded) ------------------------
if "tune_binary_threshold_ev" not in globals():
    def tune_binary_threshold_ev(y, p, odds, *, grid=None):
        """Return threshold that maximizes EV = p*(o-1) - (1-p).
        y: true labels (0/1), p: predicted prob for class 1, odds: decimal odds for class 1.
        """
        import numpy as _np
        y = _np.asarray(y, dtype=float)
        p = _np.asarray(p, dtype=float)
        o = _np.asarray(odds, dtype=float)
        if grid is None:
            grid = _np.linspace(0.05, 0.95, 19)
        best_t, best_ev = 0.5, -1e9
        for t in grid:
            pick = (p >= t)
            if pick.any():
                ev = (p[pick] * (o[pick] - 1.0) - (1.0 - p[pick])).mean()
            else:
                ev = -1e9
            if ev > best_ev:
                best_ev, best_t = ev, float(t)
        return best_t, best_ev

if "tune_threshold_guard" not in globals():
    def tune_threshold_guard(y, p, *, odds=None, default_metric: str = "f1"):
        """Choose threshold tuning strategy by env THR_TUNER: 'ev' or falls back to F1.
        odds is required for EV tuning.
        """
        import os as _os
        tuner = str(_os.getenv("THR_TUNER", "")).strip().lower()
        if tuner == "ev" and odds is not None:
            try:
                return tune_binary_threshold_ev(y, p, odds)
            except Exception:
                pass
        try:
            return tune_binary_threshold(y, p, metric=default_metric)
        except Exception:
            return 0.5, None
# Helper: future-proof calibrated classifier (no 'prefit', wraps with Frozen if available)
if "_calibrated_cv2" not in globals():
    def _calibrated_cv2(estimator, method: str = "isotonic"):
        """
        Return CalibratedClassifierCV(estimator, method, cv=2) with a Frozen wrapper
        when available (sklearn >=1.6). Use this wherever we previously did cv='prefit'.
        """
        try:
            from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
            est = _Freeze(estimator)
        except Exception:
            est = estimator
        # Use robust calibrator factory
        return _make_calibrator(est, method=method, cv=3)
