# --- Recovery utility: scan logs for missing symbols vs this module (CLI-friendly) ---
# Usage example:
#   python _baseline_ftr_pipeline.py --scan-missing path/to/console_or_chat_log.txt --out missing_scan.csv

def _recovery_rtf_to_text(s: str) -> str:
    """Very small, tolerant RTF→text converter (good enough for chat logs)."""
    import re
    # decode hex escapes like \'3f
    def _hex(m):
        try:
            return bytes.fromhex(m.group(1)).decode("latin-1", errors="ignore")
        except Exception:
            return ""
    s = re.sub(r"\\'([0-9a-fA-F]{2})", _hex, s)
    # drop groups and control words
    s = re.sub(r"[{}]", " ", s)
    s = re.sub(r"\\[a-zA-Z]+-?\d* ?|\\", " ", s)
    s = s.replace("\r\n", "\n")
    return s


def _recovery_extract_candidates(text: str):
    """Return a Counter of candidate names from a log (function-like tokens, NameError, etc.)."""
    import re, collections
    c = collections.Counter()
    # function-style tokens
    for m in re.finditer(r"\b([A-Za-z_][A-Za-z0-9_]*)\s*\(", text):
        c[m.group(1)] += 1
    # explicit NameError mentions → heavier weight
    for m in re.finditer(r"[Nn]ame[Ee]rror:\s*name\s+'?([A-Za-z_][A-Za-z0-9_]*)'?\s+is\s+not\s+defined", text):
        c[m.group(1)] += 10
    # AttributeError for missing attributes (light weight)
    for m in re.finditer(r"[Aa]ttribute[Ee]rror:.*'([A-Za-z_][A-Za-z0-9_]*)'", text):
        c[m.group(1)] += 1
    return c


def _recovery_extract_missing_modules(text: str) -> set[str]:
    import re
    mods = set()
    for m in re.finditer(r"[Nn]o module named ['\"]?([A-Za-z0-9_\.]+)['\"]?", text):
        mods.add(m.group(1))
    return mods


def _recovery_defined_names(source_path: str) -> tuple[set[str], set[str]]:
    """Parse *this* module's source to collect defined names (defs/classes/assigns) and imported names."""
    import ast
    defined: set[str] = set()
    imported: set[str] = set()
    try:
        with open(source_path, "r", encoding="utf-8") as f:
            src = f.read()
    except Exception:
        return defined, imported
    try:
        tree = ast.parse(src)
    except Exception:
        return defined, imported
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            defined.add(node.name)
        elif isinstance(node, ast.Assign):
            for t in node.targets:
                if hasattr(t, "id"):
                    defined.add(t.id)
        elif isinstance(node, ast.ImportFrom):
            for a in node.names:
                imported.add(a.asname or a.name.split(".")[0])
        elif isinstance(node, ast.Import):
            for a in node.names:
                imported.add(a.asname or a.name.split(".")[0])
    return defined, imported


def analyze_missing_from_log(log_text_or_path: str,
                             *, module_source_path: str | None = None,
                             extra_known: list[str] | None = None) -> dict:
    """Return a dict with undefined names, missing modules, and candidate counts from a log/RTF.

    Args:
      log_text_or_path: path to a text/RTF log, or the raw text itself
      module_source_path: path to the module to compare against (defaults to __file__)
      extra_known: optional extra names to ignore as already satisfied elsewhere
    """
    import os, builtins
    text = log_text_or_path
    if os.path.exists(log_text_or_path):
        try:
            with open(log_text_or_path, "rb") as f:
                raw = f.read()
            try:
                text = raw.decode("utf-8")
            except Exception:
                text = raw.decode("latin-1", errors="ignore")
        except Exception:
            text = str(log_text_or_path)

    # tolerate RTF input from chat exports
    if "{\\rtf" in text[:20] or "\\rtf" in text[:200]:
        text = _recovery_rtf_to_text(text)

    cnt = _recovery_extract_candidates(text)
    missing_mods = _recovery_extract_missing_modules(text)

    defined, imported = set(), set()
    if module_source_path is None:
        try:
            module_source_path = __file__
        except Exception:
            module_source_path = None
    if module_source_path:
        d, i = _recovery_defined_names(module_source_path)
        defined |= d; imported |= i

    ignore = set(dir(builtins)) | {"print", "logger", "pd", "np", "os", "re"}
    if extra_known:
        ignore |= set(extra_known)

    candidates = set(cnt.keys())
    undefined = [n for n in sorted(candidates) if n not in defined and n not in imported and n not in ignore]

    return {
        "undefined": undefined,
        "defined": sorted(defined),
        "imported": sorted(imported),
        "missing_modules": sorted(missing_mods),
        "candidate_counts": dict(cnt),
    }


