def _league_name(league) -> str:
    """Return a string league name from either a dict-like or a plain string."""
    try:
        if isinstance(league, dict):
            for k in ("name", "league", "league_name", "competition"):
                if league.get(k):
                    return str(league[k])
        return str(league)
    except Exception:
        return str(league)

 # --- League aliasing + disk discovery fallbacks (for --quick when overlay builders return empty) ---
import glob as _glob
import datetime as _dt
import re as _re

_LEAGUE_ALIAS_MAP = {
    "spain la liga": ["spain primera division","la liga","laliga","spanish la liga","spain primera división"],
    "england premier league": ["premier league","epl","english premier league"],
    "germany bundesliga": ["bundesliga","german bundesliga"],
    "italy serie a": ["serie a","italian serie a"],
    "france ligue 1": ["ligue 1","french ligue 1"],
}

def _aliases_for(name: str) -> list[str]:
    n = (name or "").strip().lower()
    al = _LEAGUE_ALIAS_MAP.get(n, [])
    # also include simple variants
    variants = {n, n.replace(" la liga"," laliga"), n.replace(" laliga"," la liga"), n.replace(" ", "_")}
    return list(dict.fromkeys([n] + al + list(variants)))

def _best_dir_under(base: Path, league_name: str) -> Path | None:
    try:
        base = _Path(base)
        if not base.exists():
            return None
        aliases = _aliases_for(league_name)
        best = None; best_score = -1
        for p in base.iterdir():
            if not p.is_dir(): 
                continue
            name = p.name.lower()
            score = sum(1 for a in aliases if a in name)
            # simple token overlap helps when names are spaced differently
            toks = set(_re.split(r"[^a-z0-9]+", name))
            for a in aliases:
                score += sum(1 for t in _re.split(r"[^a-z0-9]+", a) if t and t in toks)
            if score > best_score:
                best, best_score = p, score
        return best
    except Exception:
        return None

def _read_csvs(paths: list[str]) -> pd.DataFrame:
    import glob as _glob
    dfs: list[pd.DataFrame] = []
    tried: list[str] = []
    for p in paths:
        try:
            # Expand directories and globs
            if os.path.isdir(p):
                files = sorted(_glob.glob(os.path.join(p, "*.csv")))
            else:
                files = sorted(_glob.glob(p)) if any(ch in p for ch in "*?[]") else [p]
            for f in files:
                tried.append(f)
                try:
                    df = pd.read_csv(f, low_memory=False)
                    df["__source_file"] = f
                    dfs.append(df)
                except Exception:
                    continue
        except Exception:
            continue
    if not dfs:
        # Verbose hint when nothing was read
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"⚠️ _read_csvs: no CSVs found for patterns={paths} | tried={tried[:5]}{' …' if len(tried)>5 else ''}")
        except Exception:
            pass
        return pd.DataFrame()
    try:
        out = pd.concat(dfs, axis=0, ignore_index=True)
        out = out.loc[:, ~out.columns.duplicated()].copy()
        return out
    except Exception:
        return pd.DataFrame()



# --- Normalization helpers for schema variants ---

def _find_col(df: pd.DataFrame, candidates: list[str]) -> str | None:
    """Return the first matching column from candidates (case-insensitive)."""
    try:
        cols = {c.lower(): c for c in df.columns}
        for c in candidates:
            if c in df.columns:
                return c
            lc = str(c).lower()
            if lc in cols:
                return cols[lc]
    except Exception:
        pass
    return None

# --- League mask (alias-aware) & canonizer for global CSVs ---
if "_league_mask" not in globals():
    def _league_mask(df: pd.DataFrame, league_query: str) -> pd.Series:
        """
        Tolerant league filter for 'global' CSVs.
        Uses alias tokens (GER 1 / 1. Bundesliga / Germany Bundesliga, etc.)
        and checks common league columns.
        Returns a boolean Series mask; if no league columns exist, returns True for all rows.
        """
        import pandas as _pd, re as _re
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return _pd.Series(False, index=getattr(df, "index", []))
        q = (league_query or "").strip().lower()
        try:
            aliases = set(_aliases_for(q))
        except Exception:
            aliases = {q} if q else set()
        # probable league columns
        wanted = {"league","competition","tournament","division","league_name","competition_name"}
        cols = [c for c in df.columns if str(c).lower() in wanted]
        if not cols:
            # No explicit league column → don't filter
            return _pd.Series(True, index=df.index)

        mask = _pd.Series(False, index=df.index)
        for c in cols:
            s = df[c].astype(str).str.lower()
            s = s.str.replace(r"\s+", " ", regex=True)
            for a in aliases:
                toks = [t for t in _re.split(r"[/\-\s]+", a) if t]
                if not toks:
                    continue
                pat = "|".join(map(_re.escape, toks))
                mask = mask | s.str.contains(pat, na=False)
        return mask

if "_canonize" not in globals():
    def _canonize(df: pd.DataFrame) -> pd.DataFrame:
        """
        Canonicalize common columns for team names, dates, goals, odds, and xG.
        Safe to call on both completed and upcoming frames.
        """
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        rename = {
            # teams
            "home team": "home_team_name", "home_team": "home_team_name",
            "hometeam": "home_team_name", "home": "home_team_name",
            "team1": "home_team_name", "home club": "home_team_name",
            "away team": "away_team_name", "away_team": "away_team_name",
            "awayteam": "away_team_name", "away": "away_team_name",
            "team2": "away_team_name", "away club": "away_team_name",
            "homename": "home_team_name", "awayname": "away_team_name",
            "hometeamname": "home_team_name", "awayteamname": "away_team_name",
            # dates
            "date": "match_date", "match day": "match_date", "matchdate": "match_date",
            "kickoff": "match_date", "kickoff_date": "match_date",
            "game_date": "match_date", "fixture_date": "match_date",
            # goals (FT)
            "fthg": "home_team_goal_count", "home_goals": "home_team_goal_count",
            "goals_home": "home_team_goal_count", "hg": "home_team_goal_count",
            "ftag": "away_team_goal_count", "away_goals": "away_team_goal_count",
            "goals_away": "away_team_goal_count", "ag": "away_team_goal_count",
            # odds 1X2
            "home_odds": "odds_ft_home_team_win", "home win odds": "odds_ft_home_team_win",
            "odds home": "odds_ft_home_team_win",
            "draw_odds": "odds_ft_draw", "draw win odds": "odds_ft_draw",
            "odds draw": "odds_ft_draw",
            "away_odds": "odds_ft_away_team_win", "away win odds": "odds_ft_away_team_win",
            "odds away": "odds_ft_away_team_win",
            # market odds
            "over25_odds": "odds_ft_over25", "o25_odds": "odds_ft_over25",
            "over 2.5 odds": "odds_ft_over25",
            "btts_odds": "odds_ft_btts", "both teams to score odds": "odds_ft_btts",
            # xG (pre-match)
            "home_xg": "pre_match_xg_home", "xg_home": "pre_match_xg_home",
            "pre-match xg home": "pre_match_xg_home", "prematch_xg_home": "pre_match_xg_home",
            "away_xg": "pre_match_xg_away", "xg_away": "pre_match_xg_away",
            "pre-match xg away": "pre_match_xg_away", "prematch_xg_away": "pre_match_xg_away",
        }

        lower = {c.lower(): c for c in df.columns}
        ren = {}
        for lc, canon in rename.items():
            if lc in lower:
                ren[lower[lc]] = canon
        if ren:
            df = df.rename(columns=ren)

        # robust datetime and numeric goals
        if "match_date" in df.columns:
            df["match_date"] = _pd.to_datetime(df["match_date"], errors="coerce")
        for c in ("home_team_goal_count","away_team_goal_count"):
            if c in df.columns:
                df[c] = _pd.to_numeric(df[c], errors="coerce")
        return df



def _normalize_upcoming_columns_inplace(df: pd.DataFrame) -> pd.DataFrame:
    """
    Map common schema variants for upcoming fixtures. Does NOT require goal columns.
    Ensures: home_team_name, away_team_name, match_date (datetime if present).
    """
    import pandas as _pd
    if not isinstance(df, _pd.DataFrame) or df.empty:
        return df

    home_name_col = _find_col(df, ["home_team_name","home_team","home","hometeam","home_club","home_name","HomeTeam"])
    away_name_col = _find_col(df, ["away_team_name","away_team","away","awayteam","away_club","away_name","AwayTeam"])
    if home_name_col and "home_team_name" not in df.columns:
        df["home_team_name"] = df[home_name_col]
    if away_name_col and "away_team_name" not in df.columns:
        df["away_team_name"] = df[away_name_col]

    date_col = _find_col(df, ["match_date","date","date_GMT","Date_GMT","fixture_date","kickoff_date","kickoff","game_date","matchday_date","MatchDate","Date"])
    if date_col and "match_date" not in df.columns:
        df["match_date"] = df[date_col]
    if "match_date" in df.columns:
        df["match_date"] = _pd.to_datetime(df["match_date"], errors="coerce")

    return df
