if "_ensure_match_id" not in globals():
    def _ensure_match_id(df: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty or 'match_id' in df.columns:
            return df
        h = df.get('home_team_name', df.get('home_team'))
        a = df.get('away_team_name', df.get('away_team'))
        t = _pd.to_datetime(df.get('timestamp', df.get('date_GMT', df.get('match_date'))), errors='coerce')
        key = (h.astype(str) + '|' + a.astype(str) + '|' + t.astype(str)).fillna('nan')
        try:
            df['match_id'] = key.map(hash).astype('int64')
        except Exception:
            df['match_id'] = key.map(hash)
        return df

# === PATCH TARGET: _fallback_build_upcoming_dataframe injection ===
def _fallback_build_upcoming_dataframe(league_name: str) -> pd.DataFrame:
    """
    Scan Matches/<league>/ (or Upcoming/<league>/) for upcoming fixtures (no realized goals).
    Robust to schema variants.
    """
    root = PROJECT_ROOT
    cand = _best_dir_under(_Path(root) / "Matches", league_name) or _best_dir_under(_Path(root) / "Upcoming", league_name)
    if cand is None:
        return pd.DataFrame()
    try:
        files = sorted(_glob.glob(str(cand / "*.csv")))
        # prefer newer files for upcoming; cap for speed
        files = files[-20:] if len(files) > 20 else files

        # Debug probe
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"🔎 [quick] upcoming dir: {cand} | csv_count={len(files)}")
        except Exception:
            pass

        df = _read_csvs(files)
        if df.empty:
            return pd.DataFrame()

        # Canonicalize + optional league filter if a global file slipped in
        try:
            df = _canonize(df)
        except Exception:
            pass
        try:
            _m = _league_mask(df, league_name)
            if getattr(_m, "any", lambda: False)():
                if _m.any() and int(_m.sum()) != len(df):
                    df = df.loc[_m].copy()
        except Exception:
            pass

        # Normalize common column variants for upcoming fixtures
        df = _normalize_upcoming_columns_inplace(df)

        # OG PATCH: inject league+season and implied trio for upcoming
        try:
            import os as _os
            _league = _os.getenv("OG_LEAGUE_NAME", _os.getenv("LEAGUE_NAME", "<LEAGUE>"))
            # detect target variable name used in this function (out/df)
            _target_name = None
            try:
                out  # noqa: F821
                _target_name = 'out'
            except NameError:
                try:
                    df  # noqa: F821
                    _target_name = 'df'
                except NameError:
                    _target_name = None
            if _target_name == 'out':
                out['league_name'] = out['league_name'].fillna(_league) if 'league_name' in out.columns else _league
                if 'match_date' in out.columns:
                    out['season'] = pd.to_datetime(out['match_date'], errors='coerce').dt.year
                else:
                    out['season'] = pd.NA
                out = _ensure_implied_1x2_guard(out)
            elif _target_name == 'df':
                df['league_name'] = df['league_name'].fillna(_league) if 'league_name' in df.columns else _league
                if 'match_date' in df.columns:
                    df['season'] = pd.to_datetime(df['match_date'], errors='coerce').dt.year
                else:
                    df['season'] = pd.NA
                df = _ensure_implied_1x2_guard(df)
        except Exception:
            pass

        return df
    except Exception:
        return pd.DataFrame()


