if "_build_aligned_matrix" not in globals():
    def _build_aligned_matrix(_df: pd.DataFrame, _mdl, feats: list[str]) -> pd.DataFrame:
        _df = _df.loc[:, ~_df.columns.duplicated()].copy()
        for ft in feats:
            if ft not in _df.columns:
                _df[ft] = 0
        X_raw = (
            _df[feats]
                .replace([np.inf, -np.inf], np.nan)
                .fillna(SENTINEL)
                .loc[:, ~_df[feats].columns.duplicated()]
        )
        return _align_dataframe_to_model(X_raw, _mdl)

# --- OG: robust implied 1x2 builder (in-place; preferred by guard) ---------
if "_ensure_implied_1x2_inplace" not in globals():
    def _ensure_implied_1x2_inplace(df: pd.DataFrame) -> pd.DataFrame:
        """Compute robust implied 1x2 probabilities when corresponding odds exist.
        - Writes prob_implied_home/draw/away only where odds side exists
        - Renormalizes within 1x2 market when at least two sides present
        - Adds flags: has_implied_home/draw/away
        - Does NOT invent complements for other markets (e.g., no fake U2.5)
        Also mirrors values into legacy columns if those are missing for back-compat.
        """
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        # 1x2 implied (compute only where that odds side exists)
        mapping = [
            ("prob_implied_home", "odds_ft_home_team_win"),
            ("prob_implied_draw", "odds_ft_draw"),
            ("prob_implied_away", "odds_ft_away_team_win"),
        ]
        for out_col, odd_col in mapping:
            if odd_col in df.columns:
                df[out_col] = 1.0 / _pd.to_numeric(df[odd_col], errors="coerce")
            else:
                df[out_col] = _np.nan
        # renormalize within market if we have at least two sides present
        ii = df[["prob_implied_home","prob_implied_draw","prob_implied_away"]].copy()
        s = ii.sum(axis=1)
        renorm_mask = (ii.notna().sum(axis=1) >= 2) & (s > 0)
        try:
            df.loc[renorm_mask, ["prob_implied_home","prob_implied_draw","prob_implied_away"]] = \
                ii[renorm_mask].div(s[renorm_mask], axis=0)
        except Exception:
            pass
        # flags
        df["has_implied_home"] = df["prob_implied_home"].notna().astype(int)
        df["has_implied_draw"] = df["prob_implied_draw"].notna().astype(int)
        df["has_implied_away"] = df["prob_implied_away"].notna().astype(int)
        # Back-compat: mirror to legacy names if absent
        try:
            if "home_win_implied_prob" not in df.columns:
                df["home_win_implied_prob"] = _pd.to_numeric(df["prob_implied_home"], errors="coerce")
            if "draw_win_implied_prob" not in df.columns:
                df["draw_win_implied_prob"] = _pd.to_numeric(df["prob_implied_draw"], errors="coerce")
            if "away_win_implied_prob" not in df.columns:
                df["away_win_implied_prob"] = _pd.to_numeric(df["prob_implied_away"], errors="coerce")
            if "implied_home_prob" not in df.columns:
                df["implied_home_prob"] = _pd.to_numeric(df["prob_implied_home"], errors="coerce")
            if "implied_draw_prob" not in df.columns:
                df["implied_draw_prob"] = _pd.to_numeric(df["prob_implied_draw"], errors="coerce")
            if "implied_away_prob" not in df.columns:
                df["implied_away_prob"] = _pd.to_numeric(df["prob_implied_away"], errors="coerce")
            if "implied_prob_diff" not in df.columns:
                df["implied_prob_diff"] = _pd.to_numeric(df["prob_implied_home"], errors="coerce") - \
                                           _pd.to_numeric(df["prob_implied_away"], errors="coerce")
        except Exception:
            pass
        return df
# --- OG: robust implied BTTS & Over/Under builders (in-place) ---------------
if "_ensure_implied_btts_inplace" not in globals():
    def _ensure_implied_btts_inplace(df: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        # Accept common BTTS odds names; canonizer maps btts_odds → odds_ft_btts
        yes_col = None
        for c in ("odds_btts_yes", "odds_ft_btts", "btts_yes_odds"):
            if c in df.columns:
                yes_col = c
                break
        no_col = "odds_btts_no" if "odds_btts_no" in df.columns else None

        # Compute only when side exists; do not invent complements
        if yes_col:
            df["prob_btts_yes"] = 1.0 / _pd.to_numeric(df[yes_col], errors="coerce")
        else:
            df["prob_btts_yes"] = _np.nan
        if no_col:
            df["prob_btts_no"] = 1.0 / _pd.to_numeric(df[no_col], errors="coerce")
        else:
            df["prob_btts_no"] = _np.nan

        # Renorm if both sides present
        ii = df[["prob_btts_yes", "prob_btts_no"]].copy()
        s = ii.sum(axis=1)
        m = (ii.notna().sum(axis=1) >= 2) & (s > 0)
        try:
            df.loc[m, ["prob_btts_yes", "prob_btts_no"]] = ii[m].div(s[m], axis=0)
        except Exception:
            pass

        # Flags
        df["has_btts_yes"] = df["prob_btts_yes"].notna().astype(int)
        df["has_btts_no"]  = df["prob_btts_no"].notna().astype(int)

        # Convenience: expose main signal expected elsewhere
        if "prob_btts" not in df.columns:
            df["prob_btts"] = _pd.to_numeric(df["prob_btts_yes"], errors="coerce")
        return df

if "_ensure_implied_over_under_inplace" not in globals():
    def _ensure_implied_over_under_inplace(df: pd.DataFrame, line: str = "25") -> pd.DataFrame:
        """
        Compute robust implied Over/Under probs for a given line (e.g., '25' → O/U 2.5).
        Writes prob_over{line}, prob_under{line} only where that side's odds exist,
        renormalizes when both present, and adds flags has_over{line}/has_under{line}.
        Does not invent complements.
        """
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        over_col  = f"odds_ft_over{line}"
        under_col = f"odds_ft_under{line}"
        p_over, p_under = f"prob_over{line}", f"prob_under{line}"

        if over_col in df.columns:
            df[p_over] = 1.0 / _pd.to_numeric(df[over_col], errors="coerce")
        else:
            df[p_over] = _np.nan
        if under_col in df.columns:
            df[p_under] = 1.0 / _pd.to_numeric(df[under_col], errors="coerce")
        else:
            df[p_under] = _np.nan

        ii = df[[p_over, p_under]].copy()
        s = ii.sum(axis=1)
        m = (ii.notna().sum(axis=1) >= 2) & (s > 0)
        try:
            df.loc[m, [p_over, p_under]] = ii[m].div(s[m], axis=0)
        except Exception:
            pass

        df[f"has_over{line}"]  = df[p_over].notna().astype(int)
        df[f"has_under{line}"] = df[p_under].notna().astype(int)
        return df

if "_ensure_implied_markets_guard" not in globals():
    def _ensure_implied_markets_guard(df: pd.DataFrame) -> pd.DataFrame:
        """Ensure implied BTTS and O/U markets are computed robustly when odds exist.
        Non-destructive: fills only missing; no complements invented.
        """
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        try:
            df = _ensure_implied_btts_inplace(df)
        except Exception:
            pass
        for ln in ("15", "25", "35", "45"):
            try:
                df = _ensure_implied_over_under_inplace(df, ln)
            except Exception:
                pass
        return df
# --- OG: reusable implied-prob guard (safe & idempotent) ---------------------
if "_ensure_implied_1x2_guard" not in globals():
    def _ensure_implied_1x2_guard(df: pd.DataFrame) -> pd.DataFrame:
        """Ensure implied 1x2 probability trio exists.
        Tries project helper first; falls back to local computation from canonical odds.
        Non-destructive: fills only when missing or all-zero.
        """
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        # Prefer project helper if available
        try:
            if "_ensure_implied_1x2_inplace" in globals() and callable(_ensure_implied_1x2_inplace):
                return _ensure_implied_1x2_inplace(df)
        except Exception:
            pass
        try:
            _h = _pd.to_numeric(df.get('odds_ft_home_team_win'), errors='coerce')
            _d = _pd.to_numeric(df.get('odds_ft_draw'), errors='coerce')
            _a = _pd.to_numeric(df.get('odds_ft_away_team_win'), errors='coerce')
            inv_h = 1.0 / _h.replace(0, _np.nan)
            inv_d = 1.0 / _d.replace(0, _np.nan)
            inv_a = 1.0 / _a.replace(0, _np.nan)
            tot   = inv_h + inv_d + inv_a
            home_imp = (inv_h / tot).fillna(0.0)
            draw_imp = (inv_d / tot).fillna(0.0)
            away_imp = (inv_a / tot).fillna(0.0)
            def _need(cols):
                if not all(c in df.columns for c in cols):
                    return True
                try:
                    s = sum(float(_pd.to_numeric(df[c], errors='coerce').fillna(0.0).abs().sum()) for c in cols)
                except Exception:
                    s = 0.0
                return s == 0.0
            if _need(['home_win_implied_prob','draw_win_implied_prob','away_win_implied_prob']):
                df['home_win_implied_prob'] = home_imp
                df['draw_win_implied_prob'] = draw_imp
                df['away_win_implied_prob'] = away_imp
            if _need(['implied_home_prob','implied_draw_prob','implied_away_prob']):
                df['implied_home_prob'] = home_imp
                df['implied_draw_prob'] = draw_imp
                df['implied_away_prob'] = away_imp
            if 'implied_prob_diff' not in df.columns:
                df['implied_prob_diff'] = (home_imp - away_imp)
        except Exception:
            pass
        return df
    
    # --- OG: attach team-season features when PPG/xG are missing -----------------
# --- OG: goal-prediction attach (uses above helpers for schema/align) -------------

# === FINAL OVERRIDE: robust goal-prediction attach (schema-safe, aligned) ===
# This override ensures we do not hit direct `.feature_names_` access from older duplicates.
try:
    SENTINEL  # reuse existing constant if present
except NameError:
    SENTINEL = 0.0

def add_goal_predictions_to_complete_data(
    df: pd.DataFrame,
    model_home,
    model_away,
    SENTINEL: float = SENTINEL,
    *,
    fold_models_home=None,
    fold_models_away=None,
) -> pd.DataFrame:
    """
    Attach home_goals_pred and away_goals_pred with strict schema alignment.
    Works for both single models and fold ensembles. Never touches `.feature_names_` directly.
    """
    if df is None or len(df) == 0:
        return df

    # Ensemble path (preferred when given)
    if fold_models_home is not None and fold_models_away is not None:
        # Exemplars
        home_ex = fold_models_home[0] if isinstance(fold_models_home, (list, tuple)) and len(fold_models_home) > 0 else fold_models_home
        away_ex = fold_models_away[0] if isinstance(fold_models_away, (list, tuple)) and len(fold_models_away) > 0 else fold_models_away
        feats_h = _model_feature_schema(home_ex, df, tag="home-ens-final")
        feats_a = _model_feature_schema(away_ex, df, tag="away-ens-final")
        df_nodup = df.loc[:, ~df.columns.duplicated()].copy()
        Xh = _build_aligned_matrix(df_nodup, home_ex, feats_h)
        Xa = _build_aligned_matrix(df_nodup, away_ex, feats_a)
        for _c in ("home_team_id", "away_team_id"):
            if _c in Xh.columns: Xh[_c] = Xh[_c].astype(str)
            if _c in Xa.columns: Xa[_c] = Xa[_c].astype(str)
        df["home_goals_pred"] = _ensemble_predict(fold_models_home, Xh)
        df["away_goals_pred"] = _ensemble_predict(fold_models_away, Xa)
        return df

    # Single-model fallback
    feats_h = _model_feature_schema(model_home, df, tag="home-single-final")
    feats_a = _model_feature_schema(model_away, df, tag="away-single-final")
    Xh = _build_aligned_matrix(df, model_home, feats_h)
    Xa = _build_aligned_matrix(df, model_away, feats_a)
    df["home_goals_pred"] = model_home.predict(Xh)
    df["away_goals_pred"] = model_away.predict(Xa)
    return df

# Dedented block: _attach_team_season_features_if_missing helper at top-level
if "_attach_team_season_features_if_missing" not in globals():
    def _attach_team_season_features_if_missing(df: pd.DataFrame) -> pd.DataFrame:
        """Fill pre_match_ppg_* and pre_match_xg_* from Teams season aggregates
        when they are missing or all-zero. Merges by (team_name, season) using
        df['league_name'] and df['season'] (or env). Non-destructive.
        """
        import os as _os, re as _re
        import pandas as _pd
        from pathlib import Path as _Path
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        def _need(cols):
            if any(c not in df.columns for c in cols):
                return True
            try:
                s = sum(float(_pd.to_numeric(df[c], errors="coerce").fillna(0.0).abs().sum()) for c in cols)
            except Exception:
                s = 0.0
            return s == 0.0

        need_ppg = _need(["Pre-Match PPG (Home)", "Pre-Match PPG (Away)"])
        need_xg  = _need(["Home Team Pre-Match xG", "Away Team Pre-Match xG"]) and _need(["pre_match_xg_home","pre_match_xg_away"])
        if not (need_ppg or need_xg):
            if "ppg_diff" not in df.columns:
                df["ppg_diff"] = _pd.to_numeric(df.get("Pre-Match PPG (Home)"), errors="coerce") - \
                                _pd.to_numeric(df.get("Pre-Match PPG (Away)"), errors="coerce")
            return df

        # league + slug
        try:
            league = str(df["league_name"].dropna().iloc[0])
        except Exception:
            league = _os.getenv("OG_LEAGUE_NAME", _os.getenv("LEAGUE_NAME", ""))
        slug = _re.sub(r"[^a-z0-9]+","_", league.lower()).strip("_") or "unknown_league"

        # Use unified Teams resolver, then gather CSV candidates
        teams_dir_path, _t_tried = _resolve_teams_data_dir(league, _os.getenv("TEAMS_CSV_DIR", "") or None)
        cands = []
        if teams_dir_path is not None:
            try:
                cands = list(_Path(teams_dir_path).glob("*.csv"))
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    try:
                        print(f"📂 Teams attach dir → {teams_dir_path} | csv={len(cands)}")
                    except Exception:
                        pass
            except Exception:
                cands = []
        if not cands:
            alt = _os.getenv("TEAMS_CSV_OVERRIDE", "")
            if alt and _Path(alt).exists():
                cands = [_Path(alt)]
            else:
                return df

        # Score candidates by token overlap with league; fallback to newest
        def _tok(s: str):
            try:
                return set(_re.split(r"[^a-z0-9]+", str(s).lower()))
            except Exception:
                return set()
        lg_toks = _tok(league)
        best, best_score = None, -1
        for p in cands:
            name = p.name
            score = len(lg_toks & _tok(name))
            if score > best_score:
                best, best_score = p, score
        tpath = best if best is not None else max(cands, key=lambda p: p.stat().st_mtime)
        try:
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"📂 Teams attach: using {tpath}")
        except Exception:
            pass

        try:
            tdf = _pd.read_csv(tpath, low_memory=False)
        except Exception:
            return df
        if not isinstance(tdf, _pd.DataFrame) or tdf.empty:
            return df
        try:
            tdf = _pd.read_csv(tpath, low_memory=False)
        except Exception:
            return df
        if not isinstance(tdf, _pd.DataFrame) or tdf.empty:
            return df

        # choose columns in Teams
        def _first_col(_df, names):
            for n in names:
                if n in _df.columns:
                    return n
            return None

        team_col   = _first_col(tdf, ["team_name","common_name","Team","team"]) or "team_name"
        season_col = _first_col(tdf, ["season","Season","year","Year"]) or "season"
        if season_col not in tdf.columns:
            tdf["season"] = _pd.NA
            season_col = "season"

        ppg_home_col = _first_col(tdf, ["points_per_game_home","ppg_home"])
        ppg_away_col = _first_col(tdf, ["points_per_game_away","ppg_away"])
        ppg_col      = _first_col(tdf, ["points_per_game","ppg"])
        xgf_o_col    = _first_col(tdf, ["xg_for_avg_overall","xg_for_avg","xg_for"])
        xgf_h_col    = _first_col(tdf, ["xg_for_avg_home"])
        xgf_a_col    = _first_col(tdf, ["xg_for_avg_away"])
        xga_o_col    = _first_col(tdf, ["xg_against_avg_overall","xg_against_avg","xg_against"])

        # home side frame
        keep_h = [c for c in [
            ppg_home_col, ppg_col,
            xgf_o_col, xgf_h_col, xgf_a_col, xga_o_col,
            # extra team-season features for priors/diffs
            _first_col(tdf, ["matches_played","Matches_Played"]),
            _first_col(tdf, ["goals_scored_per_match"]),
            _first_col(tdf, ["goals_conceded_per_match"]),
            _first_col(tdf, ["average_total_goals_per_match"]),
            _first_col(tdf, ["cards_per_match"]),
            _first_col(tdf, ["corners_per_match"]),
            _first_col(tdf, ["btts_percentage","btts_percentage_overall"]),
            _first_col(tdf, ["over25_percentage","over_25_percentage","over25_percentage_overall"]),
            _first_col(tdf, ["first_team_to_score_percentage"]),
            _first_col(tdf, ["clean_sheet_percentage"]),
            _first_col(tdf, ["draw_at_half_time_percentage"]),
            _first_col(tdf, ["goal_difference_half_time","goal_difference_half_time_home"])  # some feeds
        ] if c in tdf.columns]
        tdf_home = tdf[[team_col, season_col] + keep_h].copy()
        tdf_home.columns = ["home_team_name","season"] + [f"__home_{c}" for c in tdf_home.columns[2:]]

        # away side frame
        keep_a = [c for c in [
            ppg_away_col, ppg_col,
            xgf_o_col, xgf_h_col, xgf_a_col, xga_o_col,
            _first_col(tdf, ["matches_played","Matches_Played"]),
            _first_col(tdf, ["goals_scored_per_match"]),
            _first_col(tdf, ["goals_conceded_per_match"]),
            _first_col(tdf, ["average_total_goals_per_match"]),
            _first_col(tdf, ["cards_per_match"]),
            _first_col(tdf, ["corners_per_match"]),
            _first_col(tdf, ["btts_percentage","btts_percentage_overall"]),
            _first_col(tdf, ["over25_percentage","over_25_percentage","over25_percentage_overall"]),
            _first_col(tdf, ["first_team_to_score_percentage"]),
            _first_col(tdf, ["clean_sheet_percentage"]),
            _first_col(tdf, ["draw_at_half_time_percentage"]),
            _first_col(tdf, ["goal_difference_half_time","goal_difference_half_time_away"])  # some feeds
        ] if c in tdf.columns]
        tdf_away = tdf[[team_col, season_col] + keep_a].copy()
        tdf_away.columns = ["away_team_name","season"] + [f"__away_{c}" for c in tdf_away.columns[2:]]

        if "season" not in df.columns:
            df["season"] = _pd.to_datetime(df.get("match_date"), errors="coerce").dt.year

        # merges
        try: df = df.merge(tdf_home, on=["home_team_name","season"], how="left")
        except Exception: pass
        try: df = df.merge(tdf_away, on=["away_team_name","season"], how="left")
        except Exception: pass
        # --- Shrinkage: blend team-season priors toward league-season means ---
        # Applies BEFORE filling PPG/xG and deriving diffs to stabilize early-season values
        try:
            import pandas as _pd
            import numpy as _np
            k = float(_os.getenv("TEAM_SHRINK_K", "10"))  # default k≈10
            alpha_prev_default = float(_os.getenv("OG_PREV_SEASON_ALPHA", "0.30"))  # default 0.30

            # determine month from match_date (if present); else no prev-season blending
            _md = _pd.to_datetime(df.get("match_date"), errors='coerce') if "match_date" in df.columns else None
            if _md is not None and hasattr(_md, "dt"):
                _month = _md.dt.month
                _use_prev = _month.isin([8, 9]).fillna(False)
            else:
                _use_prev = _pd.Series(False, index=df.index)

            # keep a log of shrunk columns for debug
            _shrunk_cols = []

            def _shrink_inplace(col: str, mp_col: str):
                if col in df.columns and mp_col in df.columns:
                    s  = _pd.to_numeric(df[col], errors='coerce')
                    mp = _pd.to_numeric(df[mp_col], errors='coerce').fillna(0)
                    w  = mp / (mp + k)
                    # league-season mean for current season
                    if "season" in df.columns:
                        season_series = df["season"]
                        season_means = s.groupby(season_series).mean()
                        mu_curr = season_series.map(season_means).astype(float)
                        # previous-season mean aligned to current season: E[s | season-1]
                        prev_means_dict = {int(se)+1: float(val) for se, val in season_means.items() if _pd.notna(se)}
                        mu_prev = season_series.map(prev_means_dict)
                        # blend prev-season mean for August–September
                        a_prev = _pd.Series(alpha_prev_default, index=df.index).where(_use_prev, other=0.0)
                        mu = (1.0 - a_prev) * mu_curr + a_prev * mu_prev.fillna(mu_curr)
                    else:
                        mu = s.mean()
                    df[col] = (w * s + (1.0 - w) * mu).fillna(s)
                    _shrunk_cols.append(col)

            # matches-played columns from Teams.csv (if present)
            home_mp = "__home_matches_played"
            away_mp = "__away_matches_played"

            # Candidate metrics to shrink (home/away prefixes)
            home_metrics = [
                "__home_points_per_game_home", "__home_points_per_game_away", "__home_points_per_game",
                "__home_xg_for_avg_overall", "__home_xg_against_avg_overall",
                "__home_xg_for_avg_home", "__home_xg_for_avg_away",
                "__home_goals_scored_per_match", "__home_goals_conceded_per_match",
                "__home_average_total_goals_per_match",
                "__home_cards_per_match", "__home_corners_per_match",
                "__home_btts_percentage", "__home_over25_percentage",
                "__home_first_team_to_score_percentage", "__home_clean_sheet_percentage",
                "__home_draw_at_half_time_percentage",
            ]
            away_metrics = [
                "__away_points_per_game_home", "__away_points_per_game_away", "__away_points_per_game",
                "__away_xg_for_avg_overall", "__away_xg_against_avg_overall",
                "__away_xg_for_avg_home", "__away_xg_for_avg_away",
                "__away_goals_scored_per_match", "__away_goals_conceded_per_match",
                "__away_average_total_goals_per_match",
                "__away_cards_per_match", "__away_corners_per_match",
                "__away_btts_percentage", "__away_over25_percentage",
                "__away_first_team_to_score_percentage", "__away_clean_sheet_percentage",
                "__away_draw_at_half_time_percentage",
            ]

            # Optional before/after probe (only when VERBOSE_QUICK=1)
            _probe_idx = df.index[0] if len(df.index) > 0 else None
            _probe_cols = [c for c in [
                "__home_points_per_game_home","__home_xg_for_avg_overall",
                "__away_points_per_game_home","__away_xg_for_avg_overall"
            ] if c in df.columns]
            _pre_snap = {}
            if _os.getenv("VERBOSE_QUICK","0") == "1" and _probe_idx is not None and _probe_cols:
                for _c in _probe_cols:
                    try:
                        _pre_snap[_c] = float(_pd.to_numeric(df.loc[_probe_idx, _c], errors="coerce"))
                    except Exception:
                        _pre_snap[_c] = None

            # Apply shrinkage where columns exist
            for c in home_metrics:
                if c in df.columns and home_mp in df.columns:
                    _shrink_inplace(c, home_mp)
            for c in away_metrics:
                if c in df.columns and away_mp in df.columns:
                    _shrink_inplace(c, away_mp)

            # One-row before/after probe (only when VERBOSE_QUICK=1)
            if _os.getenv("VERBOSE_QUICK","0") == "1" and _probe_idx is not None and _probe_cols:
                try:
                    parts = []
                    for _c in _probe_cols:
                        _pre = _pre_snap.get(_c)
                        try:
                            _post = float(_pd.to_numeric(df.loc[_probe_idx, _c], errors="coerce"))
                        except Exception:
                            _post = None
                        def _fmt(v):
                            try:
                                import math
                                return "nan" if v is None or (isinstance(v, float) and math.isnan(v)) else f"{v:.3f}"
                            except Exception:
                                return str(v)
                        parts.append(f"{_c}: {_fmt(_pre)}→{_fmt(_post)}")
                    print("🧪 shrink probe idx=", _probe_idx, "|", "  ".join(parts))
                except Exception:
                    pass

            # Debug: show k, alpha_prev and a few columns shrunk
            if _os.getenv("VERBOSE_QUICK","0") == "1" and _shrunk_cols:
                try:
                    _sample_cols = ", ".join(_shrunk_cols[:8]) + (" …" if len(_shrunk_cols) > 8 else "")
                    print(f"🧮 shrinkage k={k:.2f}, alpha_prev={alpha_prev_default:.2f} | cols={len(_shrunk_cols)} → {_sample_cols}")
                except Exception:
                    pass
        except Exception:
            pass
        # fill PPG
        if need_ppg:
            try:
                if "Pre-Match PPG (Home)" not in df.columns:
                    df["Pre-Match PPG (Home)"] = _pd.to_numeric(df.get("__home_points_per_game_home"), errors="coerce")
                if df["Pre-Match PPG (Home)"].isna().all() and "__home_points_per_game" in df.columns:
                    df["Pre-Match PPG (Home)"] = _pd.to_numeric(df.get("__home_points_per_game"), errors="coerce")
                if "Pre-Match PPG (Away)" not in df.columns:
                    df["Pre-Match PPG (Away)"] = _pd.to_numeric(df.get("__away_points_per_game_away"), errors="coerce")
                if df["Pre-Match PPG (Away)"].isna().all() and "__away_points_per_game" in df.columns:
                    df["Pre-Match PPG (Away)"] = _pd.to_numeric(df.get("__away_points_per_game"), errors="coerce")
            except Exception:
                pass

        # fill xG (simple provider-agnostic logic, with optional blend)
        if need_xg:
            try:
                def _coalesce(*names):
                    for n in names:
                        if n and n in df.columns:
                            s = _pd.to_numeric(df.get(n), errors="coerce")
                            if not s.isna().all():
                                return s
                    return _pd.Series(_pd.NA, index=df.index)

                hxg = _coalesce("Home Team Pre-Match xG","pre_match_xg_home","__home_xg_for_avg_home","__home_xg_for_avg_overall")
                axg = _coalesce("Away Team Pre-Match xG","pre_match_xg_away","__away_xg_for_avg_away","__away_xg_for_avg_overall")

                hxga_opp = _pd.to_numeric(df.get("__away_xg_against_avg_overall"), errors="coerce") if "__away_xg_against_avg_overall" in df.columns else None
                axga_opp = _pd.to_numeric(df.get("__home_xg_against_avg_overall"), errors="coerce") if "__home_xg_against_avg_overall" in df.columns else None

                if hxga_opp is not None and hxga_opp.notna().any():
                    hxg = _pd.concat([hxg, (hxg + hxga_opp)/2.0], axis=1).min(axis=1)
                if axga_opp is not None and axga_opp.notna().any():
                    axg = _pd.concat([axg, (axg + axga_opp)/2.0], axis=1).min(axis=1)

                if "Home Team Pre-Match xG" not in df.columns or _pd.to_numeric(df["Home Team Pre-Match xG"], errors="coerce").isna().all():
                    df["Home Team Pre-Match xG"] = hxg
                if "Away Team Pre-Match xG" not in df.columns or _pd.to_numeric(df["Away Team Pre-Match xG"], errors="coerce").isna().all():
                    df["Away Team Pre-Match xG"] = axg
            except Exception:
                pass

        if "ppg_diff" not in df.columns:
            try:
                df["ppg_diff"] = _pd.to_numeric(df.get("Pre-Match PPG (Home)"), errors="coerce") - \
                                _pd.to_numeric(df.get("Pre-Match PPG (Away)"), errors="coerce")
            except Exception:
                pass

        # --- Derived priors & parity diffs from team-season aggregates ---
        try:
            import pandas as _pd
            def _nz(s):
                return _pd.to_numeric(s, errors="coerce")
            # xG nets & ratios
            if "__home_xg_for_avg_overall" in df.columns and "__home_xg_against_avg_overall" in df.columns:
                df["home_xg_net"] = _nz(df["__home_xg_for_avg_overall"]) - _nz(df["__home_xg_against_avg_overall"]) 
            if "__away_xg_for_avg_overall" in df.columns and "__away_xg_against_avg_overall" in df.columns:
                df["away_xg_net"] = _nz(df["__away_xg_for_avg_overall"]) - _nz(df["__away_xg_against_avg_overall"]) 
            if "home_xg_net" in df.columns and "away_xg_net" in df.columns and "xg_net_diff" not in df.columns:
                df["xg_net_diff"] = _nz(df["home_xg_net"]) - _nz(df["away_xg_net"]) 
            if all(c in df.columns for c in ["__home_xg_for_avg_overall","__home_xg_against_avg_overall","__away_xg_for_avg_overall","__away_xg_against_avg_overall"]):
                hr = _nz(df["__home_xg_for_avg_overall"]) / _nz(df["__home_xg_against_avg_overall"]).replace(0, _pd.NA)
                ar = _nz(df["__away_xg_for_avg_overall"]) / _nz(df["__away_xg_against_avg_overall"]).replace(0, _pd.NA)
                df["xg_ratio_diff"] = hr.fillna(0) - ar.fillna(0)

            # Home-advantage prior
            if "__home_points_per_game_home" in df.columns and "__home_points_per_game_away" in df.columns:
                df["home_adv_idx"] = _nz(df["__home_points_per_game_home"]) - _nz(df["__home_points_per_game_away"]) 
            if "__away_points_per_game_home" in df.columns and "__away_points_per_game_away" in df.columns:
                df["away_adv_idx"] = _nz(df["__away_points_per_game_home"]) - _nz(df["__away_points_per_game_away"]) 
            if "home_adv_idx" in df.columns and "away_adv_idx" in df.columns:
                df["home_advantage_diff"] = _nz(df["home_adv_idx"]) - _nz(df["away_adv_idx"]) 

            # Goal environment & parity
            for base, outname in [
                ("goals_scored_per_match","gfpm_diff"),
                ("goals_conceded_per_match","gapm_diff"),
                ("average_total_goals_per_match","avg_total_goals_diff"),
                ("cards_per_match","cards_per_match_diff"),
                ("corners_per_match","corners_per_match_diff"),
                ("btts_percentage","btts_rate_diff"),
                ("over25_percentage","over25_rate_diff"),
                ("first_team_to_score_percentage","fts_rate_diff"),
                ("clean_sheet_percentage","clean_sheet_rate_diff"),
                ("draw_at_half_time_percentage","ht_draw_rate_diff"),
                ("goal_difference_half_time","ht_gd_diff"),
            ]:
                hcol = f"__home_{base}"
                acol = f"__away_{base}"
                if hcol in df.columns and acol in df.columns and outname not in df.columns:
                    df[outname] = _nz(df[hcol]) - _nz(df[acol])

            # Optional z-score indices by season (xG strength/weakness)
            if "season" in df.columns:
                for side, pref in (("home","__home_"),("away","__away_")):
                    for key, out in (("xg_for_avg_overall", f"{side}_xg_for_idx"),
                                     ("xg_against_avg_overall", f"{side}_xg_against_idx")):
                        col = f"{pref}{key}"
                        if col in df.columns:
                            s = _nz(df[col])
                            mu = s.groupby(df["season"]).transform("mean")
                            sd = s.groupby(df["season"]).transform("std").replace(0, _pd.NA)
                            df[out] = ((s - mu) / sd).fillna(0)
        except Exception:
            pass

        return df
# --- OG: basic strength/momentum enrichment (report-path fallback) ---
if "_ensure_strength_basics" not in globals():
    def _ensure_strength_basics(df: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        # Ensure datetime + sort for rest-days
        if "match_date" in df.columns:
            df["match_date"] = _pd.to_datetime(df["match_date"], errors="coerce")
            df = df.sort_values("match_date")

        # Rest days (difference from previous match per team)
        for team_col, out_col in [("home_team_name","rest_days_home"),("away_team_name","rest_days_away")]:
            try:
                prev = df.groupby(team_col)["match_date"].shift(1)
                df[out_col] = (df["match_date"] - prev).dt.days
            except Exception:
                df[out_col] = _np.nan

        # Points per match, shifted EWMA for pre-match signals
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        hp = _np.where(hh>aa,3,_np.where(hh==aa,1,0))
        ap = _np.where(aa>hh,3,_np.where(hh==aa,1,0))
        df["__home_points__"], df["__away_points__"] = hp, ap
        try:
            df["ewma_ppg_home"] = df.groupby("home_team_name")["__home_points__"].transform(
                lambda s: _pd.Series(s).shift(1).ewm(span=5, adjust=False).mean())
        except Exception:
            df["ewma_ppg_home"] = _np.nan
        try:
            df["ewma_ppg_away"] = df.groupby("away_team_name")["__away_points__"].transform(
                lambda s: _pd.Series(s).shift(1).ewm(span=5, adjust=False).mean())
        except Exception:
            df["ewma_ppg_away"] = _np.nan
        df["ewma_ppg_diff"] = _pd.to_numeric(df.get("ewma_ppg_home"), errors="coerce") - \
                              _pd.to_numeric(df.get("ewma_ppg_away"), errors="coerce")

        # Simple elo-like proxy via EWMA goal diff (pre-match)
        try:
            df["__gd_home__"] = (hh - aa)
            df["__gd_away__"] = (aa - hh)
            df["elo_home_pre"] = df.groupby("home_team_name")["__gd_home__"].transform(
                lambda s: _pd.Series(s).shift(1).ewm(span=10, adjust=False).mean())
            df["elo_away_pre"] = df.groupby("away_team_name")["__gd_away__"].transform(
                lambda s: _pd.Series(s).shift(1).ewm(span=10, adjust=False).mean())
            df["elo_diff"] = _pd.to_numeric(df.get("elo_home_pre"), errors="coerce") - \
                             _pd.to_numeric(df.get("elo_away_pre"), errors="coerce")
        except Exception:
            pass

        # Cleanup temps
        for c in ("__home_points__","__away_points__","__gd_home__","__gd_away__"):
            if c in df.columns:
                try: del df[c]
                except Exception: pass

        return df
    
# --- OG: draw-feature enrichment (report-path fallback) ---
if "_ensure_draw_features_inplace" not in globals():
    def _ensure_draw_features_inplace(df: pd.DataFrame, *, window:int=5, h2h_window:int=6) -> pd.DataFrame:
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        out = df.copy()

        # Ensure datetime for ordering
        if "match_date" in out.columns:
            out["match_date"] = _pd.to_datetime(out["match_date"], errors="coerce")
            out = out.sort_values("match_date")

        # Build draw flag from goals if present; else try text labels; else 0
        draw = None
        try:
            hh = _pd.to_numeric(out.get("home_team_goal_count"), errors="coerce")
            aa = _pd.to_numeric(out.get("away_team_goal_count"), errors="coerce")
            if hh.notna().any() and aa.notna().any():
                draw = (hh == aa).astype(float)
        except Exception:
            draw = None
        if draw is None:
            txt = out.get("FTR") or out.get("ftr") or out.get("full_time_result") or out.get("ft_result") or out.get("result")
            if txt is not None:
                s = txt.astype(str).str.lower().str.strip()
                draw = (s.isin(["1","d","draw"]).astype(float))
        if draw is None:
            draw = _pd.Series(0.0, index=out.index)
        out["__draw_flag__"] = _pd.to_numeric(draw, errors="coerce").fillna(0.0)

        # Rolling team draw rates (pre-match via shift)
        try:
            out["home_draw_rate_rolling"] = (
                out.groupby("home_team_name")["__draw_flag__"].transform(lambda s: _pd.Series(s).shift(1).rolling(window, min_periods=1).mean())
            )
        except Exception:
            out["home_draw_rate_rolling"] = _np.nan
        try:
            out["away_draw_rate_rolling"] = (
                out.groupby("away_team_name")["__draw_flag__"].transform(lambda s: _pd.Series(s).shift(1).rolling(window, min_periods=1).mean())
            )
        except Exception:
            out["away_draw_rate_rolling"] = _np.nan

        # Parity between teams' draw tendencies
        try:
            out["team_draw_parity"] = (
                _pd.to_numeric(out.get("home_draw_rate_rolling"), errors="coerce") -
                _pd.to_numeric(out.get("away_draw_rate_rolling"), errors="coerce")
            ).abs()
        except Exception:
            out["team_draw_parity"] = _np.nan

        # H2H draw rate (canonical pair key, pre-match via shift)
        try:
            def _pair(a,b):
                try:
                    return (a if a<=b else b) + "__" + (b if b>=a else a)
                except Exception:
                    return str(a)+"__"+str(b)
            out["__pair__"] = [ _pair(a,b) for a,b in zip(out.get("home_team_name"), out.get("away_team_name")) ]
            out["h2h_draw_rate"] = out.groupby("__pair__")["__draw_flag__"].transform(
                lambda s: _pd.Series(s).shift(1).rolling(h2h_window, min_periods=1).mean()
            )
        except Exception:
            out["h2h_draw_rate"] = _np.nan

        # Simple pre-match xG diff abs if xG present
        try:
            xh = _pd.to_numeric(out.get("pre_match_xg_home"), errors="coerce")
            xa = _pd.to_numeric(out.get("pre_match_xg_away"), errors="coerce")
            out["recent_xg_diff_abs"] = (xh - xa).abs()
        except Exception:
            out["recent_xg_diff_abs"] = _np.nan

        # cleanup temps
        for c in ("__draw_flag__","__pair__"):
            if c in out.columns:
                try: del out[c]
                except Exception: pass

        return out
