if "_apply_tuned_gate_gamma_for_league" not in globals():
    def _apply_tuned_gate_gamma_for_league(league_name: str):
        """Load tuned (gamma, gate) for league and set env for quick paths.
        Skips if DISABLE_TUNED_GATE_GAMMA=1. Prints a hint when VERBOSE_QUICK=1.
        """
        import os as _os
        if _os.getenv("DISABLE_TUNED_GATE_GAMMA", "0") == "1":
            return
        tuned = None
        try:
            tuned = _load_gate_gamma(league_name)
        except Exception:
            tuned = None
        if isinstance(tuned, dict):
            g = tuned.get("gamma")
            t = tuned.get("gate")
            if g is not None:
                _os.environ["FTR_CONF_SHARPEN"] = str(g)
            if t is not None:
                _os.environ["FTR_PICK_GATE"] = str(t)
            if _os.getenv("VERBOSE_QUICK", "0") == "1":
                try:
                    print(f"⚙️ quick: using tuned gate={_os.environ.get('FTR_PICK_GATE','?')} "
                          f"gamma={_os.environ.get('FTR_CONF_SHARPEN','?')} for {league_name}")
                except Exception:
                    pass

# OG_PATCH_OK: quantile gating helper
def _quantile_gate_threshold(maxp_array, *, cov_target=None, default_thr=None):
    """Return a gating threshold. If *cov_target* (0<k<1) is given, use the (1-k) quantile of maxP; else *default_thr*."""
    import numpy as _np
    if maxp_array is None:
        return float(default_thr or 0.5)
    try:
        arr = _np.asarray(maxp_array, dtype=float)
        if arr.size == 0:
            return float(default_thr or 0.5)
    except Exception:
        return float(default_thr or 0.5)
    if cov_target is not None:
        try:
            cov_target = float(cov_target)
            cov_target = max(0.0, min(0.99, cov_target))
            return float(_np.quantile(arr, 1.0 - cov_target))
        except Exception:
            pass
    return float(default_thr or 0.5)
if "_append_gated_holdout_metrics" not in globals():
    def _append_gated_holdout_metrics(lines, clf, X_val, y_val):
        import os as _os, numpy as _np
        # Gate & sharpen parameters
        gate_thr_env   = _os.getenv('FTR_PICK_GATE', None)
        cov_target_env = _os.getenv('FTR_COV_TARGET', None)
        gate_default   = 0.68 if gate_thr_env is None else float(gate_thr_env)
        try:
            _maxP = locals().get('maxp', None) or locals().get('maxP_holdout', None) or globals().get('_MAXP_HOLDOUT', None)
            gate = _quantile_gate_threshold(_maxP,
                                            cov_target=float(cov_target_env) if cov_target_env else None,
                                            default_thr=gate_default)
        except Exception:
            gate = gate_default
        try:
            gamma = float(_os.getenv("FTR_CONF_SHARPEN", "1.0"))
        except Exception:
            gamma = 1.0

        # Prefer the precomputed 3-way probs from the report (global),
        # optionally using mixed probs if requested.
        P3 = globals().get("_P_FOR_GATE", None)
        if _os.getenv("USE_MIX_FOR_GATE", "0") == "1":
            P3 = globals().get("_P_FOR_GATE_MIX", P3)

        # Fallback: compute from clf if not available
        if P3 is None:
            try:
                P = _np.asarray(clf.predict_proba(X_val), dtype=float)
                classes = _np.asarray(getattr(clf, 'classes_', [0, 1, 2]))
                def _ix(c):
                    w = _np.where(classes == c)[0]
                    return int(w[0]) if w.size else int(c)
                ih, idr, ia = _ix(0), _ix(1), _ix(2)
                P3 = P[:, [ih, idr, ia]]
            except Exception:
                P3 = None

        if P3 is None:
            try:
                lines.append(f"Gated hold-out (≥{gate:.2f}) → unavailable (no predict_proba).")
            except Exception:
                pass
            return

        # Apply the same sharpening + renorm as top-pick
        try:
            P3s = _sharpen_and_renorm(P3, gamma)
        except Exception:
            # inline safeguard if helper is unavailable
            P3c = _np.clip(P3, 1e-12, 1.0)
            if abs(gamma - 1.0) > 1e-12:
                P3c = P3c ** gamma
            denom = P3c.sum(axis=1, keepdims=True)
            denom = _np.where(denom == 0.0, 1.0, denom)
            P3s = P3c / denom

        maxp = P3s.max(axis=1)
        # Optional quantile-gating override via FTR_COV_TARGET
        try:
            _cov = _os.getenv("FTR_COV_TARGET", None)
            if _cov is not None:
                gate = _quantile_gate_threshold(maxp,
                                                cov_target=float(_cov),
                                                default_thr=gate)
        except Exception:
            pass
        # Expose hold-out maxP for other report sections to reuse consistently
        try:
            globals()["_MAXP_HOLDOUT"] = maxp
        except Exception:
            pass
        m = (maxp >= gate)
        if not bool(m.any()):
            try:
                lines.append(f"Gated hold-out (≥{gate:.2f}) → no selections (coverage=0.0%).")
            except Exception:
                pass
            return

        yhat = P3s.argmax(axis=1)
        try:
            acc = float((_np.asarray(y_val) == yhat)[m].mean())
            cov = float(m.mean())
            lines.append(f"Gated hold-out (≥{gate:.2f}) → acc={acc:.3f} | coverage={cov*100:.1f}% | n={int(m.sum())}")
        except Exception:
            try:
                lines.append(f"Gated hold-out (≥{gate:.2f}) → internal error computing metrics.")
            except Exception:
                pass
def _fallback_build_training_dataframe(league_name: str) -> pd.DataFrame:
    """Scan Matches/<league>/ (or Completed/<league>/) for historical rows with realized goals (fast + robust)."""
    root = PROJECT_ROOT
    cand = _best_dir_under(_Path(root) / "Matches", league_name) or _best_dir_under(_Path(root) / "Completed", league_name)
    if cand is None:
        return pd.DataFrame()
    try:
        files = sorted(_glob.glob(str(cand / "*.csv")))
        # prefer older files first for history; cap for speed
        files = files[:50] if len(files) > 50 else files

        # Debug probe
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"🔎 [quick] training dir: {cand} | csv_count={len(files)}")
        except Exception:
            pass

        df = _read_csvs(files)
        if df.empty:
            return pd.DataFrame()

        # Canonicalize + optional league filter if a global file slipped in
        try:
            df = _canonize(df)
        except Exception:
            pass
        try:
            _m = _league_mask(df, league_name)
            if getattr(_m, "any", lambda: False)():
                if _m.any() and int(_m.sum()) != len(df):
                    df = df.loc[_m].copy()
        except Exception:
            pass

        # Normalize common column variants BEFORE label mask
        df = _normalize_history_columns_inplace(df)
        # If a status column exists, keep only completed rows
        _status_col = _find_col(df, ["status","match_status","game_status","fixture_status"])
        if _status_col:
            _s = df[_status_col].astype(str).str.lower().str.strip()
            _m_complete = _s.isin(["complete","completed","finished","full time","full-time","ft","result"])
            try:
                if os.getenv("VERBOSE_QUICK","0") == "1":
                    print(f"🔎 [quick] status filter (completed): kept={int(_m_complete.sum())}/{len(df)}")
            except Exception:
                pass
            df = df.loc[_m_complete].copy()

        # Debug headers (first few)
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                cols_preview = list(df.columns)[:20]
                print(f"🔎 [quick] columns sample: {cols_preview}")
        except Exception:
            pass

        # Keep only realized rows
        hh = pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        mask = hh.notna() & aa.notna()
        # Verbose: realized rows after normalization
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"🔎 [quick] realized rows after normalisation: {int(mask.sum())}/{len(df)}")
        except Exception:
            pass
        if not mask.any():
            try:
                if os.getenv("VERBOSE_QUICK","0") == "1":
                    print("ℹ️  [quick] No realized-goal rows after normalization "
                          f"(home_team_goal_count non-null={int(hh.notna().sum())}, "
                          f"away_team_goal_count non-null={int(aa.notna().sum())})")
            except Exception:
                pass
            # Return an empty but schema-friendly frame
            out = df.copy().head(0)
            # Ensure required columns exist
            for c in ("home_team_name","away_team_name","match_date",
                      "home_team_goal_count","away_team_goal_count"):
                if c not in out.columns:
                    out[c] = pd.Series(dtype="float64")
            # Ensure goal columns are numeric
            for c in ("home_team_goal_count","away_team_goal_count"):
                out[c] = pd.to_numeric(out.get(c), errors="coerce")
            return out

        out = df.loc[mask].copy()
        # Ensure core ID columns exist
        for c in ("home_team_name","away_team_name","match_date"):
            if c not in out.columns:
                out[c] = None
        return out
    except Exception:
        return pd.DataFrame()

def _fallback_build_upcoming_dataframe(league_name: str) -> pd.DataFrame:
    """Scan Matches/<league>/ and Fixtures/ (if any) for upcoming rows."""
    root = PROJECT_ROOT
    # Try Matches/<league> first, then Fixtures/<league>, then Upcoming/<league>
    dirs = [
        _best_dir_under(_Path(root) / "Matches", league_name),
        _best_dir_under(_Path(root) / "Fixtures", league_name),
        _best_dir_under(_Path(root) / "Upcoming", league_name),
    ]
    cand = next((d for d in dirs if d is not None), None)
    if cand is None:
        return pd.DataFrame(columns=["home_team_name","away_team_name","match_date"])
    try:
        files = sorted(_glob.glob(str(cand / "*.csv")))
        files = files[-20:] if len(files) > 20 else files  # prefer recent
        if os.getenv("VERBOSE_QUICK","0") == "1":
            try:
                print(f"🔎 [quick] upcoming dir: {cand} | csv_count={len(files)}")
            except Exception:
                pass

        df = _read_csvs(files)
        if df.empty:
            return pd.DataFrame(columns=["home_team_name","away_team_name","match_date"])
        # Canonicalize + optional league filter if a global file slipped in
        try:
            df = _canonize(df)
        except Exception:
            pass
        try:
            _m = _league_mask(df, league_name)
            if getattr(_m, "any", lambda: False)():
                if _m.any() and int(_m.sum()) != len(df):
                    df = df.loc[_m].copy()
        except Exception:
            pass
        # Normalize upcoming columns once
        df = _normalize_upcoming_columns_inplace(df)
        md = pd.to_datetime(df.get("match_date"), errors="coerce")
        today = pd.Timestamp.today().normalize()

        md = pd.to_datetime(df.get("match_date"), errors="coerce")
        today = pd.Timestamp.today().normalize()

        # status-based upcoming (authoritative in this schema: 'incomplete' means future)
        status_col = _find_col(df, ["status","match_status","game_status","fixture_status"])
        status_future = pd.Series(False, index=df.index)
        status_complete = pd.Series(False, index=df.index)
        if status_col:
            s = df[status_col].astype(str).str.lower().str.strip()
            # Future / not-yet-played statuses
            status_future = s.isin([
                "incomplete","not started","scheduled","upcoming","fixture",
                "postponed","delayed","tbd","to be played"
            ])
            # Completed / finished markers
            status_complete = s.isin([
                "complete","completed","finished","full time","full-time","ft","result"
            ])
        else:
            s = None
        # Treat future-dated fixtures as future even if status is missing/unrecognized
        if md.notna().any():
            status_future = status_future | (md >= today)

        # goals (may be absent in many fixture files)
        hh = pd.to_numeric(df["home_team_goal_count"], errors="coerce") if "home_team_goal_count" in df.columns else pd.Series(np.nan, index=df.index)
        aa = pd.to_numeric(df["away_team_goal_count"], errors="coerce") if "away_team_goal_count" in df.columns else pd.Series(np.nan, index=df.index)
        realized_mask = (hh.notna() & aa.notna())

        # Consider rows as realized only if provider marks them complete.
        # This avoids misclassifying fixtures that have placeholder 0-0 goals.
        realized = status_complete | (realized_mask & ~status_future)

        # date-based (secondary)
        if md.notna().any():
            date_upcoming = (md >= today) & (~realized)
        else:
            date_upcoming = pd.Series(False, index=df.index)

        # Build a robust upcoming mask:
        #  - explicit future status OR future date
        #  - and not explicitly complete/realized
        upcoming_mask = (status_future | date_upcoming) & (~realized)
        out = df.loc[upcoming_mask].copy()

        # Keep core cols at least
        for c in ("home_team_name","away_team_name","match_date"):
            if c not in out.columns:
                out[c] = None

        # Debug counts
        if os.getenv("VERBOSE_QUICK","0") == "1":
            try:
                _sf = int(status_future.sum()) if isinstance(status_future, pd.Series) else 0
                _rc = int(realized.sum()) if "realized" in locals() and isinstance(realized, pd.Series) else int(realized_mask.sum())
                print(
                    f"🔎 [quick] upcoming rows: total={len(df)} | selected={len(out)} | "
                    f"has_dates={md.notna().any()} | realized_rows={_rc} | future_flagged={_sf}"
                )
            except Exception:
                pass

        return out
    except Exception:
        return pd.DataFrame(columns=["home_team_name","away_team_name","match_date"])

# --- Goal-model I/O helpers + λ̂ attach (in-place, model-store based) ---
if "_load_goal_models" not in globals():
    def _load_goal_models(league: str):
        """
        Load persisted home/away goal regressors for a league from DEFAULT_MODEL_DIR.
        Returns (home_model, away_model) or (None, None) if missing.
        """
        import joblib as _joblib, os as _os, re as _re
        from pathlib import Path as _Path
        slug = _re.sub(r"[^a-z0-9]+", "_", str(league).lower()).strip("_") or "unknown_league"
        base = _Path(DEFAULT_MODEL_DIR)
        try:
            hm = _joblib.load(base / f"{slug}_home_goals_model.pkl")
        except Exception:
            hm = None
        try:
            am = _joblib.load(base / f"{slug}_away_goals_model.pkl")
        except Exception:
            am = None
        return hm, am
    
# Persist a home/away goal-model pair to disk (used by quick λ̂ fallback)
if "_persist_goal_pair" not in globals():
    def _persist_goal_pair(home_model, away_model, league: str):  # pyright: ignore[reportUnusedFunction]
        """
        Persist home/away goal regressors to DEFAULT_MODEL_DIR.
        Returns tuple of saved paths (p_home, p_away); None if a side failed.
        """
        import joblib as _joblib, re as _re
        from pathlib import Path as _Path

        slug = _re.sub(r"[^a-z0-9]+", "_", str(league).lower()).strip("_") or "unknown_league"
        base = _Path(DEFAULT_MODEL_DIR)
        base.mkdir(parents=True, exist_ok=True)

        p_home = base / f"{slug}_home_goals_model.pkl"
        p_away = base / f"{slug}_away_goals_model.pkl"

        try:
            _joblib.dump(home_model, p_home)
        except Exception:
            p_home = None
        try:
            _joblib.dump(away_model, p_away)
        except Exception:
            p_away = None

        # Nice console hint
        try:
            if p_home and p_away:
                print(f"💾 Saved goal models → {p_home}  &  {p_away}")
            elif p_home or p_away:
                print(f"💾 Saved goal model → {p_home or p_away}")
        except Exception:
            pass

        return p_home, p_away

if "attach_lambda_features_inplace" not in globals():
    def attach_lambda_features_inplace(df: pd.DataFrame, league: str) -> pd.DataFrame:
        """
        Attach λ_home, λ_away, exp_goals_sum, p00_est to df using goal models loaded
        from DEFAULT_MODEL_DIR. If missing, train a tiny ridge fallback on realized
        rows (numeric-only), persist via _persist_goal_pair (if available), then score.
        Safe to call on both training & upcoming frames.
        """
        # Warn if CatBoost stub is active (defensive; ok if function missing)
        try:
            _warn_if_catboost_stub()  # type: ignore[name-defined]
        except Exception:
            pass
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        # Try to load persisted models
        hm, am = _load_goal_models(league)

        # If either side missing, attempt a light fallback fit on realized rows
        if hm is None or am is None:
            try:
                from sklearn.linear_model import Ridge
                yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
                ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
                m = yh.notna() & ya.notna()
                if int(m.sum()) >= 500:
                    X = df.loc[m].select_dtypes(include=["number"]).replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
                    _hm = Ridge(alpha=2.0).fit(X, yh[m].astype(float))
                    _am = Ridge(alpha=2.0).fit(X, ya[m].astype(float))
                    # Persist using the canonical helper if available
                    try:
                        _persist_goal_pair(_hm, _am, league)  # type: ignore[name-defined]
                    except Exception:
                        # Fallback: no-op if persist helper not present
                        pass
                    hm = hm or _hm
                    am = am or _am
            except Exception:
                pass  # leave hm/am as-is (possibly None)

        # If still nothing to score with, exit quietly
        if hm is None and am is None:
            return df

        # Build numeric feature matrix for inference and score
        try:
            Xall = df.select_dtypes(include=["number"]).replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
            # Align feature matrix to models' expected columns if available
            def _feat_names(mdl):
                try:
                    cols = list(getattr(mdl, "feature_names_in_", []))
                    return cols if cols else None
                except Exception:
                    return None

            use_cols = None
            h_cols = _feat_names(hm) if hm is not None else None
            a_cols = _feat_names(am) if am is not None else None
            if h_cols and a_cols:
                inter = [c for c in h_cols if c in set(a_cols)]
                use_cols = inter if len(inter) else h_cols
            elif h_cols:
                use_cols = h_cols
            elif a_cols:
                use_cols = a_cols
            if use_cols:
                Xall = Xall.reindex(columns=use_cols, fill_value=0.0)
            if hm is not None:
                df["lambda_home"] = _np.clip(_np.asarray(hm.predict(Xall), dtype=float), 0.01, 10.0)
            if am is not None:
                df["lambda_away"] = _np.clip(_np.asarray(am.predict(Xall), dtype=float), 0.01, 10.0)
            if "lambda_home" in df.columns and "lambda_away" in df.columns:
                L = _pd.to_numeric(df["lambda_home"], errors="coerce").fillna(0) + \
                    _pd.to_numeric(df["lambda_away"], errors="coerce").fillna(0)
                df["exp_goals_sum"] = L
                df = _lambda_sanitize_inplace(df)
                with _np.errstate(over="ignore"):
                    df["p00_est"] = _np.exp(-_pd.to_numeric(df["exp_goals_sum"], errors="coerce"))
        except Exception:
            # leave frame untouched if scoring fails
            pass

        return df

# --- Lambda features (expected goals + 0-0 prob) for quick FTR ---
if "attach_lambda_features" not in globals():
    def attach_lambda_features(df: pd.DataFrame, goal_bundle) -> pd.DataFrame:
        import numpy as _np, pandas as _pd, os as _os
        if not isinstance(df, _pd.DataFrame) or df.empty or not goal_bundle:
            return df

        # Extract models + optional selector
        try:
            fs = goal_bundle.get("feature_selector", None) if isinstance(goal_bundle, dict) else None
        except Exception:
            fs = None
        try:
            h_model = goal_bundle.get("home") if isinstance(goal_bundle, dict) else None
            a_model = goal_bundle.get("away") if isinstance(goal_bundle, dict) else None
        except Exception:
            h_model = a_model = None

        if h_model is None or a_model is None:
            return df

        # Helper: prefer explicit feature names from model, else None
        def _feat_names(mdl):
            try:
                cols = list(getattr(mdl, "feature_names_in_", []))
                return cols if cols else None
            except Exception:
                return None

        # Build candidate feature matrix
        try:
            if callable(fs):
                X = fs(df)
            else:
                X = df.select_dtypes(include=["number"])
        except Exception:
            X = df.select_dtypes(include=["number"])

        # Clean numeric features
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)

        # Align to models' expected columns if declared
        h_cols = _feat_names(h_model)
        a_cols = _feat_names(a_model)

        use_cols = None
        if h_cols and a_cols:
            # intersection in case the models differ slightly
            inter = [c for c in h_cols if c in set(a_cols)]
            use_cols = inter if len(inter) else h_cols
        elif h_cols:
            use_cols = h_cols
        elif a_cols:
            use_cols = a_cols

        if use_cols:
            # reindex strictly to expected features
            X = X.reindex(columns=use_cols, fill_value=0.0)
        # else: keep X as-is (numeric-only); models without feature names should still have n_features_in_ consistency

        # Try to predict; if it fails, emit a verbose hint and return df unchanged
        try:
            lam_h = h_model.predict(X)
            lam_a = a_model.predict(X)
        except Exception as _e:
            # Optional verbose diagnostics
            try:
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    _nhi = getattr(h_model, "n_features_in_", None)
                    _nai = getattr(a_model, "n_features_in_", None)
                    print(f"ℹ️  λ-attach skipped (shape mismatch?): X_cols={X.shape[1]} h_in={_nhi} a_in={_nai} err={_e}")
            except Exception:
                pass
            return df

        out = df.copy()
        out["lambda_home"] = _np.clip(_pd.to_numeric(lam_h, errors="coerce"), 0.01, 10.0)
        out["lambda_away"] = _np.clip(_pd.to_numeric(lam_a, errors="coerce"), 0.01, 10.0)
        L = out["lambda_home"] + out["lambda_away"]
        out["exp_goals_sum"] = L
        out["p00_est"] = _np.exp(-_pd.to_numeric(out["exp_goals_sum"], errors="coerce"))
        return out
    
# --- Tiny sanity logger for λ̂ presence (guarded by VERBOSE_LAMBDA or VERBOSE_QUICK) ---
if "_log_lambda_presence" not in globals():
    def _log_lambda_presence(df, phase_hint: str | None = None):
        try:
            import os as _os, pandas as _pd, numpy as _np
            if not isinstance(df, _pd.DataFrame) or df.empty:
                return
            # Respect VERBOSE_LAMBDA first, else fall back to VERBOSE_QUICK
            if _os.getenv("VERBOSE_LAMBDA", _os.getenv("VERBOSE_QUICK", "0")) != "1":
                return
            # Heuristic to tag phase if not supplied: if realized goals mostly present → "training"
            if phase_hint is None:
                try:
                    hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
                    aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
                    if (hh.notna().mean() > 0.6) and (aa.notna().mean() > 0.6):
                        phase_hint = "training"
                    else:
                        phase_hint = "upcoming"
                except Exception:
                    phase_hint = "data"
            n = int(df.get("exp_goals_sum", _pd.Series()).notna().sum()) if "exp_goals_sum" in df.columns else 0
            print(f"🧮 λ-features ({phase_hint}) → exp_goals_sum non-NaN={n}/{len(df)}")
        except Exception:
            pass

# --- Wrapper: ensure λ̂ features also applied via persisted models (covers full pipeline) ---
if "_ATTACH_LAMBDA_WRAPPED" not in globals():
    _ATTACH_LAMBDA_WRAPPED = True
    _attach_lambda_features_orig = attach_lambda_features
    def attach_lambda_features(df: pd.DataFrame, goal_bundle) -> pd.DataFrame:
        """
        Call the original attach_lambda_features first (uses goal_bundle),
        then apply in-place λ̂ using any persisted league models. This ensures
        full-mode paths also receive lambda_home/lambda_away/exp_goals_sum/p00_est
        even if the bundle is missing or mismatched.
        """
        out = _attach_lambda_features_orig(df, goal_bundle)
        try:
            _lname = globals().get("league_name", None)
            if _lname:
                out = attach_lambda_features_inplace(out, _lname)
        except Exception:
            pass
        # Optional: tiny sanity print for full/quick paths alike
        try:
            _log_lambda_presence(out, None)
        except Exception:
            pass
        # Ensure FTR engineered features are available after λ attach
        try:
            out = _ensure_ftr_derived_features(out)
        except Exception:
            pass
        # Ensure Poisson fallback for Over 1.5 / 3.5 / 4.5 (new totals markets)
        try:
            out = _ensure_poisson_over_probs_inplace(out)
        except Exception:
            pass
        return out

# --- Quick fallback: ensure a goal-model bundle if project helper is missing ---
if "_ensure_goal_bundle_quick" not in globals():
    def _ensure_goal_bundle_quick(df: pd.DataFrame, league: str):  # pyright: ignore[reportUnusedFunction]
        """
        Very small, dependency-light trainer for expected goals:
          - Uses numeric features (excluding goal labels and leaky features)
          - Fits home & away regressors (PoissonRegressor if available, else Ridge)
          - Returns a bundle: {"home": model_home, "away": model_away, "feature_selector": selector}
        """
        # Warn if CatBoost stub is active (defensive; ok if function missing)
        try:
            _warn_if_catboost_stub()  # type: ignore[name-defined]
        except Exception:
            pass
        import numpy as _np, pandas as _pd
        from pathlib import Path as _Path
        import re as _re
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return None
        # Keep only realized rows
        yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        m  = yh.notna() & ya.notna()
        if int(m.sum()) < 300:
            return None
        hist = df.loc[m].copy()
        # Build leak-free numeric feature set
        drop_exact = {
            "home_team_goal_count","away_team_goal_count","total_goal_count",
            "home_team_goal_count_half_time","away_team_goal_count_half_time",
            "exp_goals_sum","p00_est","lambda_home","lambda_away",
        }
        drop_prefix = ("ft_","ht_","shots_","cards_","fouls_","minute_","min_")
        X = hist.select_dtypes(include=["number"]).copy()
        X = X.drop(columns=[c for c in X.columns if (c in drop_exact) or c.startswith(drop_prefix)], errors="ignore")
        X = X.replace([_np.inf,-_np.inf], _np.nan).fillna(0.0)
        # If too few features, fall back to all numeric excluding labels
        if X.shape[1] < 8:
            X = hist.select_dtypes(include=["number"]).drop(columns=list(drop_exact), errors="ignore")
            X = X.replace([_np.inf,-_np.inf], _np.nan).fillna(0.0)
        y_h = yh[m].astype(float).values
        y_a = ya[m].astype(float).values
        # Prefer PoissonRegressor; else Ridge
        home_model = away_model = None
        try:
            from sklearn.linear_model import PoissonRegressor
            home_model = PoissonRegressor(alpha=1.0, max_iter=300)
            away_model = PoissonRegressor(alpha=1.0, max_iter=300)
        except Exception:
            from sklearn.linear_model import Ridge
            home_model = Ridge(alpha=2.0)
            away_model = Ridge(alpha=2.0)
        try:
            home_model.fit(X, y_h)
            away_model.fit(X, y_a)
        except Exception:
            return None
        # Persist models under canonical slug names
        try:
            _persist_goal_pair(home_model, away_model, league)  # type: ignore[name-defined]
        except Exception:
            pass
        # Build a simple selector that reindexes to the models' expected columns
        feat_cols = list(getattr(home_model, "feature_names_in_", []))
        if not feat_cols:
            feat_cols = list(getattr(away_model, "feature_names_in_", []))
        def _selector(_df: pd.DataFrame):
            Z = _df.select_dtypes(include=["number"]).replace([_np.inf,-_np.inf], _np.nan).fillna(0.0)
            if feat_cols:
                Z = Z.reindex(columns=feat_cols, fill_value=0.0)
            return Z
        return {"home": home_model, "away": away_model, "feature_selector": _selector}
# --- Quick-run pipeline (main for --quick CLI or as importable) ---

def run_league_quick(league: str, export: str | None = None) -> pd.DataFrame:
    """
    Lightweight end-to-end run for a single league using quick/fallback helpers.
    - Rebuilds press artefacts using the saved baseline_blend (α) if available
    - Ensures goal λ̂ models exist (quick trainer) and attaches λ̂ to upcoming
    - Mixes FTR via the overlay's adaptive mixer (predict_FTR_adaptive under the hood)
    - Writes a predictions CSV to PredictionReports/<LeagueTag>_predictions.csv (or export)
    Returns the scored DataFrame.
    """
    print(f"🚀 quick entry: using run_league_quick@{__file__}:{run_league_quick.__code__.co_firstlineno}")
    # Warn if CatBoost stub is active (defensive; ok if function missing)
    try:
        _warn_if_catboost_stub()  # type: ignore[name-defined]
    except Exception:
        pass

    league_name = _league_name(league)
    try:
        _apply_tuned_gate_gamma_for_league(league_name)
    except Exception:
        pass
    tag = league_name.replace(" ", "_")
    globals()["league_name"] = league_name

    # 1) Prepare press artefacts with the same α the draw trainer used
    try:
        from prediction_overlay import prepare_league_for_inference as _prep  # type: ignore
        _prep(league_name, overwrite_intensity=False, debug_attach=False)
    except Exception:
        pass

    # 2) Build training/upcoming frames via disk discovery
    hist = _fallback_build_training_dataframe(league_name)
    upc  = _fallback_build_upcoming_dataframe(league_name)
    if upc is None or upc.empty:
        try:
            print(f"ℹ️  No upcoming fixtures found for {league_name}.")
        except Exception:
            pass
        return pd.DataFrame()
    # Ensure specialist side probabilities are present for upcoming inference
    try:
        upc = _ensure_upcoming_side_probs(upc, league_name)
    except Exception:
        pass

    # 3) Ensure λ̂ models and attach λ̂ to upcoming
    try:
        # Persist quick goal models if needed
        if hist is not None and not hist.empty:
            _ = _ensure_goal_bundle_quick(hist, league_name)  # type: ignore[name-defined]
        # Attach λ̂ in-place to upcoming
        upc = attach_lambda_features_inplace(upc, league_name)
        # Map to overlay-expected columns if needed
        if "lambda_home" in upc.columns and "home_goals_pred" not in upc.columns:
            upc["home_goals_pred"] = upc["lambda_home"]
        if "lambda_away" in upc.columns and "away_goals_pred" not in upc.columns:
            upc["away_goals_pred"] = upc["lambda_away"]
        # Derived features & Poisson totals fallbacks
        upc = _ensure_ftr_derived_features(upc)
        upc = _ensure_poisson_over_probs_inplace(upc)
    except Exception:
        pass

        # 4) Mix FTR via overlay (force overwrite + loud logs)
    try:
        import os as _os
        print(f"🔎 quick guard: ENABLE_QUICK_FTR={_os.getenv('ENABLE_QUICK_FTR')} "
              f"DISABLE_QUICK_FTR={_os.getenv('DISABLE_QUICK_FTR')}")
        if _os.getenv("ENABLE_QUICK_FTR", "0") == "1" and _os.getenv("DISABLE_QUICK_FTR", "0") != "1":
            # robust loader so we can see what module we actually import
            try:
                import importlib
                import prediction_overlay as _po
                print(f"🔧 baseline: overlay module → {_po.__file__}")
                attach = getattr(_po, "attach_ftr_with_draw_mix", None)
                if attach is None:
                    print("⚠️ overlay missing 'attach_ftr_with_draw_mix'; available names (subset):",
                          [n for n in dir(_po) if ("attach" in n or "draw" in n)][:20])
                    scored = upc
                else:
                    print(f"🔧 baseline: calling overlay attach_ftr_with_draw_mix (league={league_name})")
                    upc = attach(upc, league_name)  # overwrite upstream frame
                    scored = upc
            except Exception as _e:
                print(f"⚠️ overlay import failed: {_e}")
                scored = upc
        else:
            print("ℹ️ overlay bypassed (ENABLE_QUICK_FTR!=1 or DISABLE_QUICK_FTR=1)")
            scored = upc
    except Exception as e:
        print(f"⚠️  overlay FTR mix failed: {e}")
        scored = upc

    

    # 5) Write predictions CSV
    try:
        out_dir = export or DEFAULT_PREDICTION_REPORTS_DIR
        os.makedirs(out_dir, exist_ok=True)
        out_path = os.path.join(out_dir, f"{tag}_predictions.csv")
        scored.to_csv(out_path, index=False)
        print(f"✅ quick predictions → {out_path} ({len(scored)} rows)")
    except Exception:
        pass

    # Write time-split FTR report using historical data (no leakage)
    try:
        if hist is not None and not hist.empty:
            _write_time_split_ftr_report(hist, league_name)
    except Exception:
        pass

    return scored

def run_pipeline_for_league(league: str, *, export: str | None = None) -> pd.DataFrame:
    """
    Full-mode wrapper that currently delegates to the quick path, then saves a
    deployable FTR CSV via the overlay shim (if available). Returns the DataFrame.
    """
    # Warn if CatBoost stub is active
    try:
        _warn_if_catboost_stub()  # type: ignore[name-defined]
    except Exception:
        pass

    df = run_league_quick(league, export)

    # Attempt to save a deployable FTR file (overlay saver if available)
    import os as _os
    try:
        if _os.getenv("ENABLE_QUICK_FTR", "0") == "1" and _os.getenv("DISABLE_QUICK_FTR", "0") != "1":
            try:
                from prediction_overlay import _ensure_roi_inputs_inplace as _ensure_roi  # type: ignore
                df = _ensure_roi(df)
            except Exception:
                pass
            ok = _shim_save_deployable_ftr(df, _league_name(league))
            if ok:
                print("✅ deployable FTR saved via overlay")
        else:
            # overlay saver disabled (quick attach is OFF)
            pass
    except Exception:
        pass
    return df

def score_ftr_csv(league: str, csv_path: str, *, out_csv: str | None = None, tail: int | None = None) -> pd.DataFrame | None:
    """
    Score a CSV (or directory of CSVs) for FTR using the overlay mixer.
    - Reads/normalizes the input CSV(s)
    - Ensures λ̂ models and press artefacts, attaches λ̂ to the frame
    - Calls overlay mixer to produce confidence_home/draw/away and ftr_pred_outcome
    - Writes a CSV to `out_csv` or to PredictionReports/<LeagueTag>_predictions.csv
    Returns the scored DataFrame.
    """
    # Warn if CatBoost stub is active
    try:
        _warn_if_catboost_stub()  # type: ignore[name-defined]
    except Exception:
        pass

    league_name = _league_name(league)
    tag = league_name.replace(" ", "_")

    # Read one file or a directory of files
    try:
        if os.path.isdir(csv_path):
            paths = sorted([os.path.join(csv_path, p) for p in os.listdir(csv_path) if p.lower().endswith('.csv')])
            df = _read_csvs(paths)
        else:
            df = pd.read_csv(csv_path, low_memory=False)
    except Exception as e:
        print(f"⚠️  could not read {csv_path}: {e}")
        return None

    if df is None or df.empty:
        print("ℹ️  input CSV(s) produced an empty frame")
        return None

    # Canonicalize / normalize upcoming schema
    try:
        df = _canonize(df)
    except Exception:
        pass
    df = _normalize_upcoming_columns_inplace(df)
    try:
        df = _ensure_upcoming_side_probs(df, league_name)
    except Exception:
        pass

    # Prepare press artefacts with α, ensure λ̂ models exist
    try:
        from prediction_overlay import prepare_league_for_inference as _prep  # type: ignore
        _prep(league_name, overwrite_intensity=False, debug_attach=False)
    except Exception:
        pass
    try:
        hist = _fallback_build_training_dataframe(league_name)
        if hist is not None and not hist.empty:
            _ = _ensure_goal_bundle_quick(hist, league_name)  # type: ignore[name-defined]
        df = attach_lambda_features_inplace(df, league_name)
        if "lambda_home" in df.columns and "home_goals_pred" not in df.columns:
            df["home_goals_pred"] = df["lambda_home"]
        if "lambda_away" in df.columns and "away_goals_pred" not in df.columns:
            df["away_goals_pred"] = df["lambda_away"]
        df = _ensure_ftr_derived_features(df)
        df = _ensure_poisson_over_probs_inplace(df)
    except Exception:
        pass

    # Mix FTR via overlay (force overwrite + loud logs)
    try:
        import os as _os
        print(f"🔎 quick guard: ENABLE_QUICK_FTR={_os.getenv('ENABLE_QUICK_FTR')} "
              f"DISABLE_QUICK_FTR={_os.getenv('DISABLE_QUICK_FTR')}")
        if _os.getenv("ENABLE_QUICK_FTR", "0") == "1" and _os.getenv("DISABLE_QUICK_FTR", "0") != "1":
            try:
                import importlib
                import prediction_overlay as _po
                print(f"🔧 baseline: overlay module → {_po.__file__}")
                attach = getattr(_po, "attach_ftr_with_draw_mix", None)
                if attach is None:
                    print("⚠️ overlay missing 'attach_ftr_with_draw_mix'; available names (subset):",
                          [n for n in dir(_po) if ("attach" in n or "draw" in n)][:20])
                    scored = df
                else:
                    print(f"🔧 baseline: calling overlay attach_ftr_with_draw_mix (league={league_name})")
                    df = attach(df, league_name)    # overwrite the working frame
                    scored = df
            except Exception as _e:
                print(f"⚠️ overlay import failed: {_e}")
                scored = df
        else:
            print("ℹ️ overlay bypassed (ENABLE_QUICK_FTR!=1 or DISABLE_QUICK_FTR=1)")
            scored = df
    except Exception as e:
        print(f"⚠️  overlay FTR mix failed: {e}")
        scored = df

    if tail is not None:
        try:
            scored = scored.tail(int(tail))
        except Exception:
            pass

    # Write predictions CSV
    try:
        out_path = out_csv
        if not out_path:
            out_dir = DEFAULT_PREDICTION_REPORTS_DIR
            os.makedirs(out_dir, exist_ok=True)
            out_path = os.path.join(out_dir, f"{tag}_predictions.csv")
        scored.to_csv(out_path, index=False)
        print(f"✅ scored CSV → {out_path} ({len(scored)} rows)")
    except Exception as e:
        print(f"⚠️  could not save predictions CSV: {e}")

    return scored

 # --- Deterministic fallback draw model (logistic) ----------------------------
if "_draw_fallback_logistic" not in globals():
    def _draw_fallback_logistic(df: pd.DataFrame, league) -> dict:
        """Train a simple logistic fallback on numeric features with deterministic order.
        Returns a bundle dict {"estimator": clf, "feature_names": cols}.
        """
        import numpy as _np, pandas as _pd
        from sklearn.linear_model import LogisticRegression
        if not isinstance(df, _pd.DataFrame) or df.empty:
            # minimal dummy classifier (predicts class 0)
            class _Dummy:
                classes_ = _np.array([0,1])
                n_features_in_ = 1
                def predict_proba(self, X):
                    import numpy as _np
                    n = getattr(X, 'shape', [0])[0] or (len(X) if hasattr(X, '__len__') else 0)
                    return _np.tile([0.9,0.1], (n,1)).astype(float)
            return {"estimator": _Dummy(), "feature_names": []}
        # Build numeric X deterministically
        X = df.select_dtypes(include=["number"]).copy()
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        cols_sorted = sorted(list(X.columns))
        X = X.reindex(columns=cols_sorted, fill_value=0.0)
        # Label: treat draws as 1, others 0 (fallback)
        y = _pd.to_numeric(df.get("is_draw"), errors="coerce")
        if y is None or y.isna().all():
            hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
            aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
            y = (hh == aa).astype(int)
        y = y.fillna(0).astype(int).to_numpy()
        # Train
        clf = LogisticRegression(max_iter=400, n_jobs=1, solver="lbfgs")
        try:
            clf.fit(X, y)
        except Exception:
            clf = LogisticRegression(max_iter=800, n_jobs=1, solver="lbfgs", C=0.5)
        clf.fit(X, y)
        # Record deterministic feature names for inference alignment
        try:
            clf.feature_names_in_ = _np.array(cols_sorted, dtype=object)  # type: ignore[attr-defined]
        except Exception:
            pass
        # OG_IMPORTING/ALLOW_IMPORT_REPORT guard for predict_proba
        # (inference-time hack: see https://github.com/oddsguru/OG/issues/206)
        # Only call predict_proba if not importing (or explicit override)
        if (os.getenv("OG_IMPORTING", "1") != "1") or (os.getenv("ALLOW_IMPORT_REPORT", "0") == "1"):
            P_tr = clf.predict_proba(X)
        return {"estimator": clf, "feature_names": cols_sorted}

# --- Draw bundle builder (unconditional override; logs fallback, persists path) ---
def _build_draw_bundle(df: pd.DataFrame, league) -> object:
    """Try project draw bundle; on failure, log and fall back to logistic.
    Returns a bundle or estimator usable by _attach_draw_prob_with_bundle.
    """
    import os as _os, re
    # 0) Try to load a persisted bundle first (JSON hint → slug path)
    try:
        from pathlib import Path as _Path
        import joblib as _joblib, re as _re, json as _json
        base = _Path(DEFAULT_MODEL_DIR)
        tag  = str(league).replace(" ", "_")
        thr  = base / f"{tag}_draw_threshold.json"
        # (a) JSON hint
        if thr.exists():
            try:
                with open(thr, "r", encoding="utf-8") as fh:
                    meta = _json.load(fh) or {}
                hint = meta.get("model_bundle_path")
                if hint:
                    hp = _Path(hint)
                    if not hp.is_absolute():
                        hp = base / hp
                    if hp.exists():
                        bundle = _joblib.load(hp)
                        try:
                            print(f"💾 draw bundle loaded ← {hp}")
                        except Exception:
                            pass
                        return bundle
            except Exception:
                pass
        # (b) Slugged path fallback
        slug = _re.sub(r"[^a-z0-9]+","_", str(league).lower()).strip("_") or "unknown_league"
        p = base / f"{slug}__draw_bundle.joblib"
        if p.exists():
            bundle = _joblib.load(p)
            try:
                print(f"💾 draw bundle loaded ← {p}")
            except Exception:
                pass
            return bundle
    except Exception:
        pass

    # Try import first
    try:
        from train_draw_classifier import ensure_draw_bundle as _ensure_draw_bundle  # type: ignore
    except Exception as e:
        _ensure_draw_bundle = None
        reason = f"import_error:{e}"
    else:
        reason = None

    bundle = None
    if callable(_ensure_draw_bundle):
        try:
            row_cap = int(float(_os.getenv("DRAW_ROW_CAP", "20000")))
            n_jobs  = int(float(_os.getenv("SKLEARN_JOBS", "1")))
            permimp = (str(_os.getenv("DISABLE_DRAW_PERMIMP", "0")) != "1")
            # Train on historical data (labels present), not on upcoming frames
            try:
                df_hist = _fallback_build_training_dataframe(str(league))
            except Exception:
                df_hist = df
            bundle = _ensure_draw_bundle(df_hist, league, row_cap=row_cap, n_jobs=n_jobs, perm_importance=permimp)
        except Exception as e:
            reason = f"ensure_error:{e}"
            bundle = None

    if bundle is None:
        # Fallback (log reason if any)
        try:
            print(f"⚠️  draw bridge fallback → {reason or 'none_returned'}")
        except Exception:
            pass
        return _draw_fallback_logistic(df, league)  # type: ignore[name-defined]

    # Persist bundle (best-effort)
    try:
        from pathlib import Path as _Path
        import joblib as _joblib
        base = _Path(DEFAULT_MODEL_DIR)
        base.mkdir(parents=True, exist_ok=True)
        slug = re.sub(r"[^a-z0-9]+","_", str(league).lower()).strip("_") or "unknown_league"
        p = base / f"{slug}__draw_bundle.joblib"
        _joblib.dump(bundle, p)
        print(f"💾 draw bundle saved → {p}")
    except Exception:
        pass

    try:
        print("✅ draw bridge OK (project bundle)")
    except Exception:
        pass
    return bundle

# --- Attach draw probability via bundle (train once, score many) --------------
if "_attach_draw_prob_with_bundle" not in globals():
    def _attach_draw_prob_with_bundle(df: pd.DataFrame, league, bundle=None) -> tuple[pd.DataFrame, object]:
        """Ensure df has prob_draw_model using a draw bundle. Returns (df, bundle).
        If bundle is None, builds via _build_draw_bundle(df, league). Non-destructive to
        other columns; only sets/overwrites 'prob_draw_model'.
        """
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df, bundle
        try:
            b = bundle if bundle is not None else _build_draw_bundle(df, league)  # type: ignore[name-defined]
        except Exception:
            b = None
        if b is None:
            return df, bundle  # leave as-is; later tempering handles missing

        # Resolve estimator
        est = None
        if isinstance(b, dict):
            est = b.get("estimator") or b.get("model") or b.get("est")
        if est is None:
            est = b

        # Helper: resolve feature names from estimator (recursively) or bundle meta
        def _resolve_feat_names(estimator, bundle_dict):
            def _get_fni(est):
                for attr in ("feature_names_in_", "feature_names_"):
                    try:
                        cols = list(getattr(est, attr, []))
                        if cols:
                            return cols
                    except Exception:
                        pass
                # nested (e.g., CalibratedClassifierCV)
                try:
                    inner = getattr(est, "estimator", None) or getattr(est, "base_estimator", None)
                    if inner is not None:
                        return _get_fni(inner)
                except Exception:
                    pass
                return None
            # 1) bundle-provided list (if any)
            if isinstance(bundle_dict, dict):
                for key in ("feature_names", "features", "feature_list", "features_used", "trained_feature_cols"):
                    fl = bundle_dict.get(key)
                    if isinstance(fl, (list, tuple)) and len(fl):
                        return list(fl)
            # 2) estimator-provided
            return _get_fni(estimator)

        # Build candidate X using bundle feature_selector if provided; else numeric-only
        try:
            fs = None
            if isinstance(b, dict):
                sel = b.get("feature_selector", None)
                fs = sel if callable(sel) else None
            if callable(fs):
                X = fs(df)
            else:
                X = df.select_dtypes(include=["number"])  # candidate numeric frame
        except Exception:
            X = df.select_dtypes(include=["number"])      # fallback
        # Deterministic order for numeric columns
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        X = X.reindex(columns=sorted(list(X.columns)), fill_value=0.0)

        # Align strictly to expected feature names if any are known
        try:
            fni = _resolve_feat_names(est, b)
            if isinstance(fni, (list, tuple)) and fni:
                X = X.reindex(columns=list(fni), fill_value=0.0)
        except Exception:
            pass
        # If estimator declares only n_features_in_, trim/expand deterministically
        try:
            nfi = int(getattr(est, "n_features_in_", 0))
            if nfi and X.shape[1] != nfi:
                if X.shape[1] > nfi:
                    X = X.iloc[:, :nfi]
                else:
                    # pad with zeros columns if needed (rare)
                    add = nfi - X.shape[1]
                    for k in range(add):
                        X[f"__pad_{k}"] = 0.0
                    X = X.iloc[:, :nfi]
        except Exception:
            pass
        try:
            proba = None
            try:
                if hasattr(est, "predict_proba"):
                    proba = est.predict_proba(X)
                elif isinstance(b, dict) and callable(b.get("predict_proba", None)):
                    proba = b["predict_proba"](X)
            except Exception as _name_err:
                # Retry with numpy array to bypass strict feature-name checks
                try:
                    _Xn = X.to_numpy(copy=False)
                    if hasattr(est, "predict_proba"):
                        proba = est.predict_proba(_Xn)
                    elif isinstance(b, dict) and callable(b.get("predict_proba", None)):
                        proba = b["predict_proba"](_Xn)
                except Exception:
                    raise _name_err

            arr = _np.asarray(proba, dtype=float) if proba is not None else None
            if arr is not None and arr.ndim == 2 and arr.shape[0] == len(X):
                # find draw column: prefer classes_ if present, else index 1
                try:
                    classes = list(getattr(est, "classes_", []))
                    idx_draw = classes.index("draw") if classes and "draw" in classes else 1
                except Exception:
                    idx_draw = 1
                df["prob_draw_model"] = _np.clip(arr[:, idx_draw], 0.0, 1.0)
        except Exception as _e:
            try:
                import os as _os
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    print(f"⚠️  draw attach failed: {_e}")
            except Exception:
                pass
        return df, b        
# --- Threshold tuner shim: avoid recall-only tuning for deploy markets -----
try:
    _orig_tune_binary_threshold = tune_binary_threshold  # type: ignore[name-defined]
    def tune_binary_threshold(y, p, metric: str = "f1", **kwargs):  # type: ignore[override]
        # Force F1 when callers request recall; allow EV via tune_threshold_guard elsewhere
        m = (metric or "f1").lower()
        if m == "recall":
            m = "f1"
        return _orig_tune_binary_threshold(y, p, metric=m, **kwargs)
except Exception:
    pass
 # --- Confidence gate: fail-closed wrapper ---------------------------------
if "_gate_ftr_by_confidence" in globals() and "_GATE_WRAP" not in globals():
    _GATE_WRAP = True
    _gate_ftr_by_confidence_orig = _gate_ftr_by_confidence
    def _gate_ftr_by_confidence(df: pd.DataFrame) -> pd.DataFrame:  # type: ignore[override]
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df.iloc[0:0].copy() if isinstance(df, _pd.DataFrame) else _pd.DataFrame()
        cols = {"confidence_home","confidence_draw","confidence_away"}
        if not cols.issubset(df.columns):
            # no confidences ⇒ fail-closed
            return df.iloc[0:0].copy()
        return _gate_ftr_by_confidence_orig(df)
elif "_gate_ftr_by_confidence" not in globals():
    def _gate_ftr_by_confidence(df: pd.DataFrame) -> pd.DataFrame:  # minimal fail-closed gate
        import os as _os, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df.iloc[0:0].copy() if isinstance(df, _pd.DataFrame) else _pd.DataFrame()
        cols = {"confidence_home","confidence_draw","confidence_away"}
        if not cols.issubset(df.columns):
            return df.iloc[0:0].copy()
        thr = float(_os.getenv("FTR_PICK_GATE","0.68"))
        mx = df[["confidence_home","confidence_draw","confidence_away"]].max(axis=1)
        return df.loc[mx >= thr].copy()

# --- FTR engineered features (built off safe inputs) ---
def _add_ftr_engineered_features_inplace(df: pd.DataFrame) -> pd.DataFrame:
    import numpy as _np, pandas as _pd
    if not isinstance(df, _pd.DataFrame) or df.empty:
        return df
    eps = 1e-6
    # Core lambdas (safe if missing)
    lh = _pd.to_numeric(df.get("lambda_home"), errors="coerce")
    la = _pd.to_numeric(df.get("lambda_away"), errors="coerce")
    L  = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce")

    # Specialist OOFs (safe if missing)
    o25  = _pd.to_numeric(df.get("oof_prob_over25"), errors="coerce")
    btts = _pd.to_numeric(df.get("oof_prob_btts"), errors="coerce")
    h2   = _pd.to_numeric(df.get("oof_prob_home_over15tg"), errors="coerce")
    a2   = _pd.to_numeric(df.get("oof_prob_away_over15tg"), errors="coerce")
    hfts = _pd.to_numeric(df.get("oof_prob_home_fts"), errors="coerce")
    afts = _pd.to_numeric(df.get("oof_prob_away_fts"), errors="coerce")

    # PPG diff (multiple schema variants)
    hppg = _pd.to_numeric(df.get("Pre-Match PPG (Home)"), errors="coerce")
    appg = _pd.to_numeric(df.get("Pre-Match PPG (Away)"), errors="coerce")
    if hppg.isna().all() and "home_ppg" in df.columns:
        hppg = _pd.to_numeric(df.get("home_ppg"), errors="coerce")
    if appg.isna().all() and "away_ppg" in df.columns:
        appg = _pd.to_numeric(df.get("away_ppg"), errors="coerce")
    ppg_diff = hppg - appg

    # xG abs diff (handle multiple header styles)
    xh = _pd.to_numeric(df.get("pre_match_xg_home"), errors="coerce")
    xa = _pd.to_numeric(df.get("pre_match_xg_away"), errors="coerce")
    if xh.isna().all():
        for cand in ("Home Team Pre-Match xG", "Home Team Pre Match xG", "home_xg", "xg_home"):
            if cand in df.columns:
                xh = _pd.to_numeric(df.get(cand), errors="coerce"); break
    if xa.isna().all():
        for cand in ("Away Team Pre-Match xG", "Away Team Pre Match xG", "away_xg", "xg_away"):
            if cand in df.columns:
                xa = _pd.to_numeric(df.get(cand), errors="coerce"); break
    xg_diff_abs = (xh - xa).abs()

    # Lambda‑based & specialist meta features
    lam_diff   = (lh - la)
    lam_parity = 1.0 - _np.abs(lh - la) / (_np.maximum(L, eps))
    lam_parity = lam_parity.clip(0.0, 1.0)

    tg_diff     = (h2 - a2)
    fts_diff    = (afts - hfts)   # higher → away more likely to keep CS / home FTS
    attack_lean = (o25 + btts).clip(lower=0.0, upper=2.0)

    df["ppg_diff"]    = ppg_diff
    df["xg_diff_abs"] = xg_diff_abs
    df["lam_diff"]    = lam_diff
    df["lam_parity"]  = lam_parity
    df["tg_diff"]     = tg_diff
    df["fts_diff"]    = fts_diff
    df["attack_lean"] = attack_lean
#
    return df
# --- FTR engineered features (explicit helper used across training & upcoming) ---
def _ensure_ftr_derived_features(df):
    import numpy as np, pandas as pd
    if df is None or df.empty:
        return df
    g = lambda c: pd.to_numeric(df.get(c), errors="coerce")

    # Pre-match context / strength
    df["ppg_diff"] = g("Pre-Match PPG (Home)") - g("Pre-Match PPG (Away)")
    df["xg_diff_abs"] = (g("Home Team Pre-Match xG") - g("Away Team Pre-Match xG")).abs()

    # λ bundle
    lam_h, lam_a, exg = g("lambda_home"), g("lambda_away"), g("exp_goals_sum")
    df["lam_diff"] = lam_h - lam_a
    with np.errstate(divide="ignore", invalid="ignore"):
        df["lam_parity"] = 1.0 - (df["lam_diff"].abs() / (exg.replace(0, np.nan).fillna(1e-6)))

    # OOF blends (direction + texture)
    df["tg_diff"]  = g("oof_prob_home_over15tg") - g("oof_prob_away_over15tg")
    df["fts_diff"] = g("oof_prob_away_fts")      - g("oof_prob_home_fts")
    df["attack_lean"] = g("oof_prob_over25") + g("oof_prob_btts")

    # Draw signal (from draw bundle)
    if "prob_draw_model" not in df.columns:
        for alt in ("p_draw","draw_prob","prob_draw"):
            if alt in df.columns:
                df["prob_draw_model"] = g(alt); break
    if "prob_draw_model" not in df.columns:
        df["prob_draw_model"] = np.nan

    # Odds parity family (ensure coverage)
    oh, od, oa = g("odds_ft_home_team_win"), g("odds_ft_draw"), g("odds_ft_away_team_win")
    with np.errstate(divide="ignore", invalid="ignore"):
        ih, idr, ia = 1/oh, 1/od, 1/oa
        df["draw_implied"]      = idr
        df["implied_prob_diff"] = ih - ia
        df["odds_diff"]         = oh - oa
        df["odds_parity"]       = 1.0 - (df["odds_diff"].abs() / (oh + oa).replace(0, np.nan))
        df["odds_skew"]         = (ih + ia - 2*idr)

    df.replace([np.inf,-np.inf], np.nan, inplace=True)
    return df

# --- λ̂ sanity helpers --------------------------------------------------------
if "_lambda_sanity_check" not in globals():
    def _lambda_sanity_check(lh, la) -> bool:
        import numpy as _np, pandas as _pd
        lh = _pd.to_numeric(lh, errors="coerce")
        la = _pd.to_numeric(la, errors="coerce")
        exg = lh + la
        if exg.size == 0:
            return False
        finite = _np.isfinite(exg)
        if float(finite.mean()) < 0.95:
            return False
        mean_exg = float(_np.nanmean(exg))
        if (not _np.isfinite(mean_exg)) or (mean_exg < 0.8) or (mean_exg > 4.8):
            return False
        if float((exg <= 0).mean()) > 0.05:
            return False
        return True


if "_lambda_sanitize_inplace" not in globals():
    def _lambda_sanitize_inplace(df):
        import numpy as _np, pandas as _pd, os as _os
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        lh = _pd.to_numeric(df.get("lambda_home"), errors="coerce")
        la = _pd.to_numeric(df.get("lambda_away"), errors="coerce")
        if not _lambda_sanity_check(lh, la):
            neutral = float(_os.getenv("LAMBDA_NEUTRAL_TOTAL", "2.5"))
            df["lambda_home"] = neutral * 0.5
            df["lambda_away"] = neutral * 0.5
            df["exp_goals_sum"] = neutral
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                print("⚠️  λ-attach sanity failed — using neutral priors (1.25+1.25)")
        else:
            df["exp_goals_sum"] = (lh + la)
        return df

# --- Feature-quality summary (training vs inference) -------------------------
if "_print_feature_quality" not in globals():
    def _print_feature_quality(df, feats, tag: str = ""):
        """Print a compact quality summary for features.
        Shows how many columns are present, how many have poor finite coverage,
        and how many are near-constant (≥95% zeros). Also reports exg plausibility.
        Only prints when VERBOSE_QUICK=1.
        """
        import os as _os
        if _os.getenv("VERBOSE_QUICK", "0") != "1":
            return
        try:
            import numpy as _np, pandas as _pd
            cols = [c for c in (feats or []) if c in getattr(df, "columns", [])]
            if not cols:
                print(f"🔎 feature-quality{('['+tag+']') if tag else ''}: no columns present")
                return
            g = lambda c: _pd.to_numeric(df.get(c), errors="coerce")
            finite_ratios = []
            zero_ratios = []
            for c in cols:
                s = g(c)
                s_arr = s.to_numpy() if hasattr(s, 'to_numpy') else _np.asarray(s)
                finite = _np.isfinite(s_arr)
                finite_ratios.append(float(finite.mean()) if s_arr.size else 0.0)
                z = _np.nan_to_num(s_arr, nan=0.0)
                zero_ratios.append(float((z == 0).mean()) if z.size else 1.0)
            poor = int(sum(fr < 0.70 for fr in finite_ratios))
            flat = int(sum(zr > 0.95 for zr in zero_ratios))
            msg = f"cols={len(cols)}, poor_finite<0.70: {poor}, near-const>95% zeros: {flat}"
            # λ̂ plausibility (if present)
            try:
                exg = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce")
                if exg is not None and len(exg) == len(df):
                    exg_valid = exg.between(0.8, 4.5)
                    msg += f", exg_valid={int(exg_valid.sum())}/{len(exg)}"
            except Exception:
                pass
            print(f"🔎 feature-quality{('['+tag+']') if tag else ''}: {msg}")
        except Exception:
            pass

# --- Self-test: p00 consistency under λ̂ sanitization -------------------------
if "_selftest_p00_consistency" not in globals():
    def _selftest_p00_consistency() -> bool:
        """Tiny synthetic check: p00_est ≈ exp(-exp_goals_sum) after sanitize.
        Prints a one-line PASS/FAIL; returns True on success.
        """
        import numpy as _np, pandas as _pd
        # Synthetic lambdas include one bad/edge case to exercise sanitize path
        df = _pd.DataFrame({
            "lambda_home": [1.2, 0.0, _np.nan, 2.8],
            "lambda_away": [1.1, 0.0, 1.0, 2.1],
        })
        # Derive totals and sanitize like the pipeline would
        df["exp_goals_sum"] = _pd.to_numeric(df["lambda_home"], errors="coerce") + _pd.to_numeric(df["lambda_away"], errors="coerce")
        df = _lambda_sanitize_inplace(df)
        with _np.errstate(over="ignore", invalid="ignore"):
            df["p00_est"] = _np.exp(-_pd.to_numeric(df["exp_goals_sum"], errors="coerce"))
        exp = _np.exp(-_pd.to_numeric(df["exp_goals_sum"], errors="coerce"))
        ok = _np.allclose(df["p00_est"].to_numpy(dtype=float), exp.to_numpy(dtype=float), rtol=1e-12, atol=1e-12, equal_nan=True)
        if ok:
            print("✅ self-test(p00): p00_est ≈ exp(-exp_goals_sum) under λ̂ sanitization.")
            return True
        else:
            print("❌ self-test(p00) FAILED: p00_est mismatch.")
            return False

# --- FTR allowlist + model I/O fallbacks for quick mode ---
def _resolve_ftr_allowlist() -> list[str]:
    """
    Rich allowlist for quick FTR meta‑model.
    Includes λ/Poisson features, FT OOF stackers, engineered blends, pre‑match context,
    draw signal, and odds‑parity diagnostics. FH stackers are gated via ENABLE_SPEC_FH.
    """
    base = [
        # λ & Poisson
        "lambda_home","lambda_away","exp_goals_sum","p00_est","lam_diff","lam_parity",
        # OOF stackers (FT)
        "oof_prob_over25","oof_prob_btts",
        "oof_prob_over15","oof_prob_over35","oof_prob_over45",
        "oof_prob_home_over15tg","oof_prob_away_over15tg",
        "oof_prob_home_fts","oof_prob_away_fts",
        # Engineered blends
        "tg_diff","fts_diff","attack_lean",
        # Pre‑match context
        "Pre-Match PPG (Home)","Pre-Match PPG (Away)","ppg_diff",
        "Home Team Pre-Match xG","Away Team Pre-Match xG","xg_diff_abs",
        # Draw signal
        "prob_draw_model",
        # Odds parity (diagnostics)
        "odds_ft_home_team_win","odds_ft_draw","odds_ft_away_team_win",
        "draw_implied","implied_prob_diff","odds_diff","odds_parity","odds_skew",
        # Implied 1x2 probabilities (from odds; helpful as direct features)
        "prob_implied_home","prob_implied_draw","prob_implied_away",
        "has_implied_home","has_implied_draw","has_implied_away",
        # Strength/venue stack (populated if available)
        "elo_home_pre","elo_away_pre","elo_diff",
        "rest_days_home","rest_days_away","rest_diff",
        "ewma_ppg_home","ewma_ppg_away","ewma_ppg_diff",
        # Press/momentum (5-match z-scores)
        "rolling5_home_press_z","rolling5_away_press_z","rolling5_press_z_diff",
    ]
    # Optional extras (trainer will intersect with df.columns)
    base += ["elo_diff","rest_diff","ewma_ppg_diff"]
    # OG: team-season priors & parity diffs (attached from Teams.csv)
    base += [
        # xG strength
        "xg_net_diff", "xg_ratio_diff",
        # home-advantage
        "home_advantage_diff",
        # goal environment & parity
        "gfpm_diff", "gapm_diff", "avg_total_goals_diff",
        # discipline / set-pieces
        "cards_per_match_diff", "corners_per_match_diff",
        # market rate priors
        "btts_rate_diff", "over25_rate_diff", "fts_rate_diff", "clean_sheet_rate_diff",
        # half-time profile
        "ht_draw_rate_diff", "ht_gd_diff",
        # season-normalized xG indices
        "home_xg_for_idx", "home_xg_against_idx", "away_xg_for_idx", "away_xg_against_idx",
    ]
    # FH stackers only if explicitly enabled
    try:
        import os as _os
        if _os.getenv("ENABLE_SPEC_FH","0") == "1":
            base += ["oof_prob_over15fh","oof_prob_btts_fh"]
    except Exception:
        pass
    return base

# --- Time-ordered holdout + quick FTR reporting (no leakage) -----------------
if "_time_ordered_split_indices" not in globals():
    def _time_ordered_split_indices(df: pd.DataFrame, frac: float = 0.85) -> tuple[pd.Index, pd.Index]:
        """Return (train_idx, val_idx) using time order. Falls back to index order.
        Prefers 'match_date' then 'date_GMT' then 'timestamp'.
        """
        import pandas as _pd
        # Choose a date-like column or fallback
        for col in ("match_date", "date_GMT", "timestamp"):
            if col in df.columns:
                try:
                    dt = _pd.to_datetime(df[col], errors="coerce") if col != "timestamp" else _pd.to_datetime(df[col], unit="s", errors="coerce")
                    order = dt.rank(method="first")
                except Exception:
                    order = _pd.Series(range(len(df)), index=df.index, dtype=float)
                break
        else:
            order = _pd.Series(range(len(df)), index=df.index, dtype=float)
        order = order.fillna(order)
        idx_sorted = order.sort_values().index
        n = len(idx_sorted); k = max(1, min(n - 1, int(n * float(frac))))
        return idx_sorted[:k], idx_sorted[k:]

if "_build_quick_ftr_xy" not in globals():
    def _build_quick_ftr_xy(df: pd.DataFrame) -> tuple[pd.DataFrame, np.ndarray]:
        """Select allowlisted features and build 3-way FTR labels 0/1/2 (H/D/A).
        Returns (X, y). Drops rows with missing labels.
        """
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return _pd.DataFrame(), _np.array([])
        # Ensure engineered features exist
        try:
            df = _ensure_ftr_derived_features(df)
        except Exception:
            pass
        feats = [c for c in _resolve_ftr_allowlist() if c in df.columns]
        X = df[feats].copy() if feats else _pd.DataFrame(index=df.index)
        for c in X.columns:
            X[c] = _pd.to_numeric(X[c], errors="coerce")
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        m = hh.notna() & aa.notna()
        y = _np.where(hh[m] > aa[m], 0, _np.where(hh[m] == aa[m], 1, 2)).astype(int)
        X = X.loc[m].replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        return X, y

