# --- Print effective per-league mix (post-cap) -------------------------------
if "_print_mix" not in globals():
    def _print_mix(league_name: str, *, model_dir: str = MODEL_DIR) -> dict:
        """
        Resolve and print the effective mix (after env/constants and β-cap),
        without writing a YAML file. Returns the resolved dict.
        """
        # Load mix with compatibility for older/newer load_mix_params signatures
        defaults = {
            "alpha": 0.60, "beta": 0.00, "cap": 1.00,
            "gate_scale": 0.60, "cw_draw": 1.00,
        }
        try:
            import inspect
            params = tuple(inspect.signature(load_mix_params).parameters.keys())
            if "fallback" in params:
                mix = load_mix_params(league_name, fallback=defaults)
            else:
                try:
                    mix = load_mix_params(league_name)
                except TypeError:
                    mix = defaults
        except Exception:
            mix = defaults
        # Print effective mix (post-cap) and return
        try:
            print(f"\n🧾 Effective mix for {league_name}:")
            for k in ("alpha", "beta", "cap", "gate_scale", "cw_draw"):
                if k in mix:
                    try:
                        print(f"   {k}: {float(mix[k]):.4f}")
                    except Exception:
                        print(f"   {k}: {mix[k]}")
        except Exception:
            pass
        return mix
 # --- Write per-league mix YAML (without scoring) -----------------------------
if "_write_mix_yaml" not in globals():
    def _write_mix_yaml(league_name: str, mix: dict | None = None, model_dir: str = MODEL_DIR) -> str | None:
        """
        Create/overwrite ModelStore/<LeagueTag>_mix.yaml for a league without
        running the full pipeline. If `mix` is None, it is resolved via
        load_mix_params(..., fallback=defaults) so env/constants can populate it.
        Returns the absolute path on success; None on failure.
        """
        try:
            import yaml  # type: ignore
            tag = str(league_name).replace(" ", "_")
            os.makedirs(model_dir, exist_ok=True)
            path = os.path.join(model_dir, f"{tag}_mix.yaml")
            if mix is None:
                # Use loader with a safe fallback; handle older signatures too
                defaults = {
                    "alpha": 0.60, "beta": 0.00, "cap": 1.00,
                    "gate_scale": 0.60, "cw_draw": 1.00,
                }
                try:
                    import inspect
                    params = tuple(inspect.signature(load_mix_params).parameters.keys())
                    if "fallback" in params:
                        mix = load_mix_params(league_name, fallback=defaults)
                    else:
                        # Older signature: try without fallback, else use defaults
                        try:
                            mix = load_mix_params(league_name)
                        except TypeError:
                            mix = defaults
                except Exception:
                    mix = defaults
            with open(path, "w") as fh:
                yaml.safe_dump(dict(mix), fh, sort_keys=False)
            ap = os.path.abspath(path)
            print(f"💾 mix YAML written → {ap}")
            return ap
        except Exception as e:
            print(f"⚠️  could not write mix YAML: {e}")
            return None

# --- Poisson fallback for Over 1.5 / 3.5 / 4.5 (non-destructive) ---
if "_ensure_poisson_over_probs_inplace" not in globals():
    def _ensure_poisson_over_probs_inplace(df: pd.DataFrame) -> pd.DataFrame:
        """Ensure prob_/oof_prob_ for Over 1.5 / 3.5 / 4.5 exist using Poisson(exg) fallback.
        Non-destructive: only fills when the columns are missing or entirely NaN.
        """
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        exg = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce")
        if exg is None or not getattr(exg, "notna", lambda: [])().any():
            return df

        with _np.errstate(over="ignore", invalid="ignore"):
            eL = _np.exp(-exg)
            P0 = eL
            P1 = eL * exg
            P2 = eL * (exg**2) / 2.0
            P3 = eL * (exg**3) / 6.0
            P4 = eL * (exg**4) / 24.0
            p_over15 = 1.0 - (P0 + P1)                    # ≥2 goals
            p_over35 = 1.0 - (P0 + P1 + P2 + P3)          # ≥4 goals
            p_over45 = 1.0 - (P0 + P1 + P2 + P3 + P4)     # ≥5 goals

        def _set(name, vals):
            if (name not in df.columns) or _pd.to_numeric(df.get(name), errors="coerce").isna().all():
                df[name] = vals

        # Live-style names for EV gating
        _set("prob_over15", p_over15)
        _set("prob_over35", p_over35)
        _set("prob_over45", p_over45)
        # OOF-style names for quick-FTR allowlist / compatibility
        _set("oof_prob_over15", df.get("oof_prob_over15", df["prob_over15"]))
        _set("oof_prob_over35", df.get("oof_prob_over35", df["prob_over35"]))
        _set("oof_prob_over45", df.get("oof_prob_over45", df["prob_over45"]))
        return df

if "_shim_save_deployable_ftr" not in globals():
    def _shim_save_deployable_ftr(df: pd.DataFrame, league_name: str) -> bool:
        """
        Save a local gated FTR deployable CSV and (optionally) call the overlay saver.
        Always writes: PredictionReports/<League>_FTR_deployable.csv
        Returns True if overlay saver ran without error; False otherwise.
        """
        import os as _os
        from pathlib import Path as _Path
        import pandas as _pd

        if not isinstance(df, _pd.DataFrame):
            return False


        # Ensure selected_outcome exists for the export
        try:
            _ensure_predictions_export_columns_inplace(df)
        except Exception:
            pass

        # Optional EV-based deploy filters for common markets
        try:
            import numpy as _np
            # Try to guarantee probability and odds inputs exist
            try:
                df = _ensure_completed_probs_inplace(df)
            except Exception:
                pass
            try:
                _odds_backfill_inplace(df)
            except Exception:
                pass
            # Ensure Poisson fallback probabilities for Over 1.5/3.5/4.5
            try:
                df = _ensure_poisson_over_probs_inplace(df)
            except Exception:
                pass
            # Derive GS≥1/CS from FTS (free signals for banker/filters)
            try:
                if "prob_home_fts" in df.columns:
                    df["prob_home_scores"]      = 1.0 - _pd.to_numeric(df["prob_home_fts"], errors="coerce").fillna(0.0)
                    df["prob_away_clean_sheet"] = _pd.to_numeric(df["prob_home_fts"], errors="coerce").fillna(0.0)
                if "prob_away_fts" in df.columns:
                    df["prob_away_scores"]      = 1.0 - _pd.to_numeric(df["prob_away_fts"], errors="coerce").fillna(0.0)
                    df["prob_home_clean_sheet"] = _pd.to_numeric(df["prob_away_fts"], errors="coerce").fillna(0.0)
            except Exception:
                pass
            MIN_EDGE = float(_os.getenv("MIN_EDGE", "0.00"))
            MAX_ODDS = float(_os.getenv("MAX_ODDS", "1000.0"))
            # Over 2.5 EV filter
            if {"prob_over25","odds_ft_over25"}.issubset(df.columns):
                p = _pd.to_numeric(df["prob_over25"], errors="coerce").fillna(0.0)
                o = _pd.to_numeric(df["odds_ft_over25"], errors="coerce")
                df["ev_o25"] = p * (o - 1.0) - (1.0 - p)
                df = df[(df["ev_o25"] >= MIN_EDGE) & (o <= MAX_ODDS)]
            # BTTS Yes EV filter
            if {"prob_btts","odds_ft_btts"}.issubset(df.columns):
                p = _pd.to_numeric(df["prob_btts"], errors="coerce").fillna(0.0)
                o = _pd.to_numeric(df["odds_ft_btts"], errors="coerce")
                df.loc[:, "ev_btts"] = p * (o - 1.0) - (1.0 - p)
                df = df[(df["ev_btts"] >= MIN_EDGE) & (o <= MAX_ODDS)]
            # Over 1.5 EV filter (use prob_* or fallback to oof_prob_*)
            if ({"prob_over15","odds_ft_over15"}.issubset(df.columns)) or ({"oof_prob_over15","odds_ft_over15"}.issubset(df.columns)):
                src = "prob_over15" if "prob_over15" in df.columns else "oof_prob_over15"
                p = _pd.to_numeric(df[src], errors="coerce").fillna(0.0)
                o = _pd.to_numeric(df["odds_ft_over15"], errors="coerce")
                df["ev_o15"] = p * (o - 1.0) - (1.0 - p)
                df = df[(df["ev_o15"] >= MIN_EDGE) & (o <= MAX_ODDS)]

            # Over 3.5 EV filter
            if ({"prob_over35","odds_ft_over35"}.issubset(df.columns)) or ({"oof_prob_over35","odds_ft_over35"}.issubset(df.columns)):
                src = "prob_over35" if "prob_over35" in df.columns else "oof_prob_over35"
                p = _pd.to_numeric(df[src], errors="coerce").fillna(0.0)
                o = _pd.to_numeric(df["odds_ft_over35"], errors="coerce")
                df["ev_o35"] = p * (o - 1.0) - (1.0 - p)
                df = df[(df["ev_o35"] >= MIN_EDGE) & (o <= MAX_ODDS)]

            # Over 4.5 EV filter
            if ({"prob_over45","odds_ft_over45"}.issubset(df.columns)) or ({"oof_prob_over45","odds_ft_over45"}.issubset(df.columns)):
                src = "prob_over45" if "prob_over45" in df.columns else "oof_prob_over45"
                p = _pd.to_numeric(df[src], errors="coerce").fillna(0.0)
                o = _pd.to_numeric(df["odds_ft_over45"], errors="coerce")
                df["ev_o45"] = p * (o - 1.0) - (1.0 - p)
                df = df[(df["ev_o45"] >= MIN_EDGE) & (o <= MAX_ODDS)]
        except Exception:
            pass

            # Final confidence gate (fail-closed, runs after scoring & EV filters)
        try:
            gate_thr_env   = _os.getenv('FTR_PICK_GATE', None)
            cov_target_env = _os.getenv('FTR_COV_TARGET', None)
            gate_default   = 0.68 if gate_thr_env is None else float(gate_thr_env)
            try:
                _maxP = locals().get('maxp', None) or locals().get('maxP_holdout', None) or globals().get('_MAXP_HOLDOUT', None)
                gate = _quantile_gate_threshold(_maxP,
                                                cov_target=float(cov_target_env) if cov_target_env else None,
                                                default_thr=gate_default)
            except Exception:
                gate = gate_default
            df = _gate_ftr_by_confidence(df)
        except Exception:
            pass

        # Final draw share cap (post-argmax safety)
        try:
            import os as _os
            cap = float(_os.getenv("FTR_DRAW_MAX_SHARE_FINAL", _os.getenv("FTR_DRAW_MAX_SHARE", "0.45")))
        except Exception:
            cap = 0.45
        try:
            df = _apply_draw_share_cap(df, cap)
        except Exception:
            pass
        # Local CSV write (always)
        try:
            out_dir = _Path(DEFAULT_PREDICTION_REPORTS_DIR)
            out_dir.mkdir(parents=True, exist_ok=True)
            out_ftr_deploy = out_dir / f"{str(league_name).replace(' ','_')}_FTR_deployable.csv"
            df.to_csv(out_ftr_deploy, index=False)
            try:
                thr_pct = int(float(_os.getenv("DEPLOY_MIN_IMPL","0.67")) * 100)
            except Exception:
                thr_pct = 67
            print(f"📤 Deployable FTR picks saved → {out_ftr_deploy} (min implied {thr_pct}%, rows={len(df)})")
        except Exception:
            # Don't block overlay call just because local write failed
            pass

        # Try overlay saver (if available)
        try:
            from prediction_overlay import save_deployable_ftr as _save  # type: ignore
            _save(df, league_name)
            return True
        except Exception:
            return False

# --- Odds backfill helper (decimal/fractional/american tolerant) ---
if "_odds_backfill_inplace" not in globals():
    def _odds_backfill_inplace(df: pd.DataFrame) -> pd.DataFrame:
        """
        Ensure key odds columns exist and are in decimal form by:
          • creating odds_ft_over25 / odds_ft_btts / odds_ft_draw if missing,
          • filling NaNs from common alternate column names (case-insensitive),
          • parsing fractional (e.g. '5/4') and American (e.g. '+120', '-150') odds.
        Non-destructive: only fills NaNs; never overwrites existing valid decimal odds.
        """
        import pandas as _pd, numpy as _np, re as _re
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        # Case-insensitive column resolver
        lower = {str(c).lower(): c for c in df.columns}

        def _to_decimal(x):
            try:
                if x is None:
                    return _np.nan
                if isinstance(x, (int, float)):
                    v = float(x)
                    return v if v >= 1.0 and _np.isfinite(v) else _np.nan
                s = str(x).strip()
                if not s or s.lower() in {"nan", "none", "-"}:
                    return _np.nan
                s = s.replace(",", ".")
                # fractional a/b
                m = _re.fullmatch(r"\s*(\d+)\s*/\s*(\d+)\s*", s)
                if m:
                    a, b = float(m.group(1)), float(m.group(2))
                    return 1.0 + (a / b) if b > 0 else _np.nan
                # american +120 / -150
                if s.startswith(("+", "-")) and _re.fullmatch(r"[+-]?\d+", s):
                    v = int(s)
                    if v > 0:
                        return 1.0 + (v / 100.0)
                    elif v < 0:
                        return 1.0 + (100.0 / abs(v))
                # plain decimal
                v = float(s)
                return v if v >= 1.0 and _np.isfinite(v) else _np.nan
            except Exception:
                return _np.nan

        # Candidate source columns seen across providers (case-insensitive)
        maps = {
            "odds_ft_over15": [
                "odds_ft_over15","over15_odds","o15_odds","over 1.5 odds",
                "over_1_5_odds","o1.5","o1_5","odds_over15","odds_over_1_5",
                "Odds_Over1_5","Over1.5","over15"
            ],
            "odds_ft_over25": [
                "odds_ft_over25","over25_odds","o25_odds","over 2.5 odds",
                "over_2_5_odds","o2.5","o2_5","odds_over25","odds_over_2_5",
                "Odds_Over2_5","Over2.5","over25"
            ],
            "odds_ft_over35": [
                "odds_ft_over35","over35_odds","o35_odds","over 3.5 odds",
                "over_3_5_odds","o3.5","o3_5","odds_over35","odds_over_3_5",
                "Odds_Over3_5","Over3.5","over35"
            ],
            "odds_ft_over45": [
                "odds_ft_over45","over45_odds","o45_odds","over 4.5 odds",
                "over_4_5_odds","o4.5","o4_5","odds_over45","odds_over_4_5",
                "Odds_Over4_5","Over4.5","over45"
            ],
            "odds_ft_btts": [
                "odds_ft_btts","btts_odds","btts_yes_odds","btts_yes",
                "odds_btts_yes","BTTS Yes odds","BTTS_Yes","both_teams_to_score_yes",
                "both teams to score yes","odds_btts"
            ],
            "odds_ft_draw": [
                "odds_ft_draw","draw_odds","odds_draw","draw odds","draw"
            ],
        }

        for target, candidates in maps.items():
            if target not in df.columns:
                df[target] = _np.nan
            cur = _pd.to_numeric(df[target], errors="coerce")
            for c in candidates:
                col = lower.get(str(c).lower())
                if not col:
                    continue
                src = df[col]
                if getattr(src, "dtype", None) == object:
                    src = src.map(_to_decimal)
                else:
                    src = _pd.to_numeric(src, errors="coerce")
                mask = cur.isna() & src.notna()
                if mask.any():
                    df.loc[mask, target] = src[mask]
                    cur = _pd.to_numeric(df[target], errors="coerce")
            # final clean: impossible/invalid odds → NaN
            try:
                df[target] = _pd.to_numeric(df[target], errors="coerce")
                df.loc[(df[target] < 1.01) | (~_np.isfinite(df[target])), target] = _np.nan
            except Exception:
                pass

        return df
    
# --- Ensure implied 1X2 probabilities from odds (normalized) ---
if "_ensure_implied_1x2_inplace" not in globals():
    def _ensure_implied_1x2_inplace(df: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd, numpy as _np
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        try:
            oH = _pd.to_numeric(df.get("odds_ft_home_team_win"), errors="coerce")
            oD = _pd.to_numeric(df.get("odds_ft_draw"), errors="coerce")
            oA = _pd.to_numeric(df.get("odds_ft_away_team_win"), errors="coerce")

            pH = 1.0 / oH
            pD = 1.0 / oD
            pA = 1.0 / oA

            # normalize to (approx) remove overround so pH+pD+pA≈1
            s = (pH.fillna(0) + pD.fillna(0) + pA.fillna(0))
            s = s.replace({0: _np.nan})

            df["prob_implied_home"] = (pH / s).clip(0, 1)
            df["prob_implied_draw"] = (pD / s).clip(0, 1)
            df["prob_implied_away"] = (pA / s).clip(0, 1)
        except Exception:
            pass
        # Add explicit missingness masks so models can learn when implied is absent
        try:
            df["has_implied_home"] = _pd.to_numeric(df["prob_implied_home"], errors="coerce").notna().astype(float)
            df["has_implied_draw"] = _pd.to_numeric(df["prob_implied_draw"], errors="coerce").notna().astype(float)
            df["has_implied_away"] = _pd.to_numeric(df["prob_implied_away"], errors="coerce").notna().astype(float)
        except Exception:
            pass
        return df

# --- Ensure 1X2 derived odds fields (parity/diagnostics) ---
def _ensure_1x2_derived_odds_inplace(df: pd.DataFrame) -> pd.DataFrame:
    import pandas as _pd, numpy as _np
    if not isinstance(df, _pd.DataFrame) or df.empty:
        return df
    try:
        _odds_backfill_inplace(df)
    except Exception:
        pass
    H = _pd.to_numeric(df.get("odds_ft_home_team_win"), errors="coerce")
    D = _pd.to_numeric(df.get("odds_ft_draw"), errors="coerce")
    A = _pd.to_numeric(df.get("odds_ft_away_team_win"), errors="coerce")
    with _np.errstate(divide="ignore", invalid="ignore"):
        df["draw_implied"]       = 1.0 / D
        df["implied_prob_diff"]  = (1.0 / H) - (1.0 / A)
        df["odds_diff"]          = H - A
        denom                    = (H + A).replace(0, _np.nan)
        df["odds_parity"]        = 1.0 - (H - A).abs() / denom
        df["odds_skew"]          = (H / A)
    return df
    # --- Ensure specialist OOF proxies on inference (from λ̂) ---------------------
if "_ensure_specialist_oofs_for_inference_inplace" not in globals():
    def _ensure_specialist_oofs_for_inference_inplace(df: pd.DataFrame) -> pd.DataFrame:
        """
        If the standard specialist OOF columns are missing on an inference frame,
        approximate them from λ_home/λ_away via independent Poisson models.
        Non-destructive: only fills columns that are absent.
        """
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        lam_h = _pd.to_numeric(df.get("lambda_home"), errors="coerce")
        lam_a = _pd.to_numeric(df.get("lambda_away"), errors="coerce")
        exg   = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce")
        if lam_h.isna().all() or lam_a.isna().all():
            return df
        # Poisson components
        e_h = _np.exp(-lam_h)
        e_a = _np.exp(-lam_a)
        e_L = _np.exp(-exg)
        # Over 2.5 = 1 - (P0 + P1 + P2) with total λ = exg
        P0 = e_L
        P1 = e_L * exg
        P2 = e_L * (exg**2) / 2.0
        p_over25 = 1.0 - (P0 + P1 + P2)
        # BTTS = 1 - (P(H=0) + P(A=0) - P(H=0,A=0))
        p_btts = 1.0 - (e_h + e_a - (e_h * e_a))
        # Team ≥2: 1 - (P0 + P1) per side
        p_h_ge2 = 1.0 - (e_h * (1.0 + lam_h))
        p_a_ge2 = 1.0 - (e_a * (1.0 + lam_a))
        # FTS
        p_home_fts = e_h
        p_away_fts = e_a
        # Assign if missing or if column is all-NaN
        if ("oof_prob_over25" not in df.columns) or _pd.to_numeric(df.get("oof_prob_over25"), errors="coerce").isna().all():
            df["oof_prob_over25"] = _np.clip(p_over25, 0.0, 1.0)
        if ("oof_prob_btts" not in df.columns) or _pd.to_numeric(df.get("oof_prob_btts"), errors="coerce").isna().all():
            df["oof_prob_btts"] = _np.clip(p_btts, 0.0, 1.0)
        if ("oof_prob_home_over15tg" not in df.columns) or _pd.to_numeric(df.get("oof_prob_home_over15tg"), errors="coerce").isna().all():
            df["oof_prob_home_over15tg"] = _np.clip(p_h_ge2, 0.0, 1.0)
        if ("oof_prob_away_over15tg" not in df.columns) or _pd.to_numeric(df.get("oof_prob_away_over15tg"), errors="coerce").isna().all():
            df["oof_prob_away_over15tg"] = _np.clip(p_a_ge2, 0.0, 1.0)
        if ("oof_prob_home_fts" not in df.columns) or _pd.to_numeric(df.get("oof_prob_home_fts"), errors="coerce").isna().all():
            df["oof_prob_home_fts"] = _np.clip(p_home_fts, 0.0, 1.0)
        if ("oof_prob_away_fts" not in df.columns) or _pd.to_numeric(df.get("oof_prob_away_fts"), errors="coerce").isna().all():
            df["oof_prob_away_fts"] = _np.clip(p_away_fts, 0.0, 1.0)
        # --- New: derive O1.5 / O3.5 / O4.5 from Poisson totals if missing ---
        try:
            import pandas as _pd
            # total goals ~ Poisson(exg)
            eL = _np.exp(-exg)
            P0 = eL
            P1 = eL * exg
            P2 = eL * (exg**2) / 2.0
            P3 = eL * (exg**3) / 6.0
            P4 = eL * (exg**4) / 24.0

            p_over15 = 1.0 - (P0 + P1)               # ≥2
            p_over35 = 1.0 - (P0 + P1 + P2 + P3)     # ≥4
            p_over45 = 1.0 - (P0 + P1 + P2 + P3 + P4)# ≥5

            def _set(name, vals):
                if (name not in df.columns) or _pd.to_numeric(df.get(name), errors="coerce").isna().all():
                    df[name] = vals

            # Fill OOF-style (used by quick/FTR training)…
            _set("oof_prob_over15", p_over15)
            _set("oof_prob_over35", p_over35)
            _set("oof_prob_over45", p_over45)
            # …and also mirror to live-style names for EV gating if absent
            _set("prob_over15", df.get("prob_over15", df["oof_prob_over15"]))
            _set("prob_over35", df.get("prob_over35", df["oof_prob_over35"]))
            _set("prob_over45", df.get("prob_over45", df["oof_prob_over45"]))
        except Exception:
            pass
        return df
# --- Map side-probability aliases to training names -------------------------
if "_apply_oof_aliases_inplace" not in globals():
    def _apply_oof_aliases_inplace(df: pd.DataFrame) -> pd.DataFrame:
        """Duplicate common alias columns to the oof_* names used in training.
        Non-destructive: only fills if destination is missing.
        """
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        ALIAS_MAP = {
            'prob_over25':'oof_prob_over25',
            'prob_btts':'oof_prob_btts',
            'prob_home_over15tg':'oof_prob_home_over15tg',
            'prob_away_over15tg':'oof_prob_away_over15tg',
            'prob_home_fts':'oof_prob_home_fts',
            'prob_away_fts':'oof_prob_away_fts',
        }
        for src, dst in ALIAS_MAP.items():
            if (src in df.columns) and (dst not in df.columns):
                df[dst] = _pd.to_numeric(df[src], errors="coerce")
        return df
# --- Impute must-have features with median + missing flag --------------------
if "_impute_must_have_inplace" not in globals():
    def _impute_must_have_inplace(df: pd.DataFrame, cols: list[str]) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        for col in cols:
            if col not in df.columns:
                continue
            s = _pd.to_numeric(df[col], errors="coerce")
            arr = s.to_numpy(dtype=float, copy=True)
            miss = ~_np.isfinite(arr)
            if miss.any():
                med = float(_np.nanmedian(arr)) if _np.isfinite(arr).any() else 0.0
                df[f"{col}_missing"] = miss.astype(int)
                arr[miss] = med
                df[col] = arr
        return df

  # --- Feature parity assert (guardrail) --------------------------------------
if "_assert_feature_parity" not in globals():
    def _assert_feature_parity(model, df: pd.DataFrame):
        import pandas as _pd
        feats = list(getattr(model, "feature_names_in_", []))
        if not feats: return
        missing = [c for c in feats if c not in getattr(df, "columns", [])]
        if missing:
            raise ValueError(f'Inference missing features: {missing[:10]} ... ({len(missing)} total)')
           
# --- Ensure completed-data probs for ROI (prefer OOF, then HGM, else 0.5) ---
if "_ensure_completed_probs_inplace" not in globals():
    def _ensure_completed_probs_inplace(df: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        def _mk(src_cols, fallback_series):
            for c in src_cols:
                if c in df.columns:
                    s = _pd.to_numeric(df[c], errors="coerce")
                    if s.notna().any():
                        try:
                            return s.clip(0, 1)
                        except Exception:
                            return s
            return fallback_series

        fallback = _pd.Series(0.5, index=df.index)
        try: df["prob_over25"] = _mk(["oof_prob_over25", "hgm_prob_over25"], fallback)
        except Exception: pass
        try: df["prob_btts"]   = _mk(["oof_prob_btts",   "hgm_prob_btts"],   fallback)
        except Exception: pass
        return df
    
# --- Ensure prediction export has FTR fields ---
if "_ensure_predictions_export_columns_inplace" not in globals():
    def _ensure_predictions_export_columns_inplace(df: pd.DataFrame) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        needed = ["confidence_home","confidence_draw","confidence_away"]
        if not all(c in df.columns for c in needed):
            return df
        if "selected_outcome" not in df.columns:
            proba = _pd.to_numeric(df["confidence_home"], errors="coerce").fillna(0).to_numpy()
            prd   = _pd.to_numeric(df["confidence_draw"], errors="coerce").fillna(0).to_numpy()
            pra   = _pd.to_numeric(df["confidence_away"], errors="coerce").fillna(0).to_numpy()
            P = _np.vstack([proba, prd, pra]).T
            lab = _np.array(["home","draw","away"])[_np.nanargmax(P, axis=1)]
            df["selected_outcome"] = lab
        return df

# --- Gate FTR deployable by confidence ---
def _gate_ftr_by_confidence(df: pd.DataFrame) -> pd.DataFrame:
    import os as _os, pandas as _pd
    if not isinstance(df, _pd.DataFrame) or df.empty:
        return df.iloc[0:0].copy()
    cols = {"confidence_home","confidence_draw","confidence_away"}
    if not cols.issubset(df.columns):
        # fail-closed: nothing is deployable if confidences are missing
        return df.iloc[0:0].copy()
    try:
        thr = float(_os.getenv("FTR_PICK_GATE","0.68"))
    except Exception:
        thr = 0.68
    maxp = df[["confidence_home","confidence_draw","confidence_away"]].max(axis=1)
    return df.loc[maxp >= thr].copy()
