# --- Softmax temperature scaling (probability-only variant) ---
if "_apply_temperature" not in globals():
    def _apply_temperature(P, T: float):
        import numpy as _np
        P = _np.clip(P, 1e-9, 1.0)               # guard zeros
        logp = _np.log(P)
        S = _np.exp(logp / max(T, 1e-3))
        S = S / S.sum(axis=1, keepdims=True)
        return S

if "_fit_temperature_grid" not in globals():
    def _fit_temperature_grid(P, y):
        import numpy as _np
        def nll(Q):
            idx = _np.arange(Q.shape[0])
            return float(-_np.mean(_np.log(_np.clip(Q[idx, y], 1e-12, 1.0))))
        # simple grid (fast, stable)
        grid = _np.linspace(0.7, 1.6, 20)
        best_T, best_loss = 1.0, 1e9
        for T in grid:
            Q = _apply_temperature(P, T)
            L = nll(Q)
            if L < best_loss:
                best_T, best_loss = T, L
        return float(best_T)

