# === Calibrated FTR estimator selector (LR | XGB | LGBM) ===
def _make_calibrated_ftr_estimator(league=None, *, estimator: str = None):
    """
    Return a calibrated 3-way classifier for FTR.
    estimator: 'lr' | 'xgb' | 'lgbm' (env FTR_ESTIMATOR wins; default 'xgb')
    """
    import os
    cal_mode = os.getenv("FTR_CAL_MODE", "sigmoid").strip().lower()
    from sklearn.calibration import CalibratedClassifierCV
    est = (estimator or os.getenv("FTR_ESTIMATOR", "xgb")).strip().lower()
    if est == "xgb":
        try:
            from xgboost import XGBClassifier as _XGB

            # small helper: accept new and legacy env names
            def _env(name, default, *alts):
                for k in (name,)+alts:
                    v = os.getenv(k)
                    if v is not None:
                        return v
                return default

            _xgb_params = dict(
                # stronger, sane defaults (all env-overridable)
                n_estimators      = int(float(_env("FTR_XGB_N_EST",   "1200",  "FTR_XGB_N"))),
                max_depth         = int(float(_env("FTR_XGB_MAX_DEPTH","6"))),
                learning_rate     = float(_env("FTR_XGB_LR",          "0.05")),
                subsample         = float(_env("FTR_XGB_SUBSAMPLE",   "0.80")),
                colsample_bytree  = float(_env("FTR_XGB_COLSAMPLE",   "0.80")),
                min_child_weight  = float(_env("FTR_XGB_MIN_CHILD",   "2.0")),
                reg_lambda        = float(_env("FTR_XGB_L2",          "1.0",  "FTR_XGB_LAMBDA")),
                reg_alpha         = float(_env("FTR_XGB_L1",          "0.0",  "FTR_XGB_ALPHA")),
                gamma             = float(_env("FTR_XGB_GAMMA",       "0.0")),
                objective         = "multi:softprob",
                tree_method       = _env("FTR_XGB_TREE", _env("XGB_TREE_METHOD", "hist")),
                n_jobs            = int(float(_env("FTR_XGB_NJOBS",   _env("SKLEARN_JOBS", "4")))),
                random_state      = 42,
                eval_metric       = "mlogloss",
            )
            base = _XGB(**_xgb_params)

            if cal_mode == "none":
                return base
            return CalibratedClassifierCV(base, method=cal_mode, cv=3)
        except Exception:
            pass  # fall through to LGBM / LR

    if est == "lgbm":
        try:
            from lightgbm import LGBMClassifier
            base = LGBMClassifier(
                objective="multiclass",
                n_estimators=int(os.getenv("FTR_LGBM_N", "2500")),
                learning_rate=float(os.getenv("FTR_LGBM_LR", "0.05")),
                num_leaves=int(os.getenv("FTR_LGBM_LEAVES", "63")),
                subsample=float(os.getenv("FTR_LGBM_SUBSAMPLE", "0.9")),         # bagging_fraction
                colsample_bytree=float(os.getenv("FTR_LGBM_COLSAMPLE", "0.8")),  # feature_fraction
                min_child_samples=int(os.getenv("FTR_LGBM_MIN_CHILD", "40")),
                reg_lambda=float(os.getenv("FTR_LGBM_LAMBDA", "2.0")),
                reg_alpha=float(os.getenv("FTR_LGBM_ALPHA",  "0.1")),
                n_jobs=int(os.getenv("SKLEARN_JOBS","1")),
                random_state=42,
            )
            if cal_mode == "none":
                return base
            from sklearn.calibration import CalibratedClassifierCV
            return CalibratedClassifierCV(base, method=cal_mode, cv=3)
        except Exception:
            pass

    from sklearn.linear_model import LogisticRegression
    base = LogisticRegression(
        solver="lbfgs",
        max_iter=int(os.getenv("FTR_MAX_ITER", "2000")),
        class_weight="balanced",
        multi_class="auto",
        n_jobs=1,
    )
    if cal_mode == "none":
        return base
    from sklearn.calibration import CalibratedClassifierCV
    return CalibratedClassifierCV(base, method=cal_mode, cv=3)

# --- Minimal quick FTR (multinomial LR) ---
if "_train_quick_ftr" not in globals():
    def _train_quick_ftr(df: pd.DataFrame, league: str):
        """
        Very small multinomial LogisticRegression for 1X2, trained on a leakage-safe allowlist (OOF stackers, λ̂ features, draw-model) — no bookmaker implied 1×2 in training.
        Returns a fitted model or None.
        """
        import numpy as _np, pandas as _pd
        try:
            from sklearn.linear_model import LogisticRegression
        except Exception:
            return None

        if not isinstance(df, _pd.DataFrame) or df.empty:
            return None

        # Labels from final score
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        m = hh.notna() & aa.notna()

        # Restrict to recent window if dates exist
        try:
            import os as _os
            _yrs = int(_os.getenv("QUICK_FTR_RECENT_SEASONS", "0"))
        except Exception:
            _yrs = 0
        if _yrs > 0 and "match_date" in df.columns:
            md = _pd.to_datetime(df.get("match_date"), errors="coerce")
            # Use most recent date found rather than 'today' (handles old datasets)
            _anchor = md[m].max()
            if _pd.isna(_anchor):
                _anchor = _pd.Timestamp.today()
            cutoff = _anchor - _pd.DateOffset(years=_yrs)
            m = m & (md >= cutoff)

        if int(m.sum()) < 200:  # need a bit of data
            return None

        # 0=home, 1=draw, 2=away
        y = _np.where(hh[m] > aa[m], 0, _np.where(hh[m] < aa[m], 2, 1))
        # Keep labels as a pandas Series aligned to df.index[m] for time-split indexing
        y = _pd.Series(y, index=df.index[m])

        # Ensure engineered meta-features exist (no-op if inputs missing)
        try:
            df = _ensure_ftr_derived_features(df)
        except Exception:
            pass

        # Ensure odds-parity diagnostics exist for training (derived from bookmaker odds; safe pre-match info)
        try:
            _ensure_1x2_derived_odds_inplace(df)
        except Exception:
            pass

        # Features (allowlist + present)
        feats = [c for c in _resolve_ftr_allowlist() if c in df.columns]
        # Allow engineered odds diagnostics and raw odds; only drop the raw implied 3‑way if present
        drop_raw = {"prob_implied_home","prob_implied_draw","prob_implied_away"}
        feats = [c for c in feats if c not in drop_raw]
        if not feats:
            return None

        X = df.loc[m, feats]
        try:
            X = X.select_dtypes(include=["number"])
        except Exception:
            pass
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        try:
            _print_feature_quality(df.loc[m], feats, "train")
        except Exception:
            pass
        # Debug: show design matrix & coverage for critical engineered features
        try:
            print("🔬 FTR design features (n=%d): %s" % (X.shape[1], ", ".join(list(X.columns)[:20])))
            for c in [
                "lam_diff","lam_parity","ppg_diff","xg_diff_abs",
                "tg_diff","fts_diff","attack_lean","prob_draw_model",
                "oof_prob_over25","oof_prob_btts"
            ]:
                if c in df.columns:
                    non_nan = int(_pd.to_numeric(df[c], errors="coerce").notna().sum())
                    print(f"ℹ️  coverage[{c}] = {non_nan}/{len(df)}")
        except Exception:
            pass
        if X.empty:
            return None

        from sklearn.pipeline import Pipeline
        from sklearn.preprocessing import StandardScaler
        try:
            from sklearn.linear_model import LogisticRegression
        except Exception:
            return None

        params = dict(
            max_iter=1200,
            solver="lbfgs",
            multi_class="auto",
            class_weight="balanced",
            n_jobs=1,
        )

        # Split by time (last ~15% as validation for temperature)
        try:
            md = _pd.to_datetime(df.get("match_date"), errors="coerce") if "match_date" in df.columns else None
        except Exception:
            md = None
        if md is not None:
            md_m = md[m]
            order = md_m.sort_values(kind="mergesort").index
        else:
            order = X.index

        k = int(round(0.85 * len(order)))
        tr_idx = order[:max(k, 1)]
        va_idx = order[max(k, 1):] if (len(order) - k) >= 20 else order[:0]

        # 1) Fit on train split to compute a temperature T
        clf = Pipeline([
            ("scaler", StandardScaler(with_mean=False)),
            ("lr", LogisticRegression(**params)),
        ])
        clf.fit(X.iloc[tr_idx], y.iloc[tr_idx].astype(int))

        T = 1.0
        if len(va_idx) >= 20:
            P_val = clf.predict_proba(X.iloc[va_idx])
            y_val = y.iloc[va_idx].astype(int).to_numpy()
            try:
                T = _fit_temperature_grid(P_val, y_val)
            except Exception:
                T = 1.0

        # 2) Refit on all data for final estimator
        clf_full = Pipeline([
            ("scaler", StandardScaler(with_mean=False)),
            ("lr", LogisticRegression(**params)),
        ])
        clf_full.fit(X, y.astype(int))

        model_obj = {"est": clf_full, "T": float(T), "feature_names_in_": list(X.columns)}
        try:
            _save_market_model(league, "quick_ftr", model_obj)
        except Exception:
            pass
        return model_obj
        

# --- Draw model: prefer project bridge; fall back to quick logistic ----------
if "_get_project_draw_ensurer" not in globals():
    def _get_project_draw_ensurer():
        """Return train_draw_classifier.ensure_draw_bundle if available, else None."""
        try:
            import importlib
            tdc = importlib.import_module("train_draw_classifier")
            fn = getattr(tdc, "ensure_draw_bundle", None)
            if callable(fn):
                return fn
        except Exception as e:
            print(f"ℹ️  draw trainer bridge unavailable: {e}")
        return None

# Minimal local helpers for the fallback (only defined if missing)
if "_ensure_ftr_col" not in globals():
    def _ensure_ftr_col(df):
        import numpy as np
        hh = df.get("home_team_goal_count")
        aa = df.get("away_team_goal_count")
        if "FTR" not in df.columns and hh is not None and aa is not None:
            ftr = np.where(hh > aa, 0, np.where(hh < aa, 2, 1))
            df = df.copy()
            df["FTR"] = ftr
        return df

if "_filter_completed_training_rows" not in globals():
    def _filter_completed_training_rows(df):
        # Simple, leak-safe default: keep rows with both goal counts
        hh = df.get("home_team_goal_count")
        aa = df.get("away_team_goal_count")
        if hh is not None and aa is not None:
            m = hh.notna() & aa.notna()
            return df.loc[m].copy()
        return df

if "_draw_fallback_logistic" not in globals():
    def _draw_fallback_logistic(df, league):
        """
        Leak-safe quick fallback: calibrated logistic P(draw).
        Uses only numeric *pre-match* style features (excludes in-play and labels).
        Returns {"model": clf, "feature_selector": fn(DataFrame)->X}.
        """
        _skip_fallback_draw = False
        import numpy as np, pandas as pd
        from sklearn.pipeline import Pipeline
        from sklearn.preprocessing import StandardScaler
        from sklearn.linear_model import LogisticRegression
        from sklearn.calibration import CalibratedClassifierCV

        if not isinstance(df, pd.DataFrame) or df.empty:
            return None

        # Ensure labels and restrict to completed fixtures
        try: df = _ensure_ftr_col(df.copy())
        except Exception: pass
        try: df = _filter_completed_training_rows(df)
        except Exception: pass

        if "FTR" not in df.columns:
            return None
        y = (pd.to_numeric(df["FTR"], errors="coerce") == 1).astype(int)

        # Numeric pre-match design: drop labels + typical in-play proxies
        X = df.select_dtypes(include=["number"]).drop(
            columns=[c for c in ["FTR","home_team_goal_count","away_team_goal_count","total_goals_at_half_time"] if c in df.columns],
            errors="ignore",
        )
        bad_pat = ("shots","possession","fouls","cards","minute","half","red","yellow","goal")
        X = X.loc[:, [c for c in X.columns if not any(p in c.lower() for p in bad_pat)]]
        X = X.replace([np.inf, -np.inf], np.nan).fillna(0.0)
        if X.shape[0] < 200 or X.shape[1] == 0:
            return None

        base = Pipeline([
            ("scaler", StandardScaler(with_mean=False)),
            ("lr", LogisticRegression(max_iter=800, solver="lbfgs",
                                      multi_class="auto", class_weight="balanced", n_jobs=1)),
        ])
        clf = CalibratedClassifierCV(base, method="isotonic", cv=3)
        clf.fit(X, y)

        used = list(X.columns)
        def _selector(d: pd.DataFrame):
            M = d.reindex(columns=used, fill_value=np.nan)
            return M.replace([np.inf, -np.inf], np.nan).fillna(0.0)
        # Guard: try to attach project draw bundle first; if successful, skip fallback
        try:
            import pandas as _pd
            # Resolve frame + league references used in this scope
            _frame = locals().get("df_train", None)
            if _frame is None:
                _frame = locals().get("df", None)
            _lg = locals().get("league_name", locals().get("league", None))

            # If missing or empty draw prob, attempt project bundle attach here
            need_attach = False
            if _frame is not None:
                if "prob_draw_model" not in _frame.columns:
                    need_attach = True
                else:
                    _has = _pd.to_numeric(_frame["prob_draw_model"], errors="coerce").notna().any()
                    need_attach = not bool(_has)

            if need_attach and (_frame is not None) and (_lg is not None):
                try:
                    b = _build_draw_bundle(_frame, _lg)
                    _frame, _ = _attach_draw_prob_with_bundle(_frame, _lg, b)
                except Exception:
                    pass

            # Decide skip after attempting attach
            _skip_fallback_draw = False
            if _frame is not None and ("prob_draw_model" in _frame.columns):
                _skip_fallback_draw = _pd.to_numeric(_frame["prob_draw_model"], errors="coerce").notna().any()
        except Exception:
            _skip_fallback_draw = False

        if _skip_fallback_draw:
            try:
                import os as _os
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    print("ℹ️ draw bundle used; skipping fallback logistic.")
            except Exception:
                pass
            # Return an empty bundle so any later attach call is a no‑op
            return {}
        else:
            if not _skip_fallback_draw:
                print("🧪 draw-fallback trained (calibrated logistic).")
            else:
                try:
                    import os as _os
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print("ℹ️ draw bundle used; skipping fallback logistic.")
                except Exception:
                    pass
            return {"model": clf, "feature_selector": _selector}

if "_build_draw_bundle" not in globals():
    def _build_draw_bundle(df_train, league):
        """Build/return the draw-prediction bundle using the project bridge when available.
        Falls back to the calibrated logistic emergency bridge *with explicit logs* so
        we never silently over-use the fallback. Also probes the returned bundle to
        ensure a working predict_proba with finite outputs.
        """
        try:
            edb = _get_project_draw_ensurer()  # provided by train_draw_classifier
        except Exception:
            edb = None
        if edb:
            try:
                bundle = edb(df_train, league, row_cap=20000, n_jobs=1, perm_importance=False)
                if not bundle:
                    try:
                        print("⚠️  draw bridge returned None – using fallback.")
                    except Exception:
                        pass
                    return _draw_fallback_logistic(df_train, league)
                # --- Sanity probe on bundle ---
                try:
                    import numpy as _np
                    # Accept either a raw estimator with predict_proba, or a dict with 'estimator'/'model' or callable 'predict_proba'
                    est = None
                    if isinstance(bundle, dict):
                        est = bundle.get("estimator") or bundle.get("model") or bundle.get("est")
                    if est is None:
                        est = bundle
                    # Build a small numeric probe set
                    Xprobe = (
                        df_train.select_dtypes(include=["number"])\
                                .replace([_np.inf, -_np.inf], _np.nan)\
                                .fillna(0.0)\
                                .head(128)
                    )
                    proba = None
                    if hasattr(est, "predict_proba"):
                        proba = est.predict_proba(Xprobe)
                    elif isinstance(bundle, dict) and callable(bundle.get("predict_proba", None)):
                        proba = bundle["predict_proba"](Xprobe)
                    arr = _np.asarray(proba, dtype=float) if proba is not None else None
                    ok = (arr is not None) and (arr.ndim == 2) and (arr.shape[0] == len(Xprobe)) and _np.isfinite(arr).all()
                    if not ok:
                        try:
                            print("⚠️  draw bridge sanity failed — using fallback (no/invalid predict_proba).")
                        except Exception:
                            pass
                        return _draw_fallback_logistic(df_train, league)
                except Exception as _probe_err:
                    try:
                        print(f"⚠️  draw bridge sanity exception — using fallback: {_probe_err}")
                    except Exception:
                        pass
                    return _draw_fallback_logistic(df_train, league)
                try:
                    print("✅ draw bridge OK (project bundle).")
                except Exception:
                    pass
                return bundle
            except Exception as e:
                try:
                    print(f"⚠️  draw bridge failed, using fallback: {e}")
                except Exception:
                    pass
                return _draw_fallback_logistic(df_train, league)
        try:
            print("⚠️  no draw bridge found – using fallback.")
        except Exception:
            pass
        return _draw_fallback_logistic(df_train, league)

if "_attach_draw_probs" not in globals():
    def _attach_draw_probs(df, draw_bundle, *, tag=""):
        """Attach prob_draw_model using the provided bundle."""
        import numpy as np, pandas as pd
        if not isinstance(df, pd.DataFrame) or df.empty:
            return df
        if not draw_bundle:
            return df
        mdl = draw_bundle.get("model")
        sel = draw_bundle.get("feature_selector")
        if mdl is None or sel is None:
            return df
        try:
            X = sel(df)
            p = mdl.predict_proba(X)[:, 1]
            df = df.copy()
            df["prob_draw_model"] = p
            ok = int(np.isfinite(p).sum()); total = len(df)
            where = f" ({tag})" if tag else ""
            print(f"🧲 draw-model attach{where} → non-NaN={ok}/{total}")
        except Exception as e:
            print(f"⚠️  draw attach failed{(' ' + tag) if tag else ''}: {e}")
        return df

if "_score_quick_ftr" not in globals():
    def _score_quick_ftr(df: pd.DataFrame, league: str, *, model=None) -> pd.DataFrame:
        """
        Attach confidence_home/draw/away + selected_outcome using a trained quick-FTR model.
        Non-destructive; returns the same df with extra columns when possible.
        """
        # --- Early attach for upcoming inference -----------------------------
        # Ensure λ̂ and engineered/odds diagnostics exist BEFORE scoring so the
        # draw override & gates use real totals, not neutral fallbacks.
        try:
            # NOTE: the param is named `league` in this function; if yours is
            # `league_name`, swap accordingly:
            _lname = locals().get("league", None) or locals().get("league_name", None) or globals().get("league_name", "unknown_league")
            df = attach_lambda_features_inplace(df, _lname)
        except Exception:
            pass

        # Attach live side-probabilities for upcoming (project heads), then alias to oof_*
        try:
            from side_prob_models import attach_side_probabilities as _attach_side_probs  # type: ignore
            try:
                df = _attach_side_probs(df, league_tag=_lname)
            except TypeError:
                # fallback signature without keyword
                df = _attach_side_probs(df, _lname)
        except Exception:
            pass

        # Local alias fallback: map prob_* → oof_* so quick FTR sees the training names
        try:
            # score real specialists first (preferred)
            df = attach_specialists_for_inference_inplace(df, _lname)
        except Exception:
            pass
        try:
            # then back-fill any missing OOFs via λ̂ proxies (no overwrite)
            df = _ensure_specialist_oofs_for_inference_inplace(df)
        except Exception:
            pass
        try:
            df = _apply_oof_aliases_inplace(df)
        except Exception:
            pass
        try:
            df = _impute_must_have_inplace(df, [
                "rolling5_home_sot_ratio",
                "rolling5_away_sot_ratio",
            ])
        except Exception:
            pass
        try:
            df = _ensure_ftr_derived_features(df)
        except Exception:
            pass
        try:
            df = _ensure_1x2_derived_odds_inplace(df)
        except Exception:
            pass
        # Verbose λ̂ presence probe for upcoming
        # Optional: confirm league slug for specialist loading
        try:
            import os as _os
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"🧪 upcoming league for specialists: {_lname}")
        except Exception:
            pass
        try:
            _log_lambda_presence(df, "upcoming")
        except Exception:
            pass
        
        import numpy as _np, pandas as _pd, os as _os
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        # Load / normalize model (supports wrapper dict or raw estimator)
        if model is None:
            try:
                model = _load_market_model(league, "quick_ftr")
            except Exception:
                model = None
        if model is None:
            return df

        est = model.get("est") if isinstance(model, dict) else model
        T   = float(model.get("T", 1.0)) if isinstance(model, dict) else 1.0

        # optional self-test (tiny synthetic): checks p00_est ~ exp(-exp_goals_sum)
        if _os.getenv("RUN_SELF_TESTS","0") == "1":
            try:
                _selftest_p00_consistency()
            except Exception:
                pass

        # Ensure engineered meta-features exist on inference frame

        feats = (model.get("feature_names_in_") if isinstance(model, dict) else list(getattr(est, "feature_names_in_", []))) or \
                [c for c in _resolve_ftr_allowlist() if c in df.columns]
        if not feats:
            return df
        try:
            _assert_feature_parity(est, df)
        except Exception as _e:
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                print(f"❌ feature parity: {_e}")
            return df
        try:
            _print_feature_quality(df, feats, "inference")
        except Exception:
            pass

        try:
            X = df.reindex(columns=feats, fill_value=_np.nan)
            X = X.select_dtypes(include=["number"]).replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        except Exception:
            return df
        if X.empty:
            return df

        try:
            P = est.predict_proba(X)
        except Exception:
            return df

        # Apply temperature scaling if available
        try:
            if T and abs(T - 1.0) > 1e-6:
                P = _apply_temperature(P, T)
        except Exception:
            pass

        # Robust class index mapping (do not assume 0,1,2 order)
        try:
            classes = _np.asarray(getattr(est, "classes_", ["home","draw","away"]))
            _map = {str(c).lower(): i for i, c in enumerate(classes)}
            idx_home = _map.get("home", 0)
            idx_draw = _map.get("draw", 1)
            idx_away = _map.get("away", 2)
        except Exception:
            idx_home, idx_draw, idx_away = 0, 1, 2

        # Ensure implied 1x2 priors exist from odds (idempotent)
        try:
            _odds_backfill_inplace(df)
            _ensure_implied_1x2_inplace(df)
        except Exception:
            pass

        # Optional market prior blend (stabilises inference when features are thin)
        try:
            prior_on = (_os.getenv("FTR_PRIOR_BLEND", "0") == "1")
            _lng = locals().get("_lname", None) or globals().get("league_name", "unknown_league")
            w = float(_resolve_per_league_env("FTR_PRIOR_WEIGHT", _lng, 0.0))
        except Exception:
            prior_on, w = False, 0.0
        if prior_on and w > 0.0:
            pH0 = _pd.to_numeric(df.get("prob_implied_home"), errors="coerce").fillna(0.0).to_numpy()
            pD0 = _pd.to_numeric(df.get("prob_implied_draw"), errors="coerce").fillna(0.0).to_numpy()
            pA0 = _pd.to_numeric(df.get("prob_implied_away"), errors="coerce").fillna(0.0).to_numpy()
            Prior = _np.vstack([pH0, pD0, pA0]).T
            s = Prior.sum(axis=1, keepdims=True); s[s == 0] = 1.0
            Prior = Prior / s
            P = (1.0 - w) * P + w * Prior
            P = P / P.sum(axis=1, keepdims=True)
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                try:
                    _pre = _np.nanargmax(Prior, axis=1)
                    pre_dist_prior = {"home": int((_pre==idx_home).sum()), "draw": int((_pre==idx_draw).sum()), "away": int((_pre==idx_away).sum())}
                    print(f"🧪 prior blend: w={w:.2f} | prior argmax mix: {pre_dist_prior}")
                except Exception:
                    pass

        # Extract per-class probabilities after any temperature/prior blending
        p_home = P[:, idx_home]
        p_draw = P[:, idx_draw]
        p_away = P[:, idx_away]
                # --- Draw strictness gate (reduce false draws pre-override) ---
        try:
            import os as _os, numpy as _np, pandas as _pd
            # --- Master switch for draw-strict (default OFF) + NO_DRAW_GATE off-switch ---
            use_gate = (_os.getenv("NO_DRAW_GATE", "0") != "1")
            _DRAW_STRICT = (_os.getenv("DRAW_STRICT", "0") == "1") and use_gate

            if _DRAW_STRICT:
                # per-league draw-strict thresholds
                _lng = locals().get("_lname", None) or globals().get("league_name", "unknown_league")
                min_imp    = float(_resolve_per_league_env("DRAW_MIN_IMPLIED", _lng, 0.26))
                min_par    = float(_resolve_per_league_env("DRAW_MIN_PARITY",  _lng, 0.65))
                min_margin = float(_resolve_per_league_env("DRAW_MIN_MARGIN",  _lng, 0.02))
                imp   = _pd.to_numeric(df.get("prob_implied_draw"), errors="coerce").fillna(0.0).to_numpy()
                par   = _pd.to_numeric(df.get("lam_parity"), errors="coerce").fillna(0.0).to_numpy()
                margin = p_draw - _np.maximum(p_home, p_away)
                ok = (imp >= min_imp) & (par >= min_par) & (margin >= min_margin)
                # shrink p_draw where conditions are NOT met
                if (~ok).any():
                    shrink = float(_os.getenv("DRAW_SHRINK","0.50"))
                    p_draw = _np.where(ok, p_draw, p_draw * shrink)
                    # renormalize row-wise
                    S = (p_home + p_draw + p_away)
                    S[S == 0] = 1.0
                    p_home, p_draw, p_away = p_home / S, p_draw / S, p_away / S
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print(
                            f"🛠 draw-strict: shrunk {int((~ok).sum())}/{len(ok)} rows "
                            f"(imp≥{min_imp}, parity≥{min_par}, margin≥{min_margin})"
                        )
        except Exception:
            pass
        # Log pre-override outcome mix
        if _os.getenv("VERBOSE_QUICK","0") == "1":
            try:
                _pre_proba = _np.vstack([p_home, p_draw, p_away]).T
                _pre_argmax = _np.nanargmax(_pre_proba, axis=1)
                _pre_dist = {
                    "home": int((_pre_argmax == 0).sum()),
                    "draw": int((_pre_argmax == 1).sum()),
                    "away": int((_pre_argmax == 2).sum()),
                }
                print(f"📊 pre-override outcome mix: {_pre_dist}")
            except Exception:
                pass
        # initialize override masks once
        force_mask = None
        soft_mask  = None

        try:
            _ensure_1x2_derived_odds_inplace(df)
        except Exception:
            pass

# --- Ensure 1X2 derived odds fields (parity/diagnostics) ---


        # Optional: explicit draw uplifts from draw-model and 0-0 Poisson prior (apply after implied blend)
        try:
            du = float(_os.getenv("FTR_DRAW_UPLIFT", "0"))  # additional blend with prob_draw_model
            pu = float(_os.getenv("FTR_P00_UPLIFT", "0"))   # small push from p00_est (0-0 prior)
            changed = False

            if du > 0:
                pdm = _pd.to_numeric(df.get("prob_draw_model"), errors="coerce").fillna(0.0).values
                # convex blend toward the draw-model signal
                p_draw = (1.0 - du) * p_draw + du * pdm
                changed = True

            if pu > 0:
                p00 = _pd.to_numeric(df.get("p00_est"), errors="coerce").fillna(0.0).values
                # Not every draw is 0-0; treat p00 as a weak proxy (scale by 0.5)
                p_draw = p_draw + pu * (0.5 * p00)
                changed = True

            if changed:
                s = (p_home + p_draw + p_away)
                s = _np.where(s > 0, s, 1.0)  # avoid divide-by-zero
                p_home = (p_home / s).astype(float)
                p_draw = (p_draw / s).astype(float)
                p_away = (p_away / s).astype(float)
        except Exception:
            pass

        # Conjunctive draw override (parity + low totals + model draw + tie band + margin)
        try:
            if _os.getenv("FTR_DRAW_OVERRIDES","1") == "1":
                # thresholds (safe defaults; FTR_DECISION_EPS also accepted as alias)
                eps  = float(_os.getenv("FTR_DECISION_EPS", _os.getenv("FTR_DRAW_DECISION_EPS","0.015")))
                marg = float(_os.getenv("FTR_DRAW_MARGIN","0.01"))
                par  = float(_os.getenv("FTR_PARITY_DELTA","0.06"))
                lo   = float(_os.getenv("FTR_LOW_TOTAL","1.95"))
                pdm_min = float(_os.getenv("FTR_DRAW_MODEL_MIN","0.28"))

                lam_diff = _pd.to_numeric(df.get("lam_diff"), errors="coerce")
                if lam_diff.isna().all():
                    lh = _pd.to_numeric(df.get("lambda_home"), errors="coerce")
                    la = _pd.to_numeric(df.get("lambda_away"), errors="coerce")
                    lam_diff = (lh - la)
                exg = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce")
                pdm = _pd.to_numeric(df.get("prob_draw_model"), errors="coerce").fillna(0.0).values

                sym_ok   = lam_diff.abs().to_numpy() < (par * _np.maximum(1.0, exg.fillna(0.0).to_numpy()))
                # λ̂ sanity: only trust totals in [0.8, 4.5]; otherwise treat as "not low"
                exg_valid = exg.between(0.8, 4.5)
                low_tot   = exg_valid & (exg < lo)
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    try:
                        print(f"ℹ️  low_tot qualified rows: {int(low_tot.sum())}/{len(df)}")
                    except Exception:
                        pass
                pdm_ok    = pdm >= pdm_min
                # also require both sides to have some mass; avoid draws when both sides ~0
                tie_band = (_np.abs(p_home - p_away) <= (eps + marg)) & (p_home >= 0.12) & (p_away >= 0.12)
                near_top = p_draw >= (_np.maximum(p_home, p_away) - marg)

                mask = sym_ok & low_tot & pdm_ok & tie_band & near_top
                if mask.any():
                    p_draw = p_draw.copy()
                    p_draw[mask] = _np.maximum(p_draw[mask], _np.maximum(p_home[mask], p_away[mask]))
                    # Renormalize to keep probabilities summing to 1
                    s = (p_home + p_draw + p_away)
                    s = _np.where(s > 0, s, 1.0)
                    p_home = (p_home / s).astype(float)
                    p_draw = (p_draw / s).astype(float)
                    p_away = (p_away / s).astype(float)
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print(f"🎯 draw conjunctive override → {int(mask.sum())} fixtures")
        except Exception:
            pass

        # (second-pass draw override removed)

        # Parity-based draw rescue (conservative): only if explicitly enabled
        try:
            if _os.getenv("FTR_DRAW_OVERRIDES","1") == "1" and _os.getenv("FTR_PARITY_RESCUE","0") == "1":
                # thresholds (reuse safe conjunctive defaults)
                eps     = float(_os.getenv("FTR_DECISION_EPS", _os.getenv("FTR_DRAW_DECISION_EPS","0.015")))
                marg    = float(_os.getenv("FTR_DRAW_MARGIN","0.01"))
                dmax    = float(_os.getenv("FTR_PARITY_DELTA", "0.06"))
                lmax    = float(_os.getenv("FTR_LOW_TOTAL", "1.95"))
                min_imp = float(_os.getenv("FTR_DRAW_MIN_IMP", "0.22"))
                max_imp = float(_os.getenv("FTR_DRAW_MAX_IMP", "0.60"))
                pdm_min = float(_os.getenv("FTR_DRAW_MODEL_MIN","0.28"))

                lam_h = _pd.to_numeric(df.get("lambda_home"), errors="coerce").values
                lam_a = _pd.to_numeric(df.get("lambda_away"), errors="coerce").values
                L     = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce").values
                if L is None or _np.isnan(L).all():
                    L = _pd.to_numeric(df.get("lambda_home"), errors="coerce").fillna(0.0).values + \
                        _pd.to_numeric(df.get("lambda_away"), errors="coerce").fillna(0.0).values

                pi_d = _pd.to_numeric(df.get("prob_implied_draw"), errors="coerce").fillna(0.0).values
                pdm  = _pd.to_numeric(df.get("prob_draw_model"), errors="coerce").fillna(0.0).values

                sym      = _np.isfinite(lam_h) & _np.isfinite(lam_a) & (_np.abs(lam_h - lam_a) <= dmax * _np.maximum(1.0, L))
                low      = _np.isfinite(L) & (L <= lmax)
                imp_ok   = (pi_d >= min_imp) & (pi_d <= max_imp)
                pdm_ok   = (pdm >= pdm_min)
                tie_band = _np.abs(p_home - p_away) <= eps
                near_top = p_draw >= (_np.maximum(p_home, p_away) - marg)

                parity_mask = sym & low & imp_ok & pdm_ok & tie_band & near_top
                if getattr(parity_mask, "any", lambda: False)():
                    # lift toward max(prior draw, model draw) but don't steamroll
                    target = _np.maximum(pi_d, pdm)
                    p_draw = _np.where(parity_mask, _np.maximum(p_draw, target), p_draw)
                    # renormalize
                    s = (p_home + p_draw + p_away); s = _np.where(s > 0, s, 1.0)
                    p_home = (p_home / s).astype(float)
                    p_draw = (p_draw / s).astype(float)
                    p_away = (p_away / s).astype(float)
                    # mark for soft labeling
                    soft_mask = (soft_mask | parity_mask) if soft_mask is not None else parity_mask
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        try:
                            print(f"🪙 draw parity-rescue (conservative) → {int(parity_mask.sum())} fixtures")
                        except Exception:
                            pass
        except Exception:
            pass
        except Exception:
            pass


        proba = _np.vstack([p_home, p_draw, p_away]).T
        argmax = _np.nanargmax(proba, axis=1)
        labels = _np.array(["home", "draw", "away"])[argmax]

        # Hard-label overrides: margin-based and soft condition
        try:
            if force_mask is not None and getattr(force_mask, "any", lambda: False)():
                labels = labels.copy()
                labels[force_mask] = "draw"
            if soft_mask is not None and getattr(soft_mask, "any", lambda: False)():
                labels = labels.copy()
                labels[soft_mask] = "draw"
        except Exception:
            pass

        # Optional: cap draw share on upcoming frames to avoid pathological skew
        try:
            max_share_env = _os.getenv("FTR_DRAW_MAX_SHARE", "0")
            max_share = float(max_share_env) if max_share_env not in (None, "", "None") else 0.0
            if max_share and 0.0 < max_share < 1.0 and len(labels) > 0:
                is_draw = (labels == "draw")
                cur_share = float(is_draw.mean())
                if cur_share > max_share:
                    # Allow a looser cap if market strongly implies draws
                    med_imp = _pd.to_numeric(df.get("prob_implied_draw"), errors="coerce").median()
                    if _np.isfinite(med_imp) and med_imp > 0.33:
                        max_share = min(0.75, max_share + 0.10)
                    # Re-check after adjustment
                    if cur_share > max_share:
                        target_draws = int(_np.floor(max_share * len(labels)))
                        n_drop = int(max(0, (is_draw.sum() - target_draws)))
                        if n_drop > 0:
                            # Flip weakest draws first: smallest (p_draw - max(p_home,p_away))
                            second = _np.maximum(p_home, p_away)
                            margin = p_draw - second
                            idx_draw = _np.where(is_draw)[0]
                            order = idx_draw[_np.argsort(margin[idx_draw])]  # weakest first
                            flip = order[:n_drop]
                            # Send to stronger of home/away
                            to_home = p_home[flip] >= p_away[flip]
                            new_labels = labels.copy()
                            if _np.any(to_home):
                                new_labels[flip[to_home]] = "home"
                            if _np.any(~to_home):
                                new_labels[flip[~to_home]] = "away"
                            labels = new_labels
                            if _os.getenv("VERBOSE_QUICK","0") == "1":
                                try:
                                    print(f"🧯 draw cap override → flipped {n_drop} to respect cap {max_share:.2f}")
                                except Exception:
                                    pass
        except Exception:
            pass

        # Emergency: if NO draws were selected, relax thresholds and force a few plausible draws
        try:
            if (labels == "draw").sum() == 0 and _os.getenv("FTR_DRAW_EMERGENCY", "1") == "1":
                eps2    = float(_os.getenv("FTR_DRAW_DECISION_EPS2", "0.08"))
                dmax2   = float(_os.getenv("FTR_PARITY_DELTA2", "0.25"))
                lmax2   = float(_os.getenv("FTR_LOW_TOTAL2", "2.45"))
                min_imp = float(_os.getenv("FTR_DRAW_MIN_IMP", "0.20"))
                max_imp = float(_os.getenv("FTR_DRAW_MAX_IMP", "0.65"))
                share   = float(_os.getenv("FTR_DRAW_EMERGENCY_SHARE", "0.04"))

                lam_h = _pd.to_numeric(df.get("lambda_home"), errors="coerce").fillna(0.0).values
                lam_a = _pd.to_numeric(df.get("lambda_away"), errors="coerce").fillna(0.0).values
                L     = _pd.to_numeric(df.get("exp_goals_sum"), errors="coerce").values
                if L is None or _np.isnan(L).all():
                    L = (lam_h + lam_a)
                pi_d  = _pd.to_numeric(df.get("prob_implied_draw"), errors="coerce").fillna(0.0).values
                pdm   = _pd.to_numeric(df.get("prob_draw_model"), errors="coerce").fillna(0.0).values

                leader = _np.maximum(p_home, p_away)
                parity  = _np.isfinite(lam_h) & _np.isfinite(lam_a) & (_np.abs(lam_h - lam_a) <= dmax2)
                low_tot = _np.isfinite(L) & (L <= lmax2)
                imp_ok  = (pi_d >= min_imp) & (pi_d <= max_imp)
                near    = (p_draw + eps2 >= leader) | (pdm + eps2 >= leader) | (pdm >= 0.32)
                mask    = parity & low_tot & imp_ok & near

                if getattr(mask, "any", lambda: False)():
                    k = max(1, int(round(share * len(df))))
                    cand_idx = _np.where(mask)[0]
                    # score by stronger of draw-model vs implied draw (tie-breaker: higher p00)
                    p00 = _pd.to_numeric(df.get("p00_est"), errors="coerce").fillna(0.0).values
                    score = _np.maximum(pdm[cand_idx], pi_d[cand_idx]) + 0.25 * p00[cand_idx]
                    order = cand_idx[_np.argsort(-score)]
                    pick  = order[:k]
                    # lift draw prob toward target then force label
                    target = _np.maximum(pdm[pick], pi_d[pick])
                    p_draw[pick] = _np.maximum(p_draw[pick], target)
                    s = (p_home + p_draw + p_away)
                    s = _np.where(s > 0, s, 1.0)
                    p_home = (p_home / s).astype(float)
                    p_draw = (p_draw / s).astype(float)
                    p_away = (p_away / s).astype(float)
                    labels[pick] = "draw"
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        try:
                            print(f"🛟 draw emergency-rescue → {len(pick)} fixtures (of {len(cand_idx)} candidates)")
                        except Exception:
                            pass
        except Exception:
            pass

        df["confidence_home"] = p_home
        df["confidence_draw"] = p_draw
        df["confidence_away"] = p_away
        df["selected_outcome"] = labels
        # Final draw share cap (post-argmax safety fuse)
        try:
            import os as _os, numpy as _np, pandas as _pd
            cap_env = _os.getenv("FTR_DRAW_MAX_SHARE_FINAL", _os.getenv("FTR_DRAW_MAX_SHARE", ""))
            cap = float(cap_env) if cap_env not in (None, "",) else -1.0
        except Exception:
            cap = -1.0
        if isinstance(cap, float) and (0.0 < cap < 1.0) and "selected_outcome" in df.columns:
            lab = df["selected_outcome"].astype(str).to_numpy()
            draw_idx = (lab == "draw")
            n = lab.size if lab is not None else 0
            share = float(draw_idx.mean()) if n else 0.0
            if n and (share > cap):
                ph = _pd.to_numeric(df.get("confidence_home"), errors="coerce").fillna(0.0).to_numpy()
                pdw = _pd.to_numeric(df.get("confidence_draw"), errors="coerce").fillna(0.0).to_numpy()
                pa  = _pd.to_numeric(df.get("confidence_away"), errors="coerce").fillna(0.0).to_numpy()
                # Flip least-confident draws first: margin = draw - max(home, away)
                margin = (pdw - _np.maximum(ph, pa))
                draw_ix = _np.where(draw_idx)[0]
                need = int(_np.ceil(n*share - n*cap))
                order = draw_ix[_np.argsort(margin[draw_ix])]  # smallest draw-advantage first
                flip_ix = order[:max(0, need)]
                if flip_ix.size:
                    side = _np.where(ph[flip_ix] >= pa[flip_ix], "home", "away")
                    lab[flip_ix] = side
                    df["selected_outcome"] = lab
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print(f"🧯 final draw cap → flipped {int(flip_ix.size)} to respect cap {cap}")
        # Optional auto-save of prediction report for quick runs
        try:
            import os as _os
            if _os.getenv("AUTO_SAVE_PRED_REPORT","1") == "1":
                _save_prediction_report(df.copy(), league)
        except Exception:
            pass
        # Also write a λ̂-aware FULL predictions file to a separate path so
        # downstream probes can target a stable artifact with exp_goals_sum.
        try:
            import os as _os
            if _os.getenv("AUTO_SAVE_PRED_REPORT", "1") == "1":
                _lname = locals().get("league", None) or locals().get("league_name", None) or globals().get("league_name", "unknown_league")
                _save_prediction_report_full(df.copy(), _lname)
        except Exception:
            pass
        # Log post-override outcome mix
        if _os.getenv("VERBOSE_QUICK","0") == "1":
            try:
                _final_idx = _np.where(labels == "home", 0, _np.where(labels == "draw", 1, 2))
                _final_dist = {
                    "home": int((_final_idx == 0).sum()),
                    "draw": int((_final_idx == 1).sum()),
                    "away": int((_final_idx == 2).sum()),
                }
                print(f"📊 post-override outcome mix: {_final_dist}")
            except Exception:
                pass
        # Ensure selected_outcome exists for downstream exports
        try:
            _ensure_predictions_export_columns_inplace(df)
        except Exception:
            pass
        return df
    
# --- Quick FTR evaluation (CV or in-sample), with artifacts saved ---
if "_eval_quick_ftr" not in globals():
    def _eval_quick_ftr(df: pd.DataFrame, league: str, *, model=None, cv_splits: int = 5) -> dict:
        """
        Evaluate quick-FTR on completed data (1X2).
        Saves: confusion PNG, text report, and a scored CSV of OOF/in-sample preds.
        Returns a dict of metrics.
        """
        import numpy as _np, pandas as _pd, re as _re
        from pathlib import Path as _Path
        from datetime import datetime as _dt
        try:
            from sklearn.model_selection import StratifiedKFold
            from sklearn.linear_model import LogisticRegression
            from sklearn.metrics import confusion_matrix, classification_report, accuracy_score
        except Exception:
            return {}

        if not isinstance(df, _pd.DataFrame) or df.empty:
            return {}

        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        m = hh.notna() & aa.notna()
        if int(m.sum()) < 200:
            return {}
        # Ensure λ̂ and derived/meta features (no-ops when already present)
        try:
            df = attach_lambda_features_inplace(df, league)
        except Exception:
            pass
        try:
            df = _ensure_ftr_derived_features(df)
        except Exception:
            pass
        try:
            df = _add_ftr_engineered_features_inplace(df)
        except Exception:
            pass

        y = _np.where(hh[m] > aa[m], 0, _np.where(hh[m] < aa[m], 2, 1))  # 0=home,1=draw,2=away
        # Hardened: assert/inspect the exact FTR allowlist and warn if any of the 11 are missing
        try:
            allowlist = list(_resolve_ftr_allowlist())
            missing = [c for c in allowlist if c not in df.columns]
            # Optional features we don't warn about:
            optional = {"elo_diff","rest_diff","ewma_ppg_diff","oof_prob_over15fh","oof_prob_btts_fh"}
            missing_strict = [c for c in missing if c not in optional]
            if missing_strict:
                print(f"⚠️  quick FTR eval: missing allowlist features → {', '.join(missing_strict)}")

            # Nice, non-fatal coverage line for odds diagnostics
            try:
                _ensure_implied_1x2_inplace(df)
                _ensure_1x2_derived_odds_inplace(df)
                def _cov(c):
                    s = _pd.to_numeric(df.get(c), errors="coerce")
                    return f"{int(s.notna().sum())}/{len(df)}"
                cov_msg = "; ".join([
                    f"odds_ft_home_team_win non-NaN={_cov('odds_ft_home_team_win')}",
                    f"odds_ft_draw non-NaN={_cov('odds_ft_draw')}",
                    f"odds_ft_away_team_win non-NaN={_cov('odds_ft_away_team_win')}",
                    f"draw_implied non-NaN={_cov('draw_implied')}",
                    f"implied_prob_diff non-NaN={_cov('implied_prob_diff')}",
                    f"odds_diff non-NaN={_cov('odds_diff')}",
                    f"odds_parity non-NaN={_cov('odds_parity')}",
                    f"odds_skew non-NaN={_cov('odds_skew')}",
                ])
                print(f"ℹ️  coverage: {cov_msg}")
            except Exception:
                pass
        except Exception:
            pass

        # Base allowlist + rich pre-match stack
        _base = list(_resolve_ftr_allowlist())
        _rich = [
            # prematch team strength / form
            "pre_match_ppg_home","pre_match_ppg_away",
            "pre_match_xg_home","pre_match_xg_away",
            "weighted_home_ppg","weighted_away_ppg",
            "home_recent_form","away_recent_form",
            # λ̂ / Poisson meta
            "lambda_home","lambda_away","exp_goals_sum","p00_est",
            "lam_diff","lam_parity","tg_diff","fts_diff","attack_lean",
            # OOF specialists (stackers)
            "oof_prob_over25","oof_prob_btts",
            "oof_prob_home_over15tg","oof_prob_away_over15tg",
            "oof_prob_home_fts","oof_prob_away_fts",
            # odds diagnostics (keep parity/diff; still exclude raw implied_* below)
            "odds_parity","odds_diff","implied_prob_diff","draw_implied",
            # xG diffs
            "xg_diff_abs","ppg_diff",
            # press/intensity signals (if present)
            "rolling5_home_press_intensity","rolling5_away_press_intensity",
            "rolling5_press_intensity_diff","rolling5_home_press_z",
            "rolling5_away_press_z","rolling5_press_z_diff",
            # supervised draw model feature (already guarded in your code)
            "prob_draw_model",
        ]
        feats = [c for c in (_base + _rich)
                if (c in df.columns) and not str(c).startswith("prob_implied_")]

        # De-dup while preserving order
        feats = list(dict.fromkeys(feats))
        if not feats:
            return {}

        X = df.loc[m, feats]
        try:
            X = X.select_dtypes(include=["number"])
        except Exception:
            pass
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        if X.empty:
            return {}

        slug = _re.sub(r"[^a-z0-9]+", "_", str(league).lower()).strip("_") or "unknown_league"
        model_dir = _Path(DEFAULT_MODEL_DIR); model_dir.mkdir(parents=True, exist_ok=True)
        report_dir = _Path(DEFAULT_PREDICTION_REPORTS_DIR); report_dir.mkdir(parents=True, exist_ok=True)
        ts = _dt.now().strftime("%Y%m%d-%H%M%S")

        # CV if each class has at least cv_splits samples; else in-sample
        unique, counts = _np.unique(y, return_counts=True)
        min_class = int(counts.min()) if len(counts) else 0
        use_cv = (min_class >= max(2, cv_splits))

        y_pred = _np.zeros_like(y)
        proba = _np.zeros((len(y), 3), dtype=float)

        if use_cv:
            skf = StratifiedKFold(n_splits=min(cv_splits, min_class), shuffle=True, random_state=42)
            for tr, va in skf.split(X, y):
                # Calibrated estimator (XGB/LGBM/LR) – selected via FTR_ESTIMATOR (default: xgb)
                clf = _make_calibrated_ftr_estimator()
                clf.fit(X.iloc[tr], y[tr].astype(int))
                P = clf.predict_proba(X.iloc[va])
                classes = list(getattr(clf, "classes_", [0,1,2]))
                idx_home = classes.index(0); idx_draw = classes.index(1); idx_away = classes.index(2)
                proba[va, 0] = P[:, idx_home]
                proba[va, 1] = P[:, idx_draw]
                proba[va, 2] = P[:, idx_away]
                y_pred[va] = _np.argmax(proba[va], axis=1)
        else:
            clf = model
            if clf is None:
                clf = _make_calibrated_ftr_estimator()
                clf.fit(X, y.astype(int))
            P = clf.predict_proba(X)
            classes = list(getattr(clf, "classes_", [0,1,2]))
            idx_home = classes.index(0); idx_draw = classes.index(1); idx_away = classes.index(2)
            proba[:,0] = P[:, idx_home]; proba[:,1] = P[:, idx_draw]; proba[:,2] = P[:, idx_away]
            y_pred = _np.argmax(proba, axis=1)

        acc = float(accuracy_score(y, y_pred))
        cm  = confusion_matrix(y, y_pred, labels=[0,1,2])
        try:
            # Human-friendly labels for the report
            report_human = classification_report(
                y, y_pred, labels=[0,1,2],
                target_names=["Home Win","Draw","Away Win"], digits=3
            )
        except Exception:
            report_human = f"accuracy={acc:.4f}\n"

        # --- Top-pick gating & stronger text report ---
        thr = float(os.getenv("FTR_PICK_GATE","0.68"))
        maxp = proba.max(axis=1)
        pick_mask = (maxp >= thr)
        acc_pick = float((y[pick_mask] == y_pred[pick_mask]).mean()) if pick_mask.any() else float("nan")
        coverage = f"{int(pick_mask.sum())}/{len(y)} ({100.0*pick_mask.mean():.1f}%)"

        # Specialist accuracies (if labels+OOF exist)
        spec_lines = []
        try:
            hg = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
            ag = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
            tg = hg + ag
            def _acc(prob_col, truth):
                p = _pd.to_numeric(df.loc[m, prob_col], errors="coerce")
                if p.notna().any():
                    return float(((p >= 0.5) == truth).mean())
                return None
            a = _acc("oof_prob_over25", tg >= 3);            spec_lines.append(("Over 2.5 Goals", a))
            a = _acc("oof_prob_btts",  (hg > 0) & (ag > 0)); spec_lines.append(("BTTS", a))
            # FH BTTS if you have HT goals (optional)
            if "home_team_goal_count_half_time" in df.columns and "away_team_goal_count_half_time" in df.columns:
                hht = _pd.to_numeric(df.get("home_team_goal_count_half_time"), errors="coerce")
                aht = _pd.to_numeric(df.get("away_team_goal_count_half_time"), errors="coerce")
                a = _acc("oof_prob_fh_btts", (hht > 0) & (aht > 0)); spec_lines.append(("BTTS First-Half", a))
            a = _acc("oof_prob_home_over15tg", hg >= 2);     spec_lines.append(("Home ≥2-Goals", a))
            a = _acc("oof_prob_away_over15tg", ag >= 2);     spec_lines.append(("Away ≥2-Goals", a))
            a = _acc("oof_prob_home_fts", hg == 0);          spec_lines.append(("Home FTS", a))
            a = _acc("oof_prob_away_fts", ag == 0);          spec_lines.append(("Away FTS", a))
        except Exception:
            spec_lines = []

        # Build nice text report
        lines = []
        lines.append("===== FTR Classification Report =====")
        lines.append(report_human.strip())
        lines.append("")
        for name, val in spec_lines:
            if val is not None:
                lines.append(f"{name} Model Accuracy: {100.0*val:.2f}%")
        if pick_mask.any():
            lines.append("")
            lines.append(f"Top-pick accuracy (≥{thr:.2f}): {100.0*acc_pick:.2f}% | coverage {coverage}")
        lines.append("")
        lines.append("Confusion Matrix (rows = actual, cols = predicted):")
        lines.append(_np.array2string(cm, separator=" "))

        report_block = "\n".join(lines)

        # Save in ModelStore (timestamped) and PredictionReports (stable)
        model_dir = _Path(DEFAULT_MODEL_DIR); model_dir.mkdir(parents=True, exist_ok=True)
        report_dir = _Path(DEFAULT_PREDICTION_REPORTS_DIR); report_dir.mkdir(parents=True, exist_ok=True)
        ts = _dt.now().strftime("%Y%m%d-%H%M%S")
        try:
            with open(model_dir / f"{slug}_FTR_report {ts}.txt", "w", encoding="utf-8") as f:
                f.write(report_block + "\n")
        except Exception:
            pass
        try:
            _stable = report_dir / f"{league.replace(' ', '_')}_FTR_report.txt"
            with open(_stable, "w", encoding="utf-8") as f:
                f.write(report_block + "\n")
            print(f"📝 Saved FTR report → {_stable}")
        except Exception:
            pass

        # Confusion matrix PNG
        try:
            import matplotlib.pyplot as _plt
            fig = _plt.figure()
            _plt.imshow(cm, interpolation="nearest")
            _plt.title(f"Quick FTR Confusion ({league})")
            _plt.colorbar()
            _plt.xticks([0,1,2], ["home","draw","away"])
            _plt.yticks([0,1,2], ["home","draw","away"])
            for i in range(3):
                for j in range(3):
                    _plt.text(j, i, str(cm[i, j]), ha="center", va="center")
            _plt.xlabel("Predicted"); _plt.ylabel("True")
            _plt.tight_layout()
            _plt.savefig(model_dir / f"{slug}_FTR_confusion_matrix.png")
            _plt.close(fig)
        except Exception:
            pass

        # Text report (rich format + specialist accuracies + confusion matrix)
        try:
            # Helper to compute accuracy for a given probability column vs a boolean label
            def _acc_from_prob(prob_col: str, label_bool: pd.Series):
                if prob_col not in df.columns:
                    return None
                s = _pd.to_numeric(df.loc[m, prob_col], errors="coerce")
                mask2 = s.notna() & label_bool.notna()
                n = int(mask2.sum())
                if n == 0:
                    return None
                pred = (s[mask2] >= 0.5).astype(int)
                return float(accuracy_score(label_bool[mask2].astype(int), pred))

            # Build labels on realized rows m
            tot_goals = _pd.to_numeric(hh[m], errors="coerce").fillna(0) + _pd.to_numeric(aa[m], errors="coerce").fillna(0)
            lbl_over25 = (tot_goals > 2)
            lbl_btts   = (_pd.to_numeric(hh[m], errors="coerce").fillna(0) > 0) & (_pd.to_numeric(aa[m], errors="coerce").fillna(0) > 0)
            lbl_h_ge2  = (_pd.to_numeric(hh[m], errors="coerce").fillna(0) >= 2)
            lbl_a_ge2  = (_pd.to_numeric(aa[m], errors="coerce").fillna(0) >= 2)
            lbl_h_fts  = (_pd.to_numeric(hh[m], errors="coerce").fillna(0) == 0)
            lbl_a_fts  = (_pd.to_numeric(aa[m], errors="coerce").fillna(0) == 0)

            # Optional first-half BTTS label if HT columns present
            acc_fh_btts = None
            if ("home_team_goal_count_half_time" in df.columns) and ("away_team_goal_count_half_time" in df.columns):
                hht = _pd.to_numeric(df.loc[m, "home_team_goal_count_half_time"], errors="coerce")
                aht = _pd.to_numeric(df.loc[m, "away_team_goal_count_half_time"], errors="coerce")
                mask_ht = hht.notna() & aht.notna()
                if int(mask_ht.sum()) > 0:
                    lbl_fh_btts = (hht.fillna(0) > 0) & (aht.fillna(0) > 0)
                    # Try a few common column names for FH BTTS model output
                    fh_candidates = ["oof_prob_fh_btts", "oof_prob_btts_fh", "oof_prob_first_half_btts"]
                    fh_col = next((c for c in fh_candidates if c in df.columns), None)
                    if fh_col:
                        s = _pd.to_numeric(df.loc[m, fh_col], errors="coerce")
                        mm = mask_ht & s.notna()
                        if int(mm.sum()) > 0:
                            pred = (s[mm] >= 0.5).astype(int)
                            acc_fh_btts = float(accuracy_score(lbl_fh_btts[mm].astype(int), pred))

            # Accuracies for specialist models (if OOF present)
            acc_over25 = _acc_from_prob("oof_prob_over25", lbl_over25)
            acc_btts   = _acc_from_prob("oof_prob_btts",   lbl_btts)
            acc_h_ge2  = _acc_from_prob("oof_prob_home_over15tg", lbl_h_ge2)
            acc_a_ge2  = _acc_from_prob("oof_prob_away_over15tg", lbl_a_ge2)
            acc_h_fts  = _acc_from_prob("oof_prob_home_fts", lbl_h_fts)
            acc_a_fts  = _acc_from_prob("oof_prob_away_fts", lbl_a_fts)

            # Format confusion matrix as a compact string (rows=actual, cols=predicted)
            cm_str = _np.array2string(cm, separator=" ", max_line_width=100000)

            # Assemble rich text report
            lines = []
            lines.append("===== FTR Classification Report =====")
            lines.append(report_human.strip())
            lines.append("")

            def _fmt(name, val):
                if val is None:
                    return None
                return f"{name}: {val*100:.2f}%"

            for label, val in [
                ("Over 2.5 Goals Model Accuracy", acc_over25),
                ("BTTS Model Accuracy", acc_btts),
                ("BTTS First‑Half Model Accuracy", acc_fh_btts),
                ("Home ≥2‑Goals Model Accuracy", acc_h_ge2),
                ("Away ≥2‑Goals Model Accuracy", acc_a_ge2),
                ("Home FTS Model Accuracy", acc_h_fts),
                ("Away FTS Model Accuracy", acc_a_fts),
            ]:
                s = _fmt(label, val)
                if s:
                    lines.append(s)

            if lines and not lines[-1]:
                lines.pop()

            lines.append("")
            lines.append("Confusion Matrix (rows = actual, cols = predicted):")
            lines.append(cm_str)

            txt = "\n".join(lines) + "\n"
            # Console print of the full FTR accuracy report
            try:
                print("\n" + txt)
            except Exception:
                pass

            # Save both a timestamped copy and a stable filename in PredictionReports
            path1 = model_dir / f"{slug}_FTR_report {ts}.txt"
            with open(path1, "w", encoding="utf-8") as f:
                f.write(txt)

            path2 = report_dir / f"{league.replace(' ', '_')}_FTR_report.txt"
            try:
                with open(path2, "w", encoding="utf-8") as f:
                    f.write(txt)
            except Exception:
                pass

            # Optional console hint
            try:
                print(f"📝 Saved FTR report → {path1}")
            except Exception:
                pass
        except Exception:
            pass

        # Scored training CSV (OOF or in-sample)
        try:
            completed_idx = df.index[m]
            out = _pd.DataFrame({
                "home_team_name": df.get("home_team_name"),
                "away_team_name": df.get("away_team_name"),
                "match_date": df.get("match_date"),
            }, index=df.index)
            out = out.loc[completed_idx].copy()
            out["true_outcome"] = _np.where(hh[m] > aa[m], "home", _np.where(hh[m] < aa[m], "away", "draw"))
            out["p_home"] = proba[:,0]; out["p_draw"] = proba[:,1]; out["p_away"] = proba[:,2]
            out["predicted_outcome"] = _np.array(["home","draw","away"])[_np.argmax(proba, axis=1)]
            out.to_csv(report_dir / f"{league.replace(' ', '_')}_FTR_training_scored.csv", index=False)
        except Exception:
            pass

        try:
            dist = {k:int(v) for k,v in zip(["home","draw","away"], _np.bincount(y_pred, minlength=3))}
            print(f"📈 quick FTR {'CV ' if use_cv else ''}accuracy: {acc:.3f} | pred_dist={dist}")
        except Exception:
            pass
        # Console summary of gated (top-pick) accuracy
        try:
            import os as _os, numpy as _np
            thr = float(_os.getenv("FTR_PICK_GATE", "0.68"))
            maxp = _np.nanmax(proba, axis=1)
            mask = (maxp >= thr)
            if mask.any():
                acc_pick = float((y[mask] == y_pred[mask]).mean())
                cov = float(mask.mean())
                print(f"🎯 top-pick@{thr:.2f}: acc={acc_pick:.3f} | cov={cov:.3f} ({int(mask.sum())}/{len(mask)})")
            else:
                print(f"🎯 top-pick@{thr:.2f}: acc=NA | cov=0.000 (0/{len(maxp)})")
        except Exception:
            pass

        return {"accuracy": acc, "cm": cm.tolist()}
    
    def configure_quick_env():
        """Set sensible defaults for a fast/dev run without touching user overrides."""
        # Core pipeline toggles
        os.environ.setdefault("ENABLE_BANKER_HGM", "1")
        # Do not force quick attach on; default OFF unless user explicitly sets it.
        if os.getenv("DISABLE_QUICK_FTR", "0") == "1":
            os.environ["ENABLE_QUICK_FTR"] = "0"
        else:
            os.environ.setdefault("ENABLE_QUICK_FTR", "0")
        os.environ.setdefault("EXPORT_DEPLOYABLE_AUTOSAVE", "1")
        os.environ.setdefault("DEPLOY_MIN_IMPL", "0.67")

        # Specialists (quick)
        os.environ.setdefault("ENABLE_SPEC_OVER25", "1")
        os.environ.setdefault("ENABLE_SPEC_BTTS", "1")
        os.environ.setdefault("ENABLE_SPEC_FTS", "1")
        os.environ.setdefault("ENABLE_SPEC_GE2TG", "1")
        os.environ.setdefault("ENABLE_SPEC_FH", "0")  # FH off unless testing

        # Fast path defaults / resources
        os.environ.setdefault("FAST_MODE", "1")
        os.environ.setdefault("SKIP_DRAW_CALIBRATION", "1")
        os.environ.setdefault("SKLEARN_JOBS", "1")
        os.environ.setdefault("DRAW_ROW_CAP", "20000")
        os.environ.setdefault("ROI_ROW_CAP", "4000")
        os.environ.setdefault("DISABLE_SHAP", "1")
        os.environ.setdefault("OMP_NUM_THREADS", "1")
        os.environ.setdefault("OPENBLAS_NUM_THREADS", "1")
        os.environ.setdefault("MKL_NUM_THREADS", "1")
        os.environ.setdefault("NUMEXPR_NUM_THREADS", "1")

        # FTR training window/row caps
        os.environ.setdefault("FTR_ROW_CAP", "25000")
        os.environ.setdefault("QUICK_FTR_RECENT_SEASONS", "3")  # approx. 3 seasons/years

        # --- FTR reporting / priors / gating defaults ---
        os.environ.setdefault("FTR_PICK_GATE", "0.68")      # min confidence for deployable FTR
        os.environ.setdefault("FTR_PRIOR_BLEND", "1")       # keep soft prior blend ON
        os.environ.setdefault("FTR_PRIOR_WEIGHT", "0.20")   # ~20% toward implied 1x2
        # disable additive nudges in quick mode (let the classifier speak)
        os.environ.setdefault("FTR_DRAW_UPLIFT", "0")
        os.environ.setdefault("FTR_P00_UPLIFT", "0")
        os.environ.setdefault("FTR_PARITY_RESCUE", "0")  # off by default in quick runs

        # --- Draw override thresholds (tight/safe defaults) ---
        os.environ.setdefault("FTR_DRAW_OVERRIDES", "1")
        os.environ.setdefault("FTR_DECISION_EPS", "0.015")
        os.environ.setdefault("FTR_DRAW_DECISION_EPS", "0.015")  # alias
        os.environ.setdefault("FTR_DRAW_MARGIN", "0.01")
        os.environ.setdefault("FTR_PARITY_DELTA", "0.06")
        os.environ.setdefault("FTR_LOW_TOTAL", "1.95")
        os.environ.setdefault("FTR_DRAW_MODEL_MIN", "0.28")      # min draw-model prob to even consider
        os.environ.setdefault("FTR_DRAW_MIN_IMP", "0.22")        # plausible market draw lower bound
        os.environ.setdefault("FTR_DRAW_MAX_IMP", "0.60")        # plausible market draw upper bound

        # Emergency draw rescue (only if zero draws selected)
        os.environ.setdefault("FTR_DRAW_EMERGENCY", "1")
        os.environ.setdefault("FTR_DRAW_EMERGENCY_SHARE", "0.04")
        os.environ.setdefault("FTR_DRAW_DECISION_EPS2", "0.08")
        os.environ.setdefault("FTR_PARITY_DELTA2", "0.25")
        os.environ.setdefault("FTR_LOW_TOTAL2", "2.45")

        # Optional hard cap on draw share (0 disables)
