# --- OG GUARD (early): load_mix_params fallback (YAML -> constants -> defaults)
if "load_mix_params" not in globals():
    def load_mix_params(league_name: str) -> dict:
        """Resolve per-league overlay mix parameters.
        Priority: ModelStore/<slug>_mix.yaml → constants.LOCKED_FTR_MIX → safe defaults.
        """
        import os, re
        try:
            import yaml  # type: ignore
        except Exception:
            yaml = None
        try:
            from constants import MODEL_DIR, LOCKED_FTR_MIX as _LOCKED
        except Exception:
            MODEL_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "ModelStore"))
            _LOCKED = {}
        def _slug(s):
            return re.sub(r"[^a-z0-9]+","_", str(s).lower()).strip("_")
        slug = _slug(league_name)
        # 1) Try YAML in ModelStore (flat or subdir)
        yml_candidates = [
            os.path.join(MODEL_DIR, f"{slug}_mix.yaml"),
            os.path.join(MODEL_DIR, slug, "mix.yaml"),
        ]
        for yp in yml_candidates:
            try:
                if yaml is not None and os.path.exists(yp):
                    with open(yp, "r", encoding="utf-8") as fh:
                        data = yaml.safe_load(fh) or {}
                    if isinstance(data, dict) and data:
                        return {
                            "alpha": float(data.get("alpha", 0.50)),
                            "beta": float(data.get("beta",  0.10)),
                            "cap": float(data.get("cap",   0.33)),
                            "gate_scale": float(data.get("gate_scale", 1.00)),
                        }
            except Exception:
                continue
        # 2) constants map (exact league name or slug key)
        try:
            m = (_LOCKED or {}).get(league_name) or (_LOCKED or {}).get(slug)
            if isinstance(m, dict) and m:
                return {
                    "alpha": float(m.get("alpha", 0.50)),
                    "beta": float(m.get("beta",  0.10)),
                    "cap": float(m.get("cap",   0.33)),
                    "gate_scale": float(m.get("gate_scale", 1.00)),
                }
        except Exception:
            pass
        # 3) Safe defaults
        return {"alpha": 0.50, "beta": 0.10, "cap": 0.33, "gate_scale": 1.00}
    
