# --- OOF helpers (isotonic + attach) [defined early so quick-run can use them] ---
if "_oof_probs_isotonic" not in globals():
    def _oof_probs_isotonic(model, X, y, *, n_splits: int = 5, random_state: int = 42):
        import numpy as _np, pandas as _pd
        try:
            from sklearn.model_selection import StratifiedKFold
            from sklearn.calibration import CalibratedClassifierCV
            from sklearn.base import clone as _sk_clone
        except Exception:
            # sklearn not available -> return NaNs (caller will handle)
            X_df = _pd.DataFrame(X)
            return _pd.Series(_np.full(len(X_df), _np.nan), index=X_df.index)

        # Clean y and align X
        y = _pd.to_numeric(_pd.Series(y), errors="coerce")
        mask = y.notna()
        X = _pd.DataFrame(X).loc[mask]
        y = y.loc[mask].astype(int)

        # Not enough signal/rows -> neutral
        if y.nunique() < 2 or len(y) < 50:
            return _pd.Series(_np.full(len(X), _np.nan), index=X.index)

        # Numeric-only, finite, filled
        try:
            X = X.select_dtypes(include=["number"])
        except Exception:
            pass
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)

        # Stratified K-fold with safe split count
        n_splits = int(max(2, min(n_splits, int(y.value_counts().min()))))
        skf = StratifiedKFold(n_splits=n_splits, shuffle=True, random_state=random_state)
        oof = _np.full(len(X), _np.nan, dtype=float)

        for tr_idx, va_idx in skf.split(X, y):
            est = _sk_clone(model)
            try:
                est.fit(X.iloc[tr_idx], y.iloc[tr_idx])
            except Exception:
                # can't fit -> leave NaNs for this fold
                continue
            # Isotonic calibration without 'prefit' (sklearn ≥1.6 friendly):
            # run a tiny CV on the validation fold itself (cv=2). If this fails, fall back to raw proba.
            try:
                # fresh, unfitted base estimator for calibration
                est_base = _sk_clone(model)
                try:
                    from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
                    est_base = _Freeze(est_base)  # optional wrapper; safe across sklearn versions
                except Exception:
                    pass
                calib = _calibrated_cv2(est_base, method="isotonic")
                calib.fit(X.iloc[va_idx], y.iloc[va_idx])
                oof[va_idx] = calib.predict_proba(X.iloc[va_idx])[:, 1]
            except Exception:
                try:
                    oof[va_idx] = est.predict_proba(X.iloc[va_idx])[:, 1]
                except Exception:
                    # leave NaNs
                    pass

        return _pd.Series(oof, index=X.index)

if "_attach_oof_for_market" not in globals():
    def _attach_oof_for_market(df, market: str, model):
        import numpy as _np, pandas as _pd, os as _os
        if not isinstance(df, _pd.DataFrame) or model is None:
            return df, None

        # Build the binary target per market from labels
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        if market == "over25":
            y = (hh.add(aa) > 2).astype(int)
        elif market == "btts":
            y = ((hh > 0) & (aa > 0)).astype(int)
        elif market == "home_over15tg":
            y = (hh >= 2).astype(int)
        elif market == "away_over15tg":
            y = (aa >= 2).astype(int)
        elif market == "home_fts":
            y = (hh == 0).astype(int)
        elif market == "away_fts":
            y = (aa == 0).astype(int)
        else:
            return df, None

        # Align features to model if the model declares them
        feats = list(getattr(model, "feature_names_in_", []))
        if feats:
            try:
                X = df[feats]
            except Exception:
                X = df.reindex(columns=feats, fill_value=_np.nan)
        else:
            X = df.select_dtypes(include=["number"])

        oof = _oof_probs_isotonic(model, X, y)
        col = f"oof_prob_{market}"
        try:
            df[col] = oof.reindex(df.index)
        except Exception:
            pass

        # Debug: show how many OOF values attached (quick-only)
        try:
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                n_ok = int(df[col].notna().sum()) if col in df.columns else 0
                print(f"🧪 OOF attach → {col}: non-NaN={n_ok}/{len(df)}")
        except Exception:
            pass

        return df, col

# --- ROI helpers (early for quick path) ---
# Define idempotently so later guarded copies (if any) won't re-define them.
# Define idempotently so later guarded copies (if any) won't re-define them.
if "_coerce_decimal_odds" not in globals():
    def _coerce_decimal_odds(x):
        import pandas as _pd, numpy as _np
        s = _pd.to_numeric(_pd.Series(x), errors="coerce")
        if s.empty:
            return s
        # If values look like probabilities (0,1], convert to decimal odds
        prob_mask = (s > 0) & (s <= 1.0)
        s.loc[prob_mask] = 1.0 / s.loc[prob_mask]
        # If values look like percentages in [1, 100], try converting % -> prob -> odds
        perc_mask = (s >= 1.0) & (s <= 100.0) & (s.round() == s)
        try:
            if perc_mask.mean() >= 0.6:
                s.loc[perc_mask] = 100.0 / s.loc[perc_mask]  # to prob
                s.loc[perc_mask] = 1.0 / s.loc[perc_mask]    # to odds
        except Exception:
            pass
        s = s.replace([_np.inf, -_np.inf], _np.nan)
        try:
            import os as _os
            cap = float(_os.getenv("ROI_ODDS_CAP", "20"))
            s = s.clip(lower=1.01, upper=cap)
        except Exception:
            s = s.clip(lower=1.01)
        return s

if "_implied_mask" not in globals():
    def _implied_mask(decimal_odds, min_implied=0.67):
        import pandas as _pd, numpy as _np
        o = _coerce_decimal_odds(_pd.to_numeric(decimal_odds, errors="coerce"))
        impl = _pd.Series(_np.where(o > 0, 1.0 / o, _np.nan), index=o.index)
        return impl.notna() & (impl >= float(min_implied))

if "_ensure_roi_inputs_inplace" not in globals():
    def _ensure_roi_inputs_inplace(df):
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        for c in ("odds_ft_over25","odds_ft_btts"):
            if c in df.columns:
                df[c] = _coerce_decimal_odds(_pd.to_numeric(df[c], errors="coerce"))
        return df

# --- Ensure prediction export has FTR fields ---
def _ensure_predictions_export_columns_inplace(df: pd.DataFrame) -> pd.DataFrame:
    import numpy as _np, pandas as _pd
    if not isinstance(df, _pd.DataFrame) or df.empty:
        return df
    # Make sure confidence_* exist; if not, do nothing
    needed = ["confidence_home","confidence_draw","confidence_away"]
    if not all(c in df.columns for c in needed):
        return df
    # Add selected_outcome if missing (argmax over confidences)
    if "selected_outcome" not in df.columns:
        proba = _pd.to_numeric(df["confidence_home"], errors="coerce").fillna(0).to_numpy()
        prd   = _pd.to_numeric(df["confidence_draw"], errors="coerce").fillna(0).to_numpy()
        pra   = _pd.to_numeric(df["confidence_away"], errors="coerce").fillna(0).to_numpy()
        P = _np.vstack([proba, prd, pra]).T
        lab = _np.array(["home","draw","away"])[_np.nanargmax(P, axis=1)]
        df["selected_outcome"] = lab
    return df

if "_print_roi_snapshot" not in globals():
    def _print_roi_snapshot(df, stake: float = 10.0):
        import os as _os, numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return
        df = df.copy()
        _ensure_roi_inputs_inplace(df)

        MIN_IMPL = float(_os.getenv("DEPLOY_MIN_IMPL", "0.67"))

        yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        realized = yh.notna() & ya.notna()
        if not realized.any():
            try: print("ℹ️  ROI snapshot skipped: no realized matches in training slice")
            except Exception: pass
            return

        y_over = (yh.add(ya) > 2)
        y_btts = ((yh > 0) & (ya > 0))

        odds_o25 = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_over25"), errors="coerce"))
        odds_btts = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_btts"), errors="coerce"))
        # Verbose odds quantiles (sanity-check capping) when VERBOSE_QUICK=1
        try:
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                _qq_o = (odds_o25.quantile([0, 0.5, 0.95, 0.99, 1.0])
                         if hasattr(odds_o25, "quantile") else None)
                _qq_b = (odds_btts.quantile([0, 0.5, 0.95, 0.99, 1.0])
                         if hasattr(odds_btts, "quantile") else None)
                if _qq_o is not None and _qq_b is not None:
                    print(f"ℹ️  O2.5 odds quantiles: {_qq_o.to_dict()} | BTTS odds quantiles: {_qq_b.to_dict()}")
        except Exception:
            pass
        valid_o25 = realized & odds_o25.notna() & _np.isfinite(odds_o25) & (odds_o25 >= 1.01)
        valid_bt  = realized & odds_btts.notna() & _np.isfinite(odds_btts) & (odds_btts >= 1.01)

        p_o25 = _pd.to_numeric(df.get("prob_over25", _pd.Series(_np.nan, index=df.index)), errors="coerce")
        p_bt  = _pd.to_numeric(df.get("prob_btts",  _pd.Series(_np.nan, index=df.index)), errors="coerce")

        sel_dep_o25 = valid_o25 & _implied_mask(odds_o25, MIN_IMPL) & p_o25.notna()
        sel_dep_bt  = valid_bt  & _implied_mask(odds_btts, MIN_IMPL) & p_bt.notna()

        def _roi(y, sel, odds):
            # Numpy-based to avoid any index alignment surprises
            import numpy as _np, os as _os
            n = int(sel.sum())
            if n == 0:
                return (0, 0.0, 0.0)
            cap = float(_os.getenv("ROI_ODDS_CAP", "20"))
            o = _np.asarray(odds, dtype=float)
            s = _np.asarray(sel, dtype=bool)
            yv = _np.asarray(y, dtype=bool)
            with _np.errstate(invalid="ignore"):
                o = _np.clip(o, 1.01, max(cap, 1.01))
            win_idx = s & yv
            loss_count = int((s & ~yv).sum())
            win_profit = _np.nan_to_num((o[win_idx] - 1.0) * stake, nan=0.0).sum()
            profit = float(win_profit - loss_count * stake)
            roi = float(profit) / float(max(n * stake, 1.0))
            return (n, float(profit), roi)
        
        odds_o25 = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_over25"), errors="coerce"))
        odds_btts = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_btts"), errors="coerce"))

        n_dep_o25, prof_dep_o25, roi_dep_o25 = _roi(y_over, sel_dep_o25, odds_o25)
        n_dep_bt,  prof_dep_bt,  roi_dep_bt  = _roi(y_btts, sel_dep_bt,  odds_btts)

        sel_all_o25 = valid_o25 & p_o25.notna()
        sel_all_bt  = valid_bt  & p_bt.notna()
        n_all_o25, prof_all_o25, roi_all_o25 = _roi(y_over, sel_all_o25, odds_o25)
        n_all_bt,  prof_all_bt,  roi_all_bt  = _roi(y_btts, sel_all_bt,  odds_btts)

        print("---- ROI snapshot (completed) ----------------------")
        print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets={n_dep_o25} profit={prof_dep_o25:+.2f} roi={roi_dep_o25:.1%}")
        print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets={n_dep_bt}  profit={prof_dep_bt:+.2f} roi={roi_dep_bt:.1%}")
        print(f"(All odds)           O2.5  bets={n_all_o25} profit={prof_all_o25:+.2f} roi={roi_all_o25:.1%}")
        print(f"(All odds)           BTTS  bets={n_all_bt}  profit={prof_all_bt:+.2f} roi={roi_all_bt:.1%}")
        print("----------------------------------------------------")

