if "backtest_hgm_bankers" not in globals():
    def backtest_hgm_bankers(df: pd.DataFrame, league: str) -> None:
        import os as _os, numpy as _np, pandas as _pd
        MIN_IMPL = float(_os.getenv("DEPLOY_MIN_IMPL", "0.67"))

        def _print_zero():
            print("---- HGM ROI (completed) -------------------------")
            print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets=0 profit=+0.00 roi=0.0%")
            print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets=0 profit=+0.00 roi=0.0%")
            print(f"(All odds)           O2.5  bets=0 profit=+0.00 roi=0.0%")
            print(f"(All odds)           BTTS  bets=0 profit=+0.00 roi=0.0%")
            print("--------------------------------------------------")

        if not isinstance(df, _pd.DataFrame) or df.empty:
            _print_zero(); return

        # If full banker engine exists, try to populate HGM columns; otherwise continue if columns are present.
        try:
            if "_hgm_probs_inplace" in globals():
                _hgm_probs_inplace(df, league)
        except Exception:
            pass

        yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        realized = yh.notna() & ya.notna()
        if not realized.any():
            _print_zero(); return

        y_over = (yh.add(ya) > 2)
        y_btts = ((yh > 0) & (ya > 0))

        odds_o25 = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_over25"), errors="coerce"))
        odds_btts = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_btts"), errors="coerce"))
        valid_o25 = realized & odds_o25.notna() & _np.isfinite(odds_o25) & (odds_o25 >= 1.01)
        valid_bt  = realized & odds_btts.notna() & _np.isfinite(odds_btts) & (odds_btts >= 1.01)

        # Use HGM probabilities if available; otherwise this will behave like the generic ROI snapshot.
        p_o25 = _pd.to_numeric(df.get("hgm_prob_over25", _pd.Series(_np.nan, index=df.index)), errors="coerce")
        p_bt  = _pd.to_numeric(df.get("hgm_prob_btts",  _pd.Series(_np.nan, index=df.index)), errors="coerce")

        sel_dep_o25 = valid_o25 & _implied_mask(odds_o25, MIN_IMPL) & p_o25.notna()
        sel_dep_bt  = valid_bt  & _implied_mask(odds_btts, MIN_IMPL) & p_bt.notna()
        sel_all_o25 = valid_o25 & p_o25.notna()
        sel_all_bt  = valid_bt  & p_bt.notna()

        def _roi(y, sel, odds, stake=10.0):
            n = int(sel.sum())
            if n == 0: return (0, 0.0, 0.0)
            wins = y & sel
            losses = sel & ~y
            profit = ((odds[wins].fillna(0) - 1.0) * stake).sum() - (losses.sum() * stake)
            roi = float(profit) / float(max(n * stake, 1.0))
            return (n, float(profit), roi)

        n_dep_o25, prof_dep_o25, roi_dep_o25 = _roi(y_over, sel_dep_o25, odds_o25)
        n_dep_bt,  prof_dep_bt,  roi_dep_bt  = _roi(y_btts, sel_dep_bt,  odds_btts)
        n_all_o25, prof_all_o25, roi_all_o25 = _roi(y_over, sel_all_o25, odds_o25)
        n_all_bt,  prof_all_bt,  roi_all_bt  = _roi(y_btts, sel_all_bt,  odds_btts)

        print("---- HGM ROI (completed) -------------------------")
        print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets={n_dep_o25} profit={prof_dep_o25:+.2f} roi={roi_dep_o25:.1%}")
        print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets={n_dep_bt}  profit={prof_dep_bt:+.2f} roi={roi_dep_bt:.1%}")
        print(f"(All odds)           O2.5  bets={n_all_o25} profit={prof_all_o25:+.2f} roi={roi_all_o25:.1%}")
        print(f"(All odds)           BTTS  bets={n_all_bt}  profit={prof_all_bt:+.2f} roi={roi_all_bt:.1%}")
        print("--------------------------------------------------")

# If the accuracy variant isn't available, provide a minimal one too.
if "backtest_hgm_bankers_accuracy" not in globals():
    def backtest_hgm_bankers_accuracy(df: pd.DataFrame, league: str) -> None:
        import os as _os, numpy as _np, pandas as _pd
        MIN_IMPL = float(_os.getenv("DEPLOY_MIN_IMPL", "0.67"))

        def _print_zero():
            print("---- HGM Accuracy (completed) --------------------")
            print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets=0  acc=0.0%")
            print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets=0  acc=0.0%")
            print(f"(All odds)           O2.5  bets=0  acc=0.0%")
            print(f"(All odds)           BTTS  bets=0  acc=0.0%")
            print("--------------------------------------------------")

        if not isinstance(df, _pd.DataFrame) or df.empty:
            _print_zero(); return

        try:
            if "_hgm_probs_inplace" in globals():
                _hgm_probs_inplace(df, league)
        except Exception:
            pass

        yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        realized = yh.notna() & ya.notna()
        if not realized.any():
            _print_zero(); return

        y_over = (yh.add(ya) > 2)
        y_btts = ((yh > 0) & (ya > 0))

        odds_o25 = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_over25"), errors="coerce"))
        odds_btts = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_btts"), errors="coerce"))
        valid_o25 = realized & odds_o25.notna() & _np.isfinite(odds_o25) & (odds_o25 >= 1.01)
        valid_bt  = realized & odds_btts.notna() & _np.isfinite(odds_btts) & (odds_btts >= 1.01)

        p_o25 = _pd.to_numeric(df.get("hgm_prob_over25", _pd.Series(_np.nan, index=df.index)), errors="coerce")
        p_bt  = _pd.to_numeric(df.get("hgm_prob_btts",  _pd.Series(_np.nan, index=df.index)), errors="coerce")

        sel_dep_o25 = valid_o25 & _implied_mask(odds_o25, MIN_IMPL) & p_o25.notna()
        sel_dep_bt  = valid_bt  & _implied_mask(odds_btts, MIN_IMPL) & p_bt.notna()
        sel_all_o25 = valid_o25 & p_o25.notna()
        sel_all_bt  = valid_bt  & p_bt.notna()

        def _acc(y, sel):
            n = int(sel.sum())
            if n == 0: return (0, 0.0)
            acc = float((y & sel).sum()) / float(n)
            return (n, acc)

        n_dep_o25, acc_dep_o25 = _acc(y_over, sel_dep_o25)
        n_dep_bt,  acc_dep_bt  = _acc(y_btts, sel_dep_bt)
        n_all_o25, acc_all_o25 = _acc(y_over, sel_all_o25)
        n_all_bt,  acc_all_bt  = _acc(y_btts, sel_all_bt)

        print("---- HGM Accuracy (completed) --------------------")
        print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets={n_dep_o25}  acc={acc_dep_o25:.1%}")
        print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets={n_dep_bt}  acc={acc_dep_bt:.1%}")
        print(f"(All odds)           O2.5  bets={n_all_o25}  acc={acc_all_o25:.1%}")
        print(f"(All odds)           BTTS  bets={n_all_bt}  acc={acc_all_bt:.1%}")
        print("--------------------------------------------------")



