# Best-effort merge of press-intensity features to match-level df (home/away).
# Tries ETL helpers if present; otherwise no-op. Idempotent and NA-safe.
def attach_press_intensity(df: pd.DataFrame, league: str | None = None):
    """
    Best-effort merge of press-intensity features to match-level df (home/away).
    Tries ETL helpers if present; otherwise no-op. Idempotent and NA-safe.
    """
    if not isinstance(df, pd.DataFrame) or df.empty:
        return df
    if _pi_run is None and _pi_compute is None and _pi_players_merge is None:
        return df
    import pandas as _pd
    try:
        # Ensure on-disk artefacts if supported by the ETL
        if callable(_pi_players_merge):
            try:
                _ = _pi_players_merge(league=league)
            except TypeError:
                try:
                    _ = _pi_players_merge(league)
                except Exception:
                    _ = _pi_players_merge()
        if callable(_pi_run):
            try:
                _ = _pi_run(league=league)
            except TypeError:
                try:
                    _ = _pi_run(league)
                except Exception:
                    _ = _pi_run()
    except Exception as _e:
        if VERBOSE_PRESS:
            try:
                print(f"ℹ️ press-intensity ensure skipped: {_e}")
            except Exception:
                pass

    pi = None
    try:
        if callable(_pi_compute):
            try:
                pi = _pi_compute(league=league)
            except TypeError:
                try:
                    pi = _pi_compute(league)
                except Exception:
                    pi = _pi_compute()
        if isinstance(pi, tuple):
            for _x in pi:
                if isinstance(_x, _pd.DataFrame):
                    pi = _x
                    break
    except Exception as _e:
        if VERBOSE_PRESS:
            try:
                print(f"ℹ️ press-intensity compute skipped: {_e}")
            except Exception:
                pass
        pi = None

    if not isinstance(pi, _pd.DataFrame) or pi.empty:
        return df

    # Normalise likely column names for join
    cols = {c.lower(): c for c in pi.columns}
    def _getcol(*cands):
        for c in cands:
            if c in cols:
                return cols[c]
        return None

    team_col = _getcol("team", "team_name", "club", "club_name", "name", "squad")
    date_col = _getcol("match_date", "date", "fixture_date", "kickoff_date", "kickoff", "game_date", "matchday_date")
    val_col  = _getcol("press_intensity", "pressing_intensity", "ppi", "ppda", "press_ppi", "ppda_def", "opp_ppda")

    if not team_col or not date_col or not val_col:
        return df

    try:
        pi = pi[[team_col, date_col, val_col]].copy()
        pi.rename(columns={team_col: "__pi_team", date_col: "__pi_date", val_col: "__pi_val"}, inplace=True)
        pi["__pi_date"] = _pd.to_datetime(pi["__pi_date"], errors="coerce").dt.date

        dmatch = df.copy()
        if "match_date" in dmatch.columns:
            dmatch["__match_date"] = _pd.to_datetime(dmatch["match_date"], errors="coerce").dt.date
        else:
            dmatch["__match_date"] = _pd.NaT

        # Home merge
        if "home_team_name" in dmatch.columns:
            mH = dmatch.merge(pi, left_on=["home_team_name", "__match_date"], right_on=["__pi_team", "__pi_date"], how="left")
            if "__pi_val" in mH.columns:
                dmatch["home_press_intensity"] = _pd.to_numeric(mH["__pi_val"], errors="coerce")

        # Away merge
        if "away_team_name" in dmatch.columns:
            mA = dmatch.merge(pi, left_on=["away_team_name", "__match_date"], right_on=["__pi_team", "__pi_date"], how="left")
            if "__pi_val" in mA.columns:
                dmatch["away_press_intensity"] = _pd.to_numeric(mA["__pi_val"], errors="coerce")

        # Reflect into original df where missing
        for _c in ("home_press_intensity", "away_press_intensity"):
            if _c in dmatch.columns and _c not in df.columns:
                df[_c] = dmatch[_c]

        if VERBOSE_PRESS:
            try:
                got = int(dmatch.get("home_press_intensity").notna().sum()) if "home_press_intensity" in dmatch.columns else 0
                got += int(dmatch.get("away_press_intensity").notna().sum()) if "away_press_intensity" in dmatch.columns else 0
                print(f"✅ Press-intensity merged rows: {got}")
            except Exception:
                pass
    except Exception as _e:
        if VERBOSE_PRESS:
            try:
                print(f"ℹ️ press-intensity merge skipped: {_e}")
            except Exception:
                pass

    return df
