def train_draw_classifier(*args, **kwargs):
    """
    Lazy wrapper + feature shim: if only a DataFrame is provided,
    derive a safe feature list from the allowlist.
    """
    import pandas as _pd
    global _TD_IMPL
    if _TD_IMPL is None:
        from train_draw_classifier import train_draw_classifier as _TD_IMPL

    if len(args) == 1 and isinstance(args[0], _pd.DataFrame) and "feature_cols" not in kwargs:
        df0 = args[0]
        feats = [c for c in _resolve_ftr_allowlist() if c in df0.columns]
        try:
            return _TD_IMPL(df0, feats, **kwargs)
        except TypeError:
            # legacy signature (df, feats)
            return _TD_IMPL(df0, feats)

    return _TD_IMPL(*args, **kwargs)



