# --- FTR feature allowlist resolver (safe fallback) ---
if "_resolve_ftr_allowlist" not in globals():
    def _resolve_ftr_allowlist() -> list[str]:
        import os as _os, json as _json, re as _re
        # 1) ENV override
        env_list = _os.getenv("FTR_FEATURES")
        if env_list:
            try:
                items = [s.strip() for s in env_list.split(",") if s.strip()]
                if items:
                    return items
            except Exception:
                pass
        # 2) File override
        path = _os.getenv("FTR_FEATURES_PATH")
        if path:
            try:
                with open(path, "r", encoding="utf-8") as f:
                    txt = f.read()
                if path.lower().endswith(".json"):
                    data = _json.loads(txt)
                    if isinstance(data, list):
                        return [str(x) for x in data]
                parts = [p.strip() for p in _re.split(r"[,;\n]+", txt) if p.strip()]
                if parts:
                    return parts
            except Exception:
                pass
        # 3) constants
        try:
            from constants import ALLOWED_FTR_FEATURES  # type: ignore
            return list(ALLOWED_FTR_FEATURES)
        except Exception:
            # Fallback: include OOF stacker + λ features + simple priors
            return [
                # OOF stacker features (specialists)
                "oof_prob_over25","oof_prob_btts",
                "oof_prob_over15","oof_prob_over35","oof_prob_over45",
                "oof_prob_home_over15tg","oof_prob_away_over15tg",
                "oof_prob_home_fts","oof_prob_away_fts",
                # Overlay probabilities (if available)
                "prob_over25","prob_btts",
                # Classic confidences (if already present)
                "confidence_home","confidence_draw","confidence_away",
                # Lambda features
                "lambda_home","lambda_away","exp_goals_sum","p00_est",
                # Light priors / context
                "pre_match_xg_home","pre_match_xg_away",
                # Odds (sometimes informative)
                "odds_ft_home_team_win","odds_ft_draw","odds_ft_away_team_win",
                "prob_draw_model",  # NEW: use draw signal in FTR
                "lam_diff","lam_parity","tg_diff","fts_diff","attack_lean",
            ]


