if "_bind_specialist_trainers" not in globals():
    def _bind_specialist_trainers():
        import os as _os, importlib
        names = [
            "train_and_evaluate_over25_model",
            "train_and_evaluate_btts_model",
            "train_and_evaluate_over15tg_model",
            "train_and_evaluate_fts_model",
        ]
        # Allow override: export SPECIALIST_TRAINERS_MODULE=package.path
        mod_hint = _os.getenv("SPECIALIST_TRAINERS_MODULE", "").strip()
        candidates = [mod_hint] if mod_hint else []
        candidates += ["specialist_trainers", "market_trainers", "trainers.specialists"]
        for mn in candidates:
            if not mn:
                continue
            try:
                m = importlib.import_module(mn)
                for n in names:
                    if n not in globals() and hasattr(m, n):
                        globals()[n] = getattr(m, n)
                return True
            except Exception:
                continue
        return False
    try:
        _bind_specialist_trainers()
    except Exception:
        pass

        
