if "_strict_align" not in globals():
    def _strict_align(X: pd.DataFrame, model):
        return _align_dataframe_to_model(X, model)

    # --- OOF helpers (isotonic + attach) ---
    if "_oof_probs_isotonic" not in globals():
        def _oof_probs_isotonic(model, X, y, *, n_splits: int = 5, random_state: int = 42):
            import numpy as _np, pandas as _pd
            from sklearn.model_selection import StratifiedKFold
            from sklearn.base import clone as _sk_clone

            # Coerce labels and mask valid rows
            y = _pd.to_numeric(_pd.Series(y), errors="coerce")
            mask = y.notna()
            if hasattr(X, "loc"):
                X = X.loc[mask]
            else:
                X = _pd.DataFrame(X).loc[mask]
            y = y.loc[mask].astype(int)

            # If too few positives/negatives, return NaNs
            if y.nunique() < 2 or len(y) < 50:
                return _pd.Series(_np.full(len(X), _np.nan), index=X.index)

            # Numeric-only, clean matrix
            try:
                X = X.select_dtypes(include=["number"])
            except Exception:
                pass
            X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)

            # Robust split count
            n_splits = int(max(2, min(n_splits, int(y.value_counts().min()))))
            skf = StratifiedKFold(n_splits=n_splits, shuffle=True, random_state=random_state)
            oof = _np.full(len(X), _np.nan, dtype=float)

            for tr_idx, va_idx in skf.split(X, y):
                # Fit a fresh clone for the fold
                try:
                    est = _sk_clone(model).fit(X.iloc[tr_idx], y.iloc[tr_idx])
                except Exception:
                    est = model
                # Prefer calibrated probabilities on the validation fold
                try:
                    calib = _calibrated_cv2(_sk_clone(model), method="isotonic")
                    calib.fit(X.iloc[va_idx], y.iloc[va_idx])
                    oof[va_idx] = calib.predict_proba(X.iloc[va_idx])[:, 1]
                except Exception:
                    try:
                        oof[va_idx] = est.predict_proba(X.iloc[va_idx])[:, 1]
                    except Exception:
                        # leave NaNs for this fold
                        pass

            return _pd.Series(oof, index=X.index)

if "_attach_oof_for_market" not in globals():
    def _attach_oof_for_market(df, market: str, model):
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or model is None:
            return df, None

        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        if market == "over25":
            y = (hh.add(aa) > 2).astype(int)
        elif market == "btts":
            y = ((hh > 0) & (aa > 0)).astype(int)
        elif market == "home_over15tg":
            y = (hh >= 2).astype(int)
        elif market == "away_over15tg":
            y = (aa >= 2).astype(int)
        elif market == "home_fts":
            y = (hh == 0).astype(int)
        elif market == "away_fts":
            y = (aa == 0).astype(int)
        else:
            return df, None

        feats = list(getattr(model, "feature_names_in_", []))
        if feats:
            try:
                X = df[feats]
            except Exception:
                X = df.reindex(columns=feats, fill_value=_np.nan)
        else:
            X = df.select_dtypes(include=["number"])
        oof = _oof_probs_isotonic(model, X, y)
        col = f"oof_prob_{market}"
        try:
            df[col] = oof.reindex(df.index)
        except Exception:
            pass
        # Debug: show how many OOF values attached (quick-only)
        try:
            import os as _os
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                n_ok = int(df[col].notna().sum()) if col in df.columns else 0
                print(f"🧪 OOF attach → {col}: non-NaN={n_ok}/{len(df)}")
        except Exception:
            pass
        return df, col
    

    # --- Inference-time specialist probs → 'oof_prob_*' (no OOF splits) ---
    def attach_specialist_probs_for_inference(
        df: pd.DataFrame,
        league_name: str,
        markets: tuple[str, ...] = ("over25", "btts", "home_over15tg", "away_over15tg", "home_fts", "away_fts"),
    ) -> pd.DataFrame:
        """
        Self-contained inference helper:
        - loads each specialist model from disk,
        - aligns features via model.feature_names_in_ (if present) else numeric-only,
        - coerces non-finite to NaN then fills with 0.0,
        - writes probabilities into 'oof_prob_*' columns on a copy of df.
        Safe no-op for missing models or scoring errors.
        """
        import numpy as _np, pandas as _pd

        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        out = df.copy()

        for m in markets:
            # Load model safely
            try:
                mdl = _load_market_model(league_name, m)
            except Exception:
                mdl = None
            if mdl is None:
                continue

            # Feature alignment: prefer declared feature_names_in_, else numeric columns
            feats = list(getattr(mdl, "feature_names_in_", []))
            try:
                if feats:
                    X = out.reindex(columns=feats, fill_value=_np.nan)
                else:
                    X = out.select_dtypes(include=["number"])
            except Exception:
                # If alignment fails, skip this market
                continue

            # Clean matrix
            X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)

            # Predict probabilities
            try:
                proba = mdl.predict_proba(X)
                p = (
                    proba[:, 1]
                    if getattr(proba, "ndim", 1) == 2 and proba.shape[1] >= 2
                    else _np.asarray(proba, dtype=float).ravel()
                )
            except Exception as _e:
                if VERBOSE_MODELSTORE:
                    try:
                        print(f"⚠️ Could not score {m} specialist for inference: {_e}")
                    except Exception:
                        pass
                continue

            col = f"oof_prob_{m}"
            # Only write if column missing or entirely NaN to avoid clobbering prior values
            try:
                needs_write = (col not in out.columns) or out[col].isna().all()
            except Exception:
                needs_write = (col not in out.columns)
            if needs_write:
                out[col] = _np.clip(p, 0.0, 1.0)

        return out
        
# --- Quick FTR (multinomial LR) helpers ---
if "_prepare_ftr_matrix" not in globals():
    def _prepare_ftr_matrix(df: pd.DataFrame, model=None) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return _pd.DataFrame(index=_pd.RangeIndex(0))
        feats = list(_resolve_ftr_allowlist())
        cols = [c for c in feats if c in df.columns]
        X = df[cols].copy() if cols else df.select_dtypes(include=["number"]).copy()
        try:
            X = X.select_dtypes(include=["number"])
        except Exception:
            pass
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        try:
            if model is not None and hasattr(model, "feature_names_in_"):
                want = list(getattr(model, "feature_names_in_", []))
                X = X.reindex(columns=want, fill_value=0.0)
        except Exception:
            pass
        return X

if "_train_quick_ftr" not in globals():
    # DEPRECATED: legacy quick FTR trainer (kept for reference; not used)
    def _train_quick_ftr_legacy(df: pd.DataFrame, league_name: str):
        """Fast multinomial LogisticRegression on allowlist+OOF features."""
        import numpy as _np, pandas as _pd, os as _os
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return None
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        mask = hh.notna() & aa.notna()
        if int(mask.sum()) < 100:
            return None
        y = _np.where(hh[mask] > aa[mask], 0, _np.where(hh[mask] == aa[mask], 1, 2))
        X = _prepare_ftr_matrix(df.loc[mask])
        try:
            cap = int(float(_os.getenv("FTR_ROW_CAP", "25000")))
        except Exception:
            cap = 25000
        if len(X) > cap:
            try:
                idx = []
                for c in (0,1,2):
                    ii = X.index[y == c]
                    if len(ii) == 0: 
                        continue
                    take = max(1, int(cap * (len(ii) / len(X))))
                    idx.extend(list(ii.to_series().sample(take, random_state=42)))
                X = X.loc[idx]
                y = _np.where(hh.loc[X.index] > aa.loc[X.index], 0,
                              _np.where(hh.loc[X.index] == aa.loc[X.index], 1, 2))
            except Exception:
                X = X.sample(cap, random_state=42)
                y = y[:len(X)]
        try:
            from sklearn.linear_model import LogisticRegression
            params = dict(max_iter=800, solver="lbfgs", class_weight="balanced")
            try:
                # keep single-core for reproducibility in quick runs
                if "n_jobs" in LogisticRegression().get_params():
                    params["n_jobs"] = 1
            except Exception:
                pass
            m = LogisticRegression(**params)
            m.fit(X, y)
            try: m.feature_names_in_ = list(getattr(X, "columns", []))
            except Exception: pass
        except Exception:
            class _DummyFTR:
                def __init__(self, feats): self.feature_names_in_ = feats
                def predict_proba(self, X):
                    import numpy as _np
                    n = getattr(getattr(X, "shape", None), "__getitem__", lambda i: len(X))(0)
                    return _np.full((n,3), 1/3.0, dtype=float)
            m = _DummyFTR(list(getattr(X, "columns", [])))
        try: _save_quick_ftr_model(league_name, m)
        except Exception: pass
        return m

if "_score_quick_ftr" not in globals():
    def _score_quick_ftr(df: pd.DataFrame, league_name: str, model=None) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        mdl = model
        if mdl is None:
            try:
                mdl = _load_quick_ftr_model(league_name)
            except Exception:
                mdl = None
        if mdl is None:
            return df
        X = _prepare_ftr_matrix(df, model=mdl)
        try:
            P = mdl.predict_proba(X)
            if isinstance(P, _np.ndarray) and P.shape[1] == 3:
                ch, cd, ca = P[:,0], P[:,1], P[:,2]
            else:
                n = len(X); ch = cd = ca = _np.full(n, 1/3.0, dtype=float)
        except Exception:
            n = len(X); ch = cd = ca = _np.full(n, 1/3.0, dtype=float)
        try:
            df["confidence_home"] = _pd.to_numeric(ch, errors="coerce")
            df["confidence_draw"] = _pd.to_numeric(cd, errors="coerce")
            df["confidence_away"] = _pd.to_numeric(ca, errors="coerce")
            argmax = _np.vstack([ch, cd, ca]).T.argmax(1)
            mapping = _np.array(["home","draw","away"])
            df["selected_outcome"] = mapping[argmax]
        except Exception:
            pass
        return df

