def _bind_banker_wrapper_full_pipeline():
    g = globals()
    _orig = g.get("run_pipeline_for_league", None)
    if callable(_orig) and not getattr(_orig, "_banker_wrapped", False):
        def _RPFL_BANKER_WRAPPER(*args, **kwargs):
            res = _orig(*args, **kwargs)
            # Hard off-switch: if DISABLE_QUICK_FTR=1, never apply quick attach
            import os as _os
            if _os.getenv("DISABLE_QUICK_FTR", "0") == "1":
                return res
            # Derive league name for reporting
            try:
                if len(args) >= 1:
                    _lg = args[0]
                else:
                    _lg = kwargs.get("league", None)
                _lname = _league_name(_lg) if _lg is not None else None
            except Exception:
                _lname = None
            try:
                return _apply_banker_hooks_if_enabled(res, _lname)
            except Exception:
                return res
        _RPFL_BANKER_WRAPPER._banker_wrapped = True
        g["run_pipeline_for_league"] = _RPFL_BANKER_WRAPPER

# --- Wrapper binder for quick FTR (scores pipeline output) ---
def _bind_quick_ftr_wrapper_full_pipeline():
    g = globals()
    _orig = g.get("run_pipeline_for_league", None)
    if callable(_orig) and not getattr(_orig, "_quickftr_wrapped", False):
        def _RPFL_QFTR_WRAPPER(*args, **kwargs):
            res = _orig(*args, **kwargs)

            # 1) Hard off-switch wins
            import os as _os
            if _os.getenv("DISABLE_QUICK_FTR", "0") == "1":
                return res

            # 2) Resolve league name
            try:
                _lg = args[0] if len(args) >= 1 else kwargs.get("league", None)
                _lname = _league_name(_lg) if _lg is not None else None
            except Exception:
                _lname = None

            # 3) Only run if explicitly enabled and we have a league
            if (_lname is None) or (_os.getenv("ENABLE_QUICK_FTR", "0") != "1"):
                return res

            # 4) Call the overlay mixer (with draw gate), not the skinny scorer
            try:
                import os as _os
                # guard print – always shows the current env values
                print(f"🔎 quick guard (wrapper): ENABLE_QUICK_FTR={_os.getenv('ENABLE_QUICK_FTR')} "
                    f"DISABLE_QUICK_FTR={_os.getenv('DISABLE_QUICK_FTR')}")
                if _os.getenv("ENABLE_QUICK_FTR", "0") == "1" and _os.getenv("DISABLE_QUICK_FTR", "0") != "1":
                    from prediction_overlay import attach_ftr_with_draw_mix  # local import to avoid top-level side effects
                    print(f"🧪 quick wrapper → overlay attach_ftr_with_draw_mix | league={_lname}")
                    out = attach_ftr_with_draw_mix(res, _lname)  # overwrite result with overlay mix
                    try:
                        out.attrs["_overlay_done"] = True
                    except Exception:
                        pass
                else:
                    print("ℹ️ quick wrapper bypassed overlay (ENABLE_QUICK_FTR!=1 or DISABLE_QUICK_FTR=1)")
                    out = res
            except Exception as e:
                print(f"⚠️ quick wrapper overlay failed: {e}")
                out = res
            return out
        _RPFL_QFTR_WRAPPER._quickftr_wrapped = True
        g["run_pipeline_for_league"] = _RPFL_QFTR_WRAPPER

