def _resolve_ftr_allowlist() -> list[str]:
    """
    Resolve the FTR allowlist robustly:
      • ENV overrides (FTR_FEATURES / FTR_FEATURES_PATH) if present
      • otherwise curated base ∪ project constants ∪ safe OOF adds.
    """
    import os as _os, json as _json, re as _re
    # 1) ENV comma‑separated override
    env_list = _os.getenv("FTR_FEATURES")
    if env_list:
        try:
            items = [s.strip() for s in env_list.split(",") if s.strip()]
            if items: return items
        except Exception:
            pass
    # 2) File override (.json list or .txt/.csv)
    path = _os.getenv("FTR_FEATURES_PATH")
    if path:
        try:
            with open(path, "r", encoding="utf-8") as f:
                txt = f.read()
            if path.lower().endswith(".json"):
                data = _json.loads(txt)
                if isinstance(data, list):
                    return [str(x) for x in data]
            parts = [p.strip() for p in _re.split(r"[,;\n]+", txt) if p.strip()]
            if parts:
                return parts
        except Exception:
            pass
    # 3) Default: curated base ∪ project constants ∪ OOF adds
    g = globals()
    core = list(g.get("_FTR_BASE_ALLOW", []))
    base = list(g.get("ALLOWED_FTR", []))
    legacy = list(g.get("_ALLOWED_FTR", []))
    chosen = base or legacy

    # If we already have a curated allowlist from constants or earlier assembly,
    # keep using it (union with the curated core to preserve order).
    if chosen:
        return list(dict.fromkeys(core + chosen))

    # --- Explicit fallback (order is intentional) ---
    # Minimal but robust set covering confidences, OOF stackers, HGM summaries,
    # odds, key pre‑match percentages and a few rolling stats.
    return [
        "confidence_home","confidence_draw","confidence_away",
        "prob_over25","prob_btts","btts_confidence","over25_confidence",
        "adjusted_btts_confidence","adjusted_over25_confidence",
        # NEW: OOF stacker features
        "oof_prob_over25","oof_prob_btts",
        "oof_prob_home_over15tg","oof_prob_away_over15tg",
        "oof_prob_home_fts","oof_prob_away_fts",
        # HGM summaries
        "hgm_prob_over25","hgm_prob_btts","hgm_lambda_home","hgm_lambda_away",
        # Odds (1X2 + markets)
        "odds_ft_home_team_win","odds_ft_draw","odds_ft_away_team_win",
        "odds_ft_over25","odds_ft_btts",
        # Pre‑match market percentages
        "over_25_percentage_pre_match","btts_percentage_pre_match",
        "home_two_plus_percentage","away_two_plus_percentage",
        "home_concede_two_plus_percentage","away_concede_two_plus_percentage",
        # Lightweight rolling indicators
        "rolling5_home_shots","rolling5_away_shots",
        "rolling5_home_sot_ratio","rolling5_away_sot_ratio",
        "home_big_chances","away_big_chances",
        "home_big_chances_per_game","away_big_chances_per_game",
        # Draw-centric signals
        "home_draw_rate_rolling","away_draw_rate_rolling","team_draw_parity","h2h_draw_rate",
        # Pre-match xG and simple parity
        "pre_match_xg_home","pre_match_xg_away","recent_xg_diff_abs",
    ]

