if "_ensure_report_probs_inplace" not in globals():
    def _ensure_report_probs_inplace(df):
        """
        Ensure downstream-compatible probability/label columns exist on *df* in-place:
          • prob_over25, prob_btts  ← from adjusted_* → raw *_confidence → 0.5
          • Over25, BTTS            ← from those probabilities when absent
        """
        import pandas as pd
        if not isinstance(df, pd.DataFrame):
            return df
        if "prob_over25" not in df.columns:
            src = (
                df["adjusted_over25_confidence"] if "adjusted_over25_confidence" in df.columns
                else (df["over25_confidence"] if "over25_confidence" in df.columns
                      else pd.Series(0.5, index=df.index))
            )
            df["prob_over25"] = pd.to_numeric(src, errors="coerce").fillna(0.5).clip(0, 1)
        if "prob_btts" not in df.columns:
            src = (
                df["adjusted_btts_confidence"] if "adjusted_btts_confidence" in df.columns
                else (df["btts_confidence"] if "btts_confidence" in df.columns
                      else pd.Series(0.5, index=df.index))
            )
            df["prob_btts"] = pd.to_numeric(src, errors="coerce").fillna(0.5).clip(0, 1)
        if "Over25" not in df.columns:
            df["Over25"] = (df["prob_over25"] > 0.5).astype(int)
        if "BTTS" not in df.columns:
            df["BTTS"] = (df["prob_btts"] > 0.5).astype(int)

        # Derived combined market (independence approx) for Over2.5 & BTTS
        if "prob_over25_btts" not in df.columns:
            df["prob_over25_btts"] = (
                pd.to_numeric(df["prob_over25"], errors="coerce").fillna(0.5)
                * pd.to_numeric(df["prob_btts"], errors="coerce").fillna(0.5)
            ).clip(0, 1)

        return df

# --- Compatibility helper for ROI odds columns (idempotent) ---
if "_ensure_roi_inputs_inplace" not in globals():
    def _ensure_roi_inputs_inplace(df):
        """
        Ensure ROI-required odds columns exist in *df*:
          • odds_ft_over25  (aliases: odds_ft_over2_5, odds_over_2_5, odds_over25, odds_o25)
          • odds_ft_btts    (aliases: odds_btts_yes, odds_btts, btts_odds_yes, odds_yes_btts)
          • odds_ft_over25_btts (aliases: see below)
        If none are present, create NaN columns so ROI code can skip rows without KeyError.
        """
        import pandas as pd, numpy as np
        if not isinstance(df, pd.DataFrame):
            return df

        alias_map = {
            "odds_ft_over25": ["odds_ft_over2_5", "odds_over_2_5", "odds_over25", "odds_o25"],
            "odds_ft_btts":   ["odds_btts_yes", "odds_btts", "btts_odds_yes", "odds_yes_btts"],
            "odds_ft_over25_btts": [
                "odds_over25_btts", "odds_o25_btts", "odds_btts_over25",
                "odds_over25_and_btts_yes", "odds_btts_yes_over25",
                "odds_yes_btts_o25", "odds_ft_o25_btts",
                "odds_o2_5_btts", "odds_over2_5_btts", "odds_over_2_5_btts"
            ],
        }

        for target, alts in alias_map.items():
            if target not in df.columns:
                for a in alts:
                    if a in df.columns:
                        df[target] = pd.to_numeric(df[a], errors="coerce")
                        break
                else:
                    # create the column to avoid KeyError; NaN lets ROI naturally skip
                    df[target] = np.nan
        return df
    # --- Ensure prediction export has FTR fields ---
    def _ensure_predictions_export_columns_inplace(df: pd.DataFrame) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df
        needed = ["confidence_home","confidence_draw","confidence_away"]
        if not all(c in df.columns for c in needed):
            return df
        if "selected_outcome" not in df.columns:
            proba = _pd.to_numeric(df["confidence_home"], errors="coerce").fillna(0).to_numpy()
            prd   = _pd.to_numeric(df["confidence_draw"], errors="coerce").fillna(0).to_numpy()
            pra   = _pd.to_numeric(df["confidence_away"], errors="coerce").fillna(0).to_numpy()
            P = _np.vstack([proba, prd, pra]).T
            lab = _np.array(["home","draw","away"])[_np.nanargmax(P, axis=1)]
            df["selected_outcome"] = lab
        return df

    # --- Implied probability mask helper (idempotent) ---
    if "_implied_mask" not in globals():
        def _implied_mask(odds_series, min_impl: float):
            """
            Return a boolean mask where decimal odds imply probability >= min_impl.
            Also ensures odds are finite and at least a realistic minimum (>=1.01).
            """
            import numpy as _np
            import pandas as _pd
            o = _pd.to_numeric(odds_series, errors="coerce")
            with _np.errstate(divide="ignore", invalid="ignore"):
                impl = _np.where(_np.isfinite(o) & (o > 0), 1.0 / o, _np.nan)
            mask = _pd.Series(_np.isfinite(o) & (o >= 1.01) & (impl >= float(min_impl)), index=o.index)
            return mask

    # --- Odds coercion: normalise to decimal odds (idempotent best-effort) ---
    if "_coerce_decimal_odds" not in globals():
        def _coerce_decimal_odds(odds_series):
            """
            Coerce a mixed/incorrectly-scaled odds series to decimal odds:
              • If values look like probabilities (median ≤ 1.0): convert via 1/p.
              • If values look like percentages (median ≥ 10): convert via 100/x.
              • Otherwise, assume already decimal odds and return as-is.
            Leaves NaNs untouched and keeps original index.
            """
            import numpy as _np
            import pandas as _pd

            o = _pd.to_numeric(odds_series, errors="coerce")
            if o is None or len(o) == 0:
                return o

            v = o[_np.isfinite(o) & (o > 0)]
            if v.empty:
                return o

            med = _np.nanmedian(v.to_numpy())

            # Probabilities in 0..1
            if 0.0 <= med <= 1.0:
                with _np.errstate(divide="ignore", invalid="ignore"):
                    conv = 1.0 / v
                o.loc[v.index] = conv

            # Percentages like 55, 67, 120 → convert to decimal via 100/x
            elif med >= 10.0 and med <= 150.0:
                with _np.errstate(divide="ignore", invalid="ignore"):
                    conv = 100.0 / v
                o.loc[v.index] = conv

            # Else: likely already decimal odds (1.2 .. 20+). Leave unchanged.
            return o
        
        # --- HGM banker backtest (portable, env-driven) ---
        if "backtest_hgm_bankers" not in globals():
            def backtest_hgm_bankers(completed_df, league: str, seasons: int | None = None, stake: float = 10.0):
                """
                Backtests History-Only Goal Model (HGM) banker selections on completed fixtures
                over the last N seasons. Prints deploy (implied ≥ DEPLOY_MIN_IMPL) and all-odds
                views, and saves a compact CSV:
                ROIReports/<League>_hgm_banker_backtest.csv
                """
                import os, numpy as np, pandas as pd

                if not isinstance(completed_df, pd.DataFrame) or completed_df.empty:
                    print("ℹ️ HGM backtest: no completed data.")
                    return False

                # De-duplicate columns (saves memory, avoids ambiguity)
                try:
                    df = completed_df.loc[:, ~completed_df.columns.duplicated()].copy()
                except Exception:
                    df = completed_df.copy()

                # Ensure odds exist and compute HGM probabilities in-place
                try:
                    _ensure_roi_inputs_inplace(df)
                except Exception:
                    pass
                try:
                    _hgm_probs_inplace(df, league)
                except Exception as _e:
                    print(f"⚠️ HGM backtest: could not compute HGM probabilities: {_e}")
                    return False

                # Restrict to last N seasons if available
                try:
                    N = seasons if seasons is not None else int(os.getenv("HGM_BACKTEST_SEASONS", "3"))
                except Exception:
                    N = 3
                if "season" in df.columns and N > 0:
                    uniq = pd.Series(df["season"].unique()).dropna()
                    if not uniq.empty:
                        lastN = sorted(uniq)[-N:]
                        df = df[df["season"].isin(lastN)].copy()

                yh = pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
                ya = pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
                realized = yh.notna() & ya.notna()

                # Realized outcomes
                y_over = (yh.add(ya) > 2)
                y_btts = ((yh > 0) & (ya > 0))

                # Odds
                odds_o25  = pd.to_numeric(df.get("odds_ft_over25"), errors="coerce")
                odds_btts = pd.to_numeric(df.get("odds_ft_btts"),  errors="coerce")

                base_valid_o25  = realized & odds_o25.notna()  & np.isfinite(odds_o25)  & (odds_o25  >= 1.01)
                base_valid_btts = realized & odds_btts.notna() & np.isfinite(odds_btts) & (odds_btts >= 1.01)

                # HGM probabilities
                p_over = pd.to_numeric(df.get("hgm_prob_over25"), errors="coerce")
                p_btts = pd.to_numeric(df.get("hgm_prob_btts"),   errors="coerce")

                try:
                    MIN_IMPL = float(os.getenv("DEPLOY_MIN_IMPL", "0.67"))
                    MIN_PROB = float(os.getenv("HGM_BANKER_MIN_PROB", "0.68"))
                except Exception:
                    MIN_IMPL, MIN_PROB = 0.67, 0.68

                implied_o25  = 1.0 / odds_o25.replace(0, np.nan)
                implied_btts = 1.0 / odds_btts.replace(0, np.nan)

                sel_o25_deploy  = base_valid_o25  & implied_o25.ge(MIN_IMPL)  & p_over.ge(MIN_PROB)
                sel_btts_deploy = base_valid_btts & implied_btts.ge(MIN_IMPL) & p_btts.ge(MIN_PROB)

                sel_o25_all  = base_valid_o25  & p_over.ge(MIN_PROB)
                sel_btts_all = base_valid_btts & p_btts.ge(MIN_PROB)

                def _roi(mask, wins_mask, odds):
                    bets = int(mask.sum())
                    if bets == 0:
                        return 0, 0.0, 0.0
                    pnl = np.where((wins_mask & mask), (odds - 1.0) * stake, -stake)
                    pnl = float(np.nan_to_num(np.where(mask, pnl, 0.0)).sum())
                    roi = pnl / (bets * stake)
                    return bets, pnl, roi

                b_over_d, p_over_d, r_over_d = _roi(sel_o25_deploy, y_over, odds_o25)
                b_btts_d, p_btts_d, r_btts_d = _roi(sel_btts_deploy, y_btts, odds_btts)
                b_over_a, p_over_a, r_over_a = _roi(sel_o25_all,   y_over, odds_o25)
                b_btts_a, p_btts_a, r_btts_a = _roi(sel_btts_all,  y_btts, odds_btts)

                print("---- HGM Banker Backtest -----------------------------")
                print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets={b_over_d}  profit={p_over_d:.1f}  roi={r_over_d:.1%}")
                print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets={b_btts_d} profit={p_btts_d:.1f} roi={r_btts_d:.1%}")
                print(f"[All-odds]           O2.5  bets={b_over_a}  profit={p_over_a:.1f} roi={r_over_a:.1%}")
                print(f"[All-odds]           BTTS  bets={b_btts_a} profit={p_btts_a:.1f} roi={r_btts_a:.1%}")
                print("------------------------------------------------------")

                # Persist compact CSV (portable, env-driven)
                try:
                    outdir = os.getenv("ROI_REPORTS_DIR", DEFAULT_ROI_REPORTS_DIR)
                    os.makedirs(outdir, exist_ok=True)
                    out = pd.DataFrame([
                        {"view":"deploy","market":"over25","bets":b_over_d,"profit":round(p_over_d,1),"roi_pct":round(r_over_d*100,2)},
                        {"view":"deploy","market":"btts",  "bets":b_btts_d,"profit":round(p_btts_d,1),"roi_pct":round(r_btts_d*100,2)},
                        {"view":"all","market":"over25","bets":b_over_a,"profit":round(p_over_a,1),"roi_pct":round(r_over_a*100,2)},
                        {"view":"all","market":"btts",  "bets":b_btts_a,"profit":round(p_btts_a,1),"roi_pct":round(r_btts_a*100,2)},
                    ])
                    path = os.path.join(outdir, f"{str(league).replace(' ','_')}_hgm_banker_backtest.csv")
                    out.to_csv(path, index=False)
                except Exception:
                    pass

                return True

        # Compatibility alias expected by older call-sites
        if "backtest_hgm_bankers_accuracy" not in globals():
            def backtest_hgm_bankers_accuracy(df, league, *args, **kwargs):
                try:
                    return bool(backtest_hgm_bankers(df, league, *args, **kwargs))
                except Exception:
                    return False
    # --- Leak stripping & model-alignment (real impl) ---
    # The early shim defined a no-op strip_leaks to avoid NameError at import time.
    # Here we provide the real, conservative implementation and a schema-aligner.
    def strip_leaks(df: pd.DataFrame, *_, **__) -> pd.DataFrame:
        """
        Remove columns that can leak *realized* match outcomes into training or
        pre‑match inference. Conservative: only drops clearly post‑match fields.
        """
        import pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return df

        # Explicit known leakage columns (post-match outcomes or direct labels)
        hard_drop = {
            # realized final/half-time goals (keep FT goals for target construction)
            # "home_team_goal_count", "away_team_goal_count",
            "ft_home_goals", "ft_away_goals", "ht_home_goals", "ht_away_goals",
            # realized result/labels
            "ftr", "ft_result", "result", "full_time_result", "ft_winner", "winning_team",
            "selected_outcome",
            # realized classification/targets that might be present in historical data
            "full_time_btts", "full_time_over25",
        }

        # Column-name fragments that strongly suggest realized outcomes.
        # Very tight patterns to avoid dropping legitimate pre‑match rates.
        suspicious_fragments = [
            " final_score", " full_time", " fulltime", " ft_", " ht_", " half_time",
            " result", " winner", " winners", " outcome",
        ]

        cols = list(df.columns)
        drop_cols = set(c for c in cols if c in hard_drop)

        # Fragment scanning (strict; word/underscore boundaries only)
        for c in cols:
            lc = f" {str(c).lower()} "
            if any(f" {frag.strip()} " in lc.replace("_", " ") for frag in suspicious_fragments):
                drop_cols.add(c)

        if drop_cols:
            try:
                df = df.drop(columns=[c for c in drop_cols if c in df.columns])
            except Exception:
                pass

        return df

def _align_dataframe_to_model(X: pd.DataFrame, model) -> pd.DataFrame:
    import pandas as _pd
    import numpy as _np

    # Fast exits
    if not isinstance(X, _pd.DataFrame) or X.empty or model is None:
        return X

       # Resolve expected schema from model metadata (sklearn / xgboost / lightgbm)
    expected = None
    try:
        expected_attr = getattr(model, "feature_names_in_", None)
        if expected_attr is not None:
            if hasattr(expected_attr, "tolist"):
                expected = list(expected_attr.tolist())
            elif isinstance(expected_attr, (list, tuple)):
                expected = list(expected_attr)
            else:
                try:
                    expected = list(expected_attr)
                except Exception:
                    expected = None
    except Exception:
        expected = None

    if not expected:
        try:
            booster = getattr(model, "get_booster", lambda: None)()
            names = getattr(booster, "feature_names", None) if booster is not None else None
            if names:
                expected = list(names)
        except Exception:
            pass

    if not expected:
        try:
            names = getattr(model, "feature_name_", None)
            if names:
                if hasattr(names, "tolist"):
                    expected = list(names.tolist())
                elif isinstance(names, (list, tuple)):
                    expected = list(names)
                else:
                    expected = list(names)
        except Exception:
            pass

    # If nothing to align against, best-effort numeric passthrough
    if not expected:
        X_num = X.apply(_pd.to_numeric, errors="coerce").replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)
        try: X_num = X_num.astype("float64")
        except Exception: pass
        return X_num

    # Build aligned matrix in one shot (no insert → avoids fragmentation)
    X_num = X.reindex(columns=expected)                              # creates missing with NaN
    X_num = X_num.apply(_pd.to_numeric, errors="coerce")
    X_num = X_num.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)   # NA/inf → 0.0
    try: X_num = X_num.astype("float64")                              # stable dtype
    except Exception: pass
    return X_num

