if "load_league_draw_threshold" not in globals():
    def load_league_draw_threshold(league: str) -> dict:
        """
        Best-effort loader for draw thresholds for a given league.
        Tries constants.DRAW_THRESHOLDS, then a JSON file pointed at by
        DRAW_THRESHOLDS_PATH, else returns {}.
        """
        import os as _os, json as _json
        try:
            from constants import DRAW_THRESHOLDS  # type: ignore
            try:
                return dict(DRAW_THRESHOLDS.get(league, {}))
            except Exception:
                pass
        except Exception:
            pass
        try:
            path = _os.getenv("DRAW_THRESHOLDS_PATH")
            if path and _os.path.exists(path):
                with open(path, "r", encoding="utf-8") as f:
                    data = _json.load(f)
                if isinstance(data, dict):
                    return dict(data.get(league, {}))
        except Exception:
            pass
        return {}

