# --- FTR design-matrix sanitizer (leak‑safe with float32 downcast) ---
if "_sanitize_ftr_matrix" not in globals():
    def _sanitize_ftr_matrix(X: pd.DataFrame) -> pd.DataFrame:
        import pandas as _pd, numpy as _np
        if not isinstance(X, _pd.DataFrame) or X.empty:
            return X
        # De-duplicate duplicate-named columns to avoid bloat
        try:
            X = X.loc[:, ~X.columns.duplicated()].copy()
        except Exception:
            X = X.copy()
        # Never allow Poisson overlay cols through
        try:
            X = X.drop(columns=[c for c in ("pois_p_home","pois_p_draw","pois_p_away") if c in X.columns], errors="ignore")
        except Exception:
            pass
        # Derive leak‑safe goal-model summary features if available (λ̂‑based)
        if {"home_goals_pred", "away_goals_pred"}.issubset(X.columns):
            hg = _pd.to_numeric(X["home_goals_pred"], errors="coerce").clip(lower=0)
            ag = _pd.to_numeric(X["away_goals_pred"], errors="coerce").clip(lower=0)
            if "exp_goals_sum" not in X.columns:
                X["exp_goals_sum"] = (hg + ag)
            if "p00_est" not in X.columns:
                with _np.errstate(over="ignore", under="ignore", invalid="ignore"):
                    X["p00_est"] = _np.exp(-hg) * _np.exp(-ag)
        elif {"Home Team Pre-Match xG", "Away Team Pre-Match xG"}.issubset(X.columns):
            hg = _pd.to_numeric(X["Home Team Pre-Match xG"], errors="coerce").clip(lower=0)
            ag = _pd.to_numeric(X["Away Team Pre-Match xG"], errors="coerce").clip(lower=0)
            if "exp_goals_sum" not in X.columns:
                X["exp_goals_sum"] = (hg + ag)
            if "p00_est" not in X.columns:
                with _np.errstate(over="ignore", under="ignore", invalid="ignore"):
                    X["p00_est"] = _np.exp(-hg) * _np.exp(-ag)
        # Allowlist & leak stripping
        allow = _resolve_ftr_allowlist()
        try:
            Y = strip_leaks(X, allowlist=allow)
        except TypeError:
            keep = [c for c in allow if c in X.columns]
            Y = X.loc[:, keep].copy() if keep else X
        # Guarantee λ̂ summaries exist post‑strip (derive if needed)
        if {"home_goals_pred","away_goals_pred"}.issubset(X.columns):
            hg = _pd.to_numeric(X["home_goals_pred"], errors="coerce").clip(lower=0)
            ag = _pd.to_numeric(X["away_goals_pred"], errors="coerce").clip(lower=0)
            if "exp_goals_sum" not in Y.columns:
                Y["exp_goals_sum"] = (hg + ag)
            if "p00_est" not in Y.columns:
                with _np.errstate(over="ignore", under="ignore", invalid="ignore"):
                    Y["p00_est"] = _np.exp(-hg) * _np.exp(-ag)
        elif {"Home Team Pre-Match xG","Away Team Pre-Match xG"}.issubset(X.columns):
            hg = _pd.to_numeric(X["Home Team Pre-Match xG"], errors="coerce").clip(lower=0)
            ag = _pd.to_numeric(X["Away Team Pre-Match xG"], errors="coerce").clip(lower=0)
            if "exp_goals_sum" not in Y.columns:
                Y["exp_goals_sum"] = (hg + ag)
            if "p00_est" not in Y.columns:
                with _np.errstate(over="ignore", under="ignore", invalid="ignore"):
                    Y["p00_est"] = _np.exp(-hg) * _np.exp(-ag)
        # Float32 downcast for memory savings
        try:
            numcols = Y.select_dtypes(include=["float64","float32","int64","int32","int"]).columns
            for _c in numcols:
                Y[_c] = _pd.to_numeric(Y[_c], errors="coerce").astype("float32")
        except Exception:
            pass
        return Y
else:
    # Wrap existing sanitizer to add float32 downcast idempotently
    _SANITIZE_ORIG = _sanitize_ftr_matrix  # type: ignore[name-defined]
    def _sanitize_ftr_matrix(X):
        Y = _SANITIZE_ORIG(X)
        try:
            import pandas as _pd
            numcols = Y.select_dtypes(include=["float64","float32","int64","int32","int"]).columns
            for _c in numcols:
                Y[_c] = _pd.to_numeric(Y[_c], errors="coerce").astype("float32")
        except Exception:
            pass
        return Y

# --- OG PATCH: prevent accidental drop of realized labels on training_data ---
try:
    import pandas as _pd
    if not getattr(_pd.DataFrame, "_OG_SAFE_DROP_PATCH", False):
        _OG_ORIG_DROP = _pd.DataFrame.drop
        def _OG_SAFE_DROP(self, *args, **kwargs):
            """
            Intercept DataFrame.drop to prevent dropping FT goal columns from the
            *training* frame (identified by self.attrs['_is_training_frame'] = True).
            Else behave exactly like the original .drop.
            """
            try:
                cols = kwargs.get("columns", None)
                if cols is None and len(args) >= 2 and isinstance(args[1], (list, tuple, set)):
                    cols = args[1]
                if getattr(self, "attrs", {}).get("_is_training_frame"):
                    block = {"home_team_goal_count","away_team_goal_count"}
                    if cols is not None and any(c in block for c in cols):
                        # Filter out blocked columns; if nothing remains, no-op
                        keep = [c for c in cols if c not in block]
                        if keep:
                            if "columns" in kwargs:
                                kwargs["columns"] = keep
                                return _OG_ORIG_DROP(self, *args, **kwargs)
                            else:
                                _args = list(args)
                                _args[1] = keep
                                return _OG_ORIG_DROP(self, *_args, **kwargs)
                        return self  # all requested columns were blocked → no-op
            except Exception:
                # On any parsing issue, fall back to original behavior
                pass
            return _OG_ORIG_DROP(self, *args, **kwargs)
        _pd.DataFrame.drop = _OG_SAFE_DROP
        _pd.DataFrame._OG_SAFE_DROP_PATCH = True
except Exception:
    pass
        
# --- OOF helpers (isotonic + attach) ---
# Guarded duplicate: only define if a canonical implementation is not already present
if "_oof_probs_isotonic" not in globals():
    def _oof_probs_isotonic(model, X, y, *, n_splits: int = 5, random_state: int = 42):
        import numpy as _np, pandas as _pd
        try:
            from sklearn.model_selection import StratifiedKFold
            from sklearn.calibration import CalibratedClassifierCV
            from sklearn.base import clone as _sk_clone
        except Exception:
            # sklearn not available -> neutral 0.5 series
            X_df = _pd.DataFrame(X)
            return _pd.Series(_np.full(len(X_df), 0.5, dtype=float), index=X_df.index)

        # Ensure frame + mask to labeled rows
        y = _pd.to_numeric(_pd.Series(y), errors="coerce")
        mask = y.notna()
        X = _pd.DataFrame(X).loc[mask]
        y = y.loc[mask].astype(int)

        # Not enough positive/negative labels → neutral 0.5
        if y.nunique() < 2 or len(y) < 50:
            return _pd.Series(_np.full(len(X), 0.5, dtype=float), index=X.index)

        # Numeric only, clean, fill
        try:
            X = X.select_dtypes(include=["number"])
        except Exception:
            pass
        X = X.replace([_np.inf, -_np.inf], _np.nan).fillna(0.0)

        # Folds capped by minority class count
        n_splits = int(max(2, min(n_splits, int(y.value_counts().min()))))
        skf = StratifiedKFold(n_splits=n_splits, shuffle=True, random_state=random_state)
        oof = _np.full(len(X), _np.nan, dtype=float)

        for tr_idx, va_idx in skf.split(X, y):
            est = _sk_clone(model)
            try:
                est.fit(X.iloc[tr_idx], y.iloc[tr_idx])
            except Exception:
                # If model can't clone/fit, fall back to neutral for this fold
                oof[va_idx] = 0.5
                continue
            # Try isotonic calibration; fall back to raw proba
            try:
                # Wrap estimator for prefit calibration on sklearn >=1.6
                try:
                    from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
                    est_frozen = _Freeze(est)
                except Exception:
                    est_frozen = est
                calib = _calibrated_cv2(est_frozen, method="isotonic")
                calib.fit(X.iloc[va_idx], y.iloc[va_idx])
                oof[va_idx] = calib.predict_proba(X.iloc[va_idx])[:, 1]
            except Exception:
                try:
                    oof[va_idx] = est.predict_proba(X.iloc[va_idx])[:, 1]
                except Exception:
                    oof[va_idx] = 0.5

        # Fill any residual NaNs with neutral 0.5 and clip to [0,1]
        s = _pd.Series(oof, index=X.index)
        try:
            s = s.fillna(0.5).clip(0, 1)
        except Exception:
            pass
        return s

if "_attach_oof_for_market" not in globals():
    def _attach_oof_for_market(df, market: str, model):
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or model is None:
            return df, None

        # Label mask: only rows with realized FT goals are labeled
        hh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        aa = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        lbl_mask = hh.notna() & aa.notna()

        # Build target y per market (leave unlabeled as NaN; DO NOT cast to int here)
        if market == "over25":
            y = (hh.add(aa) > 2)
        elif market == "btts":
            y = ((hh > 0) & (aa > 0))
        elif market == "home_over15tg":
            y = (hh >= 2)
        elif market == "away_over15tg":
            y = (aa >= 2)
        elif market == "home_fts":
            y = (hh == 0)
        elif market == "away_fts":
            y = (aa == 0)
        elif market in ("over15fh","btts_fh"):   # FH markets not supported in quick/OOF
            return df, None
        else:
            return df, None

        # Ensure a Series with the same index and keep NaN where unlabeled
        y = _pd.Series(y, index=df.index)
        try:
            y = y.where(lbl_mask)
        except Exception:
            pass

        # Align to model features if available; otherwise numeric-only
        feats = list(getattr(model, "feature_names_in_", []))
        if feats:
            try:
                X = df[feats]
            except Exception:
                X = df.reindex(columns=feats, fill_value=_np.nan)
                miss = [c for c in feats if c not in df.columns]
                if miss:
                    X.loc[:, miss] = 0.0
        else:
            X = df.select_dtypes(include=["number"])

        oof = _oof_probs_isotonic(model, X, y)
        col = f"oof_prob_{market}"
        try:
            df[col] = oof.reindex(df.index)
        except Exception:
            try:
                df[col] = oof
            except Exception:
                return df, None

        # Debug: show how many OOF values attached and class balance (quick-only)
        try:
            import os as _os
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                total = len(df)
                n_lab = int(lbl_mask.sum())
                s = _pd.to_numeric(y, errors="coerce")
                pos = int((s == 1).sum())
                neg = int((s == 0).sum())
                n_oof = int(_pd.to_numeric(df.get(col), errors="coerce").notna().sum()) if col in df.columns else 0
                print(f"🧪 OOF attach → {col}: non-NaN={n_oof}/{total} | labeled={n_lab} (pos={pos}, neg={neg})")
        except Exception:
            pass

        return df, col

