if "_market_model_path" not in globals():
    def _market_model_path(league: str, market: str):
        from pathlib import Path as _Path
        import os as _os
        root = _os.getenv("MODEL_DIR", DEFAULT_MODEL_DIR)
        tag = _sanitize_league_tag(league)
        d = _Path(root) / tag
        try:
            d.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        # canonical name: <market>.joblib inside per-league folder
        return d / f"{market}.joblib"

if "_save_market_model" not in globals():
    def _save_market_model(league: str, market: str, model):
        import joblib as _joblib
        p = _market_model_path(league, market)
        try:
            p.parent.mkdir(parents=True, exist_ok=True)
            _joblib.dump(model, p)
        except Exception:
            pass
        return p

if "_load_market_model" not in globals():
    def _load_market_model(league: str, market: str):
        """Load model from per-league folder; try legacy flat path fallback."""
        import os as _os, joblib as _joblib
        from pathlib import Path as _Path
        root = _os.getenv("MODEL_DIR", DEFAULT_MODEL_DIR)
        tag = _sanitize_league_tag(league)
        # New canonical path
        p_new = _Path(root) / tag / f"{market}.joblib"
        try:
            if p_new.exists():
                return _joblib.load(p_new)
        except Exception:
            pass
        # Legacy flat path: <league>__<market>.joblib
        p_legacy = _Path(root) / f"{tag}__{market}.joblib"
        try:
            if p_legacy.exists():
                return _joblib.load(p_legacy)
        except Exception:
            pass
        return None

    
