        # Design matrix sanitisation
        try:
            X = _sanitize_ftr_matrix(df1[feature_cols].copy())
        except Exception:
            X = df1[feature_cols].copy()
        y = _pd.to_numeric(df1.get(target_col), errors="coerce")
        # De-dup again (belt and braces)
        try:
            X = X.loc[:, ~X.columns.duplicated()].copy()
        except Exception:
            pass
        # Float32 downcast
        try:
            for _c in X.columns:
                if str(X[_c].dtype).startswith(("float","int")):
                    X[_c] = _pd.to_numeric(X[_c], errors="coerce").astype("float32")
        except Exception:
            pass
        # Row cap (most recent slice if dates exist)
        try:
            _cap = int(_os.getenv("DRAW_ROW_CAP", "20000"))
        except Exception:
            _cap = 20000
        if _cap and X.shape[0] > _cap:
            try:
                _order = _pd.to_datetime(df1.get("match_date"), errors="coerce")
                _idx = _order.sort_values().index[-_cap:]
                X = X.loc[_idx]
                y = y.loc[_idx]
            except Exception:
                X = X.tail(_cap); y = y.tail(_cap)
        # Parallel backend context
        try:
            _jobs = int(_os.getenv("SKLEARN_JOBS", "1"))
        except Exception:
            _jobs = 1
        with _parallel_backend("loky", n_jobs=max(1, _jobs)):
            yield X, y


