# --- Robust metric extraction helper (idempotent) ---
if "_safe_metrics" not in globals():
    def _safe_metrics(m):
        import numpy as _np
        if m is None:
            return (_np.nan, _np.nan, _np.nan)
        return (
            getattr(m, "score_", _np.nan),
            getattr(m, "auc_", _np.nan),
            getattr(m, "log_loss_", _np.nan),
        )

# --- Save deployable picks (thresholded by implied probability) ---
if "save_deployable_picks" not in globals():
    def save_deployable_picks(df, league: str, *, outdir: str = "PredictionReports"):
        import os, pandas as pd, numpy as np
        from pathlib import Path as _Path
        # env + default wins (ignore param for consistency)
        outdir = os.getenv("PREDICTION_REPORTS_DIR", DEFAULT_PREDICTION_REPORTS_DIR)
        _Path(outdir).mkdir(parents=True, exist_ok=True)
        base = _sanitize_league_tag(league)
        path = _Path(outdir) / f"{base}_deployable.csv"

        if not isinstance(df, pd.DataFrame) or df.empty:
            return False
        try: _ensure_report_probs_inplace(df)
        except Exception: pass
        try: _ensure_roi_inputs_inplace(df)
        except Exception: pass

        MIN_IMPL = float(os.getenv("DEPLOY_MIN_IMPL", "0.67"))
        m_o25  = _implied_mask(df.get("odds_ft_over25"), MIN_IMPL) if "odds_ft_over25" in df.columns else None
        m_btts = _implied_mask(df.get("odds_ft_btts"),  MIN_IMPL) if "odds_ft_btts"  in df.columns else None
        if m_o25 is None and m_btts is None:
            return False

        mask = m_o25 if (m_btts is None) else (m_btts if (m_o25 is None) else (m_o25 | m_btts))
        if not bool(getattr(mask, "any", lambda: False)()):
            return False

        cols = [c for c in [
            "home_team_name","away_team_name","match_date",
            "prob_over25","prob_btts","odds_ft_over25","odds_ft_btts",
            "Over25","BTTS"
        ] if c in df.columns]

        try:
            df.loc[mask, cols].to_csv(path, index=False)
            print(f"📤 Deployable picks saved → {path} (min implied {MIN_IMPL:.0%}, rows={int(mask.sum())})")
            return True
        except Exception as _e:
            print(f"⚠️ Could not save deployable picks for {league}: {_e}")
            return False
    
# --- Save deployable FTR picks (1X2 gated by implied probability) ---
if "save_deployable_ftr" not in globals():
    def save_deployable_ftr(df, league: str, *, outdir: str = "PredictionReports", min_impl: float | None = None):
        import os, numpy as np, pandas as pd
        from pathlib import Path
        outdir = os.getenv("PREDICTION_REPORTS_DIR", DEFAULT_PREDICTION_REPORTS_DIR)

        if not isinstance(df, pd.DataFrame) or df.empty:
            return False
        try: _ensure_roi_inputs_inplace(df)
        except Exception: pass

        if min_impl is None:
            try: min_impl = float(os.getenv("DEPLOY_MIN_IMPL", "0.67"))
            except Exception: min_impl = 0.67

        sel = df.copy()

        if "selected_outcome" not in sel.columns:
            if {"confidence_home","confidence_draw","confidence_away"}.issubset(sel.columns):
                ch = pd.to_numeric(sel["confidence_home"], errors="coerce").fillna(0.0)
                cd = pd.to_numeric(sel["confidence_draw"], errors="coerce").fillna(0.0)
                ca = pd.to_numeric(sel["confidence_away"], errors="coerce").fillna(0.0)
                arr = np.vstack([ch, cd, ca]).T
                with np.errstate(invalid="ignore"):
                    idx = np.nanargmax(arr, axis=1)
                sel["selected_outcome"] = np.array(["home","draw","away"])[idx]
            else:
                return False

        odds_map = {
            "home":"odds_ft_home_team_win",
            "draw":"odds_ft_draw",
            "away":"odds_ft_away_team_win",
        }

        keep_idx = []
        for i, r in sel.iterrows():
            oc = odds_map.get(str(r.get("selected_outcome")))
            if not oc or oc not in sel.columns:
                continue
            o = pd.to_numeric(pd.Series([r[oc]]), errors="coerce").iloc[0]
            if not np.isfinite(o):
                continue
            o = _coerce_decimal_odds(pd.Series([o])).iloc[0]
            if not np.isfinite(o) or o <= 1.0:
                continue
            if (1.0 / o) >= float(min_impl):
                keep_idx.append(i)

        if not keep_idx:
            return False

        out_df = sel.loc[keep_idx].copy()
        cols = [c for c in [
            "home_team_name","away_team_name","match_date",
            "selected_outcome","confidence_home","confidence_draw","confidence_away",
            "odds_ft_home_team_win","odds_ft_draw","odds_ft_away_team_win"
        ] if c in out_df.columns]

        Path(outdir).mkdir(parents=True, exist_ok=True)
        path = Path(outdir) / f"{_sanitize_league_tag(league)}_FTR_deployable.csv"
        try:
            out_df.to_csv(path, index=False, columns=cols)
            print(f"📤 Deployable FTR picks saved → {path} (min implied {float(min_impl):.0%}, rows={len(out_df)})")
            return True
        except Exception as _e:
            print(f"⚠️ Could not save FTR deployable picks for {league}: {_e}")
            return False

# Pipe the old name (if any) to the new gated logic so legacy call-sites are safe
def simulate_accumulator_roi(df, league_name: str | None = None, stake: float = 10.0) -> dict:
    return _print_roi_snapshot(df, stake=stake)

# ============================
# History-Only Goal Model (HGM v2) + Banker selectors
# ============================
if "_hgm_probs_inplace" not in globals():
    def _z(_s):
        import numpy as _np, pandas as _pd
        # Ensure Series with numeric coercion
        s = _pd.to_numeric(_pd.Series(_s), errors="coerce")
        # If all NaN or empty, return zeros (avoids nanmean/nanstd warnings)
        if s.notna().sum() == 0:
            return _pd.Series(0.0, index=s.index)
        m = _np.nanmean(s); v = _np.nanstd(s)
        if not _np.isfinite(v) or v == 0:
            return _pd.Series(0.0, index=s.index)
        return (s - m) / (v + 1e-12)

    def _get(df, *names, default=np.nan):
        for n in names:
            if n in df.columns: return pd.to_numeric(df[n], errors="coerce")
        return pd.Series(default, index=df.index)

    def _league_hfa(league: str) -> float:
        name = (league or "").lower()
        if "mls" in name:        return 0.25
        if "bundesliga" in name: return 0.22
        if "premier" in name:    return 0.18
        if "ligue" in name:      return 0.16
        return 0.20

    def _league_kappa(league: str) -> float:
        name = (league or "").lower()
        if "mls" in name:        return 1.05
        if "bundesliga" in name: return 1.03
        if "premier" in name:    return 1.01
        if "ligue" in name:      return 1.00
        return 1.02
    def _hgm_gate_params(league: str) -> dict[str, float]:
        """
        Per-league HGM banker gates. Base = global defaults; Bundesliga tightened slightly.
        Env overrides supported (e.g., HGM_TIER_A_MIN, HGM_O25_P_MIN) if present.
        """
        import os as _os
        def _envf(key: str, default: float) -> float:
            try:
                return float(_os.getenv(key, str(default)))
            except Exception:
                return default

        base = {
            # Team O1.5 (banker)
            "o15_p_min": 0.68, "o15_team2_min": 0.55, "o15_con2_min": 0.50,
            "o15_sot_min": 4.5, "o15_bigc_min": 2.0,
            # Over 2.5
            "o25_p_min": 0.68, "o25_hist_min": 0.60,
            "o25_lam_hi": 1.6, "o25_lam_both": 1.2,
            # BTTS
            "btts_p_min": 0.68, "btts_hist_min": 0.60,
            "btts_fts_max": 0.25, "btts_cs_max": 0.35,
            # Press-intensity (optional; 0 disables)
            "pi_o15_min": 0.00,  # min PI per attacking side for O1.5
            "pi_o25_min": 0.00,  # min average PI across both sides for O2.5
            # Tiers
            "tier_A_min": 0.72, "tier_B_min": 0.68,
        }

        name = (league or "").lower()
        if "bundesliga" in name:
            bd = base.copy()
            bd.update({
                # slightly tighter, but combined with κ↑ yields a few good A/B picks
                "o15_p_min": 0.70,
                "o15_team2_min": 0.56,
                "o15_con2_min": 0.52,
                "o15_sot_min": 4.8,
                "o15_bigc_min": 2.2,
                "o25_p_min": 0.70,
                "o25_hist_min": 0.62,
                "btts_p_min": 0.70,
                "btts_hist_min": 0.62,
                "btts_fts_max": 0.23,
                "btts_cs_max": 0.33,
                "tier_A_min": 0.74,
                "tier_B_min": 0.70,
            })
            for k, v in list(bd.items()):
                bd[k] = _envf(f"HGM_{k.upper()}", v)
            return bd

        for k, v in list(base.items()):
            base[k] = _envf(f"HGM_{k.upper()}", v)
        return base
    def _hgm_probs_inplace(df: pd.DataFrame, league: str) -> pd.DataFrame:
        if not isinstance(df, pd.DataFrame) or df.empty: return df
        xgf_H = _get(df, "home_goals_scored_per_match", "pre_match_xg_home", "Home Team Pre-Match xG")
        xga_A = _get(df, "away_goals_conceded_per_match", "defensive_efficiency_away")
        xgf_A = _get(df, "away_goals_scored_per_match", "pre_match_xg_away", "Away Team Pre-Match xG")
        xga_H = _get(df, "home_goals_conceded_per_match", "defensive_efficiency_home")

        zxgf_H, zxga_A = _z(xgf_H), _z(xga_A)
        zxgf_A, zxga_H = _z(xgf_A), _z(xga_H)
        HFA   = _league_hfa(league)
        kappa = _league_kappa(league)

        lam_H = (0.45*(1+zxgf_H).clip(lower=0) + 0.45*(1+zxga_A).clip(lower=0) + 0.10*HFA).clip(lower=0.05)
        lam_A = (0.45*(1+zxgf_A).clip(lower=0) + 0.45*(1+zxga_H).clip(lower=0)).clip(lower=0.05)
        lam_H = (lam_H*kappa).clip(0,6); lam_A = (lam_A*kappa).clip(0,6)

        df["hgm_lambda_home"] = lam_H; df["hgm_lambda_away"] = lam_A

        import numpy as _np
        with _np.errstate(over="ignore", under="ignore", invalid="ignore"):
            df["hgm_prob_home_o15"] = 1.0 - _np.exp(-lam_H)*(1.0+lam_H)
            df["hgm_prob_away_o15"] = 1.0 - _np.exp(-lam_A)*(1.0+lam_A)
            L = (lam_H + lam_A).clip(0,12)
            df["hgm_prob_over25"] = 1.0 - _np.exp(-L)*(1.0 + L + (L*L)/2.0)
            df["hgm_prob_btts"]   = 1.0 - _np.exp(-lam_H) - _np.exp(-lam_A) + _np.exp(-(lam_H+lam_A))

        bump = ((xgf_H.fillna(0)>=1.2)&(xgf_A.fillna(0)>=1.2)&(xga_H.fillna(0)>=1.2)&(xga_A.fillna(0)>=1.2))
        try:
            df.loc[bump, "hgm_prob_btts"]  = (df.loc[bump,"hgm_prob_btts"]  + 0.03).clip(0,1)
            df.loc[bump, "hgm_prob_over25"] = (df.loc[bump,"hgm_prob_over25"] + 0.02).clip(0,1)
        except Exception: pass
        return df

if "rank_banker_candidates" not in globals():
    def _sot_est(df: pd.DataFrame, side: str) -> pd.Series:
        shots = _get(df, f"rolling5_{side}_shots")
        ratio = _get(df, f"rolling5_{side}_sot_ratio")
        return (shots * ratio).fillna(0)

    def rank_banker_candidates(df: pd.DataFrame, league: str):
        import numpy as _np, pandas as pd
        if not isinstance(df, pd.DataFrame) or df.empty: return df, df, df
        _hgm_probs_inplace(df, league)
        g = _hgm_gate_params(league)

        o25_hist  = _get(df, "over_25_percentage_pre_match").fillna(0)/100.0
        btts_hist = _get(df, "btts_percentage_pre_match").fillna(0)/100.0
        team2p_h  = _get(df, "home_two_plus_percentage", "home_team_two_plus_percentage")/100.0
        team2p_a  = _get(df, "away_two_plus_percentage", "away_team_two_plus_percentage")/100.0
        con2p_h   = _get(df, "home_concede_two_plus_percentage")/100.0
        con2p_a   = _get(df, "away_concede_two_plus_percentage")/100.0

        sot_h, sot_a = _sot_est(df,"home"), _sot_est(df,"away")
        bigc_h = _get(df,"home_big_chances","home_big_chances_per_game")
        bigc_a = _get(df,"away_big_chances","away_big_chances_per_game")

        cols = ["home_team_name","away_team_name","match_date"]

        th = df["hgm_prob_home_o15"].fillna(0); ta = df["hgm_prob_away_o15"].fillna(0)
        g_h = (th >= g["o15_p_min"]); g_a = (ta >= g["o15_p_min"])
        if not team2p_h.isna().all(): g_h &= (team2p_h >= g["o15_team2_min"])
        if not con2p_a.isna().all():  g_h &= (con2p_a >= g["o15_con2_min"])
        if not team2p_a.isna().all(): g_a &= (team2p_a >= g["o15_team2_min"])
        if not con2p_h.isna().all():  g_a &= (con2p_h >= g["o15_con2_min"])
        if not sot_h.isna().all():    g_h &= (sot_h >= g["o15_sot_min"])
        if not sot_a.isna().all():    g_a &= (sot_a >= g["o15_sot_min"])
        if not bigc_h.isna().all():   g_h &= (bigc_h >= g["o15_bigc_min"])
        if not bigc_a.isna().all():   g_a &= (bigc_a >= g["o15_bigc_min"])
        # Optional press-intensity gating for O1.5 (per side)
        try:
            piH = _get(df, "home_press_intensity")
            piA = _get(df, "away_press_intensity")
            _pi_min = float(g.get("pi_o15_min", 0.0))
            if _pi_min > 0:
                if not piH.isna().all():
                    g_h &= (piH >= _pi_min)
                if not piA.isna().all():
                    g_a &= (piA >= _pi_min)
        except Exception:
            pass

        o15_rows = []
        if g_h.any():
            h = df.loc[g_h, cols+["hgm_prob_home_o15"]].copy()
            h["market"]="Home O1.5"; h["prob"]=h.pop("hgm_prob_home_o15"); o15_rows.append(h)
        if g_a.any():
            a = df.loc[g_a, cols+["hgm_prob_away_o15"]].copy()
            a["market"]="Away O1.5"; a["prob"]=a.pop("hgm_prob_away_o15"); o15_rows.append(a)
        o15_df = pd.concat(o15_rows, axis=0) if o15_rows else pd.DataFrame(columns=cols+["market","prob"])

        p_o25 = df["hgm_prob_over25"].fillna(0)
        g_25  = (p_o25 >= g["o25_p_min"])
        if not o25_hist.isna().all(): g_25 &= (o25_hist >= g["o25_hist_min"])
        # Optional press-intensity average gate for O2.5
        try:
            _pi25 = float(g.get("pi_o25_min", 0.0))
            if _pi25 > 0:
                piH = _get(df, "home_press_intensity")
                piA = _get(df, "away_press_intensity")
                if not (piH.isna().all() and piA.isna().all()):
                    pi_avg = (piH.add(piA, fill_value=np.nan)) / 2.0
                    g_25 &= pi_avg.fillna(0) >= _pi25
        except Exception:
            pass
        g_25 &= ((df["hgm_lambda_home"] >= g["o25_lam_hi"]) |
                 ((df["hgm_lambda_home"] >= g["o25_lam_both"]) &
                  (df["hgm_lambda_away"] >= g["o25_lam_both"])))
        o25_df = df.loc[g_25, cols+["hgm_prob_over25"]].copy()
        if not o25_df.empty: o25_df["market"]="Over 2.5"; o25_df["prob"]=o25_df.pop("hgm_prob_over25")

        # --- BTTS Yes ---
        p_bt = df["hgm_prob_btts"].fillna(0)
        g_bt = (p_bt >= g["btts_p_min"])
        if not btts_hist.isna().all(): g_bt &= (btts_hist >= g["btts_hist_min"])
        g_bt &= ((df["hgm_lambda_home"] >= 1.0) & (df["hgm_lambda_away"] >= 1.0))
        fts_h = _get(df,"home_fts_percentage")/100.0
        fts_a = _get(df,"away_fts_percentage")/100.0
        cs_h  = _get(df,"home_clean_sheet_percentage")/100.0
        cs_a  = _get(df,"away_clean_sheet_percentage")/100.0
        if not fts_h.isna().all(): g_bt &= (fts_h <= g["btts_fts_max"])
        if not fts_a.isna().all(): g_bt &= (fts_a <= g["btts_fts_max"])
        if not cs_h.isna().all():  g_bt &= (cs_h <= g["btts_cs_max"])
        if not cs_a.isna().all():  g_bt &= (cs_a <= g["btts_cs_max"])
        btts_df = df.loc[g_bt, cols+["hgm_prob_btts"]].copy()
        if not btts_df.empty:
            btts_df["market"]="BTTS Yes"
            btts_df["prob"]=btts_df.pop("hgm_prob_btts")

        # --- Tiering + return ---
        def _tier(f):
            if f.empty:
                return f
            f["tier"] = _np.where(
                f["prob"] >= g["tier_A_min"], "A",
                _np.where(f["prob"] >= g["tier_B_min"], "B", "C")
            )
            # keep only A/B tiers for banker slips
            f = f[f["tier"].isin(["A","B"])]
            return f.sort_values("prob", ascending=False)

        return _tier(o15_df), _tier(o25_df), _tier(btts_df)

if "backtest_hgm_bankers_accuracy" not in globals():
    def backtest_hgm_bankers_accuracy(df: pd.DataFrame, league: str) -> None:
        import os as _os, numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return
        # Ensure HGM probabilities present
        try:
            _hgm_probs_inplace(df, league)
        except Exception:
            return
        # Ensure odds columns exist / coerced
        try:
            _ensure_roi_inputs_inplace(df)
        except Exception:
            pass

        MIN_IMPL = float(_os.getenv("DEPLOY_MIN_IMPL", "0.67"))

        yh = _pd.to_numeric(df.get("home_team_goal_count"), errors="coerce")
        ya = _pd.to_numeric(df.get("away_team_goal_count"), errors="coerce")
        realized = yh.notna() & ya.notna()
        y_over = (yh.add(ya) > 2)
        y_btts = ((yh > 0) & (ya > 0))

        odds_o25  = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_over25"), errors="coerce"))
        odds_btts = _coerce_decimal_odds(_pd.to_numeric(df.get("odds_ft_btts"),  errors="coerce"))

        valid_o25  = realized & odds_o25.notna()  & _np.isfinite(odds_o25)  & (odds_o25  >= 1.01)
        valid_btts = realized & odds_btts.notna() & _np.isfinite(odds_btts) & (odds_btts >= 1.01)

        p_o25 = _pd.to_numeric(df.get("hgm_prob_over25"), errors="coerce")
        p_bt  = _pd.to_numeric(df.get("hgm_prob_btts"),   errors="coerce")

        sel_dep_o25  = valid_o25  & _implied_mask(odds_o25,  MIN_IMPL) & p_o25.notna()
        sel_dep_btts = valid_btts & _implied_mask(odds_btts, MIN_IMPL) & p_bt.notna()

        def _acc(sel, wins):
            bets = int(sel.sum())
            return 0.0 if bets == 0 else float((wins & sel).sum()) / float(bets)

        acc_dep_o25 = _acc(sel_dep_o25, y_over)
        acc_dep_bt  = _acc(sel_dep_btts, y_btts)

        sel_all_o25 = valid_o25  & p_o25.notna()
        sel_all_bt  = valid_btts & p_bt.notna()

        acc_all_o25 = _acc(sel_all_o25, y_over)
        acc_all_bt  = _acc(sel_all_bt, y_btts)

        print("---- HGM Accuracy (completed) ----------------------")
        print(f"[Deploy {MIN_IMPL:.0%}] O2.5  bets={int(sel_dep_o25.sum())}  acc={acc_dep_o25:.1%}")
        print(f"[Deploy {MIN_IMPL:.0%}] BTTS  bets={int(sel_dep_btts.sum())} acc={acc_dep_bt:.1%}")
        print(f"(All odds)           O2.5  bets={int(sel_all_o25.sum())}  acc={acc_all_o25:.1%}")
        print(f"(All odds)           BTTS  bets={int(sel_all_bt.sum())} acc={acc_all_bt:.1%}")
        print("----------------------------------------------------")

# --- Banker hooks for quick/full runs ---
def _apply_banker_hooks_if_enabled(res, league):
    """
    If enabled via env, save banker slips and optionally run a quick backtest.
    Works whether *res* is a DataFrame or an iterable containing one.
    """
    import os as _os
    try:
        import pandas as _pd
    except Exception:
        _pd = None

    df = None
    if _pd is not None:
        try:
            if isinstance(res, _pd.DataFrame):
                df = res
            elif isinstance(res, (list, tuple)):
                for _x in res:
                    if isinstance(_x, _pd.DataFrame):
                        df = _x
                        break
        except Exception:
            df = None

    if df is None:
        return res

    # Save banker slips (best-effort)
    if _os.getenv("ENABLE_BANKER_HGM", "1") == "1":
        try:
            save_banker_slips(df, league)
        except Exception:
            pass
        # One-liner: where they went (idempotent)
        try:
            _dir = os.getenv("BANKER_REPORTS_DIR", DEFAULT_BANKER_REPORTS_DIR)
            if not getattr(df, "attrs", {}).get("_banker_printed"):
                print(f"Banker slips saved to {_dir}")
                try:
                    df.attrs["_banker_printed"] = True
                except Exception:
                    pass
        except Exception:
            pass

    # Optional quick accuracy backtest
    if _os.getenv("RUN_BANKER_BACKTEST", "0") == "1":
        try:
            _fn = globals().get("backtest_hgm_bankers_accuracy")
            if callable(_fn):
                _fn(df, league)
            else:
                _fn2 = globals().get("backtest_hgm_bankers")
                if callable(_fn2):
                    _fn2(df, league)
        except Exception:
            pass

    return res
