# --- Specialist OOF integration helper for full pipeline (call from your real pipeline) ---
if "_inject_specialists_oof_into_training" not in globals():
    def _inject_specialists_oof_into_training(training_data: pd.DataFrame, league) -> tuple[pd.DataFrame, pd.DataFrame, dict]:
        """
        Train enabled specialists on a label-safe copy and attach calibrated OOF
        probabilities back onto `training_data` as 'oof_prob_*' columns.
        Returns (training_data_with_oof, training_data_labelsafe, models_dict).

        Designed to be called inside your canonical run_pipeline_for_league(...) *after*
        you assemble `training_data`/`upcoming_data` and *before* FTR model training.
        """
        import pandas as _pd
        if not isinstance(training_data, _pd.DataFrame) or training_data.empty:
            return training_data, training_data, {}

        # League name (supports dict-like or str)
        try:
            lname = _league_name(league.get('name') if isinstance(league, dict) else league)
        except Exception:
            lname = str(league)

        # --- Label-safe snapshot so specialists don’t mutate labels in place ---
        training_data_labelsafe = training_data.copy()

        # --- Specialist toggles (already defined globally; default-safe here) ---
        _g = globals()
        _EN_OVER25 = bool(_g.get("ENABLE_SPEC_OVER25", True))
        _EN_BTTS   = bool(_g.get("ENABLE_SPEC_BTTS", True))
        _EN_GE2TG  = bool(_g.get("ENABLE_SPEC_GE2TG", True))
        _EN_FTS    = bool(_g.get("ENABLE_SPEC_FTS", True))

        # --- Train specialists (guard each call) ---
        over_model = None
        if _EN_OVER25 and "train_and_evaluate_over25_model" in _g and callable(_g["train_and_evaluate_over25_model"]):
            try:
                over_model = _g["train_and_evaluate_over25_model"](training_data_labelsafe, lname)
                # Direct persist of over25 model (compat with varied variable names)
                try:
                    import os as _os
                    _save_market_model(lname, "over25", over_model)  # type: ignore[name-defined]
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        try:
                            print(f"💾 specialist saved [over25] for {lname} as over_model")
                        except Exception:
                            pass
                except Exception:
                    pass
            except Exception:
                over_model = None

        btts_model = None
        if _EN_BTTS and "train_and_evaluate_btts_model" in _g and callable(_g["train_and_evaluate_btts_model"]):
            try:
                btts_model = _g["train_and_evaluate_btts_model"](training_data_labelsafe, lname)
            except Exception:
                btts_model = None

        home_over15tg_model = None
        away_over15tg_model = None
        if _EN_GE2TG and "train_and_evaluate_over15tg_model" in _g and callable(_g["train_and_evaluate_over15tg_model"]):
            try:
                home_over15tg_model = _g["train_and_evaluate_over15tg_model"](training_data_labelsafe, lname, side="home")
            except Exception:
                home_over15tg_model = None
            try:
                away_over15tg_model = _g["train_and_evaluate_over15tg_model"](training_data_labelsafe, lname, side="away")
            except Exception:
                away_over15tg_model = None

        home_fts_model = None
        away_fts_model = None
        if _EN_FTS and "train_and_evaluate_fts_model" in _g and callable(_g["train_and_evaluate_fts_model"]):
            try:
                home_fts_model = _g["train_and_evaluate_fts_model"](training_data_labelsafe, lname, side="home")
            except Exception:
                home_fts_model = None
            try:
                away_fts_model = _g["train_and_evaluate_fts_model"](training_data_labelsafe, lname, side="away")
            except Exception:
                away_fts_model = None

        # --- Phase 3: attach OOF features from specialists into the FTR frame ---
        try:
            oof_cols: list[str] = []
            if _EN_OVER25 and over_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "over25", over_model)
                if _c: oof_cols.append(_c)
            if _EN_BTTS and btts_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "btts", btts_model)
                if _c: oof_cols.append(_c)
            if _EN_GE2TG and home_over15tg_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "home_over15tg", home_over15tg_model)
                if _c: oof_cols.append(_c)
            if _EN_GE2TG and away_over15tg_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "away_over15tg", away_over15tg_model)
                if _c: oof_cols.append(_c)
            if _EN_FTS and home_fts_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "home_fts", home_fts_model)
                if _c: oof_cols.append(_c)
            if _EN_FTS and away_fts_model is not None:
                training_data_labelsafe, _c = _attach_oof_for_market(training_data_labelsafe, "away_fts", away_fts_model)
                if _c: oof_cols.append(_c)

            # Propagate OOF columns to the main FTR training frame
            for _c in oof_cols:
                try:
                    if _c in training_data_labelsafe.columns and _c not in training_data.columns:
                        training_data[_c] = training_data_labelsafe[_c]
                except Exception:
                    pass
        except Exception as _e:
            try:
                print(f"⚠️ OOF feature attach skipped: {_e}")
            except Exception:
                pass

        models = {
            "over25": over_model, "btts": btts_model,
            "home_over15tg": home_over15tg_model, "away_over15tg": away_over15tg_model,
            "home_fts": home_fts_model, "away_fts": away_fts_model,
        }
        return training_data, training_data_labelsafe, models

