# --- Banker gate waterfall diagnostics (print + CSV) ---
if "_print_banker_gate_waterfall" not in globals():
    def _banker_gate_series_counts(df: pd.DataFrame, league: str) -> pd.DataFrame:
        import numpy as _np, pandas as _pd
        if not isinstance(df, _pd.DataFrame) or df.empty:
            return _pd.DataFrame(columns=["market","gate","count"])    
        # Ensure HGM probabilities are present
        try:
            _hgm_probs_inplace(df, league)
        except Exception:
            pass
        g = _hgm_gate_params(league)

        # Helper series (safe, NA-tolerant)
        o25_hist  = _get(df, "over_25_percentage_pre_match").fillna(0)/100.0
        btts_hist = _get(df, "btts_percentage_pre_match").fillna(0)/100.0
        team2p_h  = _get(df, "home_two_plus_percentage", "home_team_two_plus_percentage")/100.0
        team2p_a  = _get(df, "away_two_plus_percentage", "away_team_two_plus_percentage")/100.0
        con2p_h   = _get(df, "home_concede_two_plus_percentage")/100.0
        con2p_a   = _get(df, "away_concede_two_plus_percentage")/100.0
        fts_h     = _get(df, "home_fts_percentage")/100.0
        fts_a     = _get(df, "away_fts_percentage")/100.0
        cs_h      = _get(df, "home_clean_sheet_percentage")/100.0
        cs_a      = _get(df, "away_clean_sheet_percentage")/100.0

        def _sot_est_local(frame: pd.DataFrame, side: str) -> pd.Series:
            shots = _get(frame, f"rolling5_{side}_shots")
            ratio = _get(frame, f"rolling5_{side}_sot_ratio")
            return (shots * ratio).fillna(0)
        sot_h = _sot_est_local(df, "home"); sot_a = _sot_est_local(df, "away")

        th = _pd.to_numeric(df.get("hgm_prob_home_o15"), errors="coerce")
        ta = _pd.to_numeric(df.get("hgm_prob_away_o15"), errors="coerce")
        p_o25 = _pd.to_numeric(df.get("hgm_prob_over25"), errors="coerce")
        p_bt  = _pd.to_numeric(df.get("hgm_prob_btts"), errors="coerce")

        rows = []
        def _add(market: str, label: str, count):
            rows.append({"market": market, "gate": label, "count": (int(count) if _np.isfinite(count) else _np.nan)})

        # Home O1.5
        market = "Home O1.5"
        m = _pd.Series(True, index=df.index)
        m = (th >= g["o15_p_min"]).fillna(False)
        _add(market, f"P(≥2) ≥ {g['o15_p_min']}", m.sum())
        if not team2p_h.isna().all():
            m = m & (team2p_h >= g["o15_team2_min"]).fillna(False)
            _add(market, f"Team 2+% ≥ {g['o15_team2_min']}", m.sum())
        else:
            _add(market, "Team 2+% (skipped)", _np.nan)
        if not con2p_a.isna().all():
            m = m & (con2p_a >= g["o15_con2_min"]).fillna(False)
            _add(market, f"Opp concede 2+% ≥ {g['o15_con2_min']}", m.sum())
        else:
            _add(market, "Opp concede 2+% (skipped)", _np.nan)
        if not sot_h.isna().all():
            m = m & (sot_h >= g["o15_sot_min"]).fillna(False)
            _add(market, f"SoT ≥ {g['o15_sot_min']}", m.sum())
        else:
            _add(market, "SoT (skipped)", _np.nan)
        if not _get(df, "home_big_chances", "home_big_chances_per_game").isna().all():
            bigc_h = _get(df, "home_big_chances", "home_big_chances_per_game")
            m = m & (bigc_h >= g["o15_bigc_min"]).fillna(False)
            _add(market, f"Big chances ≥ {g['o15_bigc_min']}", m.sum())
        else:
            _add(market, "Big chances (skipped)", _np.nan)

        # Away O1.5
        market = "Away O1.5"
        m = (ta >= g["o15_p_min"]).fillna(False)
        _add(market, f"P(≥2) ≥ {g['o15_p_min']}", m.sum())
        if not team2p_a.isna().all():
            m = m & (team2p_a >= g["o15_team2_min"]).fillna(False)
            _add(market, f"Team 2+% ≥ {g['o15_team2_min']}", m.sum())
        else:
            _add(market, "Team 2+% (skipped)", _np.nan)
        if not con2p_h.isna().all():
            m = m & (con2p_h >= g["o15_con2_min"]).fillna(False)
            _add(market, f"Opp concede 2+% ≥ {g['o15_con2_min']}", m.sum())
        else:
            _add(market, "Opp concede 2+% (skipped)", _np.nan)
        if not sot_a.isna().all():
            m = m & (sot_a >= g["o15_sot_min"]).fillna(False)
            _add(market, f"SoT ≥ {g['o15_sot_min']}", m.sum())
        else:
            _add(market, "SoT (skipped)", _np.nan)
        if not _get(df, "away_big_chances", "away_big_chances_per_game").isna().all():
            bigc_a = _get(df, "away_big_chances", "away_big_chances_per_game")
            m = m & (bigc_a >= g["o15_bigc_min"]).fillna(False)
            _add(market, f"Big chances ≥ {g['o15_bigc_min']}", m.sum())
        else:
            _add(market, "Big chances (skipped)", _np.nan)

        # Over 2.5
        market = "Over 2.5"
        m = (p_o25 >= g["o25_p_min"]).fillna(False)
        _add(market, f"P(O2.5) ≥ {g['o25_p_min']}", m.sum())
        if not o25_hist.isna().all():
            m = m & (o25_hist >= g["o25_hist_min"]).fillna(False)
            _add(market, f"O2.5 hist ≥ {g['o25_hist_min']}", m.sum())
        else:
            _add(market, "O2.5 hist (skipped)", _np.nan)
        lam_rule = ((df["hgm_lambda_home"] >= g["o25_lam_hi"]) | ((df["hgm_lambda_home"] >= g["o25_lam_both"]) & (df["hgm_lambda_away"] >= g["o25_lam_both"]))).fillna(False)
        m = m & lam_rule
        _add(market, f"λ rule (hi={g['o25_lam_hi']} or both≥{g['o25_lam_both']})", m.sum())

        # BTTS Yes
        market = "BTTS Yes"
        m = (p_bt >= g["btts_p_min"]).fillna(False)
        _add(market, f"P(BTTS) ≥ {g['btts_p_min']}", m.sum())
        if not btts_hist.isna().all():
            m = m & (btts_hist >= g["btts_hist_min"]).fillna(False)
            _add(market, f"BTTS hist ≥ {g['btts_hist_min']}", m.sum())
        else:
            _add(market, "BTTS hist (skipped)", _np.nan)
        lam_sym = ((df["hgm_lambda_home"] >= 1.0) & (df["hgm_lambda_away"] >= 1.0)).fillna(False)
        m = m & lam_sym
        _add(market, "λ symmetry (λH≥1 & λA≥1)", m.sum())
        if not fts_h.isna().all():
            m = m & (fts_h <= g["btts_fts_max"]).fillna(False)
            _add(market, f"FTS% home ≤ {g['btts_fts_max']}", m.sum())
        else:
            _add(market, "FTS% home (skipped)", _np.nan)
        if not fts_a.isna().all():
            m = m & (fts_a <= g["btts_fts_max"]).fillna(False)
            _add(market, f"FTS% away ≤ {g['btts_fts_max']}", m.sum())
        else:
            _add(market, "FTS% away (skipped)", _np.nan)
        if not cs_h.isna().all():
            m = m & (cs_h <= g["btts_cs_max"]).fillna(False)
            _add(market, f"CS% home ≤ {g['btts_cs_max']}", m.sum())
        else:
            _add(market, "CS% home (skipped)", _np.nan)
        if not cs_a.isna().all():
            m = m & (cs_a <= g["btts_cs_max"]).fillna(False)
            _add(market, f"CS% away ≤ {g['btts_cs_max']}", m.sum())
        else:
            _add(market, "CS% away (skipped)", _np.nan)

        return _pd.DataFrame(rows, columns=["market","gate","count"])        

    def _print_banker_gate_waterfall(df: pd.DataFrame, league: str) -> None:
        import pandas as _pd
        d = _banker_gate_series_counts(df, league)
        print(f"---- Banker gate waterfall [{league}] ----")
        try:
            print(f"Fixtures considered: {len(df)}")
        except Exception:
            pass
        if d.empty:
            print("No rows / insufficient data for diagnostics.")
            print("------------------------------------------------------")
            return
        for mk in ["Home O1.5","Away O1.5","Over 2.5","BTTS Yes"]:
            dd = d[d["market"]==mk]
            if dd.empty: continue
            print(f"{mk}:")
            for _, r in dd.iterrows():
                cnt = r["count"]
                if _pd.isna(cnt):
                    print(f"  - {r['gate']}: skipped")
                else:
                    print(f"  - {r['gate']}: {int(cnt)}")
        print("------------------------------------------------------")

    def _save_banker_gate_waterfall_csv(df: pd.DataFrame, league: str, *, outdir: str | None = None) -> bool:
        import os as _os, datetime as _dt
        try:
            d = _banker_gate_series_counts(df, league)
            if d.empty:
                return False
            from pathlib import Path as _Path
            if outdir is None:
                outdir = _os.getenv("BANKER_WATERFALL_DIR",
                                    _os.getenv("BANKER_REPORTS_DIR", DEFAULT_BANKER_REPORTS_DIR))
            _Path(outdir).mkdir(parents=True, exist_ok=True)
            ts = _dt.datetime.now().strftime("%Y%m%d-%H%M%S")
            path = _Path(outdir) / f"{_sanitize_league_tag(league)}_banker_waterfall_{ts}.csv"
            d.to_csv(path, index=False)
            print(f"📊 Banker waterfall saved → {path}")
            return True
        except Exception as _e:
            try:
                print(f"ℹ️  Banker waterfall save skipped: {_e}")
            except Exception:
                pass
            return False

if "save_banker_slips" not in globals():
    def save_banker_slips(df: pd.DataFrame, league: str, *, outdir: str = "BankerReports") -> bool:
        # Allow env override for banker reports directory
        outdir = os.getenv("BANKER_REPORTS_DIR", outdir)
        try: os.makedirs(outdir, exist_ok=True)
        except Exception: pass
        o15, o25, bt = rank_banker_candidates(df, league)
        # Gate waterfall diagnostics (print + CSV)
        try:
            import os as _os
            if _os.getenv("PRINT_BANKER_WATERFALL", "1") == "1":
                _print_banker_gate_waterfall(df, league)
                _save_banker_gate_waterfall_csv(df, league, outdir=_os.getenv("BANKER_WATERFALL_DIR", outdir))
        except Exception as _e:
            try: print(f"ℹ️  Banker waterfall skipped: {_e}")
            except Exception: pass
        try:
            a_cnt = int((o15.get("tier")=="A").sum()) + int((o25.get("tier")=="A").sum()) + int((bt.get("tier")=="A").sum())
            b_cnt = int((o15.get("tier")=="B").sum()) + int((o25.get("tier")=="B").sum()) + int((bt.get("tier")=="B").sum())
            print(
                f"Tiers: A={a_cnt}  B={b_cnt}  "
                f"(O1.5 A:{int((o15.get('tier')=='A').sum())} B:{int((o15.get('tier')=='B').sum())} | "
                f"O2.5 A:{int((o25.get('tier')=='A').sum())} B:{int((o25.get('tier')=='B').sum())} | "
                f"BTTS A:{int((bt.get('tier')=='A').sum())} B:{int((bt.get('tier')=='B').sum())})"
            )
        except Exception:
            pass
        picks = pd.concat([o15, o25, bt], axis=0, ignore_index=True)
        if picks.empty:
            print("ℹ️  Banker engine: no selections passed the gates.")
            return False
        a = picks[picks["tier"]=="A"].copy(); b = picks[picks["tier"]=="B"].copy()
        base = str(league).replace(" ","_")
        wrote = False
        try:
            if not a.empty:
                a.to_csv(os.path.join(outdir, f"{base}_bankers_A.csv"), index=False); wrote=True
            if not b.empty:
                b.to_csv(os.path.join(outdir, f"{base}_bankers_B.csv"), index=False); wrote=True
            if wrote:
                print(f"🧾 Banker slips saved → {outdir}/{base}_bankers_A.csv and _bankers_B.csv")
            return wrote
        except Exception as _e:
            print(f"⚠️  Banker slips save failed for {league}: {_e}")
            return False
        
