try:
    from constants import SENTINEL, safe_fill, FORCE_LOCKED
except Exception:                     # graceful degrade
    SENTINEL  = -9999.0               # generic missing‑value sentinel
    def safe_fill(df, cols, fill):
        """Lightweight stand‑in for the project helper."""
