    # --- Override safe_fill with a dtype- and duplicate-safe implementation ---
try:
    _SAFE_FILL_ORIG
except NameError:
    _SAFE_FILL_ORIG = safe_fill


def safe_fill(df, cols, fill=None, sentinel=None):
    """
    Fill NA only in the requested columns, but:
      • numeric dtypes: replace inf→NaN then fill with `fill`/`sentinel`
      • datetime/timedelta dtypes: fill missing with NaT (never numeric)
      • duplicate column names handled by positional assignment
    """
    import numpy as np
    import pandas as pd

    if fill is None and sentinel is not None:
        fill = sentinel
    if fill is None:
        fill = -9999.0

    if not isinstance(df, pd.DataFrame) or cols is None:
        return df

    cols_exist = [c for c in list(cols) if c in df.columns]
    if not cols_exist:
        return df

    df = df.copy()

    # group by dtype
    from pandas.api import types as _t
    def _is_dt(col):
        s = df[col]
        return _t.is_datetime64_any_dtype(s) or _t.is_datetime64tz_dtype(s) or _t.is_timedelta64_dtype(s)

    num_cols = [c for c in cols_exist if _t.is_numeric_dtype(df[c])]
    dt_cols  = [c for c in cols_exist if _is_dt(c)]
    has_dupes = pd.Index(df.columns).duplicated().any()

    # numeric: replace infs then fill
    if num_cols:
        if not has_dupes:
            df.loc[:, num_cols] = df[num_cols].replace([np.inf, -np.inf], np.nan).fillna(fill)
        else:
            arr = df.columns.to_numpy()
            for name in num_cols:
                idx = np.where(arr == name)[0]
                if idx.size:
                    block = df.iloc[:, idx].replace([np.inf, -np.inf], np.nan).fillna(fill)
                    df.iloc[:, idx] = block.to_numpy()

    # datetimes: fill with NaT (never numeric)
    if dt_cols:
        if not has_dupes:
            df.loc[:, dt_cols] = df[dt_cols].where(pd.notna(df[dt_cols]), pd.NaT)
        else:
            arr = df.columns.to_numpy()
            for name in dt_cols:
                idx = np.where(arr == name)[0]
                if idx.size:
                    block = df.iloc[:, idx]
                    df.iloc[:, idx] = block.where(pd.notna(block), pd.NaT).to_numpy()

    return df
    
