# --- FTR design-matrix sanitizer (leak-safe, drops overlays, keeps λ̂ summaries) ---
def _sanitize_ftr_matrix(X: pd.DataFrame) -> pd.DataFrame:
    """
    Leak-safe sanitiser for FTR design matrices.
      • Drops Poisson overlay columns if present.
      • Derives safe λ̂ summaries (exp_goals_sum, p00_est) from either
        home/away goal predictions or from pre-match xG columns.
      • Calls strip_leaks using the unified allowlist (with legacy fallback).
    """
    # Remove duplicate-named columns early (prevents fragmentation / wide bloat)
    try:
        X = X.loc[:, ~X.columns.duplicated()].copy()
    except Exception:
        pass
    # Belt-and-braces: never allow Poisson overlay cols through
    bad = [c for c in ("pois_p_home","pois_p_draw","pois_p_away") if c in X.columns]
    if bad:
        print(f"🚫  Dropping Poisson-overlay features from FTR training: {bad}")
        X = X.drop(columns=bad, errors="ignore")

    # Derive leak-safe goal-model summary features if available (λ̂-based)
    # These are pre-match predictions, not labels; safe to expose to FTR.
    if {"home_goals_pred", "away_goals_pred"}.issubset(X.columns):
        hg = pd.to_numeric(X["home_goals_pred"], errors="coerce").clip(lower=0)
        ag = pd.to_numeric(X["away_goals_pred"], errors="coerce").clip(lower=0)
        add_map = {}
        if "exp_goals_sum" not in X.columns:
            add_map["exp_goals_sum"] = (hg + ag)
        if "p00_est" not in X.columns:
            with np.errstate(over="ignore", under="ignore", invalid="ignore"):
                add_map["p00_est"] = np.exp(-hg) * np.exp(-ag)
        if add_map:
            X = X.assign(**add_map)
    elif {"Home Team Pre-Match xG", "Away Team Pre-Match xG"}.issubset(X.columns):
        # Fallback: derive from pre-match xG columns when goal predictions aren't attached
        hg = pd.to_numeric(X["Home Team Pre-Match xG"], errors="coerce").clip(lower=0)
        ag = pd.to_numeric(X["Away Team Pre-Match xG"], errors="coerce").clip(lower=0)
        if "exp_goals_sum" not in X.columns:
            X["exp_goals_sum"] = (hg + ag)
        if "p00_est" not in X.columns:
            with np.errstate(over="ignore", under="ignore", invalid="ignore"):
                X["p00_est"] = np.exp(-hg) * np.exp(-ag)

    # Apply leak stripping with unified allowlist; tolerate legacy signature
    allow = _resolve_ftr_allowlist()
    try:
        Y = strip_leaks(X, allowlist=allow)
    except TypeError:
        # Legacy strip_leaks without allowlist support -> emulate keep via allowlist
        keep = [c for c in allow if c in X.columns]
        Y = X.loc[:, keep].copy() if keep else X

    # Guarantee λ̂ summaries exist post‑strip (derive if needed)
    if {"home_goals_pred","away_goals_pred"}.issubset(X.columns):
        hg = pd.to_numeric(X["home_goals_pred"], errors="coerce").clip(lower=0)
        ag = pd.to_numeric(X["away_goals_pred"], errors="coerce").clip(lower=0)
        add_map = {}
        if "exp_goals_sum" not in Y.columns:
            add_map["exp_goals_sum"] = (hg + ag)
        if "p00_est" not in Y.columns:
            with np.errstate(over="ignore", under="ignore", invalid="ignore"):
                add_map["p00_est"] = np.exp(-hg) * np.exp(-ag)
        if add_map:
            Y = Y.assign(**add_map)
    elif {"Home Team Pre-Match xG","Away Team Pre-Match xG"}.issubset(X.columns):
        hg = pd.to_numeric(X["Home Team Pre-Match xG"], errors="coerce").clip(lower=0)
        ag = pd.to_numeric(X["Away Team Pre-Match xG"], errors="coerce").clip(lower=0)
        add_map = {}
        if "exp_goals_sum" not in Y.columns:
            add_map["exp_goals_sum"] = (hg + ag)
        if "p00_est" not in Y.columns:
            with np.errstate(over="ignore", under="ignore", invalid="ignore"):
                add_map["p00_est"] = np.exp(-hg) * np.exp(-ag)
        if add_map:
            Y = Y.assign(**add_map)

    return Y

# --- Draw bundle convenience (de-dupe, float32, row cap, parallel) ---
if "ensure_draw_bundle" not in globals():
    def ensure_draw_bundle(df: pd.DataFrame, *, row_cap: int | None = None):
        """
        Return (df_clean, parallel_ctx) where:
          • df_clean is de-duplicated and downcast to float32
          • row count capped by DRAW_ROW_CAP env (or row_cap)
          • parallel_ctx is a context manager for sklearn parallel_backend('loky', n_jobs=SKLEARN_JOBS)

        Usage:
            Xc, pctx = ensure_draw_bundle(X)
            with pctx:
                # fit draw models safely
                ...
        """
        import os as _os
        import pandas as _pd
        from contextlib import nullcontext as _nullcontext
        try:
            from sklearn.utils import parallel_backend as _parallel_backend
        except Exception:
            _parallel_backend = None

        # Handle empty / non-DataFrame early
        if not isinstance(df, _pd.DataFrame) or df.empty:
            jobs = 1
            try:
                jobs = int(_os.getenv("SKLEARN_JOBS","1"))
            except Exception:
                jobs = 1
            ctx = _parallel_backend("loky", n_jobs=jobs) if _parallel_backend else _nullcontext()
            return df, ctx

        # De-duplicate columns and downcast to float32
        try:
            dfc = df.loc[:, ~df.columns.duplicated()].copy()
        except Exception:
            dfc = df.copy()
        try:
            num = dfc.select_dtypes(include=["float64","int64","int32","float32","int"]).columns
            if len(num):
                dfc[num] = dfc[num].apply(_pd.to_numeric, errors="coerce").astype("float32")
        except Exception:
            pass

        # Cap rows (most recent slice by date if possible)
        try:
            cap = int(row_cap) if row_cap is not None else int(_os.getenv("DRAW_ROW_CAP","20000"))
        except Exception:
            cap = 20000
        if cap and isinstance(dfc, _pd.DataFrame) and len(dfc) > cap:
            try:
                dfc = dfc.sort_values("match_date").tail(cap).copy()
            except Exception:
                dfc = dfc.tail(cap).copy()

        # Parallel backend context (safe no-op if sklearn missing)
        try:
            jobs = int(_os.getenv("SKLEARN_JOBS","1"))
        except Exception:
            jobs = 1
        ctx = _parallel_backend("loky", n_jobs=jobs) if _parallel_backend else _nullcontext()
        return dfc, ctx


# --- SAFETY NORMALISERS (early guard so train_ftr_for_league can call them) ---
if "apply_safe_renames_and_whitelist" not in globals():
    import pandas as pd
    import numpy as np

    def _first_present(df: pd.DataFrame, *names: str) -> str | None:
        for n in names:
            if n in df.columns:
                return n
        return None

    def ensure_FTR_column(df: pd.DataFrame) -> pd.DataFrame:
        """
        Ensure an integer-encoded `FTR` column exists with mapping {0=Home,1=Draw,2=Away}.
        Tries textual H/D/A first, then derives from goal counts if present.
        """
        df = df.copy()

        # 1) Textual result → numeric (H/D/A → 0/1/2)
        text_col = _first_present(df, 'FTR', 'ftr', 'full_time_result', 'ft_result', 'result', 'Result')
        if text_col is not None and 'FTR' not in df.columns:
            m = df[text_col].astype(str).str.upper().str[0]
            mapped = m.map({'H': 0, 'D': 1, 'A': 2})
            if mapped.notna().any():
                df['FTR'] = mapped.astype('float')  # temporary float; cast below

        # 2) From goal counts when available
        if 'FTR' not in df.columns or df['FTR'].isna().any():
            home_g = _first_present(
                df, 'home_team_goal_count', 'FTHG', 'home_goals', 'home_score',
                'Home Team Goals', 'home_team_score'
            )
            away_g = _first_present(
                df, 'away_team_goal_count', 'FTAG', 'away_goals', 'away_score',
                'Away Team Goals', 'away_team_score'
            )
            if home_g and away_g:
                hh = pd.to_numeric(df[home_g], errors='coerce')
                aa = pd.to_numeric(df[away_g], errors='coerce')
                derived = np.where(hh > aa, 0, np.where(hh < aa, 2, 1))
                if 'FTR' in df.columns:
                    mask = df['FTR'].isna()
                    df.loc[mask, 'FTR'] = derived[mask]
                else:
                    df['FTR'] = derived

        # Final type: clean to int where possible
        if 'FTR' in df.columns:
            df['FTR'] = pd.to_numeric(df['FTR'], errors='coerce')
            try:
                df['FTR'] = df['FTR'].astype('Int64')
            except Exception:
                df['FTR'] = df['FTR'].fillna(-1).astype(int)

        return df
    
    def apply_safe_renames_and_whitelist(df: pd.DataFrame) -> pd.DataFrame:
        """
        Lightweight, leak-safe normaliser used before training:
          • renames common variants of match_date / team / goals columns;
          • ensures `FTR` exists via `ensure_FTR_column`;
          • converts match_date to datetime when present.
        """
        df = df.copy()

        # match_date
        date_col = _first_present(df, 'match_date', 'Date', 'date', 'date_GMT', 'fixture_date')
        if date_col and date_col != 'match_date':
            df = df.rename(columns={date_col: 'match_date'})
        if 'match_date' in df.columns:
            try:
                df['match_date'] = pd.to_datetime(df['match_date'], errors='coerce')
            except Exception:
                pass

        # teams
        home_col = _first_present(
            df, 'home_team_name', 'Home Team', 'home_team', 'home', 'homeTeam',
            'team_home', 'home_club', 'Home'
        )
        away_col = _first_present(
            df, 'away_team_name', 'Away Team', 'away_team', 'away', 'awayTeam',
            'team_away', 'away_club', 'Away'
        )
        ren = {}
        if home_col and home_col != 'home_team_name':
            ren[home_col] = 'home_team_name'
        if away_col and away_col != 'away_team_name':
            ren[away_col] = 'away_team_name'
        if ren:
            df = df.rename(columns=ren)

        # goals
        hg = _first_present(df, 'home_team_goal_count', 'FTHG', 'home_goals', 'home_score', 'Home Team Goals', 'home_team_score')
        ag = _first_present(df, 'away_team_goal_count', 'FTAG', 'away_goals', 'away_score', 'Away Team Goals', 'away_team_score')
        ren = {}
        if hg and hg != 'home_team_goal_count':
            ren[hg] = 'home_team_goal_count'
        if ag and ag != 'away_team_goal_count':
            ren[ag] = 'away_team_goal_count'
        if ren:
            df = df.rename(columns=ren)
        for gcol in ('home_team_goal_count', 'away_team_goal_count'):
            if gcol in df.columns:
                df[gcol] = pd.to_numeric(df[gcol], errors='coerce')

        # ensure FTR exists
        df = ensure_FTR_column(df)
        return df


# ------------------------------------------------------------------
# Lazy loader for `_apply_lambda_shrink` to avoid circular import
# with prediction_overlay. The real implementation is imported on
# first use, then cached in the module’s globals.
# ------------------------------------------------------------------
def _apply_lambda_shrink(*args, **kwargs):
    from importlib import import_module
    real = import_module("prediction_overlay")._apply_lambda_shrink
    globals()["_apply_lambda_shrink"] = real   # cache resolved function
    return real(*args, **kwargs)
