from sklearn.feature_selection import VarianceThreshold as _VarSel

_BOOKMAKER_COLS = {
    'odds_ft_home_team_win', 'odds_ft_draw', 'odds_ft_away_team_win',
    'odds_ft_over15', 'odds_ft_over25', 'odds_ft_over35', 'odds_ft_over45',
    'odds_btts_yes', 'odds_btts_no',
    'implied_prob_diff', 'odds_diff',
}

def drop_bookmaker_cols(df: pd.DataFrame) -> pd.DataFrame:
    """ 
    DEBUG-ONLY: keep bookmaker / implied-prob columns.
    We *do not* drop them here; upstream callers decide.
    """
    return df

def drop_constant_cols(df: pd.DataFrame) -> pd.DataFrame:
    """Drop numeric columns whose variance ≤ VAR_THRESH_NUM (≈ constant)."""
    num = df.select_dtypes(include=["number"])
    if num.empty:
        return df  # nothing to check

    # VarianceThreshold with project‑wide cut‑off (defaults to 1e‑5)
    keep_mask = _VarSel(threshold=VAR_THRESH_NUM).fit(num.fillna(0)).get_support()
    const_cols = [c for c, k in zip(num.columns, keep_mask) if not k]

    if const_cols:
        print(f"⚠️  Dropping near‑constant numeric cols: {const_cols[:8]}…")
        df = df.drop(columns=const_cols, errors="ignore")

    return df.copy()

def assert_prob_matrix_shape(arr: np.ndarray) -> None:
    """Ensure a 2‑D array with exactly 3 columns (Home / Draw / Away)."""
    if arr.ndim != 2 or arr.shape[1] != 3:
        raise ValueError(f"Probability matrix malformed: {arr.shape}")


# ================================================================
# Leak‑safe low‑hanging feature generators
#   • Elo ratings & differential
#   • Rest‑days differential
#   • EWMA form differential
# ================================================================
from collections import defaultdict  # NEW import (used by add_elo_features)


def add_elo_features(df: pd.DataFrame, k: int = 32) -> pd.DataFrame:
    """Pre‑match Elo ratings & their differential (home − away)."""
    if df.empty:
        return df
    df = df.sort_values("match_date").copy()
    elo = defaultdict(lambda: 1500.0)

    h_elo, a_elo = [], []
    for _, r in df.iterrows():
        h, a = r["home_team_name"], r["away_team_name"]
        # ── record PRE‑match ratings ──────────────────────────────
        h_elo.append(elo[h])
        a_elo.append(elo[a])

        # ── update ratings AFTER we stored the old ones ───────────
        exp_h = 1 / (1 + 10 ** ((elo[a] - elo[h]) / 400))
        res_h = 1 if r["FTR"] == 0 else 0.5 if r["FTR"] == 1 else 0
        elo[h] += k * (res_h - exp_h)
        elo[a] += k * ((1 - res_h) - (1 - exp_h))

    df["elo_home_pre"] = h_elo
    df["elo_away_pre"] = a_elo
    df["elo_diff"] = df["elo_home_pre"] - df["elo_away_pre"]
    return df


def add_rest_days(df: pd.DataFrame) -> pd.DataFrame:
    """Days‑since‑last‑match for each team & their differential."""
    if df.empty or "match_date" not in df.columns:
        return df
    for side in ("home", "away"):
        # store the *previous* match date for each team
        last_col = f"{side}_last_match"
        df[last_col] = (
            df.groupby(f"{side}_team_name")["match_date"]
              .shift(1)
        )

        # rest‑days = difference between current and previous fixture
        df[f"{side}_rest_days"] = (
            df["match_date"] -
            df[last_col].fillna(df["match_date"] - _pd.Timedelta(days=7))
        ).dt.days.clip(0, 14)
    df["rest_diff"] = df["home_rest_days"] - df["away_rest_days"]
    return df


def add_ewma_ppg(df: pd.DataFrame, span: int = 6) -> pd.DataFrame:
    """Exponentially‑weighted pre‑match PPG & its differential."""
    if df.empty:
        return df
    df = df.sort_values("match_date").copy()
    for side in ("home", "away"):
        # 1) lag the PPG by one match so the current fixture is excluded
        shifted_ppg = (
            df.groupby(f"{side}_team_name")[f"{side}_ppg"]
              .shift(1)
        )

        # 2) apply the EWMA on the lagged series
        df[f"{side}_ewma_ppg"] = (
            shifted_ppg.groupby(df[f"{side}_team_name"])
                       .apply(lambda s: s.ewm(span=span, min_periods=3).mean())
                       .reset_index(level=0, drop=True)
        )
    df["ewma_ppg_diff"] = df["home_ewma_ppg"] - df["away_ewma_ppg"]
    return df


# ------------------------------------------------------------------
# Lightweight FTR‑mix helper – required by debug_draw.py
# ------------------------------------------------------------------
import numpy as _np

def apply_ftr_mix(raw_proba: np.ndarray,
                  *,
                  alpha: float = 1.0,
                  beta:  float = 0.0,
                  cap:   float = 0.45,
                  implied: np.ndarray | None = None,
                  draw_prior: np.ndarray | None = None,
                  gamma: float = 0.0) -> np.ndarray:
    """
    Blend calibrated model probabilities with (optional) market-implied and a
    dedicated draw-prior from the standalone draw classifier.

    alpha : multiplicative boost on the draw column.
    beta  : linear blend weight with market-implied probabilities.
    cap   : ceiling applied to the (possibly boosted) draw column.
    draw_prior : optional 1-D array of P[D] from draw model; blended by *gamma*.
    gamma : weight for draw_prior in the draw column blend (0..1). 0 = off.
    """
    p = _np.asarray(raw_proba, dtype=float).copy()

    # ① optional blend with dedicated draw-prior, then α-scale + cap
    if draw_prior is not None and gamma > 0:
        dp = _np.asarray(draw_prior, dtype=float).reshape(-1)
        dp = _np.clip(dp, 0.0, 1.0)[: p.shape[0]]
        merged_draw = (1.0 - gamma) * p[:, 1] + gamma * dp
        p[:, 1] = _np.minimum(merged_draw * alpha, cap)
    else:
        p[:, 1] = _np.minimum(p[:, 1] * alpha, cap)

    # ② β-blend with market-implied probabilities
    if implied is not None and beta > 0.0:
        p = (1.0 - beta) * p + beta * implied

    # ③ final row-normalisation
    row_sum = p.sum(axis=1, keepdims=True)
    _np.divide(p, row_sum, out=p, where=row_sum != 0)
    return p
# ------------------------------------------------------------------
# FTR bundle loader + convenience scorer for CSVs
# ------------------------------------------------------------------
def load_ftr_bundle(league: str, model_root: str = "ModelStore"):
    """
    Load the saved FTR model bundle for *league* and return:
        (model, features, mix_dict)

    Notes
    -----
    • The saved artifact is a dict bundle: {"model": estimator, "features": [...], ...}
      This helper unwraps it so callers don't accidentally try to call
      predict_proba on the dict itself.
    • mix_dict contains draw-mix parameters inferred from
      <MODEL_ROOT>/<LEAGUE_TAG>_draw_threshold.json when present:
        {alpha, beta, cap, threshold}
    """
    import os, joblib, json
    tag = str(league).replace(" ", "_")
    pkl_path = os.path.join(model_root, tag, "ftr.pkl")
    obj = joblib.load(pkl_path)
    if isinstance(obj, dict):
        model = obj.get("model", obj)
        features = obj.get("features") or obj.get("feature_list") or []
        meta = {k: v for k, v in obj.items() if k not in ("model", "features", "feature_list")}
    else:
        model, features, meta = obj, [], {}

    # Try to load draw-mix settings (optional)
    mix = {}
    try:
        thr_json = os.path.join(model_root, f"{tag}_draw_threshold.json")
        with open(thr_json, "r") as fh:
            j = json.load(fh) or {}
        mix = {
            "alpha": float(j.get("baseline_blend", 1.0)),
            "beta": float(j.get("beta", 0.0) or 0.0),
            "cap": float(j.get("cap", 0.45)),
            "threshold": float(j.get("threshold", 0.30)),
            "gamma": float(j.get("gamma", 0.50)),  # weight for draw_prior in mixing
        }
    except Exception:
        # file missing or malformed; default-safe values
        mix = {"alpha": 1.0, "beta": 0.0, "cap": 0.45, "threshold": 0.30, "gamma": 0.0}


# --- NEW: prefer modern artifacts when present ------------------------
# (disabled) Legacy *_mix.json overrides removed — YAML is the single source of truth.
# Draw gate/market thresholds are loaded by the overlay from their own JSONs.
# Leave `mix` as constructed earlier in this function.


def load_draw_bundle(league: str, model_root: str = "ModelStore"):
    """
    Load the saved draw classifier bundle for *league* and return (model, features).
    Returns (None, []) if no draw model is present.
    """
    import os, joblib
    tag = str(league).replace(" ", "_")
    pkl_path = os.path.join(model_root, f"{tag}_draw_clf.pkl")
    try:
        obj = joblib.load(pkl_path)
    except Exception:
        return None, []
    if isinstance(obj, dict):
        mdl = obj.get("model") or obj.get("clf") or obj
        feats = list(obj.get("features") or obj.get("feature_list") or obj.get("features_used") or [])
    else:
        mdl, feats = obj, []
    return mdl, feats


def predict_draw_prior(df: pd.DataFrame,
                       league: str,
                       model_root: str = "ModelStore") -> np.ndarray | None:
    """
    Best-effort draw probability (P[D]) from the dedicated draw classifier.
    Returns a 1-D array aligned with *df* or None if unavailable.
    """
    mdl, feats = load_draw_bundle(league, model_root)
    if mdl is None:
        return None
    try:
        if feats:
            Xd = _align_design_matrix(df, feats)
        else:
            Xd = df.select_dtypes(include=["number"]).replace([np.inf, -np.inf], np.nan)
            Xd = safe_fill(Xd, Xd.columns.tolist(), SENTINEL)
        proba = np.asarray(mdl.predict_proba(Xd))
        if proba.ndim == 2:
            if proba.shape[1] == 2:          # binary [no, draw]
                dp = proba[:, 1]
            elif proba.shape[1] == 3:        # multiclass [H, D, A]
                dp = proba[:, 1]
            else:                            # unexpected width
                dp = np.asarray(proba).ravel()
        else:
            dp = np.asarray(proba).ravel()

        # --- numeric safety -------------------------------------------------
        return np.clip(dp, 0.0, 1.0)

    except Exception:
        return None

def _align_design_matrix(df: pd.DataFrame, feats: list[str]) -> pd.DataFrame:
    """
    Align *df* to the exact training feature list *feats*, add any missing
    columns filled with SENTINEL, and ensure numeric types are clean.
    """
    X = df.reindex(columns=feats).replace([np.inf, -np.inf], np.nan)
    X = safe_fill(X, X.columns.tolist(), SENTINEL)
    missing = [c for c in feats if c not in X.columns]
    for c in missing:
        X[c] = SENTINEL
    return X[feats]
def _attach_goal_predictions_if_available(df: pd.DataFrame, league: str, model_root: str = "ModelStore") -> pd.DataFrame:
    """
    If saved goal regressors exist for *league*, compute and attach
    home_goals_pred / away_goals_pred to *df* in-place.
    Fail-soft on any error.
    """
    import os, joblib, numpy as np
    tag = str(league).replace(" ", "_")
    p_home = os.path.join(model_root, f"{tag}_home_goals_model.pkl")
    p_away = os.path.join(model_root, f"{tag}_away_goals_model.pkl")
    if not (os.path.exists(p_home) and os.path.exists(p_away)):
    # Fallback: try goal_ensembles fold models (bagging wrapper)
        try:
            import glob
            class _FoldAvgReg:
                def __init__(self, models):
                    self.models = [m for m in models if m is not None]
                def predict(self, X):
                    import numpy as _np
                    preds = []
                    for m in self.models:
                        try:
                            preds.append(m.predict(X))
                        except Exception:
                            continue
                    if not preds:
                        return _np.zeros(len(X), dtype=float)
                    M = _np.column_stack(preds)
                    return M.mean(axis=1)

            ens_dir = os.path.join(model_root, "goal_ensembles")
            cand_home = sorted(glob.glob(os.path.join(ens_dir, "*home_goals*fold*.pkl")))
            cand_away = sorted(glob.glob(os.path.join(ens_dir, "*away_goals*fold*.pkl")))
            if cand_home and cand_away:
                fold_models_home = joblib.load(cand_home[-1])
                fold_models_away = joblib.load(cand_away[-1])
                m_home = _FoldAvgReg(fold_models_home if isinstance(fold_models_home, (list, tuple)) else [fold_models_home])
                m_away = _FoldAvgReg(fold_models_away if isinstance(fold_models_away, (list, tuple)) else [fold_models_away])
            else:
                return df
        except Exception:
            return df
    else:
        m_home = joblib.load(p_home)
        m_away = joblib.load(p_away)
    try:
        m_home = joblib.load(p_home)
        m_away = joblib.load(p_away)

        num = (
            df.select_dtypes(include=["number"])
              .drop(columns=["home_team_goal_count","away_team_goal_count"], errors="ignore")
              .replace([np.inf, -np.inf], np.nan)
        )
        id_cols = [c for c in ("home_team_id","away_team_id") if c in df.columns]
        Xg = pd.concat([num, df[id_cols]], axis=1)
        Xg = Xg.loc[:, ~Xg.columns.duplicated()]
        Xg = safe_fill(Xg, Xg.columns.tolist(), SENTINEL)

        try:
            Xh = _align_dataframe_to_model(Xg, m_home)  # shimmed if unavailable
        except Exception:
            Xh = Xg
        try:
            Xa = _align_dataframe_to_model(Xg, m_away)
        except Exception:
            Xa = Xg

        mu_h = np.asarray(m_home.predict(Xh)).astype(float)
        mu_a = np.asarray(m_away.predict(Xa)).astype(float)

        df["home_goals_pred"] = np.clip(mu_h, 0.0, 5.0)
        df["away_goals_pred"] = np.clip(mu_a, 0.0, 5.0)
    except Exception:
        pass
    return df

def _poisson_1x2_from_lambdas(mu_h: np.ndarray, mu_a: np.ndarray, max_goals: int = 10) -> np.ndarray:
    """
    Convert per-match λ̂ (home/away) into [P(H), P(D), P(A)] using a finite
    Poisson grid up to *max_goals*. Returns an (n,3) matrix.
    """
    import numpy as _np
    from scipy.stats import poisson as _pois
    n = len(mu_h)
    out = _np.zeros((n, 3), dtype=float)
    grid = _np.arange(0, max_goals + 1)
    for i, (mh, ma) in enumerate(zip(mu_h, mu_a)):
        ph = _pois.pmf(grid, mh)
        pa = _pois.pmf(grid, ma)
        M = _np.outer(ph, pa)
        p_draw = _np.trace(M)
        p_home = _np.tril(M, k=-1).sum()
        p_away = _np.triu(M, k=+1).sum()
        s = p_home + p_draw + p_away
        if s > 0:
            out[i] = [p_home / s, p_draw / s, p_away / s]
    return out

def score_ftr_csv(league: str,
                  csv_path: str,
                  out_csv: str | None = None,
                  *,
                  tail: int = 25) -> pd.DataFrame:
    """
    Convenience scorer:
      • loads the FTR bundle for *league*
      • rebuilds features on *csv_path* using the same leak-safe transforms
      • predicts calibrated [P(H), P(D), P(A)]
      • blends with market-implied probs via saved α/β/cap (when available)
      • writes a compact CSV if *out_csv* is provided
    Returns the DataFrame of predictions.
    """
    import os, numpy as np, pandas as pd
    model, feats, mix = load_ftr_bundle(league)

    # --- Optional runtime overrides via environment variables -------------
    import os as _os
    # Disable draw-prior blend entirely (prevents "all D" when prior is degenerate)
    if _os.getenv("NO_DRAW_PRIOR", "0") == "1":
        mix["gamma"] = 0.0
    # Disable draw gate (never force D) – sets a threshold that cannot be reached
    if _os.getenv("NO_DRAW_GATE", "0") == "1":
        mix["threshold"] = 1.0
    # Override draw threshold if provided (e.g., 0.38)
    if "DRAW_THRESHOLD" in _os.environ:
        try:
            mix["threshold"] = float(_os.getenv("DRAW_THRESHOLD"))
        except Exception:
            pass

    raw = pd.read_csv(csv_path)
        # Best-effort: ensure per-match press-intensity enrichment exists on disk
    try:
        ensure_press_intensity_on_disk(os.path.dirname(csv_path), force=False)
    except Exception:
        # Non-fatal; rest of the pipeline is robust to missing press columns
        pass
    # ------------------------------------------------------------------
    # Fallback: enrich press‑intensity from Players/ season files when
    # the raw per‑match totals are absent. This provides the passes /
    # tackles / interceptions inputs required by `compute_press_intensity`
    # so we avoid the noisy “missing columns” warning during inference.
    # ------------------------------------------------------------------
    try:
        ensure_press_from_players_on_disk(os.path.dirname(csv_path))
    except Exception:
        # Non‑fatal; keeps inference robust even if enrichment is impossible
        pass
    df = apply_safe_renames_and_whitelist(raw)
    # ------------------------------------------------------------------
    # Re‑compute the full leak‑safe feature stack so that both the FTR
    # *and* draw‑only classifiers see the same engineered columns that
    # were available at training time (Elo, rolling form, press z‑scores,
    # odds‑parity helpers …).  Without this, the design matrix falls back
    # to SENTINEL‑filled placeholders which can drive extreme or constant
    # probabilities (e.g. p_draw_prior ≈ 1.0).
    # ------------------------------------------------------------------
    try:
        df = build_team_rolling_metrics(df)          # heavy‑weight enrich
        df = filter_small_sample_teams(df)           # keep leak‑safe filter parity
    except Exception as _fe_err:
        # Fail‑soft – still return raw rename frame so inference never crashes.
        warnings.warn(f'Feature‑engine rebuild failed inside score_ftr_csv → {_fe_err}', RuntimeWarning)

    # Attach goal λ̂ if the models exist so Poisson overlay can run
    try:
        df = _attach_goal_predictions_if_available(df, league, model_root="ModelStore")
    except Exception:
        pass
    # Ensure proper dtype before any chronological operations
    if "match_date" in df.columns:
        df["match_date"] = pd.to_datetime(df["match_date"], errors="coerce")

    # Score the most recent *tail* fixtures with a valid date
    df_sc = df.sort_values("match_date", na_position="last").tail(tail).copy()

    # Design matrix aligned to the training schema
    if feats:
        X = _align_design_matrix(df_sc, feats)
    else:
        # Fallback: use all numeric features if feature list wasn't saved
        X = df_sc.select_dtypes(include=["number"]).replace([np.inf, -np.inf], np.nan)
        X = safe_fill(X, X.columns.tolist(), SENTINEL)

    proba = np.asarray(model.predict_proba(X))
    # Optional: overlay with Poisson 1X2 derived from goal λ̂ to sharpen probs
    if {"home_goals_pred","away_goals_pred"}.issubset(df_sc.columns):
        try:
            pois_mat = _poisson_1x2_from_lambdas(
                df_sc["home_goals_pred"].values,
                df_sc["away_goals_pred"].values
            )
            if np.isfinite(pois_mat).all():
                proba = (1.0 - POISSON_BLEND) * proba + POISSON_BLEND * pois_mat
        except Exception:
            pass
    assert_prob_matrix_shape(proba)

    # Optional: blend with market-implied probabilities if odds exist
    implied = None
    trio = {"odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win"}
    if trio.issubset(df_sc.columns):
        oH = df_sc["odds_ft_home_team_win"].replace(0, np.nan)
        oD = df_sc["odds_ft_draw"].replace(0, np.nan)
        oA = df_sc["odds_ft_away_team_win"].replace(0, np.nan)
        iph_raw, ipd_raw, ipa_raw = 1.0 / oH, 1.0 / oD, 1.0 / oA
        denom = (iph_raw + ipd_raw + ipa_raw)
        iph, ipd, ipa = iph_raw / denom, ipd_raw / denom, ipa_raw / denom
        implied = np.column_stack([iph, ipd, ipa]).astype(float)
        # any invalid rows → fall back to model proba
        bad = ~np.isfinite(implied).all(1)
        implied[bad] = proba[bad]
    # Optional: draw-prior from the dedicated draw classifier (if enabled)
    draw_prior = predict_draw_prior(df_sc, league) if float(mix.get("gamma", 0.0)) > 0.0 else None
    proba_mix = apply_ftr_mix(
    proba,
    alpha=mix.get("alpha", 1.0),
    beta=mix.get("beta", 0.0),
    cap=mix.get("cap", 0.45),
    implied=implied,
    draw_prior=draw_prior,
    gamma=mix.get("gamma", 0.50),
)

    labels = np.array(["H", "D", "A"])
    out = df_sc[["match_date", "home_team_name", "away_team_name"]].copy()
    out[["p_home", "p_draw", "p_away"]] = proba_mix
    if draw_prior is not None:
        out["p_draw_prior"] = draw_prior
    out["pick_raw"] = labels[proba_mix.argmax(1)]

    # --- Gate application (honor NO_DRAW_GATE as a hard bypass) -------------
    import os as _os
    if _os.getenv("NO_DRAW_GATE", "0") == "1":
        # Gate disabled: mirror raw picks, force gate flag to False.
        out["pick_thr"] = out["pick_raw"]
        out["p_draw_gate"] = False
        out["pick_gate"] = out["pick_raw"]
    else:
        thr = float(mix.get("threshold", 0.30))
        out["p_draw_gate"] = proba_mix[:, 1] >= thr
        out["pick_thr"] = np.where(out["p_draw_gate"], "D", out["pick_raw"])
        out["pick_gate"] = out["pick_thr"]

    # --- Final safety override: if NO_DRAW_GATE=1, enforce bypass just before output ---
    if _os.getenv("NO_DRAW_GATE", "0") == "1":
        out["pick_thr"] = out["pick_raw"]
        out["p_draw_gate"] = False
        out["pick_gate"] = out["pick_raw"]

    if out_csv:
        os.makedirs(os.path.dirname(out_csv) or ".", exist_ok=True)
        out.to_csv(out_csv, index=False)

    return out

# --------------------------------------------------------------
# Quick grid-search helper for FTR decision-threshold tuning
# --------------------------------------------------------------
def grid_search_thresholds(proba: np.ndarray,
                           y_true: np.ndarray,
                           metric: str = "accuracy"):
    """
    One-dimensional search for the best draw-decision threshold.
    Maximises overall 3-way accuracy by default.
    """
    cuts = np.round(np.linspace(0.02, 0.25, 47), 3)   # 0.02 → 0.25 step ≈0.005
    best_cut, best_val = 0.25, 0.0
    for c in cuts:
        pred = np.argmax(proba * (proba >= c), axis=1)
        acc  = (pred == y_true).mean()
        if acc > best_val:
            best_val, best_cut = acc, c
    return best_cut, best_val
# ------------------------------------------------------------------
# Helper: Ensure every probability matrix is 3‑column (Home/Draw/Away)
# ------------------------------------------------------------------
def pad_prob_matrix(mat, present_classes):
    """
    Assert that *mat* is already a well‑formed (n_samples, 3) probability
    matrix. If the shape deviates we raise immediately – no silent padding.
    """
    import numpy as np
    mat = np.atleast_2d(mat)
    assert_prob_matrix_shape(mat)          # hard exit on malformed shape
    return mat

# -------------------------------------------------------------------
# Minimal normalisation + safety: unify key columns and ensure FTR
# -------------------------------------------------------------------

def _first_present(df: pd.DataFrame, *names: str) -> str | None:
    """Return the first column name that exists on *df* from *names* (or None)."""
    for n in names:
        if n in df.columns:
            return n
    return None


def ensure_FTR_column(df: pd.DataFrame) -> pd.DataFrame:
    """
    Ensure an integer-encoded `FTR` column exists with mapping {0=Home,1=Draw,2=Away}.
    Sources tried (in order):
      • textual result columns (H/D/A) → map to 0/1/2
      • numeric goal counts → derive FTR
    Rows where FTR cannot be determined are left untouched here – the training
    harness can filter them afterwards.
    """
    df = df.copy()

    # 1) Textual result → numeric (H/D/A → 0/1/2)
    text_col = _first_present(df, 'FTR', 'ftr', 'full_time_result', 'ft_result', 'result', 'Result')
    if text_col is not None and 'FTR' not in df.columns:
        m = df[text_col].astype(str).str.upper().str[0]
        mapped = m.map({'H': 0, 'D': 1, 'A': 2})
        # Only create if we actually mapped something meaningful
        if mapped.notna().any():
            df['FTR'] = mapped.astype('float')  # temporary float; cast below

    # 2) From goal counts when available
    if 'FTR' not in df.columns or df['FTR'].isna().any():
        home_g = _first_present(
            df,
            'home_team_goal_count', 'FTHG', 'home_goals', 'home_score',
            'Home Team Goals', 'home_team_score'
        )
        away_g = _first_present(
            df,
            'away_team_goal_count', 'FTAG', 'away_goals', 'away_score',
            'Away Team Goals', 'away_team_score'
        )
        if home_g and away_g:
            hh = pd.to_numeric(df[home_g], errors='coerce')
            aa = pd.to_numeric(df[away_g], errors='coerce')
            derived = np.where(hh > aa, 0, np.where(hh < aa, 2, 1))
            if 'FTR' in df.columns:
                mask = df['FTR'].isna()
                df.loc[mask, 'FTR'] = derived[mask]
            else:
                df['FTR'] = derived

    # Final type: clean to int where possible
    if 'FTR' in df.columns:
        df['FTR'] = pd.to_numeric(df['FTR'], errors='coerce')
        # Leave NaNs as-is (training function may filter by completed fixtures)
        try:
            df['FTR'] = df['FTR'].astype('Int64')
        except Exception:
            # Fallback to plain int with NaNs filled by -1 (filtered later)
            df['FTR'] = df['FTR'].fillna(-1).astype(int)

    return df


def apply_safe_renames_and_whitelist(df: pd.DataFrame) -> pd.DataFrame:
    """
    Lightweight, leak-safe normaliser used before training:
      • renames common variants of match_date / team / goals columns to the
        canonical names expected by the pipeline;
      • ensures `FTR` exists via `ensure_FTR_column`;
      • converts match_date to datetime when present.
    This function intentionally does **not** drop columns; the downstream
    leak-stripping / variance-threshold steps handle pruning.
    """
    df = df.copy()

    # --- match_date normalisation ---
    date_col = _first_present(df, 'match_date', 'Date', 'date', 'date_GMT', 'fixture_date')
    if date_col and date_col != 'match_date':
        df = df.rename(columns={date_col: 'match_date'})
    if 'match_date' in df.columns:
        try:
            df['match_date'] = pd.to_datetime(df['match_date'], errors='coerce')
        except Exception:
            pass

    # --- team name columns ---
    home_col = _first_present(
        df, 'home_team_name', 'Home Team', 'home_team', 'home', 'homeTeam',
        'team_home', 'home_club', 'Home'
    )
    away_col = _first_present(
        df, 'away_team_name', 'Away Team', 'away_team', 'away', 'awayTeam',
        'team_away', 'away_club', 'Away'
    )
    ren = {}
    if home_col and home_col != 'home_team_name':
        ren[home_col] = 'home_team_name'
    if away_col and away_col != 'away_team_name':
        ren[away_col] = 'away_team_name'
    if ren:
        df = df.rename(columns=ren)

    # --- goal count columns ---
    hg = _first_present(df, 'home_team_goal_count', 'FTHG', 'home_goals', 'home_score', 'Home Team Goals', 'home_team_score')
    ag = _first_present(df, 'away_team_goal_count', 'FTAG', 'away_goals', 'away_score', 'Away Team Goals', 'away_team_score')
    ren = {}
    if hg and hg != 'home_team_goal_count':
        ren[hg] = 'home_team_goal_count'
    if ag and ag != 'away_team_goal_count':
        ren[ag] = 'away_team_goal_count'
    if ren:
        df = df.rename(columns=ren)

    # Ensure numeric types for goals when present
    for gcol in ('home_team_goal_count', 'away_team_goal_count'):
        if gcol in df.columns:
            df[gcol] = pd.to_numeric(df[gcol], errors='coerce')

    # --- guarantee FTR exists (0/1/2) ---
    df = ensure_FTR_column(df)

    return df
# -------------------------------------------------------------------
# Utility: filter out teams with very small sample size
# -------------------------------------------------------------------
def filter_small_sample_teams(df, min_games=7):
    """
    Filter out rows where either home or away team has played fewer than `min_games`.
    Requires columns 'games_played_home' and 'games_played_away'.
    """
    if "games_played_home" in df.columns:
        df = df[df["games_played_home"] >= min_games]
    if "games_played_away" in df.columns:
        df = df[df["games_played_away"] >= min_games]
    return df

# -------------------------------------------------------------------
# Helper: compute full‑pitch press‑intensity proxy (PPDA‑like)
# -------------------------------------------------------------------
def add_press_intensity_proxy(df: pd.DataFrame) -> pd.DataFrame:
    """
    Add proxy press‑intensity columns at match level.

    The metric is:
        press_intensity = opponent_total_passes / defensive_actions

    where defensive_actions = tackles + interceptions (+ pressures if available).

    Expected per‑match columns
        home_passes_total,      away_passes_total
        home_tackles_total,     away_tackles_total
        home_interceptions_total, away_interceptions_total
        (optional) home_pressures_total, away_pressures_total

    If any core column is missing the function exits early so the
    rest of the pipeline remains robust.
    """
    core_cols = [
        'home_passes_total', 'away_passes_total',
        'home_tackles_total', 'away_tackles_total',
        'home_interceptions_total', 'away_interceptions_total'
    ]
    if not all(c in df.columns for c in core_cols):
        # silently no‑op – rolling metrics will fall back to NaNs
        return df

    for side in ('home', 'away'):
        passes = df[f'{side}_passes_total']
        def_actions = (
            df[f'{side}_tackles_total'].fillna(0) +
            df[f'{side}_interceptions_total'].fillna(0)
        )
        press_col = f'{side}_pressures_total'
        if press_col in df.columns:
            def_actions += df[press_col].fillna(0)

        with np.errstate(divide='ignore', invalid='ignore'):
            df[f'{side}_press_intensity'] = (
                passes /
                def_actions.replace(0, np.nan)
            )

    return df

# -------------------------------------------------------------------
# Helper: compute overround-corrected implied probs and parity features from 1X2 odds
# -------------------------------------------------------------------
def add_odds_parity_features(df: pd.DataFrame) -> pd.DataFrame:
    """Compute overround-corrected implied probs and parity features from 1X2 odds."""
    trio = {"odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win"}
    if not trio.issubset(df.columns):
        return df
    oH = df["odds_ft_home_team_win"].replace(0, np.nan)
    oD = df["odds_ft_draw"].replace(0, np.nan)
    oA = df["odds_ft_away_team_win"].replace(0, np.nan)
    with np.errstate(divide='ignore', invalid='ignore'):
        iph_raw = 1.0 / oH
        ipd_raw = 1.0 / oD
        ipa_raw = 1.0 / oA
    denom = (iph_raw + ipd_raw + ipa_raw)
    with np.errstate(divide='ignore', invalid='ignore'):
        iph = iph_raw / denom
        ipd = ipd_raw / denom
        ipa = ipa_raw / denom
    # Core features (only create if missing to stay idempotent)
    if "draw_implied" not in df.columns:
        df["draw_implied"] = ipd
    if "implied_prob_diff" not in df.columns:
        df["implied_prob_diff"] = (iph - ipa).abs()
    if "odds_diff" not in df.columns:
        df["odds_diff"] = (oH - oA).abs()
    if "odds_parity" not in df.columns:
        df["odds_parity"] = 1.0 - (iph - ipa).abs()
    if "odds_skew" not in df.columns:
        df["odds_skew"] = iph - ipa
    if "odds_entropy" not in df.columns:
        P = np.vstack([iph.values, ipd.values, ipa.values]).T
        with np.errstate(divide='ignore', invalid='ignore'):
            ent = -(P * np.log(P)).sum(axis=1)
        df["odds_entropy"] = ent
    if "odds_closeness" not in df.columns:
        df["odds_closeness"] = np.minimum(iph, ipa)
    return df

# -------------------------------------------------------------------
# Helper: build rolling-window & EWM team metrics without look-ahead
# -------------------------------------------------------------------
# ------------------------------------------------------------------
# Helper: lagged rolling mean for press-intensity (live fallback)
# ------------------------------------------------------------------
def add_rolling_mean(df: pd.DataFrame,
                     cols: list[str],
                     *,
                     window: int = 5,
                     shift: int = 1) -> pd.DataFrame:
    """
    Compute a lagged rolling mean for each column in *cols*.

    For every fixture we take the previous *window* matches for the
    same team (shifted by *shift* so the current fixture itself is
    excluded) and write the mean back into the original column.  
    The function is idempotent and safe on empty dataframes.
    """
    if df.empty or "match_date" not in df.columns:
        return df

    df = df.sort_values("match_date").copy()
    HOME, AWAY = "home_team_name", "away_team_name"

    # Ensure the columns exist
    for col in cols:
        if col not in df.columns:
            df[col] = np.nan

    for side, team_col in (("home", HOME), ("away", AWAY)):
        base_col = f"{side}_press_intensity"
        if base_col in cols:
            df[base_col] = (
                df.groupby(team_col)[base_col]
                  .apply(lambda s: s.shift(shift).rolling(window, min_periods=1).mean())
                  .reset_index(level=0, drop=True)
            )
    return df
def _has_degenerate_press_cols(df):
    """
    Return True if both home/away_press_intensity are missing or effectively constant.
    """
    import numpy as _np
    import pandas as _pd
    if df is None or len(df) == 0:
        return True

    def _deg(series):
        s = _pd.Series(series)
        if s.empty:
            return True
        s = s.replace([_np.inf, -_np.inf], _np.nan)
        try:
            from constants import SENTINEL as _S
            s = s.mask(s == _S)
        except Exception:
            pass
        return s.nunique(dropna=True) <= 1

    return _deg(df.get("home_press_intensity")) and _deg(df.get("away_press_intensity"))


def _ensure_press_columns(match_dir: str, df: 'pd.DataFrame') -> 'pd.DataFrame':
    """
    Ensure home_press_intensity/away_press_intensity exist and are non-degenerate.

    Strategy:
      1) If missing, try in-memory compute via _pi_compute (alias-aware).
      2) If still missing OR degenerate, run disk ETL (no cache, overwrite).
      3) Final fallback: copy from *_press_baseline if present.
    Always returns a DataFrame (original or enriched).
    """
    import pandas as _pd
    if df is None or len(df) == 0:
        return df

    # Step 1: local compute (in-memory)
    need = not {"home_press_intensity", "away_press_intensity"}.issubset(df.columns)
    if need and _pi_compute is not None:
        try:
            df_pi = _pi_compute(df)
            if "match_id" in df.columns and "match_id" in df_pi.columns:
                df = df.merge(df_pi, on="match_id", how="left")
            else:
                for _c in ("home_press_intensity", "away_press_intensity"):
                    if _c in df_pi.columns and _c not in df.columns:
                        df[_c] = df_pi[_c].values
            need = False
        except Exception:
            pass

    # Step 2: disk ETL with no cache if still missing or degenerate
    if (need or _has_degenerate_press_cols(df)) and _pi_run is not None:
        try:
            _pi_run(
                match_dir,
                force=True,
                overwrite_intensity=True,
                use_cache=False,          # ← bypass any stale/flat cache
                overwrite_baseline=True,
                debug_attach=False
            )
            # We don't reload from disk here; downstream builders
            # will re-read season CSVs if needed.
        except Exception:
            pass

    # Step 3: baseline proxy fallback
    for _side in ("home", "away"):
        pi = f"{_side}_press_intensity"
        pb = f"{_side}_press_baseline"
        if pi not in df.columns and pb in df.columns:
            df[pi] = df[pb]

    return df

# ------------------------------------------------------------------
# Robust CV helpers for goal regressors (season-aware, safe on strings)
# ------------------------------------------------------------------
def _safe_season_start_year(val):
    """
    Coerce a season label to the start year as an int.
    Accepts '2018', '2018/2019', '2018-2019', '2018–2019', '2018 to 2019'.
    Returns np.nan when unparseable.
    """
    import re, numpy as _np
    if val is None:
        return _np.nan
    s = str(val).strip()
    if not s:
        return _np.nan
    m = re.search(r'^((?:19|20)\d{2})\s*(?:[/_\-–]|\s+to\s+)\s*((?:19|20)\d{2})$', s, flags=re.IGNORECASE)
    if m:
        return int(m.group(1))
    m = re.search(r'^((?:19|20)\d{2})$', s)
    if m:
        return int(m.group(1))
    return _np.nan

def _safe_stratified_split(X_df, y_raw, n_splits):
    """
    Build a CV iterator robust to string/int season labels.
    Prefers df['season_start_year'] when present; otherwise factorizes y_raw.
    Ensures folds are valid given class counts.
    Returns a *list* of (train_idx, val_idx) tuples.
    """
    import numpy as _np
    import pandas as _pd
    from sklearn.model_selection import StratifiedKFold, KFold

    # 1) Prefer numeric season_start_year if present on the DataFrame
    if isinstance(X_df, _pd.DataFrame) and "season_start_year" in X_df.columns:
        labs = _pd.to_numeric(X_df["season_start_year"], errors="coerce")
    else:
        # try to coerce string labels via helper; else factorize
        s = _pd.Series(y_raw)
        try:
            labs = s.apply(_safe_season_start_year)
        except Exception:
            labs = _pd.Series([_np.nan] * len(s))

    # If still non-numeric or NaNs remain, factorize the raw labels
    if _pd.isna(labs).any():
        s2 = _pd.Series(y_raw).astype(str)
        codes, _uniques = _pd.factorize(s2.fillna("MISSING"))
        y = _np.asarray(codes, dtype=int)
    else:
        y = _np.asarray(labs.fillna(-1)).astype(int)

    n = len(y)
    if n == 0:
        return []

    uniq = _np.unique(y)
    dummy_X = _np.zeros(n, dtype=float)

    # If only one class present, fall back to plain KFold
    if uniq.size < 2:
        k = int(max(2, min(n_splits, n)))
        return list(KFold(n_splits=k, shuffle=True, random_state=42).split(dummy_X))

    # Compute the maximum feasible number of folds given the smallest class
    counts = _np.bincount(y)
    counts = counts[counts > 0]
    min_class = int(counts.min()) if counts.size else 1
    k = int(max(2, min(n_splits, min_class)))

    skf = StratifiedKFold(n_splits=k, shuffle=True, random_state=42)
    return list(skf.split(dummy_X, y))


def build_team_rolling_metrics(df: pd.DataFrame, windows=(5, 10)):
    """
    Populate rolling‑window & EWM features WITHOUT look‑ahead leakage.

    All calculations are:
      • grouped by the appropriate team,
      • shifted by 1 so the current fixture never sees itself,
      • min_periods=1 so early‑season rows still receive a value.

    Generated columns:
        rolling{5/10}_{home/away}_shots
        rolling{5/10}_{home/away}_sot_ratio
        rolling{5/10}_{home/away}_card_ratio
        ewm10_{home/away}_possession
    """
    if df.empty:
        return df

    # --------------------------------------------------------------
    # On historic rows we can compute full press-intensity from the
    # detailed event logs.  During live inference we skip this heavy
    # post-match ETL and rely on rolling proxies instead.
    # --------------------------------------------------------------
    if not globals().get("IS_LIVE_INFERENCE", False):
        # If intensities aren't present, try local alias compute first,
        # then fall back to the external ETL helper, and finally copy
        # from season baselines when available.
        if not {"home_press_intensity", "away_press_intensity"}.issubset(df.columns):
            # ① Try to derive from any *_passes/tackles/interceptions_* aliases already on the match frame
            try:
                df = _compute_press_from_totals(df)
            except Exception:
                pass

            # ② If still missing, call the external ETL helper (expects FootyStats-style *_overall_* names)
            if not {"home_press_intensity", "away_press_intensity"}.issubset(df.columns):
                try:
                    if _pi_compute is not None:
                        df = _pi_compute(df)  # enrich with post-match metric
                    else:
                        raise RuntimeError("press-intensity helper unavailable")
                except Exception as _pi_err:
                    if VERBOSE_PRESS:
                        print(f"⚠️  Press-intensity ETL failed/skipped: {_pi_err}")

            # ③ Final fallback: promote per-season baselines (if present) to intensity proxies
            for _side in ("home", "away"):
                pi = f"{_side}_press_intensity"
                pb = f"{_side}_press_baseline"
                if pi not in df.columns and pb in df.columns:
                    df[pi] = df[pb]

        # If intensities exist but are degenerate (one value / sentinel), try to rebuild from totals
        def _degenerate_series(series: pd.Series) -> bool:
            s = pd.Series(series)
            if s.empty:
                return True
            s = s.replace([np.inf, -np.inf], np.nan)
            try:
                from constants import SENTINEL as _S
                s = s.mask(s == _S)
            except Exception:
                pass
            return s.nunique(dropna=True) <= 1

        try_rebuild = (
            "home_press_intensity" in df.columns and "away_press_intensity" in df.columns and
            _degenerate_series(df.get("home_press_intensity")) and _degenerate_series(df.get("away_press_intensity"))
        )
        if try_rebuild:
            try:
                df_try = _compute_press_from_totals(df.copy())
                ok = not (_degenerate_series(df_try.get("home_press_intensity")) and _degenerate_series(df_try.get("away_press_intensity")))
                if ok:
                    df = df_try
                    if VERBOSE_PRESS:
                        print("[press] build_team_rolling_metrics: replaced degenerate intensities with totals-derived values")
            except Exception:
                pass

        if VERBOSE_PRESS:
            try:
                _hp = int(pd.Series(df.get("home_press_intensity")).notna().sum())
                _ap = int(pd.Series(df.get("away_press_intensity")).notna().sum())
                print(f"[press] build_team_rolling_metrics: non-null counts — home={_hp}, away={_ap}")
            except Exception:
                pass
    else:
        # Live inference – replace raw NaNs with a lagged rolling mean
        for _c in ("home_press_intensity", "away_press_intensity"):
            if _c not in df.columns:
                df[_c] = np.nan
        df = add_rolling_mean(
            df,
            cols=["home_press_intensity", "away_press_intensity"],
            window=5,
            shift=1
        )
    # ── parity / fatigue helpers (Elo, rest‑days, EWMA‑PPG) ──────────
    # These helpers are fully lagged, so they remain leak‑safe.
    df = add_elo_features(df)
    df = add_rest_days(df)
    df = add_ewma_ppg(df)

    # Inject press‑intensity proxy columns if the upstream ETL hasn’t
    # provided them yet.  This keeps the rolling‑metric code below
    # leak‑free and avoids placeholder NaNs where the data exists.
    df = add_press_intensity_proxy(df)

    # Market/odds parity enrichments (overround-corrected)
    df = add_odds_parity_features(df)

    # ------------------------------------------------------------------
    # Guard‑rail: ensure every raw stat column needed below exists.
    # When a column is missing, create it filled with NaNs so the later
    # .groupby() / arithmetic never raises a KeyError.  Using NaN keeps
    # the rolling means unbiased (they’ll naturally ignore NaNs).
    # ------------------------------------------------------------------
    _raw_stats_required = [
        "home_team_shots", "away_team_shots",
        "home_team_shots_on_target", "away_team_shots_on_target",
        "home_team_yellow_cards", "away_team_yellow_cards",
        "home_team_red_cards", "away_team_red_cards",
        "home_team_fouls", "away_team_fouls",
        "home_team_possession", "away_team_possession"
    ]
    for _col in _raw_stats_required:
        if _col not in df.columns:
            df[_col] = np.nan

    df = df.sort_values("match_date").copy()

    HOME, AWAY = "home_team_name", "away_team_name"

    for w in windows:
        # ── rolling TOTAL shots ────────────────────────────────────────
        df[f"rolling{w}_home_shots"] = (
            df.groupby(HOME)["home_team_shots"]
              .apply(lambda s: s.shift(1).rolling(w, min_periods=1).mean())
              .reset_index(level=0, drop=True)
        )
        df[f"rolling{w}_away_shots"] = (
            df.groupby(AWAY)["away_team_shots"]
              .apply(lambda s: s.shift(1).rolling(w, min_periods=1).mean())
              .reset_index(level=0, drop=True)
        )

        # ── rolling SOT / shots ratio ─────────────────────────────────
        def _sot_ratio(shot_col, sot_col, team_col):
            shots = df[shot_col].replace(0, np.nan)
            ratio = (df[sot_col] / shots).shift(1)
            return (
                ratio.groupby(df[team_col])
                     .rolling(w, min_periods=1).mean()
                     .reset_index(level=0, drop=True)
            )

        df[f"rolling{w}_home_sot_ratio"] = _sot_ratio(
            "home_team_shots", "home_team_shots_on_target", HOME
        )
        df[f"rolling{w}_away_sot_ratio"] = _sot_ratio(
            "away_team_shots", "away_team_shots_on_target", AWAY
        )

        # ── rolling CARD / foul ratio ─────────────────────────────────
        def _card_ratio(yel, red, foul, team_col):
            cards = (df[yel] + df[red]).replace(0, np.nan)
            fouls = df[foul].replace(0, np.nan)
            ratio = (cards / fouls).shift(1)
            return (
                ratio.groupby(df[team_col])
                     .rolling(w, min_periods=1).mean()
                     .reset_index(level=0, drop=True)
            )

        df[f"rolling{w}_home_card_ratio"] = _card_ratio(
            "home_team_yellow_cards", "home_team_red_cards",
            "home_team_fouls", HOME
        )
        df[f"rolling{w}_away_card_ratio"] = _card_ratio(
            "away_team_yellow_cards", "away_team_red_cards",
            "away_team_fouls", AWAY
        )

        # ── rolling press-intensity proxy (full-pitch PPDA) ────────────
        # Ensure per-match press-intensity columns exist so the groupby never fails
        for col in ("home_press_intensity", "away_press_intensity"):
            if col not in df.columns:
                df[col] = np.nan  # placeholder when ETL hasn’t run yet

        df[f"rolling{w}_home_press_intensity"] = (
            df.groupby(HOME)["home_press_intensity"]
              .apply(lambda s: s.shift(1).rolling(w, min_periods=1).mean())
              .reset_index(level=0, drop=True)
        )
        df[f"rolling{w}_away_press_intensity"] = (
            df.groupby(AWAY)["away_press_intensity"]
              .apply(lambda s: s.shift(1).rolling(w, min_periods=1).mean())
              .reset_index(level=0, drop=True)
        )
        df[f"rolling{w}_press_intensity_diff"] = (
            df[f"rolling{w}_home_press_intensity"] -
            df[f"rolling{w}_away_press_intensity"]
        )

    # --- Un-flatten press z-scores: compute z BEFORE any sentinel fill, ignoring SENTINEL ---
    def _z_ignore_sentinel(s: pd.Series) -> pd.Series:
        try:
            from constants import SENTINEL as _S
            s = s.mask(s == _S)
        except Exception:
            pass
        mu = s.mean()
        sd = s.std(ddof=0)
        if pd.isna(sd) or sd == 0:
            return pd.Series(np.nan, index=s.index)
        return (s - mu) / sd

    # Standardise within season when labels exist; else, standardise globally.
    if "season_start_year" in df.columns:
        _grp = ["season_start_year"]
    elif "season" in df.columns:
        _grp = ["season"]
    else:
        _grp = None

    _win_list = list(windows) if isinstance(windows, (list, tuple)) else [windows]
    for _w in _win_list:
        for _side, _team_col in (("home", HOME), ("away", AWAY)):
            _base = f"rolling{_w}_{_side}_press_intensity"
            _zcol = f"rolling{_w}_{_side}_press_z"
            if _base in df.columns:
                if _grp:
                    df[_zcol] = (
                        df.groupby(_grp)[_base]
                          .transform(lambda s: _z_ignore_sentinel(s))
                    )
                else:
                    df[_zcol] = _z_ignore_sentinel(df[_base])
        # z-diff (home minus away) when both z columns exist
        _hz, _az = f"rolling{_w}_home_press_z", f"rolling{_w}_away_press_z"
        if _hz in df.columns and _az in df.columns:
            df[f"rolling{_w}_press_z_diff"] = df[_hz] - df[_az]

    # --- rolling 5‑match win differential ---------------------------

    # --- rolling 5‑match win differential ---------------------------
    if 'FTR' in df.columns:
        # 0 = Home Win, 2 = Away Win   (Draw = 1)
        df['is_home_win'] = (df['FTR'] == 0).astype(int)
        df['is_away_win'] = (df['FTR'] == 2).astype(int)

        df['rolling5_home_wins'] = (
            df.groupby(HOME)['is_home_win']
              .apply(lambda s: s.shift(1).rolling(5, min_periods=1).sum())
              .reset_index(level=0, drop=True)
        )
        df['rolling5_away_wins'] = (
            df.groupby(AWAY)['is_away_win']
              .apply(lambda s: s.shift(1).rolling(5, min_periods=1).sum())
              .reset_index(level=0, drop=True)
        )
        # Positive ⇒ home on a better recent streak, negative ⇒ away stronger
        df['recent_win_diff'] = df['rolling5_home_wins'] - df['rolling5_away_wins']

    # --- head‑to‑head draw rate (last 5 mutual matches) -----------------
    if {'home_team_name', 'away_team_name', 'FTR'}.issubset(df.columns):
        # Order‑agnostic fixture key so H2H history accumulates for both directions
        df['_h2h_key'] = df.apply(
            lambda r: tuple(sorted((r['home_team_name'], r['away_team_name']))),
            axis=1
        )
        df['h2h_draw_rate'] = 0.0
        for _key, _grp in df.groupby('_h2h_key', sort=False):
            # shift(1) ⇒ current match never sees its own label
            _rate = (
                (_grp['FTR'] == 1).astype(int)
                .shift(1)
                .rolling(5, min_periods=1)
                .mean()
            )
            df.loc[_grp.index, 'h2h_draw_rate'] = _rate
        df.drop(columns='_h2h_key', inplace=True)

    # ── EWM‑10 possession baseline ────────────────────────────────────
    for side, team_col, pos_col in (
        ("home", HOME, "home_team_possession"),
        ("away", AWAY, "away_team_possession"),
    ):
        df[f"ewm10_{side}_possession"] = (
            df.groupby(team_col)[pos_col]
              .apply(lambda s: s.shift(1).ewm(span=10, min_periods=1).mean())
              .reset_index(level=0, drop=True)
        )


    # ── NEW parity & low‑tempo helpers (Aug 2025) ────────────────────
    # Absolute xG differential – small values ⇒ parity ⇒ draw‑prone
    if "xg_diff" in df.columns and "xg_diff_abs" not in df.columns:
        df["xg_diff_abs"] = df["xg_diff"].abs()

    # Recent rolling‑5 xG parity (uses gaps created earlier in this func)
    if {"rolling5_home_xg_gap", "rolling5_away_xg_gap"}.issubset(df.columns) \
       and "recent_xg_diff_abs" not in df.columns:
        df["recent_xg_diff_abs"] = (
            df["rolling5_home_xg_gap"] - df["rolling5_away_xg_gap"]
        ).abs()

    # Flag – both teams press below the league‑wide 40th percentile
    low_press_cols = {"rolling5_home_press_intensity",
                      "rolling5_away_press_intensity"}
    if low_press_cols.issubset(df.columns) and "pressed_vs_pressed" not in df.columns:
        _press_vals = pd.concat([
            df["rolling5_home_press_intensity"],
            df["rolling5_away_press_intensity"]
        ])
        _low_cut = _press_vals.quantile(0.40)
        df["pressed_vs_pressed"] = (
            (df["rolling5_home_press_intensity"] < _low_cut) &
            (df["rolling5_away_press_intensity"] < _low_cut)
        ).astype(int)

    # --- mutual low‑form flag (both teams in a slump) ---------------
    if {"home_ewma_ppg", "away_ewma_ppg"}.issubset(df.columns) and \
       "both_slumping" not in df.columns:
        df["both_slumping"] = (
            (df["home_ewma_ppg"] < 1.0) &
            (df["away_ewma_ppg"] < 1.0)
        ).astype(int)
    # --------------------------------------------------------------
    # Ensure draw-ready prematch features exist (leak-safe)
    # Adds press z-score features so train & inference match
    # --------------------------------------------------------------
    def ensure_draw_ready_features(df: pd.DataFrame) -> pd.DataFrame:
        """
        Minimal, leak-safe enrichment used by both training & inference.
        Currently focuses on league-/season-normalised press-intensity
        z-scores derived from the rolling-5 press features built earlier
        in this pipeline.

        Creates the following when the base columns are available:
          • rolling5_home_press_z
          • rolling5_away_press_z
          • rolling5_press_z_diff = home_z - away_z

        Grouping is done within-season when a season column is present
        ("season", "Season", or "season_name"); otherwise global.
        """
        req = {"rolling5_home_press_intensity", "rolling5_away_press_intensity"}
        if not req.issubset(df.columns):
            return df

        # Already present? keep idempotent
        if {"rolling5_home_press_z", "rolling5_away_press_z", "rolling5_press_z_diff"}.issubset(df.columns):
            return df

        # Choose a grouping key if available
        grp_key = None
        for cand in ("season", "Season", "season_name"):
            if cand in df.columns:
                grp_key = cand
                break

        def _z(s: pd.Series) -> pd.Series:
            # mask sentinel before computing μ/σ, otherwise variance collapses
            try:
                from constants import SENTINEL as _S
                s = s.mask(s == _S)
            except Exception:
                pass
            mu = s.mean()
            sd = s.std(ddof=0)
            if pd.isna(sd) or sd == 0:
                return pd.Series(np.nan, index=s.index)
            return (s - mu) / sd

        if grp_key:
            df["rolling5_home_press_z"] = (
                df.groupby(grp_key)["rolling5_home_press_intensity"].transform(_z)
            )
            df["rolling5_away_press_z"] = (
                df.groupby(grp_key)["rolling5_away_press_intensity"].transform(_z)
            )
        else:
            df["rolling5_home_press_z"] = _z(df["rolling5_home_press_intensity"]) 
            df["rolling5_away_press_z"] = _z(df["rolling5_away_press_intensity"]) 

        df["rolling5_press_z_diff"] = (
            df["rolling5_home_press_z"] - df["rolling5_away_press_z"]
        )

        return df
    # --- Ensure draw-ready prematch features are present (leak-safe) ---
    try:
        df = ensure_draw_ready_features(df)
    except NameError:
        # If ensure_draw_ready_features isn't defined yet at import time,
        # fail-soft so the pipeline still runs.
        pass
    # Clean NaNs / infs **after** creating z-scores so they don't get flattened
    df.replace([np.inf, -np.inf], np.nan, inplace=True)
    df = safe_fill(df, df.columns.tolist(), SENTINEL)
    return df

def _safe_season_start_year(val) -> int | None:
    """
    Best-effort coercion of season labels into a start-year integer.
    Accepts '2024-25', '2024-2024', '2024/25', '2024', etc.
    Returns None when unparsable.
    """
    s = str(val)
    if not s or s.strip().lower() in {"nan", "none"}:
        return None
    yrs = re.findall(r"\d{4}", s)
    try:
        return int(yrs[0]) if yrs else None
    except Exception:
        return None
    
    # --- Persist single-file goal models for inference overlay (bag of folds) ---
try:
    class _FoldAvgReg:
        def __init__(self, models):
            self.models = [m for m in models if m is not None]
        def predict(self, X):
            import numpy as _np
            preds = []
            for m in self.models:
                try:
                    preds.append(m.predict(X))
                except Exception:
                    continue
            if not preds:
                return _np.zeros(len(X), dtype=float)
            M = _np.column_stack(preds)
            return M.mean(axis=1)

    tag = str(league_name).replace(" ", "_")
    os.makedirs(MODEL_DIR, exist_ok=True)
    try:
        _persist_goal_pair(
            _FoldAvgReg(locals()["fold_models_home"]),
            _FoldAvgReg(locals()["fold_models_away"]),
            tag,
        )
    except Exception:
        pass
except Exception as _persist_err:
    if VERBOSE_MODELSTORE:
        print(f"⚠️  Persisting goal models failed: {_persist_err}")

def quick_fit_goal_regressors(df, league_name):
    # Robust season coercion so strings like "2024-2024" / "2024-25" do not crash int() calls
    # --- Robust season start-year (no hard drops) -----------------------
    df = df.copy()
    if "season" in df.columns:
        s_norm = df["season"].astype(str).map(_norm_season)
        start_from_season = pd.to_numeric(
            s_norm.str.extract(r"((?:19|20)\d{2})")[0], errors="coerce"
        ).astype("Int64")
    else:
        start_from_season = pd.Series(pd.NA, index=df.index, dtype="Int64")

    start_from_date = _infer_season_start_year_from_date(df.get("match_date", pd.Series(index=df.index)))
    df["season_start_year"] = start_from_season.fillna(start_from_date)

    # If any remain NaN, try ffill/bfill within team; finally fill with median to avoid row drops
    if df["season_start_year"].isna().any():
        for side in ("home_team_name", "away_team_name"):
            if side in df.columns:
                df["season_start_year"] = (
                    df.groupby(side)["season_start_year"]
                    .transform(lambda s: s.ffill().bfill())
                    .fillna(df["season_start_year"])
                )
    if df["season_start_year"].isna().any():
        missing = int(df["season_start_year"].isna().sum())
        print(f"⚠️  goal-regressor: {missing} rows lack season after inference; filling with dataset median to keep them.")
        med = int(df["season_start_year"].dropna().median()) if df["season_start_year"].notna().any() else 2000
        df["season_start_year"] = df["season_start_year"].fillna(med)

    df["season_start_year"] = df["season_start_year"].astype(int)
    """
    Fit quick CatBoostRegressor models for home and away goals using only a leak-free training split.
    """
    # ------------------------------------------------------------------
    # 🛑  Live / in‑season rows → *load* the frozen goal‑model ensemble
    #     from the previous season instead of re‑training, when
    #     FORCE_LOCKED is active.  This eliminates in‑sample leakage
    #     and speeds up live inference.
    # ------------------------------------------------------------------
    # ------------------------------------------------------------------
    # Robustly derive the *current* season using season_start_year.
    # ------------------------------------------------------------------
    _current_season: int | None = None
    if "season_start_year" in df.columns and df["season_start_year"].notna().any():
        _current_season = int(pd.Series(df["season_start_year"]).dropna().max())

    # ------------------------------------------------------------------
    # Option B: live inference can load last‑season’s *frozen* 5‑fold
    # goal‑regressor ensemble instead of (re)training.  This shortcut is
    # triggered only when FORCE_LOCKED is active **and** the artefacts
    # exist.  No fragile int() parsing remains – we guard with re above.
    # ------------------------------------------------------------------
    ensemble_dir = os.path.join(MODEL_DIR, "goal_ensembles")
    if _current_season is not None:
        _frozen_home = Path(ensemble_dir) / f"{_current_season - 1}_home_goals_fold5.pkl"
        _frozen_away = _frozen_home.with_name(f"{_current_season - 1}_away_goals_fold5.pkl")
        if FORCE_LOCKED and _frozen_home.exists() and _frozen_away.exists():
            fold_models_home = joblib.load(_frozen_home)
            fold_models_away = joblib.load(_frozen_away)
            print(f"🔒  Loaded frozen goal‑model ensemble for season {_current_season}")
            return fold_models_home, fold_models_away
    # --- isolate a leak‑free training cut -----------------------------
    # Train only on data that is **at least two full seasons older**
    # than the most‑recent season present in *df*.
    if "season_start_year" in df.columns and df["season_start_year"].notna().any():
        s_num = pd.to_numeric(df["season_start_year"], errors="coerce")
        max_season = int(s_num.dropna().max()) if s_num.notna().any() else None
        # seasons ≤ max_season‑2 become the Poisson training slice
        train_df = df[s_num <= (max_season - 2)].copy()
    elif 'match_date' in df.columns and df['match_date'].notna().any():
        df['match_date'] = pd.to_datetime(df['match_date'])
        latest_date = df['match_date'].max()
        cutoff_date = latest_date - pd.DateOffset(years=2)
        train_df = df[df['match_date'] <= cutoff_date].copy()
    else:
        # fallback – first 80 % chronologically (still leak‑safe)
        cutoff = int(len(df) * 0.8)
        train_df = df.iloc[:cutoff].copy()

    if train_df.empty:
        raise RuntimeError(
            "Poisson training cut produced an empty dataframe — "
            "verify 'season' or 'match_date' columns."
        )

    # --- 10 % chronological hold‑out for isotonic calibration ---------
    val_df = df.iloc[int(len(df)*0.9):].copy()
    if val_df.empty:
        # fallback when the dataframe is very small
        val_df = train_df.sample(frac=0.15, random_state=42)
            # --- Robust prematch PPG/xG differentials (ensure variability & keep) ---
    def _pick(frame: pd.DataFrame, cands: list[str]) -> str | None:
        return next((c for c in cands if c in frame.columns), None)

    # Identify candidate source columns on the full frame (superset of train/val)
    ppg_home_src = _pick(df, ["Pre-Match PPG (Home)", "home_ppg_pre_match", "home_ppg"])
    ppg_away_src = _pick(df, ["Pre-Match PPG (Away)", "away_ppg_pre_match", "away_ppg"])
    xg_home_src  = _pick(df, ["Home Team Pre-Match xG", "home_xg_pre_match", "home_xg"])
    xg_away_src  = _pick(df, ["Away Team Pre-Match xG", "away_xg_pre_match", "away_xg"])

    # Compute on both train & val slices when sources exist
    for _name in ("train_df", "val_df"):
        _sub = locals()[_name]
        if ppg_home_src and ppg_away_src:
            _sub["ppg_diff"] = (
                pd.to_numeric(_sub.get(ppg_home_src, np.nan), errors="coerce") -
                pd.to_numeric(_sub.get(ppg_away_src, np.nan), errors="coerce")
            )
        if xg_home_src and xg_away_src:
            _sub["xg_diff"] = (
                pd.to_numeric(_sub.get(xg_home_src, np.nan), errors="coerce") -
                pd.to_numeric(_sub.get(xg_away_src, np.nan), errors="coerce")
            )
            _sub["xg_diff_abs"] = _sub["xg_diff"].abs()
        locals()[_name] = _sub

    # Sanity: warn loudly if any of the key diffs collapsed to a constant
    try:
        for c in ["ppg_diff", "xg_diff", "xg_diff_abs"]:
            if c in train_df.columns and train_df[c].nunique(dropna=True) <= 1:
                print(f"🚨 {c} collapsed; check source columns: {ppg_home_src}, {ppg_away_src}, {xg_home_src}, {xg_away_src}")
    except Exception:
        pass

    # These features must never be auto-dropped for 'low variance'
    KEEP_COLS = {"ppg_diff", "xg_diff", "xg_diff_abs", "odds_parity", "odds_skew", "implied_prob_diff"}

    # ---- numeric + categorical team IDs -------------------------------
    id_cols = [c for c in ("home_team_id", "away_team_id") if c in train_df.columns]

    num_X = (
        train_df.select_dtypes(include=['number'])
          .drop(columns=['home_team_goal_count', 'away_team_goal_count'],
                errors='ignore')
    )
    # ------------------------------------------------------------------
    # Build the initial design matrix and de‑duplicate any repeat columns
    # BEFORE safe_fill runs.  Duplicate names can cause `df[col]` to
    # return a DataFrame, which breaks the `miss.any()` check.
    # ------------------------------------------------------------------
        # Build initial design matrix (pre-fill) and de-duplicate
    X = pd.concat([num_X, train_df[id_cols]], axis=1)
    X = X.loc[:, ~X.columns.duplicated()]

    # Keep-list: never drop these if present
    keep_cols = {"ppg_diff","xg_diff","xg_diff_abs","odds_parity","odds_skew","implied_prob_diff"}

    # Drop columns that are >95% missing (computed before filling)
    miss_rate = X.isna().mean()
    too_missing = [c for c in miss_rate.index if miss_rate[c] > 0.95 and c not in keep_cols]
    if too_missing:
        print(f"⚠️  Dropping >95% missing cols (goal regressors): {too_missing[:8]}…")
        X = X.drop(columns=too_missing, errors="ignore")

    # Prepare a copy with median-fill to assess variance robustly
    X_for_var = X.copy()
    medians = X_for_var.median(numeric_only=True)
    X_for_var = X_for_var.fillna(medians)

    # Safety: drop any lingering non-numeric cols (exclude id_cols)
    non_num = X_for_var.select_dtypes(exclude=["number"]).columns.difference(id_cols)
    if len(non_num):
        print(f"⚠️  Dropping non-numeric cols: {list(non_num)[:8]}…")
        X_for_var = X_for_var.drop(columns=non_num, errors="ignore")

    # --- Variance pruning (goal regressors) with protected KEEP_COLS ---
    VAR_THRESH_NUM_LOCAL = 1e-10  # treat numerically-constant as low-variance
    KEEP_COLS = {"ppg_diff","xg_diff","xg_diff_abs","odds_parity","odds_skew","implied_prob_diff"}

    _var = X_for_var.var(numeric_only=True, ddof=0)
    _low_var = [c for c, v in _var.items() if v <= VAR_THRESH_NUM_LOCAL]
    # do NOT drop any protected columns
    _low_var = [c for c in _low_var if c not in KEEP_COLS]
    _low_var_cols = list(_low_var)  # keep for later validation alignment

    if _low_var:
        print(f"⚠️  Dropping near-constant cols (goal regressors): {_low_var[:8]}…")
        X = X.drop(columns=_low_var, errors="ignore")

    # Finally, apply sentinel fill for training
    X = safe_fill(X, X.columns.tolist(), SENTINEL)
    # -- global leak blacklist enforcement
    
    cat_feats = id_cols                            # CatBoost categorical list
    # 🛡️  rolling-window chronology audit
    assert_rolling_metrics(train_df, "goal_regressors")
    # 🩺 Feature‑integrity snapshot for goal regressors
    feature_integrity_report(train_df, X.columns, "goal_regressors")

    y_home = train_df['home_team_goal_count']
    y_away = train_df['away_team_goal_count']

    # --------------------------------------------------------------
    # Out‑of‑fold λ̂ generation (5‑fold chronological CV)
    # --------------------------------------------------------------
    params = {
        "loss_function": "RMSE",
        "iterations": 800,
        "depth": 6,
        "learning_rate": 0.075,
        "random_seed": 42,
        "verbose": False
    }
    # --- Build season-aware CV iterator that never crashes on string labels ---
    n_splits = min(5, max(2, len(train_df)))
    season_labels = (
        train_df["season_start_year"].values
        if "season_start_year" in train_df.columns
        else train_df.get("season", pd.Series([], dtype=object)).values
    )
    cv_iter = _safe_stratified_split(train_df, season_labels, n_splits)
    if len(cv_iter) == 0:
        from sklearn.model_selection import KFold
        cv_iter = list(KFold(n_splits=n_splits, shuffle=False).split(train_df))
    # --------------------------------------------------------------
    # Out‑of‑fold λ̂ generation (5‑fold CV or safe fallback)
    # --------------------------------------------------------------
    oof_home = np.full(len(train_df), np.nan, dtype=float)
    oof_away = np.full(len(train_df), np.nan, dtype=float)
    fold_models_home = []
    fold_models_away = []

    for tr_idx, va_idx in cv_iter:
        X_tr, X_va = X.iloc[tr_idx], X.iloc[va_idx]
        yh_tr, yh_va = y_home.iloc[tr_idx], y_home.iloc[va_idx]
        ya_tr, ya_va = y_away.iloc[tr_idx], y_away.iloc[va_idx]

        # --- Home goals model (robust CatBoost fit with fallbacks) ---
        try:
            from catboost import CatBoostRegressor as _CBR
            mh = _CBR(**params)
            try:
                mh.fit(X_tr, yh_tr, cat_features=cat_feats)
            except TypeError:
                # Some CatBoost builds don’t accept cat_features kw; fit without it
                mh.fit(X_tr, yh_tr)
        except Exception:
            # CatBoost unavailable/incompatible → try XGBoost, else RandomForest
            try:
                import os as _os
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    print("⏭️  CatBoost unavailable — falling back to XGBoost for goal regressors (home)")
            except Exception:
                pass
            try:
                from xgboost import XGBRegressor as _XGBR
                mh = _XGBR(
                    n_estimators=600, max_depth=5, learning_rate=0.05,
                    subsample=0.8, colsample_bytree=0.8,
                    n_jobs=int(os.getenv("SKLEARN_JOBS","4")),
                    random_state=42, tree_method=os.getenv("XGB_TREE_METHOD","hist")
                )
                mh.fit(X_tr, yh_tr)
            except Exception:
                try:
                    import os as _os
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print("⏭️  XGBoost unavailable — falling back to RandomForest for goal regressors (home)")
                except Exception:
                    pass
                from sklearn.ensemble import RandomForestRegressor as _RFR
                mh = _RFR(
                    n_estimators=400, random_state=42,
                    n_jobs=int(os.getenv("SKLEARN_JOBS","4"))
                )
                mh.fit(X_tr, yh_tr)

        # --- Away goals model (robust CatBoost fit with fallbacks) ---
        try:
            from catboost import CatBoostRegressor as _CBR
            ma = _CBR(**params)
            try:
                ma.fit(X_tr, ya_tr, cat_features=cat_feats)
            except TypeError:
                ma.fit(X_tr, ya_tr)
        except Exception:
            try:
                import os as _os
                if _os.getenv("VERBOSE_QUICK","0") == "1":
                    print("⏭️  CatBoost unavailable — falling back to XGBoost for goal regressors (away)")
            except Exception:
                pass
            try:
                from xgboost import XGBRegressor as _XGBR
                ma = _XGBR(
                    n_estimators=600, max_depth=5, learning_rate=0.05,
                    subsample=0.8, colsample_bytree=0.8,
                    n_jobs=int(os.getenv("SKLEARN_JOBS","4")),
                    random_state=42, tree_method=os.getenv("XGB_TREE_METHOD","hist")
                )
                ma.fit(X_tr, ya_tr)
            except Exception:
                try:
                    import os as _os
                    if _os.getenv("VERBOSE_QUICK","0") == "1":
                        print("⏭️  XGBoost unavailable — falling back to RandomForest for goal regressors (away)")
                except Exception:
                    pass
                from sklearn.ensemble import RandomForestRegressor as _RFR
                ma = _RFR(
                    n_estimators=400, random_state=42,
                    n_jobs=int(os.getenv("SKLEARN_JOBS","4"))
                )
                ma.fit(X_tr, ya_tr)

        # keep the trained fold models
        fold_models_home.append(mh)
        fold_models_away.append(ma)

        # Trained on raw goal counts (RMSE) ⇒ identity, no exp()
        oof_home[va_idx] = np.maximum(mh.predict(X_va), 0.0)
        oof_away[va_idx] = np.maximum(ma.predict(X_va), 0.0)

    # Attach OOF predictions back to the *original* dataframe indices
    df.loc[train_df.index, 'home_goals_pred'] = oof_home
    df.loc[train_df.index, 'away_goals_pred'] = oof_away
    # --- clip extreme λ̂ values to a sane 0‑5 goals range ------------
    df['home_goals_pred'] = df['home_goals_pred'].clip(0, 5)
    df['away_goals_pred'] = df['away_goals_pred'].clip(0, 5)

    # Any rows not covered by the training folds (e.g. future season) –
    # fill with the median of the OOF λ̂ to avoid NaNs.
    df['home_goals_pred'] = df['home_goals_pred'].fillna(np.nanmedian(oof_home))
    df['away_goals_pred'] = df['away_goals_pred'].fillna(np.nanmedian(oof_away))

    # --------------------------------------------------------------
    # Persist the 5‑fold ensemble so future inference never touches
    # in‑sample rows.  Stored once per project under ModelStore/goal_ensembles
    # --------------------------------------------------------------
    ensemble_dir = os.path.join(MODEL_DIR, "goal_ensembles")
    os.makedirs(ensemble_dir, exist_ok=True)
    joblib.dump(fold_models_home,
                os.path.join(ensemble_dir, "home_goals_fold5.pkl"))
    joblib.dump(fold_models_away,
                os.path.join(ensemble_dir, "away_goals_fold5.pkl"))

    # --------------------------------------------------------------
    # Final models trained on the full leak‑free training slice
    # (used later for inference on unseen data)
    # --------------------------------------------------------------
    # --- Full fit: Home goals model (robust CatBoost fit with fallbacks) ---
    try:
        from catboost import CatBoostRegressor as _CBR
        model_home = _CBR(**params)
        try:
            model_home.fit(X, y_home, cat_features=cat_feats)
        except TypeError:
            # Some CatBoost builds don’t accept cat_features kw; fit without it
            model_home.fit(X, y_home)
    except Exception:
        # CatBoost unavailable/incompatible → try XGBoost, else RandomForest
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print("⏭️  CatBoost unavailable — falling back to XGBoost for goal regressors (home, full fit)")
            from xgboost import XGBRegressor as _XGBR
            model_home = _XGBR(
                n_estimators=600, max_depth=5, learning_rate=0.05,
                subsample=0.8, colsample_bytree=0.8,
                n_jobs=int(os.getenv("SKLEARN_JOBS","4")),
                random_state=42, tree_method=os.getenv("XGB_TREE_METHOD","hist")
            )
            model_home.fit(X, y_home)
        except Exception:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print("⏭️  XGBoost unavailable — falling back to RandomForest for goal regressors (home, full fit)")
            from sklearn.ensemble import RandomForestRegressor as _RFR
            model_home = _RFR(
                n_estimators=400, random_state=42,
                n_jobs=int(os.getenv("SKLEARN_JOBS","4"))
            )
            model_home.fit(X, y_home)

    # --- Full fit: Away goals model (robust CatBoost fit with fallbacks) ---
    try:
        from catboost import CatBoostRegressor as _CBR
        model_away = _CBR(**params)
        try:
            model_away.fit(X, y_away, cat_features=cat_feats)
        except TypeError:
            model_away.fit(X, y_away)
    except Exception:
        try:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print("⏭️  CatBoost unavailable — falling back to XGBoost for goal regressors (away, full fit)")
            from xgboost import XGBRegressor as _XGBR
            model_away = _XGBR(
                n_estimators=600, max_depth=5, learning_rate=0.05,
                subsample=0.8, colsample_bytree=0.8,
                n_jobs=int(os.getenv("SKLEARN_JOBS","4")),
                random_state=42, tree_method=os.getenv("XGB_TREE_METHOD","hist")
            )
            model_away.fit(X, y_away)
        except Exception:
            if os.getenv("VERBOSE_QUICK","0") == "1":
                print("⏭️  XGBoost unavailable — falling back to RandomForest for goal regressors (away, full fit)")
            from sklearn.ensemble import RandomForestRegressor as _RFR
            model_away = _RFR(
                n_estimators=400, random_state=42,
                n_jobs=int(os.getenv("SKLEARN_JOBS","4"))
            )
            model_away.fit(X, y_away)

    # ------------------------------------------------------------------
    #  ⭐  Isotonic calibration on the 10 % hold‑out slice
    #      (skip gracefully if CalibratedRegressorCV is unavailable)
    # ------------------------------------------------------------------
    try:
        from sklearn.calibration import CalibratedRegressorCV

        # Align validation design‑matrix to each model’s schema
        X_val = (
            val_df.select_dtypes(include=['number'])
                  .drop(columns=['home_team_goal_count', 'away_team_goal_count'],
                        errors='ignore')
                  .replace([np.inf, -np.inf], np.nan)
        )
        X_val = pd.concat([X_val, val_df[id_cols]], axis=1) if id_cols else X_val
        X_val = safe_fill(X_val, X_val.columns.tolist(), SENTINEL)   # sentinel + flag‑whitelist
        # Drop the same near‑constant columns from the validation set
        _drop_cols = [c for c in _low_var_cols if c in X_val.columns]
        if _drop_cols:
            X_val = X_val.drop(columns=_drop_cols)
        X_val = _align_dataframe_to_model(X_val, model_home)
        y_val_home = val_df['home_team_goal_count']
        y_val_away = val_df['away_team_goal_count']

        calib_home = _calibrated_reg_cv2(model_home, method="isotonic")
        calib_home.fit(X_val, y_val_home)
        calib_away = _calibrated_reg_cv2(model_away, method="isotonic")
        calib_away.fit(X_val, y_val_away)

        # replace raw models with calibrated wrappers for downstream use
        model_home = calib_home
        model_away = calib_away
        # keep reference to the underlying estimators (optional)
        model_home.base_model_ = calib_home.estimators_[0]
        model_away.base_model_ = calib_away.estimators_[0]

    except ImportError:
        # Older sklearn versions (<1.3) don’t include CalibratedRegressorCV.
        # Fall back to the un‑calibrated models so the pipeline continues.
        warnings.warn(
            "CalibratedRegressorCV not available – skipping isotonic calibration "
            "for goal regressors.",
            UserWarning
        )

    # Tag models with last training date for leak detection
    if 'match_date' in train_df.columns:
        last_train_date = pd.to_datetime(train_df['match_date']).max()
    else:
        last_train_date = None
    for _m in (model_home, model_away):
        _m.eval_metrics_ = getattr(_m, "eval_metrics_", {})
        _m.eval_metrics_['last_train_date'] = last_train_date

    # --------------------------------------------------------------
    # Persist calibrated models
    # --------------------------------------------------------------
    try:
        _persist_goal_pair(model_home, model_away, league_name)
    except Exception:
        pass

    return model_home, model_away


# ================================================================
# Market target builders and training harness (multi‑market)
#   • Over 2.5, BTTS, BTTS 1H, Home ≥2, Away ≥2, Home FTS, Away FTS
#   • Chronological split, calibrated, per‑league model export
# ================================================================
from sklearn.metrics import accuracy_score, average_precision_score, precision_recall_curve
from sklearn.model_selection import train_test_split
from catboost import CatBoostClassifier

def _ensure_datetime_col(df: pd.DataFrame) -> pd.DataFrame:
    if "match_date" in df.columns and not np.issubdtype(df["match_date"].dtype, np.datetime64):
        try:
            df["match_date"] = pd.to_datetime(df["match_date"], errors="coerce")
        except Exception:
            pass
    return df

def build_market_targets(df: pd.DataFrame) -> pd.DataFrame:
    """Create boolean target columns for all supported markets (idempotent)."""
    df = df.copy()
    # total goals
    if {'home_team_goal_count','away_team_goal_count'}.issubset(df.columns):
        tg = df['home_team_goal_count'].fillna(0) + df['away_team_goal_count'].fillna(0)
        if 'target_over25' not in df.columns:
            df['target_over25'] = (tg >= 3).astype(int)
        if 'target_home_ge2' not in df.columns:
            df['target_home_ge2'] = (df['home_team_goal_count'].fillna(0) >= 2).astype(int)
        if 'target_away_ge2' not in df.columns:
            df['target_away_ge2'] = (df['away_team_goal_count'].fillna(0) >= 2).astype(int)
        if 'target_btts' not in df.columns:
            df['target_btts'] = ((df['home_team_goal_count'].fillna(0) > 0) & (df['away_team_goal_count'].fillna(0) > 0)).astype(int)
        if 'target_home_fts' not in df.columns:
            df['target_home_fts'] = (df['away_team_goal_count'].fillna(0) == 0).astype(int)
        if 'target_away_fts' not in df.columns:
            df['target_away_fts'] = (df['home_team_goal_count'].fillna(0) == 0).astype(int)
    # first‑half BTTS if available
    if {'home_team_goal_count_half_time','away_team_goal_count_half_time'}.issubset(df.columns):
        if 'target_btts_1h' not in df.columns:
            df['target_btts_1h'] = (
                (df['home_team_goal_count_half_time'].fillna(0) > 0) &
                (df['away_team_goal_count_half_time'].fillna(0) > 0)
            ).astype(int)
    else:
        # create a NaN column so downstream code can detect absence cleanly
        if 'target_btts_1h' not in df.columns:
            df['target_btts_1h'] = np.nan
    return df

def _select_features(df: pd.DataFrame, market: str) -> list[str]:
    """Pick a robust, leak‑safe feature list (intersect with available cols)."""
    # Prefer the expanded stack for BTTS/OU when present
    base = []
    if market in {"over25","btts","btts_1h"}:
        base = [c for c in EXPANDED_BTTS_FEATURES if c in df.columns]
    # Fallback: all numeric, excluding labels and obvious outcomes
    if not base:
        drop = {
            'home_team_goal_count','away_team_goal_count','FTR','target_over25','target_btts','target_btts_1h',
            'target_home_ge2','target_away_ge2','target_home_fts','target_away_fts'
        }
        base = [c for c in df.select_dtypes(include=['number']).columns if c not in drop]
    return list(dict.fromkeys(base))  # stable unique

def _chronological_split(df: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame]:
    """Leak-safe split: last season as test when available, else last 10% by date."""
    df = _ensure_datetime_col(df)

    # Try season-based split first, tolerating strings like "2024-2025"
    if 'season' in df.columns and df['season'].notna().any():
        s = df['season']
        s_num = pd.to_numeric(s, errors='coerce')
        if s_num.isna().any():
            import re
            def _parse_season_to_int(v):
                if pd.isna(v): return np.nan
                yrs = re.findall(r'\d{4}', str(v))
                return int(yrs[-1]) if yrs else np.nan   # use the ending year for ordering
            s_num = s.apply(_parse_season_to_int)

        if s_num.notna().nunique() >= 2:
            max_season = int(s_num.max())
            train = df[s_num < max_season].copy()
            test  = df[s_num == max_season].copy()
            if not train.empty and not test.empty:
                return train, test

    # Fallback: last 10% by date (ensure proper datetime then sort)
    if 'match_date' in df.columns:
        df = df.assign(match_date=pd.to_datetime(df['match_date'], errors='coerce'))
        df = df.sort_values('match_date', na_position='last')
    cut = int(len(df) * 0.9)
    return df.iloc[:cut].copy(), df.iloc[cut:].copy()

def train_market_model(df: pd.DataFrame,
                       market: str,
                       league_name: str,
                       *,
                       model_dir: str | None = None) -> dict:
    """
    Train a CatBoostClassifier for the given *market* and save to ModelStore.
    Returns a metrics dict with accuracy and PR‑AUC on the hold‑out slice.
    """
    if model_dir is None:
        model_dir = MODEL_DIR
    df = build_market_targets(df)
    target_map = {
        'over25': 'target_over25',
        'btts': 'target_btts',
        'btts_1h': 'target_btts_1h',
        'home_ge2': 'target_home_ge2',
        'away_ge2': 'target_away_ge2',
        'home_fts': 'target_home_fts',
        'away_fts': 'target_away_fts',
    }
    tgt = target_map.get(market)
    if tgt is None or tgt not in df.columns:
        raise ValueError(f"Unknown or unavailable market '{market}'")
    # Drop rows with NaN target (e.g., btts_1h when HT goals absent)
    dfx = df.dropna(subset=[tgt]).copy()
    if dfx.empty:
        raise RuntimeError(f"No training rows for market {market} after target filtering")
    feats = _select_features(dfx, market)
    if not feats:
        raise RuntimeError(f"No usable features for market {market}")
    X = dfx[feats].replace([np.inf, -np.inf], np.nan)
    X = safe_fill(X, X.columns.tolist(), SENTINEL)
    y = dfx[tgt].astype(int)
    train_df, test_df = _chronological_split(pd.concat([X, y], axis=1))
    X_tr, y_tr = train_df[feats], train_df[tgt]
    X_te, y_te = test_df[feats], test_df[tgt]

    params = dict(
        loss_function="Logloss",
        iterations=700,
        depth=6,
        learning_rate=0.05,
        random_seed=42,
        verbose=False,
        auto_class_weights="Balanced",
    )
    model = CatBoostClassifier(**params)
    model.fit(X_tr, y_tr)

    # Evaluate
    proba = model.predict_proba(X_te)[:, 1]
    preds = (proba >= 0.5).astype(int)
    acc   = float(accuracy_score(y_te, preds))
    try:
        pr_auc = float(average_precision_score(y_te, proba))
    except Exception:
        pr_auc = float('nan')

    # Persist model
    tag = f"{league_name.replace(' ', '_')}_{market}_model.pkl"
    os.makedirs(model_dir, exist_ok=True)
    joblib.dump(model, os.path.join(model_dir, tag))

    return {
        'market': market,
        'league': league_name,
        'features': feats,
        'accuracy': acc,
        'pr_auc': pr_auc,
        'n_train': int(len(X_tr)),
        'n_test': int(len(X_te)),
        'model_path': os.path.join(model_dir, tag),
    }

def train_all_markets_for_league(df: pd.DataFrame,
                                 league_name: str,
                                 markets: list[str] | None = None) -> pd.DataFrame:
    """
    Train all requested market classifiers for *league_name* and return
    a metrics DataFrame (rows = markets).
    """
    if markets is None:
        markets = ['over25','btts','btts_1h','home_ge2','away_ge2','home_fts','away_fts']
    metrics = []
    for m in markets:
        try:
            res = train_market_model(df, m, league_name)
            print(f"✅ Trained {m} – acc={res['accuracy']:.3f} | PR‑AUC={res['pr_auc']:.3f}")
            metrics.append(res)
        except Exception as e:
            print(f"⚠️  Skipped {m}: {e}")
    return pd.DataFrame(metrics)

def shap_top_drivers(model, X_row: pd.DataFrame, top_n: int = 5) -> list[tuple[str, float]]:
    """Return (feature, |SHAP value|) for the top drivers on a single row."""
    try:
        import shap as _sh
        explainer = _sh.TreeExplainer(model)
        sv = explainer.shap_values(X_row)[1] if isinstance(model, CatBoostClassifier) else explainer.shap_values(X_row)
        vals = np.abs(sv).reshape(-1)
        feats = X_row.columns.tolist()
        order = np.argsort(-vals)
        return [(feats[i], float(vals[i])) for i in order[:top_n]]
    except Exception:
        return []



