def load_existing_metrics(name):
    """
    Load persisted draw/mix metadata for a locked league so the main
    pipeline can summarize without retraining.

    Returns a dict with at least:
      league, mode, alpha, beta, cap, best_threshold, best_k
    Additional keys (accuracy/pr_auc) are included if found.
    """
    league_tag = str(name).replace(" ", "_")
    meta = {
        "league": name,
        "mode": "locked",
        "alpha": 0.60,   # defaults if file missing
        "beta": 0.00,
        "cap": 0.45,
        "best_threshold": 0.34,
        "best_k": 0.10,
        "status": "loaded:defaults",
    }

    import json
    thr_path = os.path.join(MODEL_DIR, f"{league_tag}_draw_threshold.json")
    try:
        with open(thr_path, "r") as fh:
            j = json.load(fh) or {}
        meta.update({
            "mode": j.get("mode", meta["mode"]),
            "alpha": float(j.get("baseline_blend", meta["alpha"])),
            "beta": float(j.get("beta", meta["beta"])) if j.get("beta") is not None else meta["beta"],
            "cap":  float(j.get("cap",  meta["cap"]))  if j.get("cap")  is not None else meta["cap"],
            "best_threshold": float(j.get("threshold", meta["best_threshold"])),
        })
        # pick the k with the best precision@k (if present)
        pk = j.get("precision_at_k") or {}
        if isinstance(pk, dict) and pk:
            best_k, best_prec = None, -1.0
            for k, v in pk.items():
                try:
                    kf = float(k)
                    vf = float(v) if v is not None else float("nan")
                except Exception:
                    continue
                if not np.isnan(vf) and vf > best_prec:
                    best_prec, best_k = vf, kf
            if best_k is not None:
                meta["best_k"] = float(best_k)
        meta["status"] = "loaded:file"
    except Exception:
        # keep defaults
        pass

    # Optional: headline metrics if you’ve persisted them
    metrics_path = os.path.join(MODEL_DIR, f"{league_tag}_ftr_metrics.json")
    try:
        with open(metrics_path, "r") as fh:
            m = json.load(fh) or {}
        meta["accuracy_draw"] = float(m.get("accuracy_draw", m.get("accuracy", float("nan"))))
        meta["pr_auc_draw"]  = float(m.get("pr_auc_draw",  m.get("pr_auc",  float("nan"))))
    except Exception:
        pass

    return meta


