# --------------------------------------------------------------
# Helper: identify truly constant columns
# --------------------------------------------------------------
def _is_constant(col: pd.Series) -> bool:
    """
    True if the column has ≤ 1 unique non-NaN value
    *and* is not in the ROLLING_SAFE allow-list.
    """
    return (col.nunique(dropna=True) <= 1) and (col.name not in ROLLING_SAFE)
def safe_fill(df: pd.DataFrame,
              cols: list[str],
              sentinel: float = -999) -> pd.DataFrame:
    """
    Replace NaNs in *cols* with *sentinel* **and** create a binary
    flag `is_missing_<col>` so the model can learn from missingness.
    """
    for col in cols:
        miss = df[col].isna()
        if miss.values.any():   # robust even when duplicate‑name slices return DataFrame
            # create the dummy only for approved top‑predictor columns
            if col in MISSING_FLAG_WHITELIST:
                df[f"is_missing_{col}"] = miss.astype(int)
            df[col] = df[col].fillna(sentinel)
    return df
def _safe_season_start_year(season_str):
    """
    Return the first 4-digit year in *season_str* (e.g. “2024-25”, “2024-2024”, “2024”).
    Returns None when nothing parseable is found, so callers can soft-skip the row.
    """
    if season_str is None or (isinstance(season_str, float) and np.isnan(season_str)):
        return None
    m = re.search(r'(?:19|20)\d{2}', str(season_str))
    return int(m.group(0)) if m else None
