def _auto_ftr_allow(df: pd.DataFrame):
    """Resolve the canonical FTR allowlist if available; else None."""
    try:
        resolver = globals().get("_resolve_ftr_allowlist") or globals().get("resolve_ftr_allowlist")
        return resolver(df.columns) if callable(resolver) else None
    except Exception:
        return None
def strip_leaks(df: pd.DataFrame, allowlist: list[str] | set[str] | None = None) -> pd.DataFrame:
    """
    Remove every column whose name matches the compiled leakage‑regex
    pattern ``_LEAK_RGX``.  Prints the first few stripped columns so the
    console makes it obvious what just got removed.

    Parameters
    ----------
    df : pd.DataFrame
        Design‑matrix to be cleaned **in‑place**.  A new DataFrame is
        returned so chained calls are safe.

    Returns
    -------
    pd.DataFrame
        Same frame with the leak‑prone columns dropped.
    """
    # short‑circuit for empty / None frames
    if df is None or df.empty:
        return df
    external = set(allowlist or [])
    # Fallback: if no external allowlist supplied, try a project resolver
    if not external:
        try:
            _resolver = globals().get("_resolve_ftr_allowlist") or globals().get("resolve_ftr_allowlist")
            if callable(_resolver):
                external = set(_resolver(df.columns))
        except Exception:
            # Silent fallback – keep using the internal allowlist only
            pass
    # Allowlist: safe pre-match & market features we explicitly keep
    LEAK_ALLOWLIST: set[str] = {
        "btts_percentage_pre_match", "over_25_percentage_pre_match",
        "over_15_percentage_pre_match", "odds_ft_home_team_win",
        "odds_ft_draw", "odds_ft_away_team_win",
        "draw_implied", "implied_prob_diff",
        "odds_parity", "odds_skew", "odds_diff",
        # NEW: make absolutely sure pre-match xG survives
        "pre_match_xg_home", "pre_match_xg_away",
        "Home Team Pre-Match xG", "Away Team Pre-Match xG",
    }
    LEAK_ALLOWLIST |= external
    leak_cols = [c for c in df.columns if _LEAK_RGX.search(c) and c not in LEAK_ALLOWLIST]
    if leak_cols:
        sample = ', '.join(leak_cols[:6])
        print(f"🚫  Dropping {len(leak_cols)} leak‑prone cols: {sample}{'…' if len(leak_cols) > 6 else ''}")
        df = df.drop(columns=leak_cols, errors="ignore")

    return df
