def predict_lambda(model, X):
    """
    Always return *linear* λ̂ from a goal‑regression model that was
    trained on log‑targets.  Works for CatBoost and XGBoost wrappers.
    Accepts a single model or a list/tuple ensemble; for ensembles,
    returns the mean λ̂ across members.
    """
    import numpy as np

    # --------------------------------------------------------------
    # Accept either a single fitted model *or* a list/tuple ensemble.
    # When given an ensemble we return the mean λ̂ across members so
    # every call site can stay unchanged.
    # --------------------------------------------------------------
    if isinstance(model, (list, tuple)):
        if len(model) == 0:
            raise ValueError("Empty model ensemble supplied to predict_lambda()")
        # Align to the first model’s schema, assume all share it.
        X_aligned = _align_dataframe_to_model(X, model[0])
        preds = [np.exp(m.predict(X_aligned)) for m in model]
        return np.mean(preds, axis=0)

    # -------- single model fallback (original behaviour) -----------
    X_aligned = _align_dataframe_to_model(X, model)
    return np.exp(model.predict(X_aligned))

