# === Per-league draw-threshold loader (trainer -> inference) ===
import json as _json

def load_league_draw_threshold(league_name: str, default_thr: float = 0.34):
    """
    Return (threshold, mode) for the league, falling back cleanly.
    Reads MODEL_DIR/<League>_draw_threshold.json written by the trainer.
    """
    league_tag = str(league_name).replace(" ", "_")
    path = os.path.join(MODEL_DIR, f"{league_tag}_draw_threshold.json")
    try:
        with open(path, "r") as fh:
            data = _json.load(fh)
        return float(data.get("threshold", default_thr)), data.get("mode", "youden")
    except Exception:
        # Fallback to any locked constant gate if present
        try:
            from constants import LOCKED_THRESHOLDS
            default_thr = LOCKED_THRESHOLDS.get(league_name, {}).get("draw", default_thr)
        except Exception:
            pass
        return float(default_thr), "default"
# === Helper: load best top-k percentage from trainer JSON ===
def load_best_topk_pct(league_name: str, default: float = 0.10) -> float:
    """
    Return the k fraction (e.g., 0.05 for 5%) that achieved the best
    precision@k during training for *league_name*. Falls back to *default*
    if unavailable.
    """
    league_tag = str(league_name).replace(" ", "_")
    path = os.path.join(MODEL_DIR, f"{league_tag}_draw_threshold.json")
    try:
        with open(path, "r") as fh:
            data = _json.load(fh)
        k_dict = data.get("precision_at_k") or {}
        if isinstance(k_dict, dict) and k_dict:
            best_k = None
            best_prec = -1.0
            for k, v in k_dict.items():
                try:
                    kf = float(k)
                    vf = float(v) if v is not None else float("nan")
                except Exception:
                    continue
                if not np.isnan(vf) and vf > best_prec:
                    best_prec = vf
                    best_k = kf
            if best_k is not None:
                return float(best_k)
    except Exception:
        pass
    return float(default)

# === Helper: rebuild press-intensity for inference using saved blend ===
def prepare_league_for_inference(
    league_name: str,
    *,
    match_root: str = "Matches",
    force: bool = False,
    use_cache: bool = True,
    overwrite_baseline: bool = False,
    overwrite_intensity: bool = False,
) -> tuple[float, float]:
    """
    Read the trainer JSON for *league_name* to obtain `baseline_blend` (α)
    and the historically best top-k fraction. Then (re)build press-baseline
    and press-intensity on disk for that α so inference uses the same setup.

    Returns (alpha, best_k_pct).
    """
    league_tag = str(league_name).replace(" ", "_")
    thr_json = os.path.join(MODEL_DIR, f"{league_tag}_draw_threshold.json")

    alpha = 0.60  # sensible default if JSON absent
    try:
        with open(thr_json, "r") as fh:
            meta = _json.load(fh)
        if isinstance(meta.get("baseline_blend"), (int, float, str)):
            alpha = float(meta["baseline_blend"])
    except Exception:
        pass  # keep default α

    best_k = load_best_topk_pct(league_name, default=0.10)

    # Rebuild baseline/intensity only if the external ETL is available
    if _pi_ensure_press is not None:
        matches_dir = os.path.join(match_root, league_name)
        try:
            _pi_ensure_press(
                matches_dir,
                force=force,
                baseline_blend=alpha,
                use_cache=use_cache,
                overwrite_baseline=overwrite_baseline,
                overwrite_intensity=overwrite_intensity,
            )
        except TypeError:
            # Older versions without the new keyword args – fall back gracefully
            _pi_ensure_press(matches_dir, force=force)
    else:
        print("⚠️  etl_press_intensity.ensure_press_intensity_on_disk unavailable; skipping on-disk rebuild.")

    print(f"ℹ️ Using baseline_blend α={alpha:.2f} and best top-k {int(best_k*100)}% for {league_name}")
    return float(alpha), float(best_k)
