# Helper: future-proof calibrated classifier (no 'prefit', wraps with Frozen if available)
if "_calibrated_cv2" not in globals():
    def _calibrated_cv2(estimator, method: str = "isotonic"):
        """
        Return CalibratedClassifierCV(estimator, method, cv=2) with a Frozen wrapper
        when available (sklearn >=1.6). Use this wherever we previously used prefit calibration.
        """
        try:
            from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
            est = _Freeze(estimator)
        except Exception:
            est = estimator
        from sklearn.calibration import CalibratedClassifierCV as _CalCV
        return _CalCV(estimator=est, method=method, cv=2)

# Helper: future-proof calibrated *regressor* (no 'prefit', wraps with Frozen if available)
if "_calibrated_reg_cv2" not in globals():
    def _calibrated_reg_cv2(estimator, method: str = "isotonic"):
        """
        Return CalibratedRegressorCV(estimator, method, cv=2) with a Frozen wrapper
        when available (sklearn >=1.6). Use this wherever we previously used prefit calibration.
        """
        try:
            from sklearn.utils.fixes import _wrap_in_frozen_estimator as _Freeze  # type: ignore
            est = _Freeze(estimator)
        except Exception:
            est = estimator
        from sklearn.calibration import CalibratedRegressorCV as _CalRegCV
        return _CalRegCV(estimator=est, method=method, cv=2)
    
