# ------------------------------------------------------------------
# Utility: persist per‑market decision thresholds
# ------------------------------------------------------------------
def _write_threshold(league_name: str,
                     market: str,
                     thr: float,
                     model_dir: str = MODEL_DIR) -> None:
    """
    Persist the latest threshold for *market* while guaranteeing that the
    CSV always contains exactly one row per market ('draw', 'home', 'away').

    Behaviour
    ---------
    • If the file exists, it is loaded, the row for *market* is overwritten
      (or appended if missing) and the whole frame is re‑written.
    • If the file is missing, a new three‑column CSV is created with a
      single row for the supplied market.
    This atomic “read‑modify‑write” pattern prevents partial files that
    trigger KeyErrors on subsequent runs.
    """
    tag      = f"{league_name.replace(' ', '_')}_thresholds.csv"
    out_path = Path(model_dir) / tag
    now      = datetime.datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")

    # ------------------------------------------------------------------
    # Always rebuild the CSV from scratch so we end up with exactly one
    # row per market every single time.  No incremental appends – this
    # avoids duplicate rows and missing‑entry KeyErrors on future loads.
    # ------------------------------------------------------------------
    default = 0.34
    if out_path.exists():
        try:
            old = pd.read_csv(out_path)
        except Exception:
            old = pd.DataFrame()
    else:
        old = pd.DataFrame()

    # carry forward previous thresholds when available
    last_vals = {
        m: float(old.loc[old["market"] == m, "threshold"].iloc[-1])
        if (old["market"] == m).any() else default
        for m in ("draw", "home", "away")
    }
    # update the one we are writing now
    last_vals[market] = round(float(thr), 4)

    # rebuild fresh dataframe – exactly three rows
    df = pd.DataFrame({
        "timestamp": [now, now, now],
        "market":    ["draw", "home", "away"],
        "threshold": [last_vals["draw"], last_vals["home"], last_vals["away"]],
    })
    # atomic write
    df.to_csv(out_path, index=False)

# -----------------------------------------------------------------
# Helper: read most‑recent thresholds back in
# -----------------------------------------------------------------
def load_last_thresholds(path: Path,
                         default: float = 0.34) -> tuple[float, float, float]:
    """
    Load the most‑recent per‑market decision thresholds.

    Parameters
    ----------
    path : pathlib.Path | str
        CSV written by `_write_threshold()`.
    default : float, default 0.34
        Fallback when the file or a specific market row is missing.

    Returns
    -------
    (t_draw, t_home, t_away) : tuple[float, float, float]
        Thresholds for Draw, Home‑win and Away‑win in that order.
    """
    # Brand‑new league → use neutral defaults
    if not Path(path).exists():
        return default, default, default

    df = pd.read_csv(path)

    def _get(row_key: str) -> float:
        vals = df.loc[df["market"] == row_key, "threshold"]
        return float(vals.iloc[-1]) if not vals.empty else default

    return _get("draw"), _get("home"), _get("away")

# -----------------------------------------------------------------
# Per‑league draw‑threshold loader (JSON persisted by trainer)
# -----------------------------------------------------------------
def load_league_draw_threshold(league_name: str, default_thr: float = 0.5):
    """
    Load a per‑league draw decision threshold saved by the trainer.

    Looks for:  ModelStore/<League_Name_With_Underscores>_draw_threshold.json

    Returns
    -------
    (threshold, mode) : tuple[float, str]
        threshold : float – the decision cut‑off for P(draw)
        mode      : str   – how it was derived (e.g. "f1", "precision@0.60", "youden"),
                             or "default" when the file is missing.
    """
    import json, os

    league_tag = league_name.replace(" ", "_")
    path = os.path.join(MODEL_DIR, f"{league_tag}_draw_threshold.json")
    try:
        with open(path, "r") as fh:
            data = json.load(fh)
        return float(data.get("threshold", default_thr)), data.get("mode", "youden")
    except Exception:
        return default_thr, "default"


# -----------------------------------------------------------------
# Convenience: choose threshold with clean fallbacks
#   1) JSON saved by trainer (if present)
#   2) constants.LOCKED_THRESHOLDS[league]["draw"] (when FORCE_LOCKED)
#   3) supplied *default_thr*
# -----------------------------------------------------------------
from constants import LOCKED_THRESHOLDS  # already imported above, safe to repeat

def choose_draw_threshold(league_name: str, default_thr: float = 0.5) -> tuple[float, str]:
    thr, mode = load_league_draw_threshold(league_name, default_thr)
    if mode != "default":
        return thr, mode
    # JSON missing -> try constants gate
    if league_name in LOCKED_THRESHOLDS and "draw" in LOCKED_THRESHOLDS[league_name]:
        return float(LOCKED_THRESHOLDS[league_name]["draw"]), "constants"
    return default_thr, "default"

# -----------------------------------------------------------------
# Convenience: apply per‑league draw threshold to predictions
# -----------------------------------------------------------------

def apply_draw_threshold(df: pd.DataFrame,
                         league_name: str,
                         p_draw_col: str = "p_draw",
                         out_col: str = "is_draw_pred",
                         default_thr: float = 0.5,
                         return_threshold: bool = False):
    """
    Apply a per‑league decision threshold to a dataframe containing
    predicted draw probabilities.

    Parameters
    ----------
    df : pd.DataFrame
        Frame that holds a column with predicted P(draw).
    league_name : str
        Human‑readable league name (e.g., "England Premier League").
    p_draw_col : str, default "p_draw"
        Column containing predicted draw probabilities.
    out_col : str, default "is_draw_pred"
        Name of the boolean/int flag column to be created.
    default_thr : float, default 0.5
        Fallback threshold when no per‑league JSON or constants gate exists.
    return_threshold : bool, default False
        When True, returns a tuple (df, threshold, mode).

    Returns
    -------
    pd.DataFrame | (pd.DataFrame, float, str)
        The dataframe with the thresholded flag column, and optionally the
        threshold value and the mode that produced it ("f1", "precision@x",
        "youden", "constants", or "default").
    """
    if p_draw_col not in df.columns:
        raise KeyError(f"Missing predicted draw‑prob column: {p_draw_col}")

    thr, mode = choose_draw_threshold(league_name, default_thr)
    df[out_col] = (df[p_draw_col] >= thr).astype(int)

    # Attach metadata for downstream inspection/debugging
    df.attrs = getattr(df, 'attrs', {})
    df.attrs['draw_threshold'] = thr
    df.attrs['draw_threshold_mode'] = mode

    if return_threshold:
        return df, thr, mode
    return df

