# ------------------------------------------------------------------
# Helper: save / load per‑league FTR mix parameters (α, β, cap, etc.)
# ------------------------------------------------------------------
def save_mix_params(league_name: str,
                    *,
                    alpha: float,
                    beta: float,
                    cap: float,
                    gate_scale: float,
                    cw_draw: float,
                    model_dir: str = MODEL_DIR) -> None:
    """
    Persist calibrated FTR mix parameters to a YAML file so later
    runs and external dashboards can reload them.

    File pattern:
        ModelStore/<League_Name_With_Underscores>_mix.yaml
    """
    payload = {
        "alpha": float(alpha),
        "beta":  float(beta),
        "cap":   float(cap),
        "gate_scale": float(gate_scale),
        "cw_draw":    float(cw_draw)
    }
    out_path = os.path.join(
        model_dir, f"{league_name.replace(' ', '_')}_mix.yaml"
    )
    with open(out_path, "w") as fh:
        yaml.safe_dump(payload, fh)


