#############################################
# Existing Feature Engineering Functions
#############################################
def calculate_emotional_spike_index(row):
    ch = row.get('rolling5_home_card_ratio', 0)
    ca = row.get('rolling5_away_card_ratio', 0)

    avg_cards  = (ch + ca) / 2
    imbalance  = abs(ch - ca)

    if avg_cards >= 0.35 or imbalance >= 0.15:
        return 1.0          # likely feisty encounter
    elif avg_cards <= 0.10:
        return -0.3         # very calm teams
    return 0.0

def calculate_possession_volatility_score(row, *, pre_match: bool = False):
    # Skip live-possession heuristic when generating pre‑match features
    if pre_match:
        return 0.0
    possession_diff = row.get('home_team_possession', 50) - row.get('away_team_possession', 50)
    xg_diff = row.get('xg_diff', 0)
    if abs(possession_diff) >= 20 and abs(xg_diff) <= 0.3:
        return 1.0
    elif abs(possession_diff) < 5:
        return -0.3
    return 0.0

def calculate_set_piece_pressure_index(row):
    # Use last-5 totals (pre-match, no leakage)
    corners = row.get('rolling5_total_corners', 0)
    fouls   = row.get('rolling5_total_fouls', 0)
    pressure = (corners + fouls) / 5.0          # per-match average

    if pressure >= 24:          # ≈ 12 corners + 12 fouls per game
        return 1.0
    elif pressure <= 8:
        return -0.5
    return 0.0

def calculate_xg_conversion_features(row):
    home_goals = row.get('home_team_goal_count', 0)
    away_goals = row.get('away_team_goal_count', 0)
    home_xg = row.get('Home Team Pre-Match xG', 0)
    away_xg = row.get('Away Team Pre-Match xG', 0)
    home_shots_on_target = row.get('home_team_shots_on_target', 1)
    away_shots_on_target = row.get('away_team_shots_on_target', 1)
    home_conversion = home_goals / (home_shots_on_target + 1e-3)
    away_conversion = away_goals / (away_shots_on_target + 1e-3)
    xg_gap = abs(home_xg - home_goals) + abs(away_xg - away_goals)
    return pd.Series({
        'finishing_efficiency_home': round(home_conversion, 3),
        'finishing_efficiency_away': round(away_conversion, 3),
        'xg_conversion_gap': round(xg_gap, 3)
    })

def calculate_momentum_trend_score(row):
    form_gap = row.get('weighted_home_ppg', 0) - row.get('weighted_away_ppg', 0)
    if abs(form_gap) < 0.1:
        return 0.0
    elif abs(form_gap) < 0.5:
        return 0.5 if form_gap > 0 else -0.5
    else:
        return 1.0 if form_gap > 0 else -1.0

def calculate_must_win_pressure(row):
    gw = row.get('Game Week', 1)
    return int(gw >= 30)

def calculate_big_team_bias(row):
    big_clubs = ["Real Madrid", "Barcelona", "Manchester City", "Liverpool", "PSG", "Bayern Munich", "Juventus"]
    is_big = row.get('home_team_name', '') in big_clubs or row.get('away_team_name', '') in big_clubs
    odds_diff = row.get('odds_diff', 0)
    implied_diff = abs(row.get('implied_prob_diff', 0))
    if is_big and odds_diff < 1.0 and implied_diff < 0.1:
        return 1.0
    elif is_big and odds_diff < 1.5:
        return 0.5
    return 0.0

def calculate_derby_volatility(row):
    known_derbies = [
        ("Arsenal", "Tottenham"), ("Man United", "Man City"),
        ("Barcelona", "Real Madrid"), ("AC Milan", "Inter"),
        ("Roma", "Lazio"), ("Dortmund", "Bayern Munich"),
        ("Benfica", "Porto"), ("Sporting CP", "Benfica"),
        ("NY Red Bulls", "NYCFC"), ("LA Galaxy", "LAFC")
    ]
    home = row.get('home_team_name', '')
    away = row.get('away_team_name', '')
    for team1, team2 in known_derbies:
        if (home == team1 and away == team2) or (home == team2 and away == team1):
            return 1.0
    return 0.0

def apply_prediction_modifiers(row):
    volatility_sum = (
        row.get('emotional_volatility_score', 0) +
        row.get('possession_dissonance_score', 0) +
        row.get('set_piece_pressure_index', 0) +
        row.get('momentum_score', 0) +
        row.get('big_team_bias_flag', 0) +
        row.get('high_stakes_flag', 0) +
        row.get('is_derby_match', 0)
    )
    if volatility_sum <= -1:
        draw_modifier = 1
    elif volatility_sum >= 3:
        draw_modifier = -1
    else:
        draw_modifier = 0
    btts_modifier = 1 if volatility_sum >= 2 else 0
    if volatility_sum <= -2:
        over25_modifier = -1
    elif volatility_sum >= 2:
        over25_modifier = 1
    else:
        over25_modifier = 0
    return pd.Series({
        'draw_overlay_modifier': draw_modifier,
        'btts_overlay_modifier': btts_modifier,
        'over25_overlay_modifier': over25_modifier
    })

def apply_volatility_stack(df, *, pre_match: bool = False):
    """
    Builds the volatility‑stack columns.

    If `pre_match=True` the function **skips any feature that would need
    post‑match data** (namely finishing‑efficiency / xG‑conversion) and
    instead fills those columns with 0 so the downstream model schema
    stays identical.

    Parameters
    ----------
    df : DataFrame
    pre_match : bool, default False
        Set to True when the dataframe corresponds to fixtures that have
        **not yet kicked‑off**.
    """
    df['emotional_volatility_score'] = df.apply(calculate_emotional_spike_index, axis=1)
    df['possession_dissonance_score'] = df.apply(
        lambda r: calculate_possession_volatility_score(r, pre_match=pre_match), axis=1
    )
    df['set_piece_pressure_index'] = df.apply(calculate_set_piece_pressure_index, axis=1)

    # --- Finishing efficiency & xG conversion --------------------------
    if not pre_match:
        xg_conversion_df = df.apply(calculate_xg_conversion_features, axis=1)
    else:
        # create empty/zero columns to preserve schema
        xg_conversion_df = pd.DataFrame({
            'finishing_efficiency_home': 0,
            'finishing_efficiency_away': 0,
            'xg_conversion_gap': 0
        }, index=df.index)

    df = pd.concat([df, xg_conversion_df], axis=1)

    # -------------------------------------------------------------------
    df['momentum_score']     = df.apply(calculate_momentum_trend_score, axis=1)
    df['high_stakes_flag']   = df.apply(calculate_must_win_pressure,   axis=1)
    df['big_team_bias_flag'] = df.apply(calculate_big_team_bias,       axis=1)
    df['is_derby_match']     = df.apply(calculate_derby_volatility,    axis=1)

    modifiers_df = df.apply(apply_prediction_modifiers, axis=1)
    df = pd.concat([df, modifiers_df], axis=1)
    return df

