# Robust season normaliser + fallback to date → start-year
try:
    # keep this single source of truth if present
    from etl_press_intensity import _normalize_season_string as _norm_season
except Exception:
    import re
    def _norm_season(season: str) -> str:
        if season is None: return ""
        s = str(season).strip()
        if not s: return s
        m = re.search(r"^((?:19|20)\d{2})\s*(?:[/_\-–]|\s+to\s+)\s*((?:19|20)\d{2})$", s, flags=re.IGNORECASE)
        if m: return f"{m.group(1)}/{m.group(2)}"
        m = re.search(r"^((?:19|20)\d{2})$", s)
        if m: y = m.group(1); return f"{y}/{y}"
        return s

def _infer_season_start_year_from_date(series: pd.Series) -> pd.Series:
    """European seasons start in July: months >= 7 belong to that calendar year."""
    dt = pd.to_datetime(series, errors="coerce")
    y = dt.dt.year
    m = dt.dt.month
    start = np.where(m >= 7, y, y - 1)
    return pd.Series(start, index=series.index).astype("Int64")
