def load_multiple_seasons(match_dir, *args, **kwargs):
    """
    Load and concatenate season CSVs found under *match_dir*.

    This minimal implementation restores syntax and basic functionality.
    If you had a richer loader previously, you can extend this function
    later; the pre-hook for press-intensity ETL is already included.
    """
    # Use local aliases so we never shadow module-level imports
    import glob as _glob, os as _os
    import pandas as _pd

    # Pre-hook: try enriching press inputs from Players/ season files
    try:
        ensure_press_from_players_on_disk(match_dir)
    except Exception as _e:
        print(f"⚠️ players→matches enrichment skipped for {match_dir}: {_e}")

    # --- Coverage snapshot (mirrors trainer output) -----------------
    try:
        _pattern = _os.path.join(str(match_dir), "**", "*.csv")
        _paths = sorted(_glob.glob(_pattern, recursive=True))

        def _skip_cov(p: str) -> bool:
            _name = _os.path.basename(p).lower()
            if any(k in _name for k in ("upcoming", "fixture", "fixtures", "prediction", "predictions", "report")):
                return True
            if any(k in p.lower() for k in ("predictions_output", "modelstore")):
                return True
            return False

        _paths = [p for p in _paths if not _skip_cov(p)]

        _have_pi = 0
        for _p in _paths:
            try:
                _hdr = _pd.read_csv(_p, nrows=1)
                if {"home_press_intensity", "away_press_intensity"}.issubset(_hdr.columns):
                    _have_pi += 1
            except Exception:
                continue

        _league = _os.path.basename(str(match_dir))
        _root = _os.path.dirname(str(match_dir))
        _players_root = _os.path.join(_root.replace("Matches", "Players"), _league)
        if _os.path.isdir(_players_root):
            _player_files = sorted(_glob.glob(_os.path.join(_players_root, "**", "*.csv"), recursive=True))
            _players_n = len(_player_files)
        else:
            _players_n = 0

        print(f"🧪 Coverage: press-intensity present in {_have_pi}/{len(_paths)} match CSVs | Players season files: {_players_n} under Players/{_league}")
    except Exception as _e:
        print(f"⚠️ coverage scan failed: {_e}")

    # Pre-hook: ensure press-intensity columns exist on disk (idempotent)
    try:
        ensure_press_intensity_on_disk(match_dir, force=False)
    except Exception as _e:
        print(f"⚠️ press-intensity ETL skipped for {match_dir}: {_e}")

    # --- Enumerate and read match CSVs (using the same _os/_glob aliases) ---
    pattern = _os.path.join(str(match_dir), "**", "*.csv")
    paths = sorted(_glob.glob(pattern, recursive=True))

    def _skip(p: str) -> bool:
        name = _os.path.basename(p).lower()
        if any(k in name for k in ("upcoming", "fixture", "fixtures", "prediction", "predictions", "report")):
            return True
        if any(k in p.lower() for k in ("predictions_output", "modelstore")):
            return True
        return False

    paths = [p for p in paths if not _skip(p)]

    frames: list[pd.DataFrame] = []
    for p in paths:
        try:
            df = pd.read_csv(p)
            if "match_date" in df.columns:
                df["match_date"] = pd.to_datetime(df["match_date"], errors="coerce")
            frames.append(df)
        except Exception as _e:
            print(f"⏩  Skipping {_os.path.basename(p)} – {_e}")

    if not frames:
        return pd.DataFrame()

    return pd.concat(frames, ignore_index=True)

def aggregate_player_metrics(player_data):
    aggregated_metrics = player_data.groupby(['Current Club']).agg({
        'rank_in_league_top_attackers': 'mean',
        'rank_in_league_top_midfielders': 'mean',
        'rank_in_league_top_defenders': 'mean',
        'rank_in_club_top_scorer': 'mean',
        'average_rating_overall': 'mean',
        'assists_per_game_overall': 'sum',
        'passes_per_90_overall': 'mean',
        'passes_total_overall': 'sum',
        'passes_completed_per_game_overall': 'mean',
        'pass_completion_rate_percentile_overall': 'mean',
        'tackles_per_90_overall': 'sum',
        'interceptions_per_game_overall': 'sum',
        'dribbles_successful_per_game_overall': 'mean',
        'shots_per_90_overall': 'mean',
        'distance_travelled_per_game_overall': 'mean',
        'xg_per_game_overall': 'mean',
        'chances_created_per_game_overall': 'mean',
        'aerial_duels_won_per_game_overall': 'mean',
        'possession_regained_per_90_overall': 'mean',
        'fouls_committed_per_90_overall': 'mean'
    }).reset_index()
    return aggregated_metrics


# ------------------------------------------------------------------
# Side‑probability placeholders (draw‑prone & U1.5 surrogates)
# ------------------------------------------------------------------
SIDE_PROB_FEATURES = {
    "draw_prone": 0,
    "home_under15_prob": 0.50,
    "away_under15_prob": 0.50,
    "under15_combined_prob": 0.50,
    "under25_combined_prob": 0.50,
}

def _inject_side_prob_placeholders(df: pd.DataFrame,
                                   feature_defaults: dict[str, float] = SIDE_PROB_FEATURES,
                                   warn: bool = True) -> pd.DataFrame:
    """
    Ensure every side‑probability column exists so downstream code
    never crashes when the specialist models haven’t run yet.

    Missing columns are injected with neutral defaults and their
    names recorded under the DataFrame attribute ``__placeholders__``.
    """
    placeholders: list[str] = []
    for col, default in feature_defaults.items():
        if col not in df.columns:
            df[col] = default
            placeholders.append(col)

    if warn and placeholders:
        print(f"⚠️  Injected neutral defaults for side‑prob columns: {placeholders}")

    df.attrs.setdefault("__placeholders__", set()).update(placeholders)
    return df


# --------------------------------------------------------------
# Helper: Summarise player‑level stats into team‑match rows
# --------------------------------------------------------------
def per_match_team_totals(players: pd.DataFrame) -> pd.DataFrame:
    """
    Summarise player‑level stats into a team‑match row that the
    press‑intensity proxy requires.

    Parameters
    ----------
    players : DataFrame
        Must contain at least:
            • match_id
            • side            (“home” / “away”)
            • passes_total_overall
            • tackles_total_overall
            • interceptions_total_overall
        Optionally:
            • pressures_total_overall

    Returns
    -------
    DataFrame
        One row per (match_id, side) with *_sum columns ready to pivot
        into the match‑level dataset.
    """
    cols_sum = [
        "passes_total_overall",
        "tackles_total_overall",
        "interceptions_total_overall",      # NOT per‑game
        "pressures_total_overall"           # optional
    ]
    existing = [c for c in cols_sum if c in players.columns]
    if not existing:
        raise ValueError(
            "Player CSV lacks passes / tackles / interceptions columns "
            f"(looked for: {cols_sum})"
        )

    df = (
        players
        .groupby(["match_id", "side"], as_index=False)[existing]
        .sum(min_count=1)
        .rename(columns={c: f"{c}_sum" for c in existing})  # avoid clashes
    )
    return df

def load_and_preprocess_data(player_folder, match_folder):
    player_data = load_multiple_seasons(player_folder)
    if player_data.empty:
        print(f"No player data loaded from {player_folder}.")
        return pd.DataFrame()
    if not set(['goals_overall', 'minutes_played_overall']).issubset(player_data.columns):
        print(f"Required columns not found in player data from {player_folder}.")
        return pd.DataFrame()
    match_data = load_multiple_seasons(match_folder)
    if match_data.empty:
        print(f"No match data loaded from {match_folder}.")
        return pd.DataFrame()
    # ------------------------------------------------------------------
    # Ensure every match row has a unique ID *before* press‑intensity ETL
    # ------------------------------------------------------------------
    if (
        "match_id" not in match_data.columns
        and {"home_team_name", "away_team_name"}.issubset(match_data.columns)
    ):
        if "match_date" in match_data.columns:
            _dt = pd.to_datetime(match_data["match_date"], errors="coerce")

        elif "date_GMT" in match_data.columns:
            # FootyStats pattern: "Aug 16 2024 - 7:00pm"
            _dt = pd.to_datetime(
                match_data["date_GMT"],
                format="%b %d %Y - %I:%M%p",
                errors="coerce"
            )
        else:
            _dt = pd.Series(pd.NaT, index=match_data.index)  # all‑NaT fallback

        _date_str = _dt.dt.strftime("%Y-%m-%d %H:%M").fillna("")

        synthetic = (
            _date_str + "_" +
            match_data["home_team_name"].astype(str) + "_" +
            match_data["away_team_name"].astype(str)
        )
        match_data["match_id"] = synthetic.factorize()[0]

    # --------------------------------------------------------------
    # Attach full‑pitch press‑intensity proxy (home/away) to matches
    # --------------------------------------------------------------
    try:
        # expects player_data with match-linked rows (match_id + side)
        press_df = compute_press_intensity(player_data)
        # press_df columns: match_id, home_press_intensity, away_press_intensity
        if {'match_id', 'home_press_intensity', 'away_press_intensity'}.issubset(press_df.columns):
            match_data = match_data.merge(
                press_df[['match_id',
                          'home_press_intensity',
                          'away_press_intensity']],
                on='match_id',
                how='left'
            )
    except Exception as _e:
        print(f"⚠️  Press-intensity ETL skipped: {_e}")
        # Ensure placeholder cols exist so the rolling builder never fails
        for _col in ('home_press_intensity', 'away_press_intensity'):
            if _col not in match_data.columns:
                match_data[_col] = np.nan

    player_data = player_data.dropna(subset=['goals_overall', 'minutes_played_overall'])
    team_metrics = aggregate_player_metrics(player_data)
    combined_data = pd.merge(match_data, team_metrics, left_on='home_team_name', right_on='Current Club', how='left')
    combined_data = pd.merge(combined_data, team_metrics, left_on='away_team_name', right_on='Current Club', how='left', suffixes=('_home', '_away'))

    # ------------------------------------------------------------------
    # Inject neutral side‑probability placeholders (draw‑prone, U1.5 etc.)
    # ------------------------------------------------------------------
    combined_data = _inject_side_prob_placeholders(combined_data)
    combined_data.drop(columns=['Current Club_home', 'Current Club_away'], errors='ignore', inplace=True)
    # Move FTR assignment block here, before any rolling average or predictions
    if 'FTR' not in combined_data.columns:
        if 'home_team_goal_count' in combined_data.columns and 'away_team_goal_count' in combined_data.columns:
            combined_data['FTR'] = combined_data.apply(
                lambda x: 0 if x.get('home_team_goal_count', 0) > x.get('away_team_goal_count', 0)
                else (1 if x.get('home_team_goal_count', 0) == x.get('away_team_goal_count', 0) else 2),
                axis=1
            )
    # combined_data['goal_count_diff'] = combined_data.get('home_team_goal_count', 0) - combined_data.get('away_team_goal_count', 0)
    # Remove any legacy goal_count_diff and goal_possession_interaction columns if present
    combined_data.drop(columns=['goal_count_diff', 'goal_possession_interaction'], errors='ignore', inplace=True)
    combined_data['predicted_goal_diff'] = combined_data.get('home_goals_pred', 0) - combined_data.get('away_goals_pred', 0)
    combined_data['possession_diff'] = combined_data.get('home_team_possession', 0) - combined_data.get('away_team_possession', 0)
    combined_data['home_recent_form'] = combined_data.get('home_ppg', 0)
    combined_data['away_recent_form'] = combined_data.get('away_ppg', 0)
    combined_data['weighted_home_ppg'] = combined_data.groupby('home_team_name')['home_recent_form'].transform(
        lambda x: x.rolling(5, min_periods=1).mean().shift(1)
    )
    combined_data['weighted_away_ppg'] = combined_data.groupby('away_team_name')['away_recent_form'].transform(
        lambda x: x.rolling(5, min_periods=1).mean().shift(1)
    )
    combined_data['ppg_diff'] = combined_data['weighted_home_ppg'] - combined_data['weighted_away_ppg']
    if 'xg_diff' not in combined_data.columns:
        if "Home Team Pre-Match xG" in combined_data.columns and "Away Team Pre-Match xG" in combined_data.columns:
            combined_data['xg_diff'] = combined_data["Home Team Pre-Match xG"] - combined_data["Away Team Pre-Match xG"]
        else:
            combined_data['xg_diff'] = np.nan
    for col in ['odds_ft_home_team_win', 'odds_ft_draw', 'odds_ft_away_team_win']:
        if col not in combined_data.columns:
            combined_data[col] = np.nan
    combined_data['implied_home_prob'] = 1 / combined_data['odds_ft_home_team_win']
    combined_data['implied_draw_prob'] = 1 / combined_data['odds_ft_draw']
    combined_data['implied_away_prob'] = 1 / combined_data['odds_ft_away_team_win']
    combined_data['implied_prob_diff'] = combined_data['implied_home_prob'] - combined_data['implied_away_prob']
    if 'odds_diff' not in combined_data.columns:
        if 'odds_ft_home_team_win' in combined_data.columns and 'odds_ft_away_team_win' in combined_data.columns:
            combined_data['odds_diff'] = np.abs(combined_data['odds_ft_home_team_win'] - combined_data['odds_ft_away_team_win'])
        else:
            combined_data['odds_diff'] = np.nan
    if 'date_GMT' in combined_data.columns:
        combined_data['match_date'] = pd.to_datetime(combined_data['date_GMT'], format='%b %d %Y - %I:%M%p', errors='coerce')
        combined_data.sort_values("match_date", inplace=True)
    # --- team IDs for CatBoost embeddings --------------------
    all_teams = pd.Series(pd.concat([
        combined_data["home_team_name"],
        combined_data["away_team_name"]
    ]).unique())
    team_map = {t: i for i, t in enumerate(all_teams)}
    combined_data["home_team_id"] = combined_data["home_team_name"].map(team_map).astype(str)
    combined_data["away_team_id"] = combined_data["away_team_name"].map(team_map).astype(str)
    # --- Filter out teams with too small sample size -----------
    combined_data = filter_small_sample_teams(combined_data)
    # --- build leak‑safe rolling metrics BEFORE further engineering ---
    combined_data = build_team_rolling_metrics(combined_data, windows=(5, 10))
    # --------------------------------------------------------------
    # Attach model‑based side probabilities
    #   • draw_prone
    #   • home_under15_prob / away_under15_prob
    #   • under15_combined_prob / under25_combined_prob
    # --------------------------------------------------------------
    try:
        league_tag = os.path.basename(match_folder)  # e.g. "England Premier League"
        combined_data = attach_side_probabilities(combined_data, league_tag)
    except Exception as _e:
        print(f"⚠️  Side‑prob model attachment failed: {_e}")
        # Safe fallback: neutral placeholders so later code never breaks
        _side_cols = [
            "draw_prone",
            "home_under15_prob", "away_under15_prob",
            "under15_combined_prob", "under25_combined_prob"
        ]
        for _c in _side_cols:
            if _c not in combined_data.columns:
                combined_data[_c] = 0.33 if "prob" in _c else 0
    
    
    # ─────────────────────────────────────────────────────────────
    # Sanity-check: never let a None / empty dataframe propagate
    # ─────────────────────────────────────────────────────────────
    assert isinstance(combined_data, pd.DataFrame) and not combined_data.empty, \
        "combined_data is empty or None – check earlier load / pre-process steps"
    # --------------------------------------------------------------
    # Final clean‑up: hard‑drop post‑match statistics so the models
    # never see current‑match outcomes, but keep the derived rolling
    # metrics we just built from the *previous* fixtures.
    # --------------------------------------------------------------
    combined_data.drop(
        columns=[c for c in combined_data.columns
                 if any(tag in c for tag in POST_MATCH_TAGS)],
        errors="ignore",
        inplace=True
    )
    return combined_data

