def add_advanced_features(df):
    """
    Build purely pre‑match composites using rolling‑window inputs.
    Falls back from rolling‑5 → rolling‑10 → 0.
    """

    # ------------------------------------------------------------------ #
    # Ensure all rolling / EWM columns exist BEFORE we reference them
    # ------------------------------------------------------------------ #
    _required_pre_match_cols = [
        # shot quality
        'rolling5_home_sot_ratio', 'rolling5_away_sot_ratio',
        'rolling10_home_sot_ratio', 'rolling10_away_sot_ratio',
        # shot volume
        'rolling5_home_shots', 'rolling5_away_shots',
        'rolling10_home_shots', 'rolling10_away_shots',
        # card ratios
        'rolling5_home_card_ratio', 'rolling5_away_card_ratio',
        'rolling10_home_card_ratio', 'rolling10_away_card_ratio',
        # possession baselines
        'ewm10_home_possession', 'ewm10_away_possession'
    ]
    for _col in _required_pre_match_cols:
        if _col not in df.columns:
            df[_col] = 0

    # ------------------------------------------------------------------ #
    # helper: prefer primary, else fallback, else 0
    # ------------------------------------------------------------------ #
    def _pick(primary: str, fallback: str):
        return df[primary].where(df[primary].notna() & (df[primary] != 0), df.get(fallback, 0))

    # ---------- 1. Offensive power ------------------------------------ #
    sot_home = _pick('rolling5_home_sot_ratio', 'rolling10_home_sot_ratio')
    sot_away = _pick('rolling5_away_sot_ratio', 'rolling10_away_sot_ratio')

    df['home_offensive_index'] = sot_home * df.get('Home Team Pre-Match xG', 0)
    df['away_offensive_index'] = sot_away * df.get('Away Team Pre-Match xG', 0)

    # ---------- Attacking‑pressure surrogate --------------------------
    #   shot‑on‑target ratio  ×  total shots (rolling‑window fallback)
    ap_home = sot_home * _pick('rolling5_home_shots',  'rolling10_home_shots')
    ap_away = sot_away * _pick('rolling5_away_shots',  'rolling10_away_shots')

    df['attacking_pressure_home'] = ap_home.fillna(0)
    df['attacking_pressure_away'] = ap_away.fillna(0)

    for _col in ('attacking_pressure_home', 'attacking_pressure_away'):
        if _col not in df.columns:
            df[_col] = 0

    # ---------- 2. Defensive discipline (cards per foul proxy) -------- #
    card_home = _pick('rolling5_home_card_ratio', 'rolling10_home_card_ratio')
    card_away = _pick('rolling5_away_card_ratio', 'rolling10_away_card_ratio')

    df['home_defensive_ratio'] = card_home
    df['away_defensive_ratio'] = card_away
    # Prevent divide‑by‑zero and huge constants when the card ratio is ~0
    df['home_defensive_efficiency'] = 1 / np.clip(df['home_defensive_ratio'], 1e-3, None)
    df['away_defensive_efficiency'] = 1 / np.clip(df['away_defensive_ratio'], 1e-3, None)
    # --- hard‑cap efficiency to avoid huge outliers -----------------
    df['home_defensive_efficiency'] = df['home_defensive_efficiency'].clip(0, 30)
    df['away_defensive_efficiency'] = df['away_defensive_efficiency'].clip(0, 30)

    # ---------- 3. Book‑maker implied probabilities (as before) ------- #
    if all(col in df.columns for col in
           ['odds_ft_home_team_win', 'odds_ft_draw', 'odds_ft_away_team_win']):
        inv_home = 1 / df['odds_ft_home_team_win']
        inv_draw = 1 / df['odds_ft_draw']
        inv_away = 1 / df['odds_ft_away_team_win']
        total_inv = inv_home + inv_draw + inv_away
        df['home_win_implied_prob'] = inv_home / total_inv
        df['draw_implied_prob']  = inv_draw / total_inv
        df['away_win_implied_prob'] = inv_away / total_inv
    else:
        df['home_win_implied_prob'] = df['draw_implied_prob'] = df['away_win_implied_prob'] = 0

    # Drop legacy implied_* columns to avoid confusion
    df.drop(columns=['implied_home_prob', 'implied_draw_prob', 'implied_away_prob'], inplace=True, errors='ignore')
    # --- guard: bookmaker odds may have been stripped (ENABLE_SIDE_PROB_ABLATION) ---
    import warnings
    if df[['home_win_implied_prob', 'draw_implied_prob', 'away_win_implied_prob']].abs().sum().sum() == 0:
        warnings.warn(
            "All implied‑prob columns are zero – odds absent or ablated. "
            "Implied‑prob‑derived features will be neutral‑filled."
        )
        # neutral placeholder so downstream code doesn’t choke
        df['implied_prob_diff'] = 0.0
        # skip the rest of this helper; everything below relies on non‑zero implied probs
        return df

    # ---------- 4. Interaction term (removed for model safety) ---------- #
    # df['goal_possession_interaction'] = df['predicted_goal_diff'] * df['possession_diff']
    # Drop if present
    df.drop(columns=['goal_possession_interaction'], errors='ignore', inplace=True)

    # ------------------------------------------------------------------ #
    # 5. Guard‑rails: make sure every rolling / EWM column exists
    #    (already handled above; redundant block removed)
    # ------------------------------------------------------------------ #

    # === OVER 2.5 ENHANCEMENTS ===
    # Total expected xG for match
    df["total_xg"] = df.get("Home Team Pre-Match xG", 0) + df.get("Away Team Pre-Match xG", 0)
    # Predicted total goals from model
    df["predicted_total_goals"] = df.get("home_goals_pred", 0) + df.get("away_goals_pred", 0)
    # Recent average goals conceded per side (via rolling5 goals conceded)
    df["home_recent_goals_conceded"] = df.get("rolling5_home_gc", 0)
    df["away_recent_goals_conceded"] = df.get("rolling5_away_gc", 0)
    # === Meta Feature: xG-overperformance deviation ===
    # Difference between expected xG total and actual outcome spread (model-safe)
    _pred_goal_diff = df.get("predicted_goal_diff", 0)
    df["goal_diff_deviation"] = df.get("total_xg", 0) - np.abs(_pred_goal_diff)
    # --- Fixture Incentive Features ---
    df["is_high_stakes_fixture"] = (df.get("Game Week", 1) >= 30).astype(int)

    # Placeholder for future logic (e.g. draw is enough, upcoming UCL/rest logic)
    df["is_draw_incentivized"] = 0
    return df

