import re  # at top of file if not already present

def _safe_season_start_year(season_str):
    """
    Return the first 4-digit year in season_str (handles "2024-25", "2024-2024", "2024").
    Returns None if nothing parseable is found so callers can soft-skip rows.
    """
    if season_str is None or (isinstance(season_str, float) and np.isnan(season_str)):
        return None
    m = re.search(r'(?:19|20)\d{2}', str(season_str))
    return int(m.group(0)) if m else None
def add_goal_predictions_to_complete_data(df, league, required_features):
    home_goals_model_path = os.path.join(MODEL_DIR, f"{league}_home_goals_model.pkl")
    away_goals_model_path = os.path.join(MODEL_DIR, f"{league}_away_goals_model.pkl")

    # ------------------------------------------------------------------
    # Prefer the leak‑free 5‑fold ensemble if it exists
    # ------------------------------------------------------------------
    ensemble_dir = os.path.join(MODEL_DIR, "goal_ensembles")
    home_ensemble_path = os.path.join(ensemble_dir, "home_goals_fold5.pkl")
    away_ensemble_path = os.path.join(ensemble_dir, "away_goals_fold5.pkl")

    # ------------------------------------------------------------------
    # Fast‑path guard: if the 5‑fold ensemble pickles are missing we
    # (re)train them on‑the‑fly so downstream loading never fails.
    # ------------------------------------------------------------------
    if not (os.path.exists(home_ensemble_path) and os.path.exists(away_ensemble_path)):
        print("🏗️  Re‑training 5‑fold goal‑regressor ensemble …")
        _ = quick_fit_goal_regressors(df.copy(), league)      # persists new pickles

    def _ensemble_predict(models: list, X_mat: pd.DataFrame) -> np.ndarray:
        """
        Mean of exp(pred) across all CatBoost fold‑models.
        Guarantees λ̂ is always returned in linear space.
        """
        if not models:
            raise ValueError("No models supplied to _ensemble_predict()")
        return np.mean([np.exp(m.predict(X_mat)) for m in models], axis=0)

    # ------------------------------------------------------------------
    # 1) Use the saved 5‑fold ensemble if present
    # ------------------------------------------------------------------
    if os.path.exists(home_ensemble_path) and os.path.exists(away_ensemble_path):
        try:
            fold_models_home = joblib.load(home_ensemble_path)
            fold_models_away = joblib.load(away_ensemble_path)
        except Exception as _load_err:
            # Corrupted / incompatible pickle – rebuild the ensemble once
            print(f"⚠️  Cached goal‑ensemble corrupted ({_load_err}) – rebuilding …")
            _ = quick_fit_goal_regressors(df.copy(), league)   # regenerate & save
            fold_models_home = joblib.load(home_ensemble_path)
            fold_models_away = joblib.load(away_ensemble_path)

        # Use feature schema from exemplars and align matrices before predict
        def _model_feature_schema(_mdl, _df, tag: str = "") -> list:
            feats = None
            if _mdl is not None:
                try:
                    feats = list(getattr(_mdl, "feature_names_in_", []) or [])
                except Exception:
                    feats = None
                if not feats:
                    try:
                        booster = getattr(_mdl, "get_booster", lambda: None)()
                        names = getattr(booster, "feature_names", None) if booster is not None else None
                        if names:
                            feats = list(names)
                    except Exception:
                        pass
            if not feats:
                try:
                    feats = [c for c in _df.columns if pd.api.types.is_numeric_dtype(_df[c])]
                except Exception:
                    feats = []
                try:
                    if os.getenv("VERBOSE_QUICK","0") == "1":
                        print(f"⚠️  Using numeric-column fallback for goal-regressor schema ({tag}): {len(feats)} columns")
                except Exception:
                    pass
            return feats

        # Exemplars from ensembles
        home_exemplar = fold_models_home[0] if isinstance(fold_models_home, (list, tuple)) and len(fold_models_home) > 0 else fold_models_home
        away_exemplar = fold_models_away[0] if isinstance(fold_models_away, (list, tuple)) and len(fold_models_away) > 0 else fold_models_away

        feats_home = _model_feature_schema(home_exemplar, df, tag="home")
        feats_away = _model_feature_schema(away_exemplar, df, tag="away")

        # Start from a de-duplicated copy once
        df_nodup = df.loc[:, ~df.columns.duplicated()].copy()

        # Build and align home matrix
        for ft in feats_home:
            if ft not in df_nodup.columns:
                df_nodup[ft] = 0
        X_home_raw = (
            df_nodup[feats_home]
                .replace([np.inf, -np.inf], np.nan)
                .fillna(SENTINEL)
                .loc[:, ~df_nodup[feats_home].columns.duplicated()]
        )
        X_home = _align_dataframe_to_model(X_home_raw, home_exemplar)

        # Build and align away matrix
        for ft in feats_away:
            if ft not in df_nodup.columns:
                df_nodup[ft] = 0
        X_away_raw = (
            df_nodup[feats_away]
                .replace([np.inf, -np.inf], np.nan)
                .fillna(SENTINEL)
                .loc[:, ~df_nodup[feats_away].columns.duplicated()]
        )
        X_away = _align_dataframe_to_model(X_away_raw, away_exemplar)

        # Ensure CatBoost categorical IDs are strings
        for _c in ("home_team_id", "away_team_id"):
            if _c in X_home.columns:
                X_home[_c] = X_home[_c].astype(str)
            if _c in X_away.columns:
                X_away[_c] = X_away[_c].astype(str)

        # Predict from ensembles (λ̂ in linear space)
        df["home_goals_pred"] = _ensemble_predict(fold_models_home, X_home)
        df["away_goals_pred"] = _ensemble_predict(fold_models_away, X_away)

    # ------------------------------------------------------------------
    # 1b) Fallback to single saved models
    # ------------------------------------------------------------------
    elif os.path.exists(home_goals_model_path) and os.path.exists(away_goals_model_path):
        home_goals_model = joblib.load(home_goals_model_path)
        away_goals_model = joblib.load(away_goals_model_path)

        # Retrieve feature list from model metadata (CatBoost / XGB)
        try:
            model_features = list(home_goals_model.feature_names_)
        except Exception:
            model_features = required_features

        df = df.loc[:, ~df.columns.duplicated()].copy()
        for ft in model_features:
            if ft not in df.columns:
                df[ft] = 0
        X_subset = df[model_features].replace([np.inf, -np.inf], np.nan)
        X_subset = safe_fill(X_subset, X_subset.columns.tolist(), SENTINEL)
        X_subset = X_subset.loc[:, ~X_subset.columns.duplicated()]
        X_subset = X_subset.select_dtypes(include=['number'])

        # Align columns to each model
        X_home = _align_dataframe_to_model(X_subset, home_goals_model)
        X_away = _align_dataframe_to_model(X_subset, away_goals_model)

        df["home_goals_pred"] = predict_lambda(home_goals_model, X_home)
        df["away_goals_pred"] = predict_lambda(away_goals_model, X_away)

    # ------------------------------------------------------------------
    # Fallback: quick-fit regressors if no saved models are present
    # ------------------------------------------------------------------
    else:
        # Fit quick goal regressors and predict for all rows
        model_home, model_away = quick_fit_goal_regressors(df, league)
        X_home = _align_dataframe_to_model(df, model_home)
        X_away = _align_dataframe_to_model(df, model_away)
        df["home_goals_pred"] = predict_lambda(model_home, X_home)
        df["away_goals_pred"] = predict_lambda(model_away, X_away)
        print("⚡  Fallback: quick‑fit goal regressors used for λ̂ predictions")

    # ------------------------------------------------------------------
    # Guard-rail: ensure λ̂ columns exist after the prediction step
    # ------------------------------------------------------------------
    if 'home_goals_pred' not in df.columns or 'away_goals_pred' not in df.columns:
        raise RuntimeError("λ̂ columns missing after goal‑prediction step – investigate model loading paths.")

    # ------------------------------------------------------------------
    # 3) Return a human‑readable correct‑score string for quick QA
    # ------------------------------------------------------------------
    def compute_correct_score(row):
        home_score = int(round(row['home_goals_pred'])) if not np.isnan(row['home_goals_pred']) else 0
        away_score = int(round(row['away_goals_pred'])) if not np.isnan(row['away_goals_pred']) else 0
        h_probs = poisson.pmf(np.arange(6), row['home_goals_pred']) if not np.isnan(row['home_goals_pred']) else np.zeros(6)
        a_probs = poisson.pmf(np.arange(6), row['away_goals_pred']) if not np.isnan(row['away_goals_pred']) else np.zeros(6)
        score_matrix = np.outer(h_probs, a_probs)
        home_win_prob = np.sum(np.tril(score_matrix, -1))
        draw_prob = np.sum(np.diag(score_matrix))
        away_win_prob = np.sum(np.triu(score_matrix, 1))
        confidence = max(home_win_prob, draw_prob, away_win_prob)
        return f"{home_score}-{away_score} (Conf: {confidence*100:.1f}%)"

    df['correct_score_pred'] = df.apply(compute_correct_score, axis=1)
    # ------------------------------------------------------------------
    # Final safeguard – clip improbable λ̂ spikes
    # ------------------------------------------------------------------
    df['home_goals_pred'] = df['home_goals_pred'].clip(0, 5)
    df['away_goals_pred'] = df['away_goals_pred'].clip(0, 5)
    # --------------------------------------------------------------
    # Smoke‑test: λ̂ must be finite and non‑negative everywhere
    # --------------------------------------------------------------
    assert np.all(np.isfinite(df['home_goals_pred'])) and (df['home_goals_pred'] >= 0).all(), \
        "home_goals_pred contains NaN, ±inf or negative values"
    assert np.all(np.isfinite(df['away_goals_pred'])) and (df['away_goals_pred'] >= 0).all(), \
        "away_goals_pred contains NaN, ±inf or negative values"

    return df
# ------------------------------------------------------------------
# Helper: guarantee ordinary Python‑str column names
# ------------------------------------------------------------------
def _ensure_str_cols(df: pd.DataFrame) -> pd.DataFrame:
    """
    Convert any numpy.str_ / bytes column names to native Python str
    so downstream scikit‑learn dtype checks never fail.
    """
    df.columns = df.columns.astype(str, copy=False)
    return df

#############################################
# Helper: align a DataFrame’s columns to a fitted model
#############################################
# DEPRECATED: legacy df-param variant; renamed to avoid shadowing the strict aligner
def _align_dataframe_to_model_legacy_df(df: pd.DataFrame, model):
    """
    Return a copy of *df* that contains *exactly* the feature columns the
    fitted model learnt, in the correct order.  Missing cols are added
    (filled with 0); extras are dropped – prevents XGBoost / CatBoost
    “feature_names mismatch” errors.
    """
    # --- normalise column dtypes (str vs numpy.str_) -----------------
    df = _ensure_str_cols(df)
    # Cast NumPy‑string (np.str_) labels to native Python str so the
    # downstream re‑index never mixes dtypes.  Some estimators (e.g.
    # XGBRegressor) expose *read‑only* `feature_names_in_`, so we wrap
    # the cast in a try/except guard and silently skip when mutation
    # isn’t allowed.
    try:
        model.feature_names_in_ = np.array(
            [str(c) for c in model.feature_names_in_], dtype=object
        )
    except (AttributeError, TypeError):
        # Read‑only attribute – safe to proceed without mutating.
        pass
    feat_names = []
    # ── 1) scikit‑learn models expose `feature_names_in_` ----------------
    if hasattr(model, "feature_names_in_") and getattr(model, "feature_names_in_", None) is not None:
        try:
            feat_names = list(model.feature_names_in_)
        except Exception:
            feat_names = []

    # ── 2) CatBoost wrappers ------------------------------------------------
    if not feat_names:
        try:
            if hasattr(model, "feature_names_") and model.feature_names_:
                feat_names = list(model.feature_names_)
        except Exception:
            pass

    # ── 3) XGBoost booster --------------------------------------------------
    if not feat_names:
        try:
            booster = getattr(model, "get_booster", lambda: None)()
            if booster is not None and booster.feature_names:
                feat_names = list(booster.feature_names)
        except Exception:
            pass

    # ── 4) Fallback: use current dataframe columns --------------------------
    if not feat_names:
        feat_names = list(df.columns)

    # de-duplicate while preserving order
    feat_names = list(dict.fromkeys(feat_names))

    feat_names = [str(f) for f in feat_names]    # enforce native str dtype

    aligned = df.copy()
    for col in feat_names:                  # add missing
        if col not in aligned.columns:
            aligned[col] = 0
    # -- last‑chance guard: drop any duplicate columns -----------------
    aligned = aligned.loc[:, ~aligned.columns.duplicated()]
    # Final safety: normalise column dtype to native str
    aligned = _ensure_str_cols(aligned)
    # exact order, drop extras
    return aligned[feat_names].copy()
#############################################
# Additional Advanced Features for Draw Prediction
#############################################
def advanced_draw_features(df, *, draw_thresh: float = 0.60, use_cap: bool = False):
    # OG PATCH: ensure ppg_diff exists (robust across schemas)
    # Prefer canonical pre-match PPG columns; fall back to EWMA proxy; else zeros.
    import os as _os
    import pandas as _pd

    def _first_col(_df, cands):
        for _c in cands:
            if _c in _df.columns:
                return _c
        return None

    if "ppg_diff" not in df.columns:
        h_ppg_col = _first_col(df, [
            "Pre-Match PPG (Home)", "pre_match_ppg_home", "home_ppg",
            "ppg_home", "pre_match_ppg_home_team", "home_team_ppg",
            "home_points_per_game"
        ])
        a_ppg_col = _first_col(df, [
            "Pre-Match PPG (Away)", "pre_match_ppg_away", "away_ppg",
            "ppg_away", "pre_match_ppg_away_team", "away_team_ppg",
            "away_points_per_game"
        ])
        if h_ppg_col and a_ppg_col:
            try:
                df["ppg_diff"] = _pd.to_numeric(df[h_ppg_col], errors="coerce") - \
                                 _pd.to_numeric(df[a_ppg_col], errors="coerce")
            except Exception:
                df["ppg_diff"] = _pd.Series(0.0, index=df.index)
        elif "ewma_ppg_diff" in df.columns:
            df["ppg_diff"] = _pd.to_numeric(df["ewma_ppg_diff"], errors="coerce")
        else:
            df["ppg_diff"] = _pd.Series(0.0, index=df.index)
            if _os.getenv("VERBOSE_QUICK","0") == "1":
                try:
                    print("⚠️ advanced_draw_features: ppg_diff unavailable; filled zeros")
                except Exception:
                    pass
    """
    Add extra features for draw prediction:
      - match_equality: 1 if absolute ppg_diff is less than 0.2.
      - low_attacking_quality: 1 if both teams' pre-match xG are less than 1.0.
      - strong_defense: 1 if average defensive efficiency is above the 75th percentile.
      - odds_balance: 1 if odds difference is in the lowest 25% of distribution.
      - draw_likelihood_score: Composite score.
    """
    # Immutable guard – if the flag already exists, do **not** recompute.
    if 'is_draw_prone' in df.columns:
        return df
    df['match_equality'] = (df['ppg_diff'].abs() < 0.2).astype(int)
    # Low-goals signal based on Over 2.5 odds
    # Robust low-goals market signal: tolerate missing odds by vectorizing default NaN
    _o25 = _pd.to_numeric(df.get("odds_ft_over25"), errors="coerce")
    if not isinstance(_o25, _pd.Series) or _o25.shape[0] != df.shape[0]:
        _o25 = _pd.Series(_np.nan, index=df.index)
    _o25_cut = float(_os.getenv("O25_LOW_ODDS_CUTOFF", "1.9"))
    df["low_goals_market_signal"] = (_o25 < _o25_cut).fillna(False).astype(int)
    # Robust low pre-match xG signal (vectorized, tolerant to missing cols)
    _hxg = _pd.to_numeric(df.get("Home Team Pre-Match xG"), errors="coerce")
    _axg = _pd.to_numeric(df.get("Away Team Pre-Match xG"), errors="coerce")
    # If either isn’t a Series (e.g., missing -> scalar), replace with NaN Series
    if not isinstance(_hxg, _pd.Series) or _hxg.shape[0] != df.shape[0]:
        _hxg = _pd.Series(_np.nan, index=df.index)
    if not isinstance(_axg, _pd.Series) or _axg.shape[0] != df.shape[0]:
        _axg = _pd.Series(_np.nan, index=df.index)
    # Also consider canonical alt names if present
    if _hxg.isna().all():
        _hxg = _pd.to_numeric(df.get("pre_match_xg_home"), errors="coerce")
    if _axg.isna().all():
        _axg = _pd.to_numeric(df.get("pre_match_xg_away"), errors="coerce")
    _xg_cut = float(_os.getenv("PMXG_LOW_CUTOFF", "1.0"))
    # Robust low pre-match xG signal (vectorized, tolerant to missing cols)
    _hxg = _pd.to_numeric(df.get("Home Team Pre-Match xG"), errors="coerce")
    _axg = _pd.to_numeric(df.get("Away Team Pre-Match xG"), errors="coerce")

    # If either isn’t a Series (e.g., missing -> scalar), replace with NaN Series
    if not isinstance(_hxg, _pd.Series) or _hxg.shape[0] != df.shape[0]:
        _hxg = _pd.Series(_np.nan, index=df.index)
    if not isinstance(_axg, _pd.Series) or _axg.shape[0] != df.shape[0]:
        _axg = _pd.Series(_np.nan, index=df.index)

    # Also consider canonical alt names if present
    if _hxg.isna().all():
        _hxg = _pd.to_numeric(df.get("pre_match_xg_home"), errors="coerce")
    if _axg.isna().all():
        _axg = _pd.to_numeric(df.get("pre_match_xg_away"), errors="coerce")

    _xg_cut = float(_os.getenv("PMXG_LOW_CUTOFF", "1.0"))

    # Ensure Series type before boolean ops (protect against scalar numpy.bool_)
    hxg_s = _hxg if isinstance(_hxg, _pd.Series) else _pd.Series(_hxg, index=df.index)
    axg_s = _axg if isinstance(_axg, _pd.Series) else _pd.Series(_axg, index=df.index)
    cond = (hxg_s < _xg_cut) & (axg_s < _xg_cut)

    # Robust defensive-efficiency averages (handle missing/duplicate cols → Series)
    hdef_raw = df.get('home_defensive_efficiency', None)
    adef_raw = df.get('away_defensive_efficiency', None)

    def _as_series(x):
        if x is None:
            return _pd.Series(_np.nan, index=df.index)
        if isinstance(x, _pd.DataFrame):
            # Duplicate column names return a DataFrame; take first column as Series
            try:
                s = x.iloc[:, 0]
            except Exception:
                s = _pd.Series(_np.nan, index=df.index)
            return _pd.to_numeric(s, errors='coerce')
        return _pd.to_numeric(x, errors='coerce')

    hdef = _as_series(hdef_raw)
    adef = _as_series(adef_raw)
    avg_def = (hdef + adef) / 2.0

    if getattr(avg_def, 'notna', lambda: _pd.Series([False], index=df.index))().any():
        df['avg_defensive_efficiency'] = avg_def
        thr = _pd.to_numeric(avg_def, errors='coerce').quantile(0.75)
        if _np.isnan(thr):
            df['strong_defense'] = 0
        else:
            df['strong_defense'] = (avg_def > thr).astype(int)
    else:
        df['avg_defensive_efficiency'] = 0
        df['strong_defense'] = 0
    if 'odds_diff' in df.columns:
        threshold_odds = df['odds_diff'].quantile(0.25)
        df['odds_balance'] = (df['odds_diff'] < threshold_odds).astype(int)
    else:
        df['odds_balance'] = 0

    # --- OG DEFENSE (unconditional): ensure component flags exist before composing score ---
    # Ensure columns are present and numeric ints
    _need = [
        'match_equality', 'low_attacking_quality',
        'strong_defense', 'odds_balance', 'low_goals_market_signal'
    ]
    for _c in _need:
        if _c not in df.columns:
            df[_c] = 0
        else:
            try:
                df[_c] = _pd.to_numeric(df[_c], errors='coerce').fillna(0).astype(int)
            except Exception:
                df[_c] = 0

    # Build low_attacking_quality if still missing (vectorised, tolerant to missing xG columns)
    if 'low_attacking_quality' not in df.columns:
        try:
            _hxg = _pd.to_numeric(df.get("Home Team Pre-Match xG"), errors="coerce")
            if not isinstance(_hxg, _pd.Series) or _hxg.shape[0] != len(df):
                _hxg = _pd.to_numeric(df.get("pre_match_xg_home"), errors="coerce")
            _axg = _pd.to_numeric(df.get("Away Team Pre-Match xG"), errors="coerce")
            if not isinstance(_axg, _pd.Series) or _axg.shape[0] != len(df):
                _axg = _pd.to_numeric(df.get("pre_match_xg_away"), errors="coerce")
            if not isinstance(_hxg, _pd.Series) or _hxg.shape[0] != len(df):
                _hxg = _pd.Series(_np.nan, index=df.index)
            if not isinstance(_axg, _pd.Series) or _axg.shape[0] != len(df):
                _axg = _pd.Series(_np.nan, index=df.index)
            _xg_cut = float(_os.getenv("PMXG_LOW_CUTOFF", "1.0"))
            df["low_attacking_quality"] = ((_hxg < _xg_cut) & (_axg < _xg_cut)).fillna(False).astype(int)
        except Exception:
            df["low_attacking_quality"] = 0
    df['draw_likelihood_score'] = (
        0.25 * df['match_equality'] +
        0.25 * df['low_attacking_quality'] +
        0.25 * df['strong_defense'] +
        0.15 * df['odds_balance'] +
        0.10 * df['low_goals_market_signal']
    )

    # --- Draw‑prone flag driven by league‑specific threshold ----------
    # Convert the calibrated “draw_prone” probability into a binary flag.
    # League‑specific tuned cut‑offs are honoured when present; otherwise
    # we fall back to a more sensitive 0.45 default (was 0.60).
    # OG GUARD: ensure a draw-prone probability exists; derive from implied odds if needed
    if "draw_prone" not in df.columns:
        # Try common sources in order: draw_implied → odds_ft_draw → neutral 1/3
        src = _pd.to_numeric(df.get("draw_implied"), errors="coerce")
        if not isinstance(src, _pd.Series) or src.shape[0] != df.shape[0]:
            src = _pd.Series(_np.nan, index=df.index)
        if src.isna().all():
            odds_d = _pd.to_numeric(df.get("odds_ft_draw"), errors="coerce")
            if not isinstance(odds_d, _pd.Series) or odds_d.shape[0] != df.shape[0]:
                odds_d = _pd.Series(_np.nan, index=df.index)
            with _np.errstate(divide='ignore', invalid='ignore'):
                src = 1.0 / odds_d.replace(0, _np.nan)
        # Final fallback: neutral draw prior
        df["draw_prone"] = src.fillna(1.0/3.0).clip(0, 1)
    draw_prone_prob = df["draw_prone"].clip(0, 1)

    league_thresholds = DRAW_PRONE_THRESHOLDS
    league = df.get("league_name") if hasattr(df, "get") else None

    if league is not None and isinstance(league, str) and league in league_thresholds:
        draw_prone_thr = league_thresholds.get(league, {}).get("draw_prone", 0.45)
    else:
        draw_prone_thr = 0.45  # NEW default

    df["is_draw_prone"] = (draw_prone_prob >= draw_prone_thr).astype(int)
    # Optional hard cap on draw_modifier if requested
    if use_cap and 'draw_modifier' in df.columns:
        df.loc[df['is_draw_prone'] == 1, 'draw_modifier'] = \
            np.clip(df['draw_modifier'], None, 0.80)
    return df
# ==============================
# Unified feature-engineering stack
# ==============================
def enrich_feature_stack(df: pd.DataFrame, *, pre_match: bool = True) -> pd.DataFrame:
    if not pre_match:
        raise ValueError(
            "enrich_feature_stack must be called with pre_match=True to avoid post-match leakage"
        )

    # --- OG ORDER ENFORCER: canonicalize, synth match_id, normalize history ---
    try:
        df = _canonize(df)
    except Exception:
        pass
    try:
        df = _ensure_match_id(df)
    except Exception:
        pass
    try:
        df = _normalize_history_columns_inplace(df)
    except Exception:
        pass
    # OG PATCH: inject league + season context prior to feature enrichment
    import os as _os
    _league = _os.getenv("OG_LEAGUE_NAME", _os.getenv("LEAGUE_NAME", "<LEAGUE>"))
    df['league_name'] = df['league_name'].fillna(_league) if 'league_name' in df.columns else _league

    # OG PATCH: ensure implied 1×2 probabilities exist (from odds), early
    try:
        # Prefer the project helper if available
        df = _ensure_implied_1x2_inplace(df)
    except Exception:
        # Fallback: compute implied probs if canonical odds exist
        try:
            _h = pd.to_numeric(df.get('odds_ft_home_team_win'), errors='coerce')
            _d = pd.to_numeric(df.get('odds_ft_draw'), errors='coerce')
            _a = pd.to_numeric(df.get('odds_ft_away_team_win'), errors='coerce')
            inv_h = 1.0 / _h.replace(0, np.nan)
            inv_d = 1.0 / _d.replace(0, np.nan)
            inv_a = 1.0 / _a.replace(0, np.nan)
            total = (inv_h + inv_d + inv_a)
            home_imp = (inv_h / total).fillna(0.0)
            draw_imp = (inv_d / total).fillna(0.0)
            away_imp = (inv_a / total).fillna(0.0)
            # Populate canonical columns *only if missing* or all‑zero
            def _need(cols):
                if not all(c in df.columns for c in cols):
                    return True
                s = sum(float(df[c].abs().sum()) for c in cols)
                return s == 0.0
            if _need(['home_win_implied_prob','draw_win_implied_prob','away_win_implied_prob']):
                df['home_win_implied_prob'] = home_imp
                df['draw_win_implied_prob'] = draw_imp
                df['away_win_implied_prob'] = away_imp
            # Also expose simple implied trio aliases (if your stack expects these names)
            if _need(['implied_home_prob','implied_draw_prob','implied_away_prob']):
                df['implied_home_prob'] = home_imp
                df['implied_draw_prob'] = draw_imp
                df['implied_away_prob'] = away_imp
            # Useful parity signal
            if 'implied_prob_diff' not in df.columns:
                df['implied_prob_diff'] = (home_imp - away_imp)
        except Exception:
            # If odds truly absent, leave as‑is; later code will neutral‑fill
            pass
    if 'match_date' in df.columns:
        df['season'] = pd.to_datetime(df['match_date'], errors='coerce').dt.year
    else:
        df['season'] = pd.NA

    # attach Teams season features when PPG/xG are missing
    try:
        df = _attach_team_season_features_if_missing(df)
    except Exception:
        pass
        # OG DEV: strict feature presence check (dev only)
        try:
            import os as _os
            if _os.getenv("STRICT_FEATURES", "0") == "1":
                _req = [
                    "Pre-Match PPG (Home)", "Pre-Match PPG (Away)",
                    "Home Team Pre-Match xG", "Away Team Pre-Match xG",
                    "odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win",
                ]
                _missing = [c for c in _req if c not in df.columns]
                if _missing:
                    raise RuntimeError(f"STRICT_FEATURES=1: missing core features in feature stack: {_missing}")
        except Exception:
            if _os.getenv("STRICT_FEATURES", "0") == "1":
                raise
            pass
    # Stage 0 – add rolling finishing efficiency (if needed)
    df = add_rolling_finishing_eff(df)

    # Stage 1 – pre‑match composites & interaction terms
    df = add_advanced_features(df)

    # Stage 2 – volatility stack (optionally leak‑safe)
    df = apply_volatility_stack(df, pre_match=True)

    # Stage 3 – draw‑specific heuristics
    df = advanced_draw_features(df)

    # Drop legacy leakage columns now replaced by rolling-window surrogates
    df.drop(
        columns=[
            'finishing_efficiency_home',
            'finishing_efficiency_away',
            'xg_conversion_gap',
            'poisson_over25_prob',
            'poisson_btts_prob',
            'home_goals_scored_per_match',
            'away_goals_conceded_per_match',
            'away_goals_scored_per_match',
            'home_goals_conceded_per_match',
            'home_clean_sheet_percentage',
            'away_clean_sheet_percentage'
        ],
        inplace=True,
        errors='ignore'
    )

    return df


#############################################
# Sanity‑check utilities
#############################################
def leave_last_season_out(df: pd.DataFrame,
                          date_col: str = "match_date") -> tuple[pd.DataFrame, pd.DataFrame]:
    """
    Chronological split → train = all but the most‑recent season,
    test  = the last season.

    If the dataframe spans only **one** season/year, fall back to an
    80 / 20 chronological split so the caller never receives empty folds.
    """
    # --------------------------------------------------------------
    df = df.copy()
    df['_year'] = pd.to_datetime(df[date_col]).dt.year    # keep existing logic

    # ── fail‑safe: single‑season fallback -------------------------
    _years = df['_year'].dropna().unique()
    if len(_years) < 2:
        cut = int(len(df) * 0.8) or 1       # guarantee ≥ 1 row in train
        return df.iloc[:cut].copy(), df.iloc[cut:].copy()

    # Standard split: last calendar year = validation
    last_year = _years.max()
    val_df   = df[df['_year'] == last_year].copy()
    train_df = df[df['_year'] <  last_year].copy()
    df.drop(columns=['_year'], inplace=True, errors='ignore')
    return train_df, val_df

def plot_draw_calibration(val_df, draw_clf, draw_features, save_path):
    """
    Reliability curve – bins predicted draw probability into deciles and 
    compares with observed frequency.
    """
    import matplotlib.pyplot as plt
    X_val = val_df[draw_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    X_val_aligned = _align_dataframe_to_model(X_val, draw_clf)
    probs = draw_clf.predict_proba(X_val_aligned)[:, 1]
    val_df = val_df.copy()
    val_df['pred_draw_prob'] = probs
    val_df['decile'] = pd.qcut(val_df['pred_draw_prob'], 10, labels=False, duplicates='drop')
    calib = val_df.groupby('decile')['FTR'].apply(lambda x: np.mean(x==1))
    mean_pred = val_df.groupby('decile')['pred_draw_prob'].mean()
    plt.figure(figsize=(6,6))
    plt.plot(mean_pred, calib, marker='o', label='Empirical')
    plt.plot([0,1],[0,1],'--',color='grey', label='Ideal')
    plt.xlabel('Predicted draw probability')
    plt.ylabel('Observed draw rate')
    plt.title('Draw‑probability calibration')
    plt.legend()
    plt.tight_layout()
    plt.savefig(save_path)
    plt.close()
    print(f"📈  Draw‑calibration plot saved to {save_path}")


# ===========================
# Patch: Cross-val sanity check for draw classifier
# ===========================

def cross_val_score_draw_classifier(draw_clf, training_data, draw_features, skf):
    """
    Wrapper for cross_val_score on the draw classifier, skipping if already calibrated.
    """
    from sklearn.model_selection import cross_val_score

    if not isinstance(draw_clf, CalibratedClassifierCV):
        try:
            X_train_raw = training_data[draw_features].replace([np.inf, -np.inf], np.nan).fillna(0)
            X_train = _align_dataframe_to_model(X_train_raw, draw_clf)
            y_train = (training_data['FTR'] == 1).astype(int)
            cv_score = cross_val_score(draw_clf, X_train, y_train, cv=skf, scoring="accuracy")
            print(f"[draw_clf] cross-val accuracy: {cv_score.mean():.4f} ± {cv_score.std():.4f}")
            return cv_score
        except Exception as e:
            print(f"⚠️  Draw classifier cross-val failed: {e}")
            return None
    else:
        print("[sanity] Skipping cross_val_score — model is already calibrated (cv=2).")
        return None

def permutation_importance_report(model, X_val, y_val, top_n=15):
    """
    Prints and returns the top‑N permutation importances for a fitted model.
    """
    X_val_aligned = _align_dataframe_to_model(X_val, model)
    result = permutation_importance(model, X_val_aligned, y_val, n_repeats=10, random_state=42, scoring='accuracy')
    imp_df = (pd.DataFrame({'feature': X_val_aligned.columns,
                            'importance': result.importances_mean})
              .sort_values('importance', ascending=False)
              .head(top_n))
    print("\n=== Permutation importance (top {0}) ===".format(top_n))
    print(imp_df.to_string(index=False))
    return imp_df
# ------------------------------------------------------------------
# Sanity utility: shuffled-label baseline
# ------------------------------------------------------------------
def temporal_shuffle_sanity(y_true):
    """
    Accuracy you’d get by guessing at random (class-prior baseline).
    For a balanced 3-way label set this should sit near 0.33.
    """
    from sklearn.metrics import accuracy_score
    shuffled = np.random.permutation(y_true)
    acc = accuracy_score(y_true, shuffled)
    print(f"[sanity] shuffled-label accuracy = {acc:.3f} (expect ≈ 0.33)")

