# -------------------------------------------------------------------
# Feature integrity/health report utility
# -------------------------------------------------------------------
def feature_integrity_report(df, features, league, model_dir=MODEL_DIR):
    """
    Sanity‑check that every feature a model expects is actually populated.

    For each column we log:
        • pct_nan   – fraction of rows that are NaN
        • pct_zero  – fraction of rows that are exactly 0
        • variance  – sample variance

    A CSV is written to
        ModelStore/<league>_feature_health.csv

    The console also highlights any columns that are *entirely* NaN or 0
    so you can spot broken feature builders instantly.
    """
    

    records = []
    for f in features:
        # Skip non‑numeric columns (object / string) – only check numeric features
        if f in df.columns and not pd.api.types.is_numeric_dtype(df[f]):
            continue
        if f in df.columns:
            col = df[f].astype(float)
            pct_nan  = col.isna().mean()
            pct_zero = (col == 0).mean()
            variance = col.var()
        else:   # missing column → 100 % NaN
            pct_nan = 1.0
            pct_zero = 0.0
            variance = 0.0
        records.append((f, pct_nan, pct_zero, variance))
        # --- ensure sortable numeric dtypes ------------------------------
    # Occasionally pct_nan / pct_zero arrive as objects (or nested Series)
    # which breaks pandas.factorize inside sort_values. Coerce to float.
    report_df = pd.DataFrame(records,
                             columns=["feature", "pct_nan", "pct_zero", "variance"])
    report_df["pct_nan"]  = pd.to_numeric(report_df["pct_nan"],  errors="coerce")
    report_df["pct_zero"] = pd.to_numeric(report_df["pct_zero"], errors="coerce")
    report_df["variance"] = pd.to_numeric(report_df["variance"], errors="coerce")

    # ---- end coercion patch ----
    # -------- constant‑killer: drop features with effectively zero variance --------
    very_low_var = report_df.loc[report_df["variance"] < 1e-9, "feature"].tolist()
    if very_low_var:
        report_df = report_df[~report_df["feature"].isin(very_low_var)]
        print(
            f"🧹  Dropped {len(very_low_var)} constant feature(s): "
            f"{', '.join(very_low_var[:8])}{' …' if len(very_low_var) > 8 else ''}"
        )

    # --- apply sort after coercion ---
    rep = report_df.sort_values(["pct_nan", "pct_zero"], ascending=False)

    out_path = os.path.join(model_dir, f"{league.replace(' ', '_')}_feature_health.csv")
    rep.to_csv(out_path, index=False)
    print(f"🩺  Feature‑health report saved → {out_path}")

    bad = rep.query("(pct_nan == 1) | (pct_zero == 1)")

    # ------- re‑append constant‑zero‑variance features so they are still flagged -------
    if very_low_var:
        bad = pd.concat(
            [
                bad,
                pd.DataFrame(
                    {
                        "feature": very_low_var,
                        "pct_nan": 0,
                        "pct_zero": 0,
                        "variance": 0,
                    }
                ),
            ],
            ignore_index=True,
        )

    if not bad.empty:
        print("\n🚨 Columns that are entirely NaN or constant‑zero:")
        print(bad.head(20).to_string(index=False))

    return rep

# -------------------------------------------------------------------
# Probability calibrator helper (isotonic/sigmoid)
# -------------------------------------------------------------------
def calibrate_probs(model, X_val, y_val, method="isotonic"):
    """
    Fit a probability‑calibration wrapper on a *prefit* classifier and
    return the fitted calibrator.  Supported methods:
        • "isotonic"  – non‑parametric, handles class‑imbalance well
        • "sigmoid"   – Platt scaling (a.k.a. temperature scaling)
    The fitted object exposes `.predict_proba`.
    """
    if method == "isotonic":
        calib = _calibrated_cv2(model, method="isotonic")
    elif method == "sigmoid":
        calib = _calibrated_cv2(model, method="sigmoid")
    else:                           # unsupported string → return None
        return None
    calib.fit(X_val, y_val)
    return calib

# -------------------------------------------------------------------
# Generic binary-threshold tuner (maximises chosen metric on val split)
# -------------------------------------------------------------------
from sklearn.metrics import f1_score

def tune_binary_threshold(y_true, y_prob, metric: str = "f1",
                          grid=np.arange(0.30, 0.71, 0.01)):
    """
    Return threshold t that maximises the given metric.

    Parameters
    ----------
    y_true : array‑like of shape (n_samples,)
    y_prob : array‑like of shape (n_samples,)
        Predicted probability for the positive class.
    metric : {"f1", "accuracy", "youden"}
    grid   : iterable[float]
        Thresholds to evaluate.

    Returns
    -------
    best_t, best_score
    """
    metric = metric.lower()
    best_t, best_s = 0.50, -1.0
    for t in grid:
        y_hat = (y_prob >= t).astype(int)
        if metric == "f1":
            s = f1_score(y_true, y_hat)
        elif metric == "youden":
            tp = ((y_hat == 1) & (y_true == 1)).sum()
            fp = ((y_hat == 1) & (y_true == 0)).sum()
            fn = ((y_hat == 0) & (y_true == 1)).sum()
            tn = ((y_hat == 0) & (y_true == 0)).sum()
            tpr = tp / (tp + fn + 1e-9)
            fpr = fp / (fp + tn + 1e-9)
            s = tpr - fpr
        else:   # accuracy
            s = accuracy_score(y_true, y_hat)
        if s > best_s:
            best_t, best_s = t, s
    return best_t, best_s

# -------------------------------------------------------------------
# Utility: log FTR metrics + embed BTTS and Over‑2.5 model accuracies
# -------------------------------------------------------------------
def log_ftr_metrics(y_true, y_pred, league_name):
    """
    Persist a full FTR classification report to disk **and** append the
    previously‑trained BTTS / Over‑2.5 model accuracies so you get every
    headline metric in one place.

    The file is written to:
        ModelStore/<league_name>_FTR_report.txt
    """
    report_txt = classification_report(
        y_true, y_pred,
        target_names=["Home Win", "Draw", "Away Win"],
        digits=3
    )
    cm = confusion_matrix(y_true, y_pred)

    # ----------------------------------------------------------------
    # Attempt to load stored BTTS & Over‑2.5 models so we can pull the
    # `score_` attribute that we explicitly stashed at training time.
    # ----------------------------------------------------------------
    over_acc = btts_acc = None
    over_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_over25_model.pkl"
    )
    btts_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_btts_model.pkl"
    )
    try:
        if os.path.exists(over_path):
            over_model = joblib.load(over_path)
            over_acc = getattr(over_model, "score_", None)
        if os.path.exists(btts_path):
            btts_model = joblib.load(btts_path)
            btts_acc = getattr(btts_model, "score_", None)
    except Exception as exc:
        print(f"⚠️  Could not retrieve BTTS/Over‑2.5 accuracies: {exc}")

    # ------------------------------------------------------------
    # First‑half market models (Over 1.5 FH & BTTS FH)
    # ------------------------------------------------------------
    fh_over_acc = fh_btts_acc = None
    fh_over_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_over15_FH_model.pkl"
    )
    fh_btts_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_btts_FH_model.pkl"
    )
    try:
        if os.path.exists(fh_over_path):
            fh_over_model = joblib.load(fh_over_path)
            fh_over_acc = getattr(fh_over_model, "score_", None)
        if os.path.exists(fh_btts_path):
            fh_btts_model = joblib.load(fh_btts_path)
            fh_btts_acc = getattr(fh_btts_model, "score_", None)
    except Exception as exc:
        print(f"⚠️  Could not retrieve FH model accuracies: {exc}")
        
    # --- Home / Away ≥ 2-goals model accuracies ---------------------------
    home_tg_acc = away_tg_acc = None
    home_tg_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_home_over15tg_model.pkl")
    away_tg_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_away_over15tg_model.pkl")
    try:
        if os.path.exists(home_tg_path):
            home_tg_model = joblib.load(home_tg_path)
            home_tg_acc = getattr(home_tg_model, "score_", None)
        if os.path.exists(away_tg_path):
            away_tg_model = joblib.load(away_tg_path)
            away_tg_acc = getattr(away_tg_model, "score_", None)
    except Exception as exc:
        print(f"⚠️  Could not retrieve TG model accuracies: {exc}")   

    # --- Failed‑to‑Score model accuracies ---------------------------
    home_fts_acc = away_fts_acc = None
    home_fts_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_home_fts_model.pkl")
    away_fts_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_away_fts_model.pkl")
    try:
        if os.path.exists(home_fts_path):
            home_fts_model = joblib.load(home_fts_path)
            home_fts_acc = getattr(home_fts_model, "score_", None)
        if os.path.exists(away_fts_path):
            away_fts_model = joblib.load(away_fts_path)
            away_fts_acc = getattr(away_fts_model, "score_", None)
    except Exception as exc:
        print(f"⚠️  Could not retrieve FTS accuracies: {exc}")
    
    # ----------------------------------------------------------------
    # Build plain‑text report
    # ----------------------------------------------------------------
    lines = []
    lines.append("===== FTR Classification Report =====")
    lines.append(report_txt)

    # ----------------------------------------------------------------
    # Append ancillary model accuracies (only if they were retrieved)
    # ----------------------------------------------------------------
    if over_acc is not None:
        lines.append(f"\nOver 2.5 Goals Model Accuracy: {over_acc*100:.2f}%")
    if btts_acc is not None:
        lines.append(f"BTTS Model Accuracy: {btts_acc*100:.2f}%")
    if fh_over_acc is not None:
        lines.append(f"Over 1.5 First‑Half Model Accuracy: {fh_over_acc*100:.2f}%")
    if fh_btts_acc is not None:
        lines.append(f"BTTS First‑Half Model Accuracy: {fh_btts_acc*100:.2f}%")
    if home_tg_acc is not None:
        lines.append(f"Home ≥2‑Goals Model Accuracy: {home_tg_acc*100:.2f}%")
    if away_tg_acc is not None:
        lines.append(f"Away ≥2‑Goals Model Accuracy: {away_tg_acc*100:.2f}%")
    if home_fts_acc is not None:
        lines.append(f"Home FTS Model Accuracy: {home_fts_acc*100:.2f}%")
    if away_fts_acc is not None:
        lines.append(f"Away FTS Model Accuracy: {away_fts_acc*100:.2f}%")
    lines.append("\nConfusion Matrix (rows = actual, cols = predicted):")
    lines.append(cm.__str__())

    # ----------------------------------------------------------------
    # Write to disk
    # ----------------------------------------------------------------
    report_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_FTR_report.txt"
    )
    with open(report_path, "w") as fh:
        fh.write("\n".join(lines))
    print(f"📑  FTR report saved to {report_path}")

#############################################
# Leakage‑diagnostic utilities (NEW)
#############################################
def leakage_diagnostic(df, feature_cols, league_name):
    """
    1) Flag feature names that look like obvious post‑match stats.
    2) Spot‑check that rolling‑window columns are computed strictly
       from past matches (no future leakage).

    A short plain‑text report is written to ModelStore/<league>_leakage_report.txt
    """
    suspicious_substrings = [
        '_team_shots', '_team_shots_on_target', '_team_shots_off_target',
        '_team_fouls', '_team_yellow_cards', '_team_red_cards',
        '_team_corner_count', '_team_goal_count', '_team_possession',
        '_goal_timings', 'total_goal_count', 'total_goals_at_half_time',
        '_goal_count_half_time'
    ]

    leaky_cols = [c for c in feature_cols
                  if any(ss in c and 'rolling' not in c and 'ewm' not in c
                         for ss in suspicious_substrings)]

    report_lines = []
    report_lines.append("==== Leakage diagnostic report ====")

    if leaky_cols:
        report_lines.append("⚠️  Potential post‑match columns present in feature matrix:")
        for col in leaky_cols:
            report_lines.append(f"  - {col}")
    else:
        report_lines.append("✅ No obvious post‑match columns detected in the feature matrix.")

    # --------- (2) Rolling window chronology spot‑check ---------------
    # We verify that, for a sample of teams, the first non‑zero rolling‑5
    # metric appears only *after* at least one historic fixture exists.
    sample_issues = []
    roll_cols = [c for c in feature_cols if c.startswith('rolling5_')]
    if 'match_date' in df.columns and roll_cols:
        for col in roll_cols:
            # pick one team for home/away metric
            base_team_field = 'home_team_name' if '_home_' in col else 'away_team_name'
            for team, grp in df[[base_team_field, 'match_date', col]].dropna().groupby(base_team_field):
                grp = grp.sort_values('match_date')
                # first non‑zero index
                nz = grp[grp[col] != 0]
                if not nz.empty:
                    first_idx = nz.index[0]
                    # how many historic matches existed before the first non‑zero value?
                    hist_ct = grp.loc[:first_idx - 1].shape[0] if first_idx > grp.index.min() else 0
                    if hist_ct < 1:   # rolling5 should need at least 1 past match (we allow <5 because min_periods=1)
                        sample_issues.append((team, col))
                break   # just sample one team per column for speed
    if sample_issues:
        report_lines.append("\n⚠️  Rolling‑window chronology issues (possible forward‑look):")
        for team, col in sample_issues[:20]:
            report_lines.append(f"  - {team}: {col} appears populated without prior history")
    else:
        report_lines.append("\n✅ Rolling‑window columns pass basic chronology spot‑check.")

    # write out
    leak_path = os.path.join(MODEL_DIR, f"{league_name.replace(' ', '_')}_leakage_report.txt")
    with open(leak_path, "w") as fh:
        fh.write("\n".join(report_lines))
    print(f"🔍  Leakage diagnostic saved to {leak_path}")

#############################################
# Auto‑generate core rolling‑5 metrics (NEW)
#############################################
def ensure_basic_rolling5_metrics(df: pd.DataFrame) -> pd.DataFrame:
    # --- OG ORDER ENFORCER: ensure canonical names & match_id exist ---
    try:
        df = _canonize(df)
    except Exception:
        pass
    try:
        df = _ensure_match_id(df)
    except Exception:
        pass
    try:
        df = _normalize_history_columns_inplace(df)
    except Exception:
        pass
    # OG PATCH: resolve/alias team-name columns and avoid crashing on schema variants
    import os as _os
    def _pick_col(_df, cands):
        for _c in cands:
            if _c in _df.columns:
                return _c
        return None
    # Prefer env-provided HOME/AWAY, then common aliases
    try:
        _HOME_CAND = [HOME] if 'HOME' in globals() else []
        _AWAY_CAND = [AWAY] if 'AWAY' in globals() else []
    except Exception:
        _HOME_CAND, _AWAY_CAND = [], []
    home_col = _pick_col(df, _HOME_CAND + [
        'home_team_name','home_team','home','Home Team','Home','home_club','HomeTeam','homeClub'
    ])
    away_col = _pick_col(df, _AWAY_CAND + [
        'away_team_name','away_team','away','Away Team','Away','away_club','AwayTeam','awayClub'
    ])
    # Create canonical aliases expected by downstream code
    if home_col and 'home_team_name' not in df.columns:
        try:
            df['home_team_name'] = df[home_col]
        except Exception:
            pass
    if away_col and 'away_team_name' not in df.columns:
        try:
            df['away_team_name'] = df[away_col]
        except Exception:
            pass
    # If still missing, soft-skip to avoid KeyError in groupby
    if 'home_team_name' not in df.columns or 'away_team_name' not in df.columns:
        if _os.getenv('VERBOSE_QUICK','0') == '1':
            try:
                missing = []
                if 'home_team_name' not in df.columns: missing.append('home_team_name')
                if 'away_team_name' not in df.columns: missing.append('away_team_name')
                print(f"⚠️ ensure_basic_rolling5_metrics: missing {', '.join(missing)}; skipping rolling metrics")
            except Exception:
                pass
        return df
    """
    Guarantee that the minimum set of rolling‑5 columns used elsewhere
    in the pipeline exist **and** contain at least one non‑zero entry.
    If a required column is missing or all zeros, we reconstruct it
    from the raw match statistics (shifted by 1 to avoid leakage).

    The function handles:
        • rolling5_home_shots           / rolling5_away_shots
        • rolling5_home_sot_ratio       / rolling5_away_sot_ratio
        • rolling5_home_card_ratio      / rolling5_away_card_ratio
        • rolling5_total_corners
        • rolling5_total_fouls
    Returns the dataframe (mutated in‑place for convenience).
    """
    side_map = {'home': home_col, 'away': away_col}
    # create canonical aliases for downstream code that expects these names
    if 'home_team_name' not in df.columns:
        df['home_team_name'] = df[home_col]
    if 'away_team_name' not in df.columns:
        df['away_team_name'] = df[away_col]
    # ------------------------------------------------------------------
    # Input guard‑rail: fail fast if a None slips through
    # ------------------------------------------------------------------
    if df is None:
        raise ValueError(
            "ensure_basic_rolling5_metrics received None dataframe – "
            "check earlier load / preprocessing steps."
        )
    # ---------- NEW: raw‑column guard‑rail ---------------------------------
    _RAW_COLS_NEEDED = [
        # shot volume / quality
        "home_team_shots", "away_team_shots",
        "home_team_shots_on_target", "away_team_shots_on_target",
        # set‑pieces & discipline
        "home_team_corner_count", "away_team_corner_count",
        "home_team_fouls", "away_team_fouls",
        "home_team_yellow_cards", "away_team_yellow_cards",
        "home_team_red_cards", "away_team_red_cards",
        # goals (for rolling goal‑count)
        "home_team_goal_count", "away_team_goal_count",
        # additional for rolling5_total_goals_ht
        "total_goals_at_half_time",
    ]
    _missing = [c for c in _RAW_COLS_NEEDED if c not in df.columns]
    if _missing:
        import numpy as _np, pandas as _pd
        _zeros = _pd.DataFrame(_np.zeros((len(df), len(_missing))), columns=_missing, index=df.index)
        try:
            df = _pd.concat([df, _zeros], axis=1)
        except Exception:
            # fallback: still create, accept potential fragmentation
            for _c in _missing:
                try:
                    df[_c] = 0.0
                except Exception:
                    pass
    # ------------------------------------------------------------------
    if "match_date" in df.columns:
        df = df.sort_values("match_date").copy()
    else:
        df = df.copy()

    # === per‑side metrics =============================================
    for side in ("home", "away"):
        # (1) Shots -----------------------------------------------------
        raw_shots = f"{side}_team_shots"
        roll_col  = f"rolling5_{side}_shots"
        if roll_col not in df.columns or df[roll_col].abs().sum() == 0:
            if raw_shots in df.columns:
                df[roll_col] = (
                    df.groupby(side_map[side])[raw_shots]
                      .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
                )
                # ── all‑zero guard --------------------------------------------------
                if df[roll_col].abs().sum() == 0:
                    df[roll_col] = df[raw_shots].mean()
            else:
                df[roll_col] = 0.0
        
        # (2) SOT ratio -------------------------------------------------
        raw_sot = f"{side}_team_shots_on_target"
        sot_ratio = f"{side}_sot_ratio_tmp"
        if raw_shots in df.columns and raw_sot in df.columns:
            df[sot_ratio] = df[raw_sot] / df[raw_shots].replace(0, np.nan)

        if f"rolling5_{side}_sot_ratio" not in df.columns or \
           df[f"rolling5_{side}_sot_ratio"].abs().sum() == 0:
            if sot_ratio in df.columns:
                df[f"rolling5_{side}_sot_ratio"] = (
                    df.groupby(side_map[side])[sot_ratio]
                      .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
                )
                # ── all‑zero guard --------------------------------------------------
                if df[f"rolling5_{side}_sot_ratio"].abs().sum() == 0:
                    df[f"rolling5_{side}_sot_ratio"] = df[sot_ratio].mean()
            else:
                df[f"rolling5_{side}_sot_ratio"] = 0.0
        # (3) Card ratio -----------------------------------------------
        # (3b) Total cards per match -----------------------------------
        yellow    = f"{side}_team_yellow_cards"
        red       = f"{side}_team_red_cards"
        card_tot  = f"{side}_total_cards_tmp"
        roll_cards = f"rolling5_{side}_total_cards"

        # helper aggregate (yellow + red) if not already present
        if card_tot not in df.columns:
            yellow_series = df[yellow] if yellow in df.columns else pd.Series(0, index=df.index)
            red_series    = df[red]    if red    in df.columns else pd.Series(0, index=df.index)
            df[card_tot]  = yellow_series.fillna(0) + red_series.fillna(0)

        if (card_tot in df.columns) and (
            roll_cards not in df.columns or df[roll_cards].abs().sum() == 0
        ):
            df[roll_cards] = (
                df.groupby(side_map[side])[card_tot]
                  .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            # ── all-zero guard --------------------------------------------------
            if df[roll_cards].abs().sum() == 0:
                df[roll_cards] = df[card_tot].mean()
        y_col = f"{side}_team_yellow_cards"
        r_col = f"{side}_team_red_cards"
        f_col = f"{side}_team_fouls"
        card_ratio_tmp = f"{side}_card_ratio_tmp"
        if all(c in df.columns for c in (y_col, r_col, f_col)):
            df[card_ratio_tmp] = (
                (df[y_col] + 2 * df[r_col]) / (df[f_col] + 1e-3)
            )
        roll_card = f"rolling5_{side}_card_ratio"
        if (card_ratio_tmp in df.columns) and (
            roll_card not in df.columns or df[roll_card].abs().sum() == 0
        ):
            df[roll_card] = (
                df.groupby(side_map[side])[card_ratio_tmp]
                  .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            # ── all‑zero guard --------------------------------------------------
            if df[roll_card].abs().sum() == 0:
                df[roll_card] = df[card_ratio_tmp].mean()
        elif roll_card not in df.columns:
            df[roll_card] = 0.0

        # ---------- (3c) Rolling goals & SOT (new) --------------------
        goals_src = f"{side}_team_goal_count"
        sot_src   = f"{side}_team_shots_on_target"

        roll_goals = f"rolling5_{side}_goal_count"
        roll_sot   = f"rolling5_{side}_sot"

        # rolling 5‑match average of *goals scored*
        if (goals_src in df.columns) and (
            roll_goals not in df.columns or df[roll_goals].abs().sum() == 0
        ):
            df[roll_goals] = (
                df.groupby(side_map[side])[goals_src]
                  .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            if df[roll_goals].abs().sum() == 0:          # all‑zero fallback
                df[roll_goals] = df[goals_src].mean()
        elif roll_goals not in df.columns:               # raw column missing
            df[roll_goals] = 0.0

        # rolling 5‑match average of *shots on target*
        if (sot_src in df.columns) and (
            roll_sot not in df.columns or df[roll_sot].abs().sum() == 0
        ):
            df[roll_sot] = (
                df.groupby(side_map[side])[sot_src]
                  .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            if df[roll_sot].abs().sum() == 0:            # all‑zero fallback
                df[roll_sot] = df[sot_src].mean()
        elif roll_sot not in df.columns:                 # raw column missing
            df[roll_sot] = 0.0
    # === fixture‑level metrics ========================================
    # Total corners -----------------------------------------------------
    if "total_corners_match" not in df.columns:
        if all(c in df.columns for c in ("home_team_corner_count", "away_team_corner_count")):
            df["total_corners_match"] = (
                df["home_team_corner_count"] + df["away_team_corner_count"]
            )
    if "rolling5_total_corners" not in df.columns or df["rolling5_total_corners"].abs().sum() == 0:
        if "total_corners_match" in df.columns:
            df["rolling5_total_corners"] = (
                df["total_corners_match"]
                  .shift(1)
                  .rolling(5, min_periods=1)
                  .mean()
            )
        else:
            df["rolling5_total_corners"] = 0.0

    # Total fouls -------------------------------------------------------
    if "total_fouls_match" not in df.columns:
        if all(c in df.columns for c in ("home_team_fouls", "away_team_fouls")):
            df["total_fouls_match"] = df["home_team_fouls"] + df["away_team_fouls"]
    if "rolling5_total_fouls" not in df.columns or df["rolling5_total_fouls"].abs().sum() == 0:
        if "total_fouls_match" in df.columns:
            df["rolling5_total_fouls"] = (
                df["total_fouls_match"]
                  .shift(1)
                  .rolling(5, min_periods=1)
                  .mean()
            )
        else:
            df["rolling5_total_fouls"] = 0.0

    # Total goals at half‑time -----------------------------------------
    if ('total_goals_at_half_time' in df.columns) and (
        'rolling5_total_goals_ht' not in df.columns or df['rolling5_total_goals_ht'].abs().sum() == 0
    ):
        df['rolling5_total_goals_ht'] = (
            df['total_goals_at_half_time']
              .shift(1)                          # strictly past matches only
              .rolling(5, min_periods=1)
              .mean()
        )
        # fallback if the whole column is still zero
        if df['rolling5_total_goals_ht'].abs().sum() == 0:
            df['rolling5_total_goals_ht'] = df['total_goals_at_half_time'].mean()

    # === rolling goals‑conceded (new) ===============================
    for side in ("home", "away"):
        # goals conceded in this fixture are the opponent’s goals scored
        conceded_tmp = f"{side}_gc_tmp"
        if side == "home":
            df[conceded_tmp] = df.get("away_team_goal_count", 0)
        else:
            df[conceded_tmp] = df.get("home_team_goal_count", 0)

        roll_gc = f"rolling5_{side}_gc"
        if roll_gc not in df.columns or df[roll_gc].abs().sum() == 0:
            df[roll_gc] = (
                df.groupby(side_map[side])[conceded_tmp]
                  .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )

    # Clean up temporary columns
    df.drop(columns=[c for c in df.columns if c.endswith("_tmp") or c.endswith("_gc_tmp")],
            inplace=True, errors='ignore')
    # Fill missing rolling-5 metrics with 0 so the leakage diagnostic sees zeros instead of NaNs
    roll_cols = [c for c in df.columns if c.startswith("rolling5_")]
    df[roll_cols] = df[roll_cols].fillna(0)
    # ------------------------------------------------------------------
    # Hard guarantee: every rolling‑5 metric must have *some* signal.
    # If the column is entirely zero (or NaN→0 after fillna) we seed
    # a tiny positive value in the first row so downstream integrity
    # checks see at least one non‑zero entry.
    # ------------------------------------------------------------------
    for col in roll_cols:
        if (df[col].abs() > 0).sum() == 0:
            # seed a minimal value; 1e‑3 is small enough to be
            # inconsequential yet non‑zero for the assert guard
            df.loc[df.index[0], col] = 1e-3
    return df

# === Additional Rolling Feature Helpers ===
def add_rolling_finishing_eff(df: pd.DataFrame) -> pd.DataFrame:
    """
    Leak‑safe finishing‑efficiency features derived **only** from the
    rolling‑5 aggregates produced by `ensure_basic_rolling5_metrics`.

        • finishing_efficiency_home  = rolling5_home_goal_count / rolling5_home_sot
        • finishing_efficiency_away  = rolling5_away_goal_count / rolling5_away_sot
        • xg_conversion_gap          = |xG_h − rolling5_home_goal_count|
                                        + |xG_a − rolling5_away_goal_count|

    All computations use *historic* windows, so no post‑match data leaks in.
    """
    # ── de‑dup any accidental duplicate column labels so df["col"]
    #    always returns a 1‑D Series, never a 2‑D DataFrame ─────────
    df = df.loc[:, ~df.columns.duplicated()].copy()

    for side in ("home", "away"):
        g_col   = f"rolling5_{side}_goal_count"
        sot_col = f"rolling5_{side}_sot"

        # Ensure required columns exist; fall back to safe defaults
        if g_col not in df.columns:
            df[g_col] = 0.0
        if sot_col not in df.columns:
            df[sot_col] = 1.0  # avoids divide‑by‑zero

        eff_col = f"finishing_efficiency_{side}"
        df[eff_col] = df[g_col] / (df[sot_col] + 1e-3)

    # xG‑conversion gap now references **pre‑match** xG only
    df["xg_conversion_gap"] = (
        (df.get("Home Team Pre-Match xG", 0) - df["rolling5_home_goal_count"]).abs() +
        (df.get("Away Team Pre-Match xG", 0) - df["rolling5_away_goal_count"]).abs()
    )

    # ── final all-zero guard (robust to duplicate labels) ─────────────
    import numpy as _np
    for c in ("finishing_efficiency_home", "finishing_efficiency_away"):
        col_obj = df.loc[:, c]
        # If duplicate column names slipped through, pandas returns a
        # DataFrame.  Collapse to the first (left-most) column.
        if isinstance(col_obj, pd.DataFrame):
            col_obj = col_obj.iloc[:, 0]

        total = float(_np.nansum(_np.abs(col_obj.values)))
        if total == 0.0:
            # replace with the global mean (or 0 if NaN)
            df[c] = float(col_obj.mean() if not _np.isnan(col_obj.mean()) else 0.0)
            # removed: return df
    # hand back the enriched dataframe
    return df

def add_rolling_xg_gap(df, window=5):
    """
    Leak-safe |xG − Goals| gap averaged over the previous *window* matches.
    Falls back cleanly when the raw columns are missing.

    Creates / updates:
        • rolling{window}_home_xg_gap
        • rolling{window}_away_xg_gap
    """
    # ── de-dupe to be sure each column label is unique
    df = df.loc[:, ~df.columns.duplicated()].copy()

    # OG PATCH: resolve canonical team columns and soft‑skip if unavailable
    import os as _os
    def _pick_col(_df, cands):
        for _c in cands:
            if _c in _df.columns:
                return _c
        return None
    try:
        _HOME_CAND = [HOME] if 'HOME' in globals() else []
        _AWAY_CAND = [AWAY] if 'AWAY' in globals() else []
    except Exception:
        _HOME_CAND, _AWAY_CAND = [], []
    home_col = _pick_col(df, _HOME_CAND + [
        'home_team_name','home_team','home','Home Team','Home','home_club','HomeTeam','homeClub'
    ])
    away_col = _pick_col(df, _AWAY_CAND + [
        'away_team_name','away_team','away','Away Team','Away','away_club','AwayTeam','awayClub'
    ])
    # Create canonical aliases expected by downstream code
    if home_col and 'home_team_name' not in df.columns:
        try: df['home_team_name'] = df[home_col]
        except Exception: pass
    if away_col and 'away_team_name' not in df.columns:
        try: df['away_team_name'] = df[away_col]
        except Exception: pass
    if 'home_team_name' not in df.columns or 'away_team_name' not in df.columns:
        if _os.getenv('VERBOSE_QUICK','0') == '1':
            try:
                missing = []
                if 'home_team_name' not in df.columns: missing.append('home_team_name')
                if 'away_team_name' not in df.columns: missing.append('away_team_name')
                print(f"⚠️ add_rolling_xg_gap: missing {', '.join(missing)}; skipping team‑grouped xg gap")
            except Exception:
                pass
        # Fail‑soft: if we cannot group by team, produce a global rolling mean as a weak proxy
        for side in ("home","away"):
            tmp  = f"{side}_xg_gap_tmp"
            roll = f"rolling{window}_{side}_xg_gap"
            if tmp in df.columns and ((roll not in df.columns) or df[roll].abs().sum() == 0):
                df[roll] = df[tmp].shift(1).rolling(window, min_periods=2).mean()
        return df
    side_map = {'home': 'home_team_name', 'away': 'away_team_name'}

    for side in ("home", "away"):
        xg_col_name = f"{'Home' if side=='home' else 'Away'} Team Pre-Match xG"
        g_col_name  = f"{side}_team_goal_count"

        # safe retrieval – Series of zeros when the source column is absent
        xg_series = df.get(xg_col_name, pd.Series(0, index=df.index)).fillna(0)
        g_series  = df.get(g_col_name,  pd.Series(0, index=df.index)).fillna(0)

        tmp  = f"{side}_xg_gap_tmp"
        roll = f"rolling{window}_{side}_xg_gap"

        df[tmp] = (xg_series - g_series).abs()

        # build the rolling-window only if it’s missing or all-zero
        if (roll not in df.columns) or (df[roll].abs().sum() == 0):
            df[roll] = (
                df.groupby(side_map[side])[tmp]
                  .transform(lambda s:
                             s.shift(1).rolling(window, min_periods=2).mean())
            )
            # all-zero guard → fallback to global mean
            if df[roll].abs().sum() == 0:
                df[roll] = df[tmp].mean()

    # clean-up temporary columns
    df.drop(columns=[c for c in df.columns if c.endswith("_xg_gap_tmp")],
            inplace=True, errors="ignore")
    return df
# --- Helper: ensure a total goals column exists (fallbacks safe) ---

def _ensure_total_goals(df: pd.DataFrame) -> pd.DataFrame:
    """Ensure a numeric 'total_goals_match' column exists.
    Prefers home/away goal columns; falls back to common aliases.
    """
    if 'total_goals_match' in df.columns:
        return df

    df = df.copy()
    # try the most likely pairs in order
    candidates = [
        ('home_team_goal_count', 'away_team_goal_count'),
        ('FTHG', 'FTAG'),
        ('home_goals', 'away_goals'),
        ('home_score', 'away_score'),
    ]
    for h, a in candidates:
        if {h, a}.issubset(df.columns):
            df['total_goals_match'] = (
                pd.to_numeric(df[h], errors='coerce').fillna(0) +
                pd.to_numeric(df[a], errors='coerce').fillna(0)
            )
            break

    if 'total_goals_match' not in df.columns:
        # create the column so downstream groupby never KeyErrors
        df['total_goals_match'] = np.nan

    return df

def add_h2h_goal_rate(df: pd.DataFrame, window: int = 8) -> pd.DataFrame:
    """Average total goals in head-to-head matchups over the previous `window` fixtures.
    Guarantees 'total_goals_match' exists and fails soft if key columns are missing.
    """
    if df is None or df.empty:
        return df

    # Ensure we have a goals column to roll over
    df = _ensure_total_goals(df)

    # Need these for stable pair key & chronology
    for c in ('home_team_name', 'away_team_name', 'match_date'):
        if c not in df.columns:
            df = df.copy()
            if 'h2h_goals_avg' not in df.columns:
                df['h2h_goals_avg'] = np.nan
            return df

    df = df.sort_values('match_date').copy()

    # Fixture key invariant to home/away ordering
    df['_pair'] = df.apply(
        lambda r: ' | '.join(sorted([str(r['home_team_name']), str(r['away_team_name'])])),
        axis=1
    )

    # rolling mean of prior head-to-head total goals
    try:
        df['h2h_goals_avg'] = (
            df.groupby('_pair')['total_goals_match']
              .transform(lambda s: s.shift(1).rolling(window, min_periods=2).mean())
        )
    except Exception:
        # fail-soft: create the column but keep NaNs rather than raising
        df['h2h_goals_avg'] = np.nan

    df.drop(columns=['_pair'], inplace=True, errors='ignore')
    return df
#############################################
# Rolling‑metric integrity assert (NEW)
#############################################
def assert_rolling_metrics(df: pd.DataFrame, league_name: str,
                           *, prefix: str = "rolling5_", min_nonzero: int = 1) -> None:
    """
    Fail fast if any **rolling‑window** column that starts with `prefix`
    is entirely NaN/zero. This prevents silent ETL leaks where the
    pipeline pads missing cols with zeros and then the model happily
    trains on nonsense.

    Parameters
    ----------
    df : DataFrame
    league_name : str   – used only for the error message
    prefix : str, default "rolling5_"
    min_nonzero : int, default 1
        Require at least this many non‑zero entries per rolling column.

    Raises
    ------
    ValueError  if any offending columns are found.
    """
    offending = []
    for col in [c for c in df.columns if c.startswith(prefix)]:
        series = df[col]
        if series.isna().all() or (series.abs() > 0).sum() < min_nonzero:
            offending.append(col)
    if offending:
        sample = ", ".join(offending[:10])
        raise ValueError(
            f"[{league_name}] ETL integrity check failed – "
            f"{len(offending)} rolling metrics missing or empty "
            f"(e.g. {sample})"
        )


def prepare_data_for_training(combined_data, league_name):
    # --- Auto‑fill rolling‑5 metrics then sanity‑check ------------
    combined_data = drop_bookmaker_cols(combined_data)
    combined_data = ensure_basic_rolling5_metrics(combined_data)
    # --- leak-safe enrichments ------------------------------------
    combined_data = add_elo_features(combined_data)
    combined_data = add_rest_days(combined_data)
    combined_data = add_ewma_ppg(combined_data)
    # Pre-stamp draw-prone flag (do not mutate later)
    combined_data = advanced_draw_features(combined_data)
    # Inject rolling-window surrogates before full stack
    combined_data = add_rolling_finishing_eff(combined_data)
    combined_data = add_rolling_xg_gap(combined_data, window=5)
    combined_data = add_h2h_goal_rate(combined_data, window=8)
    assert_rolling_metrics(combined_data, league_name)
    required_features = [
        'goal_count_diff', 'possession_diff', 'home_ppg', 'away_ppg',
        'home_recent_form', 'away_recent_form', 'total_shots_per_90',
        'weighted_home_ppg', 'weighted_away_ppg', 'ppg_diff',
        'home_offensive_index', 'away_offensive_index', 'home_defensive_efficiency', 'away_defensive_efficiency',
        'draw_prone',  # Ensures draw prone flag is included
        'under15_combined_prob',  # Ensures under15 probability is included
        'home_goals_scored_per_match', 'away_goals_scored_per_match',
        'home_goals_conceded_per_match', 'away_goals_conceded_per_match',
        'home_btts_percentage', 'away_btts_percentage',
        'home_over25_percentage', 'away_over25_percentage',
        'home_points_per_game', 'away_points_per_game',
        'home_clean_sheet_percentage', 'away_clean_sheet_percentage',
        'home_fts_percentage', 'away_fts_percentage',
        # 'xg_conversion_gap',  # Removed as per instruction
        'momentum_score', 'set_piece_pressure_index',
        'home_under15_prob', 'away_under15_prob',
        'home_over15_prob', 'away_over15_prob', 'under25_combined_prob',
        # Also include our additional draw features.
        'match_equality', 'low_attacking_quality', 'strong_defense', 'odds_balance', 'draw_likelihood_score',
        'rolling5_home_shots', 'rolling5_away_shots',
        'rolling5_home_sot_ratio', 'rolling5_away_sot_ratio',
        'rolling5_total_corners', 'rolling5_total_fouls',
        'rolling5_home_card_ratio', 'rolling5_away_card_ratio',
        'prob_over15_FH', 'prob_btts_FH',
        'prob_home_over15tg', 'prob_away_over15tg',
        'prob_home_fts', 'prob_away_fts',
    ]
    # remove any black-listed post-match columns
    required_features = [
        f for f in required_features
        if not any(tag in f for tag in POST_MATCH_TAGS)
    ]

    for feat in required_features:
        if feat not in combined_data.columns:
            combined_data[feat] = 0
             
        # ── absolute leak guard: drop raw targets, keep engineered deltas
    leak_words = (
        'home_team_goal_count',       # exact column names
        'away_team_goal_count',
        'home_goals_pred',            # model outputs
        'away_goals_pred',
        '_pred$',                     # any “*_pred” suffix
        '^FTR$'                       # whole FTR label
    )
    pattern = re.compile('|'.join(leak_words))

    required_features = [
        f for f in required_features
        if not pattern.search(f)
    ]

    # ── keep only historic (“complete”) fixtures for model training
    #    → future / in-progress rows are left for live inference later
    combined_data = combined_data[combined_data['status'] == 'complete'].copy()
    
    # Load additional prediction features from model files.
    for model_name, col in [
        (f"{league_name}_home_under15_model.pkl", 'home_under15_prob'),
        (f"{league_name}_away_under15_model.pkl", 'away_under15_prob'),
        (f"{league_name}_home_over15_model.pkl", 'home_over15_prob'),
        (f"{league_name}_away_over15_model.pkl", 'away_over15_prob'),
        (f"{league_name}_under15_combined_model.pkl", 'under15_combined_prob'),
        (f"{league_name}_under25_combined_model.pkl", 'under25_combined_prob')
    ]:
        model_path = os.path.join(MODEL_DIR, model_name)
        if os.path.exists(model_path):
            model = joblib.load(model_path)
            X_subset = combined_data[required_features[:-6]].replace([np.inf, -np.inf], np.nan).fillna(0)
            combined_data[col] = model.predict_proba(X_subset)[:, 1]
        else:
            combined_data[col] = 0.5
    features = combined_data[required_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    # ── keep side‑probability features (ablation off by default) ──
    side_prob_cols = [
        'home_under15_prob', 'away_under15_prob',
        'home_over15_prob', 'away_over15_prob',
        'under25_combined_prob',
        'prob_over15_FH', 'prob_btts_FH',
        'prob_home_over15tg', 'prob_away_over15tg',
        'prob_home_fts', 'prob_away_fts'
    ]
        # ---------------- side-probability handling ------------------------
    # 1) Optionally ablate side-model probability columns everywhere.
    if ENABLE_SIDE_PROB_ABLATION:
        # Global ablation – strip them from both the main feature matrix
        # (used by the draw classifier) and the goal-regression subset.
        features = features.drop(
            columns=[c for c in side_prob_cols if c in features.columns],
            errors="ignore"
        )

    # 2) Goal regressors should NEVER see side-prob columns (they leak target info),
    #    so we drop them unconditionally here.
    goal_feats = features.drop(
        columns=[c for c in side_prob_cols if c in features.columns],
        errors="ignore"
    )

    # Goal regressors (and direct FTR classifier) will use `goal_feats`;
    # the draw classifier sees the full, un‑dropped `features` matrix.
    cat_features = goal_feats
    # Whitelist: only keep intended feature columns and rolling surrogates
    allowed = set(required_features) | {
        'rolling5_home_fin_eff', 'rolling5_away_fin_eff',
        'rolling5_home_xg_gap', 'rolling5_away_xg_gap',
        'h2h_goals_avg',
        'xg_gap_diff',
    }
        # ---- drop legacy features that are always zero / obsolete ----
    legacy_zero = {
        'total_shots_per_90',
        'home_points_per_game','away_points_per_game',
        'home_clean_sheet_percentage','away_clean_sheet_percentage',
        'home_btts_percentage','away_btts_percentage',
        'home_over25_percentage','away_over25_percentage',
        'home_fts_percentage','away_fts_percentage',
        'home_goals_scored_per_match','away_goals_scored_per_match',
        'home_goals_conceded_per_match','away_goals_conceded_per_match',
        'draw_prone'
    }
    allowed -= legacy_zero
    cat_features = cat_features.loc[:, cat_features.columns.intersection(allowed)]
    # — Auto-drop dead features (all NaN or all zero) —
    dead_cols = [
        c for c in cat_features.columns
        if cat_features[c].isna().all() or (cat_features[c] == 0).all()
    ]
    if dead_cols:
        print(f"🔧 Dropping dead columns: {dead_cols}")
        cat_features.drop(columns=dead_cols, inplace=True)
    target_home_goals = combined_data['home_team_goal_count']
    target_away_goals = combined_data['away_team_goal_count']
    target_ftr = combined_data['FTR']

    # Time-based split for consistency
    combined = cat_features.copy()
    # Preserve match_date for time-based splitting
    combined['match_date'] = combined_data.loc[cat_features.index, 'match_date']
    combined["home_goals"] = target_home_goals
    combined["away_goals"] = target_away_goals
    combined["FTR"]        = target_ftr

    train_df, val_df = leave_last_season_out(combined)

    X_train      = train_df.drop(columns=["home_goals","away_goals","FTR"])
    X_test       = val_df .drop(columns=["home_goals","away_goals","FTR"])
    y_train_home = train_df["home_goals"]
    y_test_home  = val_df ["home_goals"]
    y_train_away = train_df["away_goals"]
    y_test_away  = val_df ["away_goals"]
    y_train_ftr  = train_df["FTR"]
    y_test_ftr   = val_df ["FTR"]

    return X_train, X_test, y_train_home, y_test_home, y_train_away, y_test_away, y_train_ftr, y_test_ftr

#############################################
# Referee Profile & Draw-Prone Flag Functions
#############################################
def generate_ref_profile_from_matches(df):
    if 'referee' not in df.columns or 'FTR' not in df.columns:
        return {}
    ref_stats = df.groupby('referee').agg({
        'home_team_yellow_cards': 'mean',
        'away_team_yellow_cards': 'mean',
        'home_team_red_cards': 'mean',
        'away_team_red_cards': 'mean',
        'FTR': lambda x: np.mean(x == 1)
    }).reset_index()
    ref_profile = {}
    for _, row in ref_stats.iterrows():
        referee = row['referee']
        avg_yellow = (row['home_team_yellow_cards'] + row['away_team_yellow_cards']) / 2
        avg_red = (row['home_team_red_cards'] + row['away_team_red_cards']) / 2
        draw_rate = row['FTR']
        aggression_score = np.clip((avg_yellow + 2 * avg_red) / 5, 0, 1)
        ref_profile[referee] = {
            "avg_yellow_cards": avg_yellow,
            "avg_red_cards": avg_red,
            "draw_rate": draw_rate,
            "aggression_score": aggression_score
        }
    return ref_profile

def calibrate_draw_parameters(df, thresholds, ref_profile, actual_draw_rate, multiplier_ranges, additive_ranges):
    best_loss = float('inf')
    best_params = None
    for (ppg_mult, xg_mult, imp_prob_mult, odds_mult) in product(
            multiplier_ranges['ppg_diff'], multiplier_ranges['xg_diff'],
            multiplier_ranges['implied_prob_diff'], multiplier_ranges['odds_diff']):
        for (ppg_add, xg_add, imp_prob_add, odds_add) in product(
            additive_ranges['ppg_diff'], additive_ranges['xg_diff'],
            additive_ranges['implied_prob_diff'], additive_ranges['odds_diff']):
            multipliers = {
                'ppg_diff': ppg_mult,
                'xg_diff': xg_mult,
                'implied_prob_diff': imp_prob_mult,
                'odds_diff': odds_mult
            }
            additives = {
                'ppg_diff': ppg_add,
                'xg_diff': xg_add,
                'implied_prob_diff': imp_prob_add,
                'odds_diff': odds_add
            }
            df_temp = df.copy()
            df_temp = add_draw_prone_flag(df_temp, thresholds, ref_profile, multipliers, additives)
            flagged_rate = df_temp['is_draw_prone'].mean()
            loss = abs(flagged_rate - actual_draw_rate)
            if loss < best_loss:
                best_loss = loss
                best_params = (multipliers, additives)
    return best_params, best_loss
def optimize_additives_for_zero_loss(training_data, thresholds, ref_profile, best_multipliers,
                                     historical_draw_rate, max_additive=0.1, step=0.01, tol=1e-4):
    """
    Iterates through all additive combinations (from 0.0 to max_additive in increments of step)
    while keeping the best_multipliers fixed, and returns the first additive combination that
    yields a loss (absolute difference between simulated draw rate and historical draw rate) of 0.0 
    (within a tolerance).
    
    Parameters:
      training_data: DataFrame used for calibration.
      thresholds: Base threshold values (dict).
      ref_profile: Referee profile dictionary.
      best_multipliers: Dictionary of best multipliers obtained from prior calibration.
      historical_draw_rate: Target historical draw rate (float).
      max_additive: Maximum additive value to try (float, default=0.1).
      step: Increment step for additive values (float, default=0.01).
      tol: Tolerance within which loss is considered 0 (float, default=1e-4).
      
    Returns:
      best_additives: Dictionary of additive values for each feature, or None if not found.
      best_loss: The achieved loss for the returned additives.x
    """
    features = ['ppg_diff', 'xg_diff', 'implied_prob_diff', 'odds_diff']
    # Create a range of candidate additive values for each feature.
    candidate_values = np.arange(0.0, max_additive + step/2, step)

    # --------------------------------------------------------------
    # New: search only along additive dimensions that are in play
    # --------------------------------------------------------------
    active_adds = [
        k for k in ('ppg_diff', 'xg_diff', 'implied_prob_diff', 'odds_diff')
        if thresholds.get(k) is not None
    ]
    if not active_adds:                     # fail‑safe so loop still runs
        active_adds = ['ppg_diff']
    
    # --------------------------------------------------------------
    # Cartesian product over *only* the active additive keys
    # --------------------------------------------------------------
    from itertools import product
    best_additives = None
    best_loss = float('inf')
    for combo in product(candidate_values, repeat=len(active_adds)):
        # start with zeros for all four additives
        candidate_additives = {
            'ppg_diff': 0.0,
            'xg_diff': 0.0,
            'implied_prob_diff': 0.0,
            'odds_diff': 0.0
        }
        # populate the currently‑active dimensions
        for k, val in zip(active_adds, combo):
            candidate_additives[k] = val

        # ------------------------------------------------------------------
        # Evaluate loss with this additive combination
        # ------------------------------------------------------------------
        temp_data = training_data  # reuse in‑place; no deep copy
        temp_data = add_draw_prone_flag(
            temp_data, thresholds, ref_profile,
            multipliers=best_multipliers,
            additives=candidate_additives
        )
        simulated_draw_rate = temp_data['is_draw_prone'].mean()
        loss = abs(simulated_draw_rate - historical_draw_rate)

        if loss < best_loss:
            best_loss = loss
            best_additives = candidate_additives
            if loss < tol:          # early‑exit if within tolerance
                print(f"Found additive combination with loss {loss:.4f}: "
                      f"{candidate_additives}")
                return best_additives, best_loss
    if best_additives is None:
        print("No additive combination achieved zero loss within the given range and step.")
        return None, None
    return best_additives, best_loss


def calculate_draw_volatility_modifier(row, ref_profile):
    """
    Pre‑match draw‑volatility adjustment driven by referee style and the two teams’
    rolling disciplinary profiles (purely historical → no leakage).

    Positive  → pushes probability toward a draw  
    Negative  → pulls probability away from a draw
    """

    # --- Referee context ---------------------------------------------------
    referee      = row.get("referee", "")
    ref_data     = ref_profile.get(referee, {})
    aggression   = ref_data.get("aggression_score", 0.5)   # 0 (lenient) – 1 (strict)
    draw_rate    = ref_data.get("draw_rate", 0.3)          # historical share of draws

    # --- Team card behaviour (5‑match rolling averages) --------------------
    home_ratio   = row.get("rolling5_home_card_ratio", 0.0)   # cards‑per‑foul or per‑match
    away_ratio   = row.get("rolling5_away_card_ratio", 0.0)

    card_imbalance = abs(home_ratio - away_ratio)
    avg_cards      = (home_ratio + away_ratio) / 2.0

    modifier = 0.0

    # Aggressive ref + clear imbalance → tempers draw likelihood
    if aggression > 0.75 and card_imbalance >= 0.10:
        modifier -= 1.0
    # Lenient ref with a history of draws → nudges towards draw
    elif aggression < 0.45 and draw_rate > 0.35:
        modifier += 1.0

    # Very calm fixture (both teams low card ratios) → small draw boost
    if avg_cards <= 0.05:
        modifier += 0.5

    # Clamp to the range [‑0.8, 0.8] so it works nicely as +/- overlay
    modifier = np.clip(modifier, -0.8, 0.8)
    return modifier

def add_draw_prone_flag(df, thresholds, ref_profile=None,
                        multipliers=None, additives=None,
                        *, draw_thresh=0.6, use_cap=False):
    # --- OG: gate noisy draw-prone prints behind VERBOSE_DRAW (once per run) ---
    import os as _os, builtins as _bi
    global _OG_DRAW_MOD_PRINTED
    if "_OG_DRAW_MOD_PRINTED" not in globals():
        _OG_DRAW_MOD_PRINTED = False
    if _os.getenv("VERBOSE_DRAW", "0") != "1":
        # Shadow local print to a no-op when not in verbose draw mode
        def print(*args, **kwargs):
            return None
    else:
        # Allow exactly one print block in verbose mode to avoid spam
        def print(*args, **kwargs):
            global _OG_DRAW_MOD_PRINTED
            if not _OG_DRAW_MOD_PRINTED:
                _bi.print(*args, **kwargs)
                _OG_DRAW_MOD_PRINTED = True
    # --- OG: coerce mis-typed config to dicts (safe defaults) ---
    if not isinstance(thresholds, dict):
        thresholds = {}
    if not isinstance(multipliers, dict):
        multipliers = {}
    if not isinstance(additives, dict):
        additives = {}
    mult_ppg = multipliers.get('ppg_diff', 1.3) if multipliers is not None else 1.3
    add_ppg = additives.get('ppg_diff', 0.05) if additives is not None else 0.05
    mult_xg = multipliers.get('xg_diff', 1.2) if multipliers is not None else 1.2
    add_xg = additives.get('xg_diff', 0.05) if additives is not None else 0.05
    mult_imp = multipliers.get('implied_prob_diff', 1.2) if multipliers is not None else 1.2
    add_imp = additives.get('implied_prob_diff', 0.03) if additives is not None else 0.03
    mult_odds = multipliers.get('odds_diff', 1.2) if multipliers is not None else 1.2
    add_odds = additives.get('odds_diff', 0.2) if additives is not None else 0.2
    condition = (
        (df['ppg_diff'].abs() < thresholds.get('ppg_diff', 0.6) * mult_ppg + add_ppg) &
        (df['xg_diff'].abs() < thresholds.get('xg_diff', 0.4) * mult_xg + add_xg) &
        (df['implied_prob_diff'].abs() < thresholds.get('implied_prob_diff', 0.25) * mult_imp + add_imp) &
        (df['odds_diff'] < thresholds.get('odds_diff', 3.25) * mult_odds + add_odds)
    )

    # --- minimum draw‑likelihood guard ----------------------------
    if 'draw_likelihood_score' in df.columns:
        condition &= (df['draw_likelihood_score'] >= draw_thresh)

    if use_cap:
        # Hard‑cap safeguard: if more than the dynamic cap of fixtures are flagged by
        # the raw heuristic, retain only the strongest K (ranked by
        # draw_likelihood_score) so we don’t swamp the model.
        _raw_idx = condition[condition].index
        hist_rate = thresholds.get("historical_draw_rate", 0.30)
        # cap = historical draw‑rate + 15 p.p. (but never above 55 %)
        target_flag_rate = min(hist_rate + 0.15, 0.55)
        _max_keep = int(target_flag_rate * len(df))
        if len(_raw_idx) > _max_keep:
            if 'draw_likelihood_score' in df.columns:
                # Keep the top‑K by draw_likelihood_score
                _top_idx = (df.loc[_raw_idx, 'draw_likelihood_score']
                              .nlargest(_max_keep)
                              .index)
                _trimmed = pd.Series(False, index=df.index)
                _trimmed.loc[_top_idx] = True
                condition = _trimmed
            else:
                # Fallback: keep the first K rows (order already pseudo‑random)
                _trimmed = pd.Series(False, index=df.index)
                _trimmed.loc[_raw_idx[:_max_keep]] = True
                condition = _trimmed
    df['is_draw_prone'] = condition.astype(int)
    print("Percentage flagged as draw prone (initial):", df['is_draw_prone'].mean() * 100)
    
    if ref_profile is not None:
        try:
            df['draw_modifier'] = _compute_draw_modifier_vectorized(df, ref_profile).astype(float)
        except Exception:
            df['draw_modifier'] = 0.0
        import numpy as _np, os as _os, pandas as _pd
        _env_thr = _os.getenv("DRAW_MODIFIER_MIN", "").strip()
        try:
            _thr = float(_env_thr) if _env_thr != "" else _np.nan
        except Exception:
            _thr = _np.nan
        if _np.isnan(_thr):
            _nz = _pd.to_numeric(df['draw_modifier'], errors='coerce')
            _nz = _nz[_nz > 0]
            if len(_nz) >= 10:
                _thr = float(_np.percentile(_nz, 80))   # top 20% of the non-zeros
            elif len(_nz) > 0:
                _thr = max(0.05, float(_nz.median()))   # sparse: use median or 0.05
            else:
                _thr = 0.05                              # all zeros → small default
        # Combine: keep any already-flagged rows OR add rows whose modifier exceeds the threshold
        df['is_draw_prone'] = _np.where(
            (df['is_draw_prone'].astype(int) == 1) | (df['draw_modifier'] >= _thr),
            1, 0
        )
        # Log post-update share (symmetric with 'initial' print)
        try:
            _pct_after = float(_pd.to_numeric(df.get('is_draw_prone'), errors='coerce').fillna(0).mean()) if len(df) else 0.0
            print(f"Percentage flagged as draw prone (after modifier): {_pct_after}")
        except Exception:
            pass
        print("Percentage flagged as draw prone (after modifier):", df['is_draw_prone'].mean() * 100)
        print("Draw modifier stats:", df['draw_modifier'].describe())
    return df

