#############################################
# Over 2.5 Goals Model Trainer (restored)  #
#############################################
def train_and_evaluate_over25_model(combined_data: pd.DataFrame,
                                    league_name: str):
    """
    Logistic‑regression classifier for the Over‑2.5 Goals market.
    Includes bookmaker odds, pre‑match xG, rolling‑window intensity,
    and the new leak‑safe offensive / defensive indices.

    Returns
    -------
    fitted LogisticRegression with attributes:
        .score_           – accuracy on the hold‑out season
        .auc_             – ROC‑AUC
        .log_loss_        – log‑loss
        .best_threshold_  – tuned probability cut‑off
    The model file is persisted to ModelStore as
        <League>_over25_model.pkl
    """
    # 1) Ensure engineered features are populated and pass chronology guard
    combined_data = drop_bookmaker_cols(combined_data)   # ← NEW
    combined_data = ensure_basic_rolling5_metrics(combined_data)
    try:
        combined_data = _ensure_implied_1x2_guard(combined_data)
    except Exception:
        pass
    combined_data = enrich_feature_stack(combined_data, pre_match=True)
    assert_rolling_metrics(combined_data, league_name)

    # 2) Binary target label
    combined_data["Over25"] = (
        combined_data["home_team_goal_count"] +
        combined_data["away_team_goal_count"] > 2
    ).astype(int)

    # 3) Assemble feature list
    over_features = list(EXPANDED_OVER25_FEATURES)   # copy to avoid mutation

    # Guarantee columns exist
    for col in over_features:
        if col not in combined_data.columns:
            combined_data[col] = 0.0

    # 4) Walk‑forward split via TimeSeriesSplit (chronological)
    from sklearn.model_selection import TimeSeriesSplit

    X_full = (combined_data[over_features]
              .replace([np.inf, -np.inf], np.nan))
    X_full = safe_fill(X_full, X_full.columns.tolist(), SENTINEL)
    y_full = combined_data["Over25"]

    tss = TimeSeriesSplit(n_splits=5, gap=0)   # five chronological folds
    for tr_idx, va_idx in tss.split(X_full):
        pass                                   # iterate to keep last split

    X_tr, X_val = X_full.iloc[tr_idx], X_full.iloc[va_idx]
    y_tr, y_val = y_full.iloc[tr_idx], y_full.iloc[va_idx]

    # 5) Fit
    clf = LogisticRegression(solver="liblinear", random_state=42)
    assert_rolling_metrics(X_tr, "over25tg")
    clf.fit(X_tr, y_tr)

    # 6) Calibration (isotonic)
    calib = calibrate_probs(clf, X_val, y_val, method="isotonic")
    if calib is not None:
        clf.calibrator_ = calib
        y_prob = calib.predict_proba(X_val)[:, 1]
        joblib.dump(
            calib,
            os.path.join(
                MODEL_DIR,
                f"{league_name.replace(' ', '_')}_over25_calibrator.pkl"
            )
        )
    else:
        y_prob = clf.predict_proba(X_val)[:, 1]

    # 7) Diagnostics
    y_hat = (y_prob >= 0.50).astype(int)
    acc   = accuracy_score(y_val, y_hat)
    try:
        auc = roc_auc_score(y_val, y_prob)
    except ValueError:
        auc = float("nan")
    ll = log_loss(y_val, y_prob, labels=[0, 1])

    # 8) Threshold tuning (macro‑F1)
    # EV-aware threshold (uses decimal odds for Over 2.5 if available)
    try:
        _odds_val = pd.to_numeric(
            combined_data.loc[X_val.index, 'odds_ft_over25'], errors='coerce'
        ).fillna(0.0).to_numpy()
    except Exception:
        _odds_val = None
    best_thr, _ = tune_threshold_guard(y_val, y_prob, odds=_odds_val, default_metric="f1")  # EV-ready
    best_thr = _apply_locked_threshold(league_name, "over25", best_thr)
    _write_threshold(league_name, "over25", best_thr)
    clf.best_threshold_ = best_thr

    # 9) Permutation importance → CSV
    try:
        from sklearn.inspection import permutation_importance

        # --- permutation importance -----------------------------------
        # Align validation matrix to the feature order remembered by the model
        X_perm = X_val[clf.feature_names_in_]

        perm = permutation_importance(
            clf,
            X_perm,             # ← aligned feature order
            y_val,
            n_repeats=5,
            random_state=42
        )

        imp_df = (
            pd.DataFrame({
                "feature": clf.feature_names_in_,
                "importance": perm.importances_mean
            })
            .sort_values("importance", ascending=False)
            .head(10)
        )

        imp_path = os.path.join(
            MODEL_DIR,
            f"{league_name.replace(' ', '_')}_over25_perm_importance.csv"
        )
        imp_df.to_csv(imp_path, index=False)
        print(f"📑  Over 2.5 permutation‑importance saved → {imp_path}")
    except Exception as exc:
        print(f"⚠️  Could not save Over25 permutation‑importance: {exc}")

    # 10) Feature‑health snapshot
    feature_integrity_report(combined_data, over_features, league_name)

    # 11) Persist model & metrics
    clf.score_      = acc
    clf.auc_        = auc
    clf.log_loss_   = ll
    joblib.dump(
        clf,
        os.path.join(
            MODEL_DIR,
            f"{league_name.replace(' ', '_')}_over25_model.pkl"
        )
    )
    print(f"[{league_name}] Over 2.5 ➜ Acc: {acc*100:.2f}% | "
          f"AUC: {auc:.3f} | LL: {ll:.3f} | Thr: {best_thr:.2f}")
    return clf

# ---------------------------------------------------------------------------
# Over 1.5 Goals specialist (EV-ready via odds_ft_over15)
# ---------------------------------------------------------------------------
def train_and_evaluate_over15_model(combined_data: pd.DataFrame, league_name: str):
    """Train O1.5 specialist; returns fitted pipeline with best threshold on EV/F1.
    Expects 'odds_ft_over15' present for EV tuning.
    """
    import numpy as _np
    from sklearn.linear_model import LogisticRegression
    from sklearn.calibration import CalibratedClassifierCV
    from sklearn.model_selection import train_test_split

    df = combined_data.copy()
    # Label
    y = (pd.to_numeric(df["total_goal_count"], errors="coerce").fillna(0).to_numpy() >= 2).astype(int)
    # Features: numeric safe
    X = df.select_dtypes(include=["number"]).replace([_np.inf, -_np.inf], np.nan).fillna(0.0)

    # split
    X_tr, X_te, y_tr, y_te = train_test_split(X, y, test_size=0.25, random_state=42, stratify=y)

    # base estimator (balanced) + isotonic calibration
    base = LogisticRegression(max_iter=1000, class_weight="balanced", n_jobs=1)
    cal = CalibratedClassifierCV(base_estimator=base, method="isotonic", cv=3)
    cal.fit(X_tr, y_tr)

    # probabilities on hold-out
    y_prob = cal.predict_proba(X_te)[:, 1]

    # EV-aware threshold (Over 1.5): use decimal odds if available
    try:
        _odds_te = pd.to_numeric(df.loc[X_te.index, 'odds_ft_over15'], errors='coerce').fillna(0.0).to_numpy()
    except Exception:
        _odds_te = None
    best_thr, _ = tune_threshold_guard(y_te, y_prob, odds=_odds_te, default_metric="f1")  # EV-ready

    # attach utility attrs
    cal.best_threshold_ = float(best_thr)
    try:
        cal.feature_names_in_ = _np.array(list(X.columns))
    except Exception:
        pass

    # Save OOF-like column for training frame (probabilities) if expected by pipeline
    try:
        combined_data["oof_prob_over15"] = pd.Series(cal.predict_proba(X)[:, 1], index=combined_data.index)
    except Exception:
        pass

    # Persist model
    try:
        _save_market_model(league_name, "over15", cal)
    except Exception:
        pass
    return cal

# ---------------------------------------------------------------------------
# First-Half Over 0.5 Goals specialist (no odds → F1 fallback)
# ---------------------------------------------------------------------------
def train_and_evaluate_fh_over05_model(combined_data: pd.DataFrame, league_name: str):
    """Train FHG0.5 specialist (label: total_goals_at_half_time >= 1)."""
    import numpy as _np
    from sklearn.linear_model import LogisticRegression
    from sklearn.calibration import CalibratedClassifierCV
    from sklearn.model_selection import train_test_split

    df = combined_data.copy()
    # Label
    y = (pd.to_numeric(df["total_goals_at_half_time"], errors="coerce").fillna(0).to_numpy() >= 1).astype(int)
    X = df.select_dtypes(include=["number"]).replace([_np.inf, -_np.inf], np.nan).fillna(0.0)

    X_tr, X_te, y_tr, y_te = train_test_split(X, y, test_size=0.25, random_state=42, stratify=y)

    base = LogisticRegression(max_iter=1000, class_weight="balanced", n_jobs=1)
    cal  = CalibratedClassifierCV(base_estimator=base, method="isotonic", cv=3)
    cal.fit(X_tr, y_tr)

    y_prob = cal.predict_proba(X_te)[:, 1]
    best_thr, _ = tune_threshold_guard(y_te, y_prob, odds=None, default_metric="f1")  # F1 fallback
    cal.best_threshold_ = float(best_thr)
    try:
        cal.feature_names_in_ = _np.array(list(X.columns))
    except Exception:
        pass
    try:
        combined_data["oof_prob_fh_over05"] = pd.Series(cal.predict_proba(X)[:, 1], index=combined_data.index)
    except Exception:
        pass
    try:
        _save_market_model(league_name, "fh_over05", cal)
    except Exception:
        pass
    return cal

#############################################
# Model Training & Evaluation Functions
#############################################
def train_and_evaluate_models(
    X_train, X_test,
    y_train_home, y_test_home,
    y_train_away, y_test_away,
    y_train_ftr, y_test_ftr,
    league_name,
    draw_classifier, draw_features,
    *,                       # ← keyword-only from here down
    alpha: float = 1.0,
    beta: float = 0.0,
    overlay_cap: float = 0.55,
    gate_scale: float = 0.60,
    **kwargs,
):
    """
    Train CatBoost goal regressors and blend with draw classifier to predict FTR.
    """
    # absorb currently-unused params to keep the signature future‑proof
    _ = (overlay_cap, gate_scale, kwargs)
    # ------------------------------------------------------------------
    # Local lock flags – honour global FORCE_LOCKED but *only* for
    # leagues explicitly frozen in constants.py
    # ------------------------------------------------------------------
    use_locked_mix = (league_name in LOCKED_FTR_MIX) and FORCE_LOCKED
    use_locked_thr = (league_name in LOCKED_THRESHOLDS) and FORCE_LOCKED
    # ------------------------------------------------------------------
    # CatBoost‑Poisson goal regressors (log‑λ output → λ)
    # ------------------------------------------------------------------
    cat_params = {
        "loss_function": "Poisson",
        "iterations": 1000,
        "learning_rate": 0.05,
        "depth": 6,
        "random_seed": 42,
        "verbose": False
    }
    # --------------------------------------------------------------
    # Champions League – reuse the locked validation split **only**
    # when the league is frozen via LOCKED_FTR_MIX / SKIP_TRAIN_LEAGUES.
    # --------------------------------------------------------------
    if use_locked_mix and league_name == "Champions League":
        tag = league_name.replace(" ", "_")
        try:
            X_test = joblib.load(os.path.join(MODEL_DIR, f"{tag}_X_test_aug.pkl"))
            y_test_ftr = joblib.load(os.path.join(MODEL_DIR, f"{tag}_y_test_ftr.pkl"))
            print(f"🔒 Using locked Champions‑League test split ({len(X_test)} rows)")
        except FileNotFoundError:
            print("⚠️  Locked CL test files missing — falling back to fresh split.")
    
    # Using provided train/test splits here; no extra chrono split in this scope.
    # -- global leak blacklist enforcement -------------------------
    X_train = strip_leaks(X_train, allowlist=_auto_ftr_allow(X_train))
    if 'X_val' in locals():
        X_val = strip_leaks(X_val, allowlist=_auto_ftr_allow(X_val))
    X_test  = strip_leaks(X_test, allowlist=_auto_ftr_allow(X_test))
    # 🛡️  feature-integrity guard – drop constant columns
    const_cols = [c for c in X_train.columns if _is_constant(X_train[c])]
    if const_cols:
        print(f"⚠️  Dropping constant cols: {const_cols}")
        X_train = X_train.drop(columns=const_cols)
        X_test  = X_test.drop(columns=const_cols)
    # --- diagnostic: flag any rolling-metrics accidentally caught ---
    bad_roll = [c for c in const_cols if c in ROLLING_SAFE]
    if bad_roll:
        print("🛑 rolling metrics incorrectly flagged constant:", bad_roll[:6])
    # ---- hard‑drop leak‑prone columns ---------------------------------
    leak_cols = list(LEAK_BLACKLIST & set(X_train.columns))
    if leak_cols:
        print(f"🚫  Dropping leak‑prone cols: {leak_cols}")
        X_train = X_train.drop(columns=leak_cols)
        X_test  = X_test.drop(columns=leak_cols)
    # ------------------------------------------------------------------
    # ---- anti‑leak assert: no label / live‑goal columns in the feature matrix ----
    _leak_cols = {"FTR", "home_team_goal_count", "away_team_goal_count"}
    assert not any(c in X_train.columns for c in _leak_cols), \
        f"label leakage – found {_leak_cols & set(X_train.columns)}"
        
    # ----- Home goals --------------------------------------------------
    model_home = CatBoostRegressor(**cat_params)
    model_home.fit(X_train, y_train_home)
    home_preds = np.exp(model_home.predict(_align_dataframe_to_model(X_test, model_home)))     # log‑λ → λ
    home_mse   = mean_squared_error(y_test_home, home_preds)

    # ----- Away goals --------------------------------------------------
    model_away = CatBoostRegressor(**cat_params)
    model_away.fit(X_train, y_train_away)
    away_preds = np.exp(model_away.predict(_align_dataframe_to_model(X_test, model_away)))    # log‑λ → λ
    away_mse   = mean_squared_error(y_test_away, away_preds)
    
    # ------------------------------------------------------------------
    # If a tuned α was supplied, skip the optimiser and use it directly
    # ------------------------------------------------------------------
    if alpha is not None:
        best_alpha = alpha
    else:
        # ------------------------------------------------------------------
        # Step 2 – Optimise the α blend‑weight for Poisson ↔ Draw‑classifier.
        # We widen the candidate grid **and** switch the objective from
        # F1‑score to *recall on the draw class* so that calibration favours
        # capturing more actual draws, even at some precision cost.
        # ------------------------------------------------------------------
        # League-specific alpha grid
        if league_name == "Germany Bundesliga":
            candidate_alphas = [0.5, 1.0, 1.5, 2.0, 2.5]   # rollback max
        elif league_name == "England Premier League":
            candidate_alphas = np.arange(0.3, 3.1, 0.25)
            # Expanded β and cap grids for deeper search
            candidate_betas  = np.arange(0.05, 0.55, 0.05)
            candidate_caps   = np.arange(0.40, 0.56, 0.05)
        elif league_name == "Portugal Liga":
            candidate_alphas = [0.5, 1.0, 1.5, 2.0, 2.5]
        else:
            candidate_alphas = [0.5, 1.0, 1.5, 2.0]
        # Use "balanced" metric for Germany Bundesliga, else macro_f1
        opt_metric = "balanced" if league_name == "Germany Bundesliga" else "macro_f1"
        best_alpha, _, _ = optimize_alpha(
            X_test, y_test_ftr,
            home_preds, away_preds,
            draw_classifier, draw_features,
            candidate_alphas,
            metric=opt_metric
        )
        print(f"Optimal alpha selected: {best_alpha:.2f}")
    # ----- Persist α & overlay cap per league/season ----------------
    season_key = y_train_ftr.index.max()  # fallback: just use max index year
    try:
        # if match_date exists, derive "YYYY-YY" style season
        if "match_date" in X_train.columns:
            years = pd.to_datetime(
                X_train["match_date"].dropna()).dt.year.unique()
            if len(years):
                yr_max = years.max()
                season_key = f"{yr_max-1}-{str(yr_max)[-2:]}"
    except Exception:
        pass

    hist_draw_rate = (y_train_ftr == 1).mean()
    if league_name == "Germany Bundesliga":
        overlay_cap = min(hist_draw_rate + 0.23, 0.55)   # +23 p.p. bump
    elif league_name == "England Premier League":
        overlay_cap = min(hist_draw_rate + 0.25, 0.70)
    elif league_name == "Portugal Liga":
        overlay_cap = min(hist_draw_rate + 0.18, 0.55)
    else:
        overlay_cap = min(hist_draw_rate + 0.15, 0.55)
    # overlay_cap is now always controlled by parameter or above logic

    # ── override cap when the entire mix is frozen ──────────────
    if use_locked_mix:
        overlay_cap = LOCKED_FTR_MIX[league_name]['cap']

    meta = _load_league_meta()
    lg_meta = meta.get(league_name, {})

    # --------------------------------------------------------------
    #  Weighted 3‑way CatBoost classifier (handles class imbalance)
    # --------------------------------------------------------------
    draw_freq  = (y_train_ftr == 1).mean()
    home_freq  = (y_train_ftr == 0).mean()
    away_freq  = (y_train_ftr == 2).mean()

    w_home = 1.0 / max(home_freq, 1e-6)
    w_draw = 1.0 / max(draw_freq, 1e-6)
    w_away = 1.0 / max(away_freq, 1e-6)

    clf_ftr = CatBoostClassifier(
        loss_function="MultiClass",
        iterations=900,
        depth=6,
        learning_rate=0.05,
        random_seed=42,
        class_weights=[w_home, w_draw, w_away],
        verbose=False
    )
    clf_ftr.fit(X_train, y_train_ftr)

    # Predict class probabilities on the held‑out test slice
    prob_mat = clf_ftr.predict_proba(
        _align_dataframe_to_model(X_test, clf_ftr)
    )
    ftr_preds = prob_mat.argmax(axis=1).tolist()

# ----- Dirichlet calibration on last-season validation ----------
    # ----- Dirichlet calibration on last-season validation ----------
    # --- ensure validation slice objects exist --------------------
    # Fallback: if X_val_dt / h_val / a_val are not defined in this scope
    # (e.g. after refactors), construct a simple 20 % chronological split
    # from the training data so the Dirichlet calibrator still has a
    # leak‑free slice to learn from.
    if 'X_val_dt' not in locals():
            # --- Chronological validation split (last 20 % by date) ----
        if 'match_date' in X_train.columns:
            _dt = X_train.join(y_train_ftr).sort_values('match_date')
            _split_date = _dt['match_date'].quantile(0.80)
            X_val_dt = _dt[_dt['match_date'] >= _split_date][X_train.columns].copy()
            y_val_dt = y_train_ftr.loc[X_val_dt.index].copy()
        else:
            # fallback – keep the original 80 % tail slice (still leak-safe)
            tail = int(len(X_train) * 0.8)
            X_val_dt = X_train.iloc[tail:].copy()
            y_val_dt = y_train_ftr.iloc[tail:].copy() 
    calib_path = os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_FTR_dirichlet.pkl")
    os.makedirs(MODEL_DIR, exist_ok=True)

    try:
        # Build probability matrix for the validation slice using the 3-way CatBoost classifier
        prob_val = clf_ftr.predict_proba(
            _align_dataframe_to_model(X_val_dt, clf_ftr)
        )

        # Fit the Dirichlet (Isotonic) calibrator on the *validation* slice
        dir_cal = DirichletCalibrator(method="isotonic")
        dir_cal.fit(prob_val, y_val_dt)
        joblib.dump(dir_cal, calib_path)
        print(f"[{league_name}] Dirichlet calibrator saved → {calib_path}")

        # Apply once to the held‑out *test* probabilities
        prob_mat = dir_cal.predict(prob_mat)
        ftr_preds = prob_mat.argmax(axis=1).tolist()
    except Exception as exc:
        print(f"⚠️  Dirichlet calibration skipped: {exc}")
    # --- persist the full probability matrix for later audits ----------
    tag = league_name.replace(" ", "_")
    np.save(os.path.join(MODEL_DIR, f"{tag}_prob_mat.npy"), prob_mat)
    # ── diagnostic: show unique rounded probability rows ──
    prob_arr = np.atleast_2d(np.asarray(prob_mat, dtype=float))
    uniq_rows = np.unique(np.round(prob_arr, 3), axis=0)

    top_n = min(10, len(uniq_rows))
    if top_n > 0:
        print(f"🔍  Unique rounded proba rows: {len(uniq_rows)} (showing top {top_n})")
        print(uniq_rows[:top_n])
    else:
        print("🔍  Unique rounded proba rows: 0")

    # ---- Threshold file (per-league) ---------------------------------
    thr_path = os.path.join(
        MODEL_DIR,
        f"{league_name.replace(' ', '_')}_thresholds.csv"
    )
    thr_file = pathlib.Path(thr_path)
    stale = (not thr_file.exists()) or (
        not FREEZE_FTR_META and
        (time.time() - thr_file.stat().st_mtime > 7 * 24 * 3600)
    )
    # --- persist the full probability matrix for later audits ----------
    # ------------------------------------------------------------------
    # 🩹  Probability‑shape repair guard
    #     A mis‑configured calibrator can return a **single‑column**
    #     array of class‑indices instead of a proper (N, 3) matrix.
    #     We detect the two common failure modes and coerce back to a
    #     well‑formed 3‑column probability matrix that our downstream
    #     code expects.
    # ------------------------------------------------------------------
    
    # Guard-rail: ensure *prob_mat* is always a well-formed (n, 3) matrix
    # so downstream helpers never crash on 1-D arrays that slipped through.
    # ------------------------------------------------------------------
    prob_mat = np.asarray(prob_mat)
    if prob_mat.ndim == 1:
        if prob_mat.size % 3 == 0:
            # reshape flat vector back to (n_samples, 3)
            prob_mat = prob_mat.reshape(-1, 3)
        else:
            # Treat as vector of predicted class labels → one-hot encode
            labels = prob_mat.astype(int)
            one_hot = np.zeros((labels.size, 3), dtype=float)
            one_hot[np.arange(labels.size), labels] = 1.0
            prob_mat = one_hot
    assert_prob_matrix_shape(prob_mat)
    # ------------------------------------------------------------------
    # 🔧  Grid-search the optimal decision thresholds (only when **not**
    #     frozen by constants.LOCKED_THRESHOLDS)
    # ------------------------------------------------------------------
    if league_name not in LOCKED_THRESHOLDS:
        # y_test_ftr must be the true 0/1/2 labels for this same proba matrix
        tuned_draw, tuned_home, tuned_away = grid_search_thresholds(
            prob_mat, y_test_ftr, metric="accuracy"
        )   
        print(f"[{league_name}]  Optimal thresholds "
              f"(draw={tuned_draw:.3f}, home={tuned_home:.3f}, away={tuned_away:.3f})")

        # Persist so future runs & dashboards pick them up
        _write_threshold(league_name, "draw", tuned_draw)
        _write_threshold(league_name, "home", tuned_home)
        _write_threshold(league_name, "away", tuned_away)
    else:
        # ── use constant locks *only* if they exist; otherwise fall back to 0.34 trio
        lt = LOCKED_THRESHOLDS.get(league_name, {})
        tuned_draw = lt.get("draw", 0.34)
        tuned_home = lt.get("home", 0.34)
        tuned_away = lt.get("away", 0.34)
    if prob_mat.size % 3 == 0:
        prob_mat = prob_mat.reshape(-1, 3)
    else:
        # fallback: each element is itself a (prob,prob,prob) array
        prob_mat = np.vstack(prob_mat)

    # 2‑D but single column → likely class‑index labels; convert to one‑hot
    if prob_mat.ndim == 2 and prob_mat.shape[1] == 1:
        class_idx = np.clip(prob_mat.astype(int).flatten(), 0, 2)
        prob_mat = np.eye(3, dtype=float)[class_idx]

    # Final shape repair – ensure we end up with a 3‑column matrix.
    if prob_mat.ndim != 2 or prob_mat.shape[1] != 3:
        prob_mat = pad_prob_matrix(
            prob_mat,
            np.arange(prob_mat.shape[-1] if prob_mat.ndim > 1 else 1)
        )
    # Split the probability matrix into individual class vectors
    p_home, p_draw, p_away = prob_mat[:, 0], prob_mat[:, 1], prob_mat[:, 2]

    # ------------------------------------------------------------------
    # Length sanity – abort if probabilities and labels diverge
    # ------------------------------------------------------------------
    if len(prob_mat) != len(y_test_ftr):
        clip_len = min(len(prob_mat), len(y_test_ftr))
        print(f"⚠️  Aligning prob_mat ({len(prob_mat)}) → y_test_ftr ({len(y_test_ftr)}) → {clip_len}")
        prob_mat   = prob_mat[:clip_len]           # or prob_mat.iloc[:clip_len] if it’s a DataFrame
        y_test_ftr = y_test_ftr.iloc[:clip_len].copy()
        X_test_aug = X_test_aug.iloc[:clip_len].copy()

    # --------------------------------------------------------------
    # Build validation frame once for walk‑forward threshold tuning
    # --------------------------------------------------------------
    val_df = pd.DataFrame({
        "FTR":   y_test_ftr,          # ground‑truth labels
        "p_home": p_home,
        "p_draw": p_draw,
        "p_away": p_away,
        # optional season column lets tuner split year‑by‑year
        "season": X_test_aug.get("season")    # None/NaN if absent
    })

    # league‑specific grid for the draw/home/away threshold tuner
    thr_grid = (
        np.arange(0.15, 0.46, 0.01)  if league_name == "England Premier League" else
        np.arange(0.15, 0.46, 0.025) if league_name == "Champions League"      else
        np.arange(0.15, 0.91, 0.05)
    )

    if use_locked_thr:
        lt = LOCKED_THRESHOLDS[league_name]
        best_t_draw = lt.get("draw", 0.34)
        best_t_home = lt.get("home", 0.34)
        best_t_away = lt.get("away", 0.34)

    elif stale or not FREEZE_FTR_META:
        # ----------------------------------------------------------
        # First‑time run or meta not frozen → tune thresholds on the
        # *calibrated* probability matrix we just built.
        # ----------------------------------------------------------
        best_t_draw, best_t_home, best_t_away = tune_ftr_thresholds_walkforward(
            val_df,
            ('p_home', 'p_draw', 'p_away'),
            grid=thr_grid
        )
        print(f"🔧  Tuned thresholds ⇒ "
              f"draw={best_t_draw:.2f}, home={best_t_home:.2f}, away={best_t_away:.2f}")

        # Persist for future runs
        _write_threshold(league_name, "draw",  best_t_draw)
        _write_threshold(league_name, "home",  best_t_home)
        _write_threshold(league_name, "away",  best_t_away)

    else:
        # ----------------------------------------------------------
        # Load last‑saved thresholds; if file is missing/invalid, fall
        # back to re‑tuning and immediately persist the new values.
        # ----------------------------------------------------------
        try:
            best_t_draw, best_t_home, best_t_away = load_last_thresholds(thr_file)
        except (FileNotFoundError, KeyError, ValueError) as exc:
            print(f"⚠️  Threshold file invalid or incomplete ({exc}). "
                  f"Re‑tuning thresholds for {league_name} …")

            best_t_draw, best_t_home, best_t_away = tune_ftr_thresholds_walkforward(
                val_df,
                ('p_home', 'p_draw', 'p_away'),
                grid=thr_grid
            )
            print(f"🔁  Re‑tuned thresholds ⇒ "
                  f"draw={best_t_draw:.2f}, home={best_t_home:.2f}, away={best_t_away:.2f}")

            _write_threshold(league_name, "draw",  best_t_draw)
            _write_threshold(league_name, "home",  best_t_home)
            _write_threshold(league_name, "away",  best_t_away)

    # ---- guard against zeroed / collapsed thresholds -----------------
    _t_vec = np.array([best_t_home, best_t_draw, best_t_away])
    assert _t_vec.min() > 0.01, "thresholds collapsed to zero – aborting"

    # ------------------------------------------------------------------
    # ➌ Metric‑safety guard – keep y_true and predictions aligned
    # ------------------------------------------------------------------
    if len(y_test_ftr) != len(ftr_preds):
        clip_len = min(len(y_test_ftr), len(ftr_preds))
        print(f"⚠️  Clipping metrics arrays to {clip_len} samples "
              f"(y_true={len(y_test_ftr)}, y_pred={len(ftr_preds)})")
        y_test_ftr = y_test_ftr[:clip_len]
        ftr_preds  = ftr_preds[:clip_len]

    ftr_acc = accuracy_score(y_test_ftr, ftr_preds)

    # 🚨 Log if implausibly high accuracy, which could indicate leakage
    print(f"⚠️ FTR Accuracy {ftr_acc:.3f} – review for potential leakage if unexpectedly high.")

    # Log FTR metrics.
    log_ftr_metrics(y_test_ftr, ftr_preds, league_name)

    # ── residual‑leak bag‑of‑tricks ─────────────────────────────
    temporal_shuffle_sanity(y_test_ftr)    # quick shuffled‑label sanity (≈0.33 acc)

    # quick correlation audit (training features only – no self‑correlation)
    try:
        corr = (
            X_train
              .apply(lambda col: col.corr(y_train_ftr))
              .abs()
              .sort_values(ascending=False)
        )
        print("[sanity] Top-20 |FTR correlation|")
        print(corr.head(20).to_string())
    except Exception as exc:
        print(f"[sanity] correlation audit failed: {exc}")
    
    # Generate SHAP plots.
    explainer_home = shap.Explainer(model_home)
    X_train_aligned_home = _align_dataframe_to_model(X_train, model_home)
    shap_values_home = explainer_home(X_train_aligned_home)
    shap.summary_plot(shap_values_home, X_train_aligned_home, show=False)
    plt.savefig(os.path.join(MODEL_DIR, f"{league_name.replace(' ', '_')}_shap_home_summary.png"))
    plt.close()

    explainer_away = shap.Explainer(model_away)
    X_train_aligned_away = _align_dataframe_to_model(X_train, model_away)
    shap_values_away = explainer_away(X_train_aligned_away)
    shap.summary_plot(shap_values_away, X_train_aligned_away, show=False)
    plt.savefig(os.path.join(MODEL_DIR, f"{league_name.replace(' ', '_')}_shap_away_summary.png"))
    plt.close()
    # shap.save_html(...) requires a Visualizer object from shap.plots.force()
    # shap.save_html(os.path.join(MODEL_DIR, f"{league_name.replace(' ', '_')}_shap_away.html"), shap_values_away)
    
    # Save models.
    try:
        _persist_goal_pair(model_home, model_away, league_name)
    except Exception:
        pass
    
    print(f"----- [{league_name}] Model Summary -----")
    print(f"Home Goals Model MSE: {home_mse:.4f}")
    print(f"Away Goals Model MSE: {away_mse:.4f}")
    print(f"FTR Prediction Accuracy: {ftr_acc*100:.2f}%")

    # ── adaptive blend‑parameter optimiser & persistence ────────────
    if not use_locked_mix:          # skip when mix is frozen
        try:
            # --------------------------------------------------------------
            # 🔎  Optuna hyper-search – jointly tune cw_draw, gate_scale, α/β/cap
            # --------------------------------------------------------------
            # --- Robust tuner invocation: compute val goal preds + try multiple signatures ---
            def _compute_val_goal_preds():
                try:
                    _Xv = _align_dataframe_to_model(X_val_dt, model_home)
                    _hv = np.exp(model_home.predict(_Xv))
                except Exception:
                    _hv = None
                try:
                    _Xv2 = _align_dataframe_to_model(X_val_dt, model_away)
                    _av = np.exp(model_away.predict(_Xv2))
                except Exception:
                    _av = None
                return _hv, _av

            h_val, a_val = _compute_val_goal_preds()

            def _safe_tune_mix():
                # Prefer full-arg call; gracefully fall back to older signatures
                try:
                    return _call_tmh_robust(
                        X_train, y_train_ftr,
                        X_val_dt, y_val_dt,
                        home_preds_val=h_val,
                        away_preds_val=a_val,
                        n_trials=30,
                        timeout=120,
                        random_state=42
                    )
                except TypeError:
                    # Try keyword-only variant (no train split)
                    try:
                        return _call_tmh_robust(
                            y_val=y_val_dt,
                            home_preds_val=h_val,
                            away_preds_val=a_val,
                            n_trials=30,
                            timeout=120,
                            random_state=42
                        )
                    except TypeError:
                        # Old API that expects base_proba (draw-classifier validation probs)
                        try:
                            _prob_val = draw_classifier.predict_proba(
                                _align_dataframe_to_model(X_val_dt, draw_classifier)
                            )
                            _base = _prob_val[:, 1]  # draw column
                        except Exception:
                            _base = None
                        return _call_tmh_robust(
                            base_proba=_base,
                            n_trials=30,
                            timeout=120,
                            random_state=42
                        )
                except Exception as _mix_err:
                    print(f"⚠️  Hyper‑parameter optimiser failed (robust path): {_mix_err}")
                    return {"alpha": 1.0, "beta": 0.0, "cap": 0.45, "gate_scale": 0.60, "cw_draw": 1.0}

            best_mix = _safe_tune_mix()

            best_alpha = float(best_mix.get("alpha", 1.0))
            best_beta  = float(best_mix.get("beta", 0.0))
            best_cap   = float(best_mix.get("cap", 0.45))
            gate_scale = float(best_mix.get("gate_scale", 0.60))
            cw_draw    = float(best_mix.get("cw_draw", 1.0))

            league_meta = _load_league_meta()
            league_meta.setdefault(league_name, {})
            league_meta[league_name]["alpha"]       = float(best_alpha)
            league_meta[league_name]["beta"]        = float(best_beta)
            league_meta[league_name]["overlay_cap"] = float(best_cap)
            league_meta[league_name]["gate_scale"]  = float(gate_scale)
            league_meta[league_name]["cw_draw"]     = float(cw_draw)
            _save_league_meta(league_meta)
            print(f"📑  Saved Optuna‑tuned mix ⇒ "
                  f"α={best_alpha:.2f}, β={best_beta:.2f}, cap={best_cap:.2f}, "
                  f"gate={gate_scale:.2f}, cw_draw={cw_draw:.2f} for {league_name}")
        except Exception as exc:
            print(f"⚠️  Hyper‑parameter optimiser failed: {exc}")
    else:
        locked = LOCKED_FTR_MIX[league_name]
        best_alpha = locked['alpha']
        best_beta  = locked['beta']
        best_cap   = locked['cap']
        print(f"🔒 Using frozen α/β/cap for {league_name}: "
              f"α={best_alpha:.2f}, β={best_beta:.2f}, cap={best_cap:.2f}")


    # --------------------------------------------------------------
    # 🔍  Diagnostic reports
    #   • Permutation‑importance for the draw classifier
    #   • Leakage heuristic on the full feature matrix
    # --------------------------------------------------------------
    try:
        perm_cols = [c for c in draw_features if c in X_test_aug.columns]
        X_pi = (X_test_aug[perm_cols]
                .replace([np.inf, -np.inf], np.nan)
                .fillna(0))
        y_pi = (y_test_ftr == 1).astype(int)
        permutation_importance_report(
            draw_classifier,
            X_pi,
            y_pi,
            top_n=15
        )
    except Exception as exc:
        print(f"⚠️  Permutation‑importance failed: {exc}")

    try:
        leakage_diagnostic(
            X_train,                     # original training matrix
            list(X_train.columns),
            league_name
        )
    except Exception as exc:
        print(f"⚠️  Leakage diagnostic failed: {exc}")

    # ---- DEBUG: persist val slice for debug_draw -------------------
    tag = league_name.replace(" ", "_")
    joblib.dump(X_test_aug, os.path.join(MODEL_DIR, f"{tag}_X_test_aug.pkl"))
    joblib.dump(y_test_ftr,  os.path.join(MODEL_DIR, f"{tag}_y_test_ftr.pkl"))
    
    
    return model_home, model_away, ftr_acc, y_test_ftr, X_test_aug, prob_mat


def train_and_evaluate_btts_model(combined_data, league_name):
    """
    Both‑Teams‑To‑Score (BTTS) classifier.

    • Strips bookmaker odds before feature generation to avoid outcome leakage.  
    • Builds engineered features, trains a logistic model, calibrates, and
      persists threshold & permutation‑importance diagnostics.

    Returns
    -------
    sklearn.linear_model.LogisticRegression
        Fitted model with extra attributes:
        .score_           – accuracy on the chrono hold‑out slice  
        .auc_             – ROC‑AUC on hold‑out  
        .log_loss_        – log‑loss on hold‑out  
        .best_threshold_  – tuned probability cut‑off for deployment
    """
    # —— leak‑guard: strip bookmaker odds ————————————
    combined_data = drop_bookmaker_cols(combined_data)
    # --- guarantee rich engineered features are present ------------
    combined_data = ensure_basic_rolling5_metrics(combined_data)
    combined_data = enrich_feature_stack(combined_data, pre_match=True)
    assert_rolling_metrics(combined_data, league_name)
    
    # ----- target label -------------------------------------------------
    combined_data['BTTS'] = (
        (combined_data['home_team_goal_count'] > 0) &
        (combined_data['away_team_goal_count'] > 0)
    ).astype(int)

    # ---------- core feature list ---------------------------------
    btts_features = [
        # in‑play stats & quality
        'goal_count_diff', 'possession_diff',
        'finishing_efficiency_home', 'finishing_efficiency_away',
        'xg_conversion_gap', 'momentum_score',
        # bookmaker prices
        'odds_btts_yes', 'odds_btts_no',
        'odds_ft_home_team_win', 'odds_ft_draw', 'odds_ft_away_team_win',
        # historical goal tendency
        'average_goals_per_match_pre_match',
        'btts_percentage_pre_match',
        'over_15_percentage_pre_match', 'over_25_percentage_pre_match',
        # form & strength
        'home_recent_form', 'away_recent_form',
        'weighted_home_ppg', 'weighted_away_ppg', 'ppg_diff', 'xg_diff'
    ]

    # --- injected richer predictors ----------------------------------
    extra_btts = [
        "home_goals_pred", "away_goals_pred",
        "poisson_over25_prob", "poisson_btts_prob",
        "attacking_pressure_home", "attacking_pressure_away",
        "home_offensive_index", "away_offensive_index",
        "home_defensive_efficiency", "away_defensive_efficiency",
        "home_clean_sheet_percentage", "away_clean_sheet_percentage",
        # rolling attack & discipline
        "rolling5_home_sot_ratio", "rolling5_away_sot_ratio",
        "rolling5_home_card_ratio", "rolling5_away_card_ratio",
        "rolling5_home_gc", "rolling5_away_gc",
        # market & side-model signals
        "odds_btts_yes", "odds_btts_no", "odds_ft_draw", "odds_ft_over15",
        "prob_home_over15tg", "prob_away_over15tg",
        "prob_home_fts", "prob_away_fts",
        # macro overlay
        "btts_overlay_modifier",
    ]
    btts_features += extra_btts
    # de-duplicate while preserving the original order
    btts_features = list(dict.fromkeys(btts_features))
    # Patch: Ensure "h2h_btts_rate" is always included
    if "h2h_btts_rate" not in btts_features:
        btts_features.append("h2h_btts_rate")
    # --- ensure dataframe has no duplicate column names ------------
    combined_data = combined_data.loc[:, ~combined_data.columns.duplicated()].copy()
        # --- populate goal-prediction columns *before* we build X -------
    combined_data = add_goal_predictions_to_complete_data(
        combined_data, league_name, btts_features
    )
    btts_features += extra_btts
    # de‑duplicate while preserving original order
    btts_features = list(dict.fromkeys(btts_features))
    for f in btts_features:
        if f not in combined_data.columns:
            combined_data[f] = np.nan

    X = combined_data[btts_features].replace([np.inf, -np.inf], np.nan)
    X = safe_fill(X, X.columns.tolist(), SENTINEL)
    assert X.columns.is_unique, "Duplicate column names detected in X"
    y = combined_data['BTTS']

    # ── walk‑forward split via TimeSeriesSplit (season‑aware) ----------
    from sklearn.model_selection import TimeSeriesSplit
    tss = TimeSeriesSplit(n_splits=5, gap=0)  # 5 chronological folds

    # iterate so that after the loop `tr_idx` / `te_idx` point to the most
    # recent (hold‑out) split
    for tr_idx, te_idx in tss.split(X):
        pass

    X_tr, X_te = X.iloc[tr_idx], X.iloc[te_idx]
    X_tr = strip_leaks(X_tr, allowlist=_auto_ftr_allow(X_tr))
    X_te = strip_leaks(X_te, allowlist=_auto_ftr_allow(X_te))
    y_tr, y_te = y.iloc[tr_idx], y.iloc[te_idx]

    clf = LogisticRegression(solver='liblinear', random_state=42)
    # rolling‑window chronology audit
    assert_rolling_metrics(X_tr, "btts")
    clf.fit(X_tr, y_tr)

    y_prob = clf.predict_proba(X_te)[:, 1]
    y_hat  = (y_prob >= 0.50).astype(int)
    acc    = accuracy_score(y_te, y_hat)
    auc    = roc_auc_score(y_te, y_prob)
    ll     = log_loss(y_te, y_prob, labels=[0, 1])

    # --- optimal probability threshold (per-league; EV-ready) ---------
    try:
        _odds_te = pd.to_numeric(X_te.get('odds_btts_yes'), errors='coerce').fillna(0.0).to_numpy()
    except Exception:
        _odds_te = None
    best_thr, _ = tune_threshold_guard(y_te, y_prob, odds=_odds_te, default_metric="f1")  # EV-ready
    # honour any frozen cut-offs declared in constants.py
    best_thr = _apply_locked_threshold(league_name, 'btts', best_thr)
    _write_threshold(league_name, 'btts', best_thr)
    clf.best_threshold_ = best_thr
    # --- permutation importance (top 10) -------------------------------
    permutation_importance_report(clf, X_te, y_te, top_n=10)
    # Persist permutation‑importance to CSV for offline analysis
    try:
        imp_df = permutation_importance_report(clf, X_te, y_te, top_n=10)
        imp_path = os.path.join(
            MODEL_DIR,
            f"{league_name.replace(' ', '_')}_btts_perm_importance.csv"
        )
        imp_df.to_csv(imp_path, index=False)
        print(f"📑  BTTS permutation‑importance saved → {imp_path}")
    except Exception as exc:
        print(f"⚠️  Could not save BTTS permutation‑importance: {exc}")
    # --- feature integrity (writes CSV to ModelStore) ---------------
    feature_integrity_report(combined_data, btts_features, league_name)
    clf.score_ = acc
    joblib.dump(
        clf,
        os.path.join(MODEL_DIR, f"{league_name.replace(' ', '_')}_btts_model.pkl")
    )
    print(f"[{league_name}] BTTS ➜ Acc: {acc*100:.2f}% | AUC: {auc:.3f} "
          f"| LL: {ll:.3f} | Thr: {best_thr:.2f}")
    return clf
