def train_and_evaluate_over15fh_model(combined_data, league_name):
    """
    Over-1.5 First-Half goals (total ≥ 2 by HT)
    """
    combined_data = drop_bookmaker_cols(combined_data)   # ← NEW
    # --- chronological split: leave‑last‑season‑out ------------------
    train_df, test_df = leave_last_season_out(combined_data)

    # Leak‑safe binary target derived from historic rolling HT‑goal average
    train_df['Over15_FH'] = (train_df['rolling5_total_goals_ht'] >= 2).astype(int)
    test_df['Over15_FH']  = (test_df['rolling5_total_goals_ht']  >= 2).astype(int)

    # --- drop the label‑defining feature to avoid leakage -----------------
    for _df in (train_df, test_df):
        _df.drop(columns=['rolling5_total_goals_ht'], inplace=True, errors='ignore')

    # Abort training when either split has only a single class
    if train_df['Over15_FH'].nunique() < 2 or test_df['Over15_FH'].nunique() < 2:
        print(f"⚠️  Not enough class variety to train Over 1.5 FH for {league_name} – skipping.")
        from sklearn.dummy import DummyClassifier
        dummy = Pipeline([
            ('scaler', MinMaxScaler()),
            ('clf',    DummyClassifier(strategy='constant', constant=0))
        ])
        joblib.dump(dummy, os.path.join(
            MODEL_DIR, f"{league_name.replace(' ', '_')}_over15_FH_model.pkl"))
        return dummy

    fh_features = [
        'rolling5_home_shots', 'rolling5_away_shots',
        'rolling5_home_sot_ratio', 'rolling5_away_sot_ratio',
        'rolling5_total_corners', 'rolling5_total_fouls',
        'Home Team Pre-Match xG', 'Away Team Pre-Match xG',
        'ppg_diff', 'momentum_score',
        'set_piece_pressure_index', 'emotional_volatility_score'
    ]
    for feat in fh_features:
        if feat not in combined_data.columns:
            combined_data[feat] = np.nan

    X_tr = train_df[fh_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_tr = train_df['Over15_FH']
    # ---- optional class-balancing (env/availability guarded) ----
    X_tr, y_tr = _smote_fit_resample(X_tr, y_tr, "Over15-FH")
    X_te = test_df[fh_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_te = test_df['Over15_FH']

    pipe = Pipeline([
        ('scaler', MinMaxScaler()),
        ('clf',    LogisticRegression(solver='liblinear',
                                      class_weight='balanced',
                                      random_state=42))
    ])
    # rolling‑window chronology audit
    assert_rolling_metrics(X_tr, "over15fh")
    pipe.fit(X_tr, y_tr)
    acc = accuracy_score(y_te, pipe.predict(X_te))
    pipe.score_ = acc                                   # keep for reporting

    # probability diagnostics
    y_prob = pipe.predict_proba(X_te)[:, 1]
    try:
        auc = roc_auc_score(y_te, y_prob)
    except ValueError:
        auc = float('nan')
    ll   = log_loss(y_te, y_prob, labels=[0, 1])
    pipe.auc_      = auc
    pipe.log_loss_ = ll
    # --- tune threshold on val split -------------------------------
    best_thr, _ = tune_threshold_guard(y_te, pipe.predict_proba(X_te)[:,1], odds=None, default_metric="f1")  # EV-ready
    pipe.best_threshold_ = best_thr
    print(f"[{league_name}] Over 1.5 FH ➜ Acc: {acc*100:.2f}% | AUC: {auc:.3f} | LL: {ll:.3f} | Thr: {best_thr:.2f}")

    joblib.dump(pipe, os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_over15_FH_model.pkl"))
    return pipe


def train_and_evaluate_btts_fh_model(combined_data, league_name):
    """
    BTTS First-Half (both sides score by HT)
    """
    combined_data = drop_bookmaker_cols(combined_data)   # ← NEW
    train_df, test_df = leave_last_season_out(combined_data)

    # Leak‑safe target: both sides averaged ≥1 goal over last 5 fixtures
    train_df['BTTS_FH'] = ((train_df['rolling5_home_goal_count'] >= 1) &
                           (train_df['rolling5_away_goal_count'] >= 1)).astype(int)
    test_df['BTTS_FH']  = ((test_df['rolling5_home_goal_count'] >= 1) &
                           (test_df['rolling5_away_goal_count'] >= 1)).astype(int)

    # --- drop the two rolling goal‑count features to prevent leakage -----
    for _df in (train_df, test_df):
        _df.drop(columns=['rolling5_home_goal_count',
                          'rolling5_away_goal_count'], inplace=True, errors='ignore')

    if train_df['BTTS_FH'].nunique() < 2 or test_df['BTTS_FH'].nunique() < 2:
        print(f"⚠️  Not enough class variety to train BTTS FH for {league_name} – skipping.")
        from sklearn.dummy import DummyClassifier
        dummy = Pipeline([
            ('scaler', MinMaxScaler()),
            ('clf',    DummyClassifier(strategy='constant', constant=0))
        ])
        joblib.dump(dummy, os.path.join(
            MODEL_DIR, f"{league_name.replace(' ', '_')}_btts_FH_model.pkl"))
        return dummy

    fh_features = [
        'rolling5_home_shots', 'rolling5_away_shots',
        'rolling5_home_sot_ratio', 'rolling5_away_sot_ratio',
        'Home Team Pre-Match xG', 'Away Team Pre-Match xG',
        'ppg_diff', 'momentum_score',
        'set_piece_pressure_index', 'emotional_volatility_score'
    ]
    for feat in fh_features:
        if feat not in combined_data.columns:
            combined_data[feat] = np.nan

    X_tr = train_df[fh_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_tr = train_df['BTTS_FH']
    # ---- optional class-balancing (env/availability guarded) ----
    X_tr, y_tr = _smote_fit_resample(X_tr, y_tr, "BTTS-FH")
    X_te = test_df[fh_features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_te = test_df['BTTS_FH']

    pipe = Pipeline([
        ('scaler', MinMaxScaler()),
        ('clf',    LogisticRegression(solver='liblinear',
                                      class_weight='balanced',
                                      random_state=42))
    ])
    # rolling‑window chronology audit
    assert_rolling_metrics(X_tr, "btts_fh")
    pipe.fit(X_tr, y_tr)
    acc = accuracy_score(y_te, pipe.predict(X_te))
    pipe.score_ = acc

    y_prob = pipe.predict_proba(X_te)[:, 1]
    try:
        auc = roc_auc_score(y_te, y_prob)
    except ValueError:
        auc = float('nan')
    ll   = log_loss(y_te, y_prob, labels=[0, 1])
    pipe.auc_      = auc
    pipe.log_loss_ = ll
    # --- tune threshold on val split -------------------------------
    best_thr, _ = tune_threshold_guard(y_te, pipe.predict_proba(X_te)[:,1], odds=None, default_metric="f1")  # EV-ready
    pipe.best_threshold_ = best_thr
    print(f"[{league_name}] BTTS FH ➜ Acc: {acc*100:.2f}% | AUC: {auc:.3f} | LL: {ll:.3f} | Thr: {best_thr:.2f}")

    joblib.dump(pipe, os.path.join(
        MODEL_DIR, f"{league_name.replace(' ', '_')}_btts_FH_model.pkl"))
    return pipe
