def train_and_evaluate_over15tg_model(combined_data, league_name, side="home"):
    """
    Train a logistic‑regression model to predict whether the
    **specified side** (home or away) scores **≥ 2 goals** in the
    full match.

    Parameters
    ----------
    combined_data : DataFrame
    league_name   : str
    side          : "home" or "away"

    Returns
    -------
    fitted sklearn Pipeline (scaler + LogisticRegression) with a
    `.score_` attribute storing hold‑out accuracy.
    """
    combined_data = drop_bookmaker_cols(combined_data)   # ← NEW
    if side not in ("home", "away"):
        raise ValueError("side must be 'home' or 'away'")

    tgt_col = f"{side}_over15tg"
    goals_col = f"{side}_team_goal_count"
    opp_side  = "away" if side == "home" else "home"

    # --- label -------------------------------------------------------
    combined_data[tgt_col] = (combined_data[goals_col] >= 2).astype(int)

    # --- feature block (mirrors FTS logic but geared toward scoring) -
    features = [
        # attacking strength
        f"{side}_goals_scored_per_match",
        f"{side}_offensive_index",
        f"rolling5_{side}_sot_ratio",
        "Home Team Pre-Match xG" if side == "home" else "Away Team Pre-Match xG",
        # opponent defensive weakness
        f"{opp_side}_goals_conceded_per_match",
        f"{opp_side}_defensive_efficiency",
        # context
        "momentum_score",
        "set_piece_pressure_index",
        "emotional_volatility_score",
        "home_win_implied_prob" if side == "home" else "away_win_implied_prob",
        "ppg_diff"
    ]
    # -------- shared λ / intensity predictors (patch) --------
    common_goal_predictors = [
        "home_goals_pred", "away_goals_pred",
        "poisson_over25_prob", "poisson_btts_prob",
        "attacking_pressure_home", "attacking_pressure_away",
    ]
    features += common_goal_predictors
    # de‑duplicate while preserving order
    features = list(dict.fromkeys(features))
    for feat in features:
        if feat not in combined_data.columns:
            combined_data[feat] = np.nan
    # Delay NaN handling until *after* the split
    X = combined_data[features].replace([np.inf, -np.inf], np.nan)
    X = safe_fill(X, X.columns.tolist(), SENTINEL)
    y = combined_data[tgt_col]

    pipe = Pipeline([
        ("scaler", MinMaxScaler()),
        ("clf",    LogisticRegression(
            solver="liblinear",
            class_weight="balanced",
            random_state=42))
    ])

    # ------------------------------------------------------------------
    # Chronological split: always leave‑last‑season‑out for consistency
    # ------------------------------------------------------------------
    train_df, test_df = leave_last_season_out(combined_data)

    # Build design-matrices *after* the split so rows stay aligned
    X_tr = train_df[features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_tr = train_df[tgt_col]
    # ---- optional class-balancing (env/availability guarded) ----
    X_tr, y_tr = _smote_fit_resample(X_tr, y_tr, f"{side.capitalize()}-≥2TG")
    X_te = test_df[features].replace([np.inf, -np.inf], np.nan).fillna(0)
    y_te = test_df[tgt_col]

    # rolling‑window chronology audit
    # ── rolling‑metric safeguard (inject sentinel if entirely zero) ──
    try:
        assert_rolling_metrics(X_tr, f"{side}_over15tg")
    except ValueError as exc:
        print(f"⚠️  {exc} — injecting sentinel for missing/zero rolling metrics.")
        for col in (
            "rolling5_home_sot_ratio", "rolling5_away_sot_ratio",
            "rolling5_home_shots",     "rolling5_away_shots",
            "rolling5_home_card_ratio","rolling5_away_card_ratio"
        ):
            if col not in X_tr.columns or X_tr[col].abs().sum() == 0:
                X_tr[col] = 1e-3       # tiny non‑zero to satisfy the integrity guard
        # retry once the fall‑backs are in place
        assert_rolling_metrics(X_tr, f"{side}_over15tg")

    # ---- fit the logistic pipeline -----------------------------------
    pipe.fit(X_tr, y_tr)

    # ---- schema guard: make sure X_te has the same columns as at fit ---
    if hasattr(pipe, "feature_names_in_"):
        for _col in pipe.feature_names_in_:
            if _col not in X_te.columns:
                X_te[_col] = np.nan   # missing flag – imputed later
        # enforce identical column order for inference
        X_te = X_te[pipe.feature_names_in_]
    acc = accuracy_score(y_te, pipe.predict(X_te))
    pipe.score_ = acc
    model_tag = f"{side}_over15tg"
    fname = os.path.join(
        MODEL_DIR,
        f"{league_name.replace(' ', '_')}_{model_tag}_model.pkl"
    )
    # metrics
    y_prob = pipe.predict_proba(X_te)[:, 1]
    try:
        auc = roc_auc_score(y_te, y_prob)
    except ValueError:
        auc = float('nan')
    ll   = log_loss(y_te, y_prob, labels=[0, 1])
    pipe.auc_      = auc
    pipe.log_loss_ = ll
    # --- tune threshold on hold-out -------------------------------
    # ≥2TG: no dependable market odds available here → keep F1-based tuning
    best_thr, _ = tune_threshold_guard(y_te, y_prob, odds=None, default_metric="f1")
    pipe.best_threshold_ = best_thr
    print(f"[{league_name}] {side.title()} ≥2‑Goals ➜ Acc: {acc*100:.2f}% | AUC: {auc:.3f} | LL: {ll:.3f} | Thr: {best_thr:.2f}")
    joblib.dump(pipe, fname)
    return pipe
