# --- Banker hooks integration: save slips + optional backtest after normal pipeline runs ---
def _apply_banker_hooks_if_enabled(_res, _league):
    """
    Post-run hook that (optionally) writes banker slips and runs a quick
    HGM backtest. Controlled by env flags:

      • ENABLE_BANKER_HGM=1      → save_banker_slips(...)
      • RUN_BANKER_BACKTEST=1    → backtest_hgm_bankers_accuracy(...)

    The hook is NA/empty-safe and tolerates a tuple/list result by
    extracting the first DataFrame it finds. No-ops if nothing suitable.
    """
    import os as _os, pandas as _pd

    # Resolve a DataFrame from pipeline result (supports df or (df, ...))
    df_main = None
    if isinstance(_res, _pd.DataFrame):
        df_main = _res
    elif isinstance(_res, (list, tuple)):
        for _x in _res:
            if isinstance(_x, _pd.DataFrame):
                df_main = _x
                break

    if df_main is None or df_main.empty:
        return _res  # nothing to do

    lname = str(_league or "")

    # Save banker slips
    try:
        if _os.getenv("ENABLE_BANKER_HGM", "0") == "1":
            save_banker_slips(df_main, lname)
    except Exception as _e:
        try:
            print(f"ℹ️  Banker slips skipped: {_e}")
        except Exception:
            pass

    # Optional backtest
    try:
        if _os.getenv("RUN_BANKER_BACKTEST", "0") == "1":
            backtest_hgm_bankers_accuracy(df_main, lname)
    except Exception as _e:
        try:
            print(f"ℹ️  Banker backtest skipped: {_e}")
        except Exception:
            pass

    return _res

