def add_h2h_goal_rate(df: pd.DataFrame, window: int = 8) -> pd.DataFrame:
    """
    Average total goals in head-to-head matchups over the previous `window` fixtures.
    Fail-soft: creates `total_goals_match` from home/away goals if missing.
    """
    if df is None or len(df) == 0:
        return df

    df = df.copy()

    # Ensure total_goals_match exists
    if "total_goals_match" not in df.columns:
        if {"home_team_goal_count", "away_team_goal_count"}.issubset(df.columns):
            df["total_goals_match"] = (
                pd.to_numeric(df["home_team_goal_count"], errors="coerce").fillna(0)
                + pd.to_numeric(df["away_team_goal_count"], errors="coerce").fillna(0)
            )
        else:
            # Create the column so downstream groupby never KeyErrors
            df["total_goals_match"] = np.nan

    # Ensure datetime + chronological order (safe if column missing)
    if "match_date" in df.columns:
        try:
            if not np.issubdtype(df["match_date"].dtype, np.datetime64):
                df["match_date"] = pd.to_datetime(df["match_date"], errors="coerce")
        except Exception:
            df["match_date"] = pd.to_datetime(df["match_date"], errors="coerce")
        df = df.sort_values("match_date")

    # Order-invariant pair key (home/away insensitive)
    df["_pair"] = pd.DataFrame({
        "a": df["home_team_name"].astype(str),
        "b": df["away_team_name"].astype(str)
    }).apply(lambda r: " | ".join(sorted([r["a"], r["b"]])), axis=1)

    # Rolling mean of total goals, lagged by 1 so the current fixture never sees itself
    df["h2h_goals_avg"] = (
        df.groupby("_pair")["total_goals_match"]
          .apply(lambda s: s.shift(1).rolling(window, min_periods=1).mean())
          .reset_index(level=0, drop=True)
    )

    # Optional: also expose an H2H draw-rate if FTR is present
    if {"home_team_name", "away_team_name", "FTR"}.issubset(df.columns):
        df["_h2h_key"] = df.apply(
            lambda r: tuple(sorted((r["home_team_name"], r["away_team_name"]))), axis=1
        )
        df["h2h_draw_rate"] = 0.0
        for _key, _grp in df.groupby("_h2h_key", sort=False):
            _rate = (
                (_grp["FTR"] == 1).astype(int)
                .shift(1)
                .rolling(5, min_periods=1)
                .mean()
            )
            df.loc[_grp.index, "h2h_draw_rate"] = _rate
        df.drop(columns="_h2h_key", inplace=True, errors="ignore")
    else:
        # Neutral fallback when labels are absent
        if "h2h_draw_rate" not in df.columns:
            df["h2h_draw_rate"] = 0.5

    df.drop(columns="_pair", inplace=True, errors="ignore")
    return df

