# Auto-tune and lock leagues utility
# -------------------------------------------------------------------

def auto_tune_and_lock_leagues(leagues, pass_criteria, output_dir="AutoLock"):
    import pandas as pd, json, os
    os.makedirs(output_dir, exist_ok=True)
    summary_rows, failed_rows = [], []

    for league in leagues:
        name = league["name"]
        print(f"\n🔍 Auto-tuning {name}...")

        # You must define the league_thresholds for each league, or adapt as needed.
        # This assumes league_thresholds is available in the scope or adapt as needed.
        summary = run_pipeline_for_league(league, draw_thresholds_dict=league_thresholds)
        report_path = os.path.join(MODEL_DIR, f"{name.replace(' ', '_')}_FTR_report.txt")

        # Parse metrics from the FTR report
        with open(report_path) as f:
            lines = f.readlines()

        def extract_scores(lines, label):
            for line in lines:
                if line.strip().startswith(label):
                    parts = line.split()
                    return float(parts[1]), float(parts[2]), float(parts[3])  # precision, recall, f1
            return 0.0, 0.0, 0.0

        p_home, r_home, f1_home = extract_scores(lines, "Home Win")
        p_draw, r_draw, f1_draw = extract_scores(lines, "Draw")
        p_away, r_away, f1_away = extract_scores(lines, "Away Win")

        pass_config = pass_criteria.get(name, {"f1": 0.72, "draw_precision": 0.5})
        passes = (
            f1_home >= pass_config["f1"] and
            f1_draw >= pass_config["f1"] and
            f1_away >= pass_config["f1"] and
            p_draw  >= pass_config["draw_precision"]
        )

        if passes:
            print(f"✅ Passed threshold criteria – locking {name}")
            LOCKED_THRESHOLDS[name] = {
                "draw": summary["t_draw"],
                "home": summary["t_home"],
                "away": summary["t_away"]
            }
            LOCKED_FTR_MIX[name] = {
                "alpha": summary["alpha"],
                "beta":  summary["beta"],
                "cap":   summary["cap"]
            }
        else:
            print(f"❌ Failed to meet all threshold metrics for {name}")
            failed_rows.append({
                "league": name,
                "p_home": p_home, "r_home": r_home, "f1_home": f1_home,
                "p_draw": p_draw, "r_draw": r_draw, "f1_draw": f1_draw,
                "p_away": p_away, "r_away": r_away, "f1_away": f1_away
            })

        summary_rows.append({
            "league": name,
            "alpha": summary.get("alpha"),
            "beta":  summary.get("beta"),
            "cap":   summary.get("cap"),
            "t_draw": summary.get("t_draw"),
            "t_home": summary.get("t_home"),
            "t_away": summary.get("t_away"),
            "f1_home": f1_home, "f1_draw": f1_draw, "f1_away": f1_away
        })

    pd.DataFrame(summary_rows).to_csv(os.path.join(output_dir, "league_tuning_summary.csv"), index=False)
    pd.DataFrame(failed_rows).to_csv(os.path.join(output_dir, "auto_lock_failures.csv"), index=False)

    # Export locked thresholds + mix
    with open(os.path.join(output_dir, "locked_thresholds.json"), "w") as f:
        json.dump(LOCKED_THRESHOLDS, f, indent=2)
    import yaml  # add once at top of the function/file if not present
    with open(os.path.join(output_dir, "locked_ftr_mix.yaml"), "w") as f:
        yaml.safe_dump(LOCKED_FTR_MIX, f, sort_keys=True)
        json.dump(LOCKED_FTR_MIX, f, indent=2)
