    def assign_confidence_columns(ftr_df, prob_mat):
        """
        Assigns three confidence columns (home/draw/away) from a (n,3) probability matrix.
        Fails soft by clipping lengths when they don't match.
        """
        import numpy as np
        # Align lengths if needed
        if len(prob_mat) != len(ftr_df):
            clip = min(len(prob_mat), len(ftr_df))
            print(f"⚠️  Aligning prob_mat ({len(prob_mat)}) → ftr_df ({len(ftr_df)}) → {clip}")
            prob_mat = prob_mat[:clip]
            ftr_df = ftr_df.iloc[:clip].copy()

        probs = np.asarray(prob_mat, dtype=float)
        if probs.ndim != 2 or probs.shape[1] != 3:
            raise ValueError(f"Expected prob_mat shape (n,3); got {probs.shape}")

        out = ftr_df.copy()
        out["confidence_home"] = probs[:, 0]
        out["confidence_draw"] = probs[:, 1]
        out["confidence_away"] = probs[:, 2]
        return out
    
