PRESERVE_DRAW_COLS = [
    "Pre-Match PPG (Home)", "Pre-Match PPG (Away)",
    "Home Team Pre-Match xG", "Away Team Pre-Match xG",
    "elo_diff", "rest_diff", "ppg_diff",
    "xg_diff_abs", "recent_xg_diff_abs",
    "home_press_intensity", "away_press_intensity",
    "rolling5_home_press_intensity", "rolling5_away_press_intensity",
    "rolling5_press_intensity_diff",
    "h2h_draw_rate", "pressed_vs_pressed", "both_slumping",
    "odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win",
    "odds_ft_over15", "odds_ft_over25", "odds_btts_yes"
]
# ================= Draw-ready feature builder (leak-safe) =================
# ---- one-time print guard for draw feature creation ----
try:
    _DRAW_FEATURES_LOGGED
except NameError:
    _DRAW_FEATURES_LOGGED = False

# Ensure the PRESERVE_DRAW_COLS constant exists (harmless if already defined)
try:
    PRESERVE_DRAW_COLS
except NameError:
    PRESERVE_DRAW_COLS = [
        "Pre-Match PPG (Home)", "Pre-Match PPG (Away)",
        "Home Team Pre-Match xG", "Away Team Pre-Match xG",
        "elo_diff", "rest_diff", "ppg_diff",
        "xg_diff_abs", "recent_xg_diff_abs",
        "home_press_intensity", "away_press_intensity",
        "rolling5_home_press_intensity", "rolling5_away_press_intensity",
        "rolling5_press_intensity_diff",
        "h2h_draw_rate", "pressed_vs_pressed", "both_slumping",
        "odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win",
        "odds_ft_over15", "odds_ft_over25", "odds_btts_yes", "odds_btts_no",
        # derived %
        "btts_percentage_pre_match", "over_15_percentage_pre_match",
        "over_25_percentage_pre_match", "over_35_percentage_pre_match",
        "over_45_percentage_pre_match",
        # parity helpers from implied / market
        "draw_implied", "odds_parity", "odds_skew",
        # optional team draw rollings if you add upstream
        "home_draw_rate_rolling", "away_draw_rate_rolling", "team_draw_parity",
    ]

def ensure_draw_ready_features(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    created: set[str] = set()

    # ---- basic diffs / parity ----
    # Elo diff
    if "elo_diff" not in out.columns:
        for a, b in (("elo_home", "elo_away"), ("elo_home_pre", "elo_away_pre")):
            if {a, b}.issubset(out.columns):
                out["elo_diff"] = out[a] - out[b]
                created.add("elo_diff")
                break

    # Rest diff
    if "rest_diff" not in out.columns:
        for a, b in (("home_rest_days","away_rest_days"),
                     ("days_rest_home","days_rest_away"),
                     ("rest_days_home","rest_days_away")):
            if {a, b}.issubset(out.columns):
                out["rest_diff"] = out[a] - out[b]
                created.add("rest_diff")
                break

    # PPG diff (prematch)
    if "ppg_diff" not in out.columns:
        h_opts = ["Pre-Match PPG (Home)", "home_ppg", "pre_match_home_ppg"]
        a_opts = ["Pre-Match PPG (Away)", "away_ppg", "pre_match_away_ppg"]
        h = next((c for c in h_opts if c in out.columns), None)
        a = next((c for c in a_opts if c in out.columns), None)
        if h and a:
            out["ppg_diff"] = out[h] - out[a]
            created.add("ppg_diff")

    # xG prematch parity → xg_diff_abs
    if "xg_diff_abs" not in out.columns:
        hxg_opts = ["Home Team Pre-Match xG", "home_team_pre_match_xg", "home_pre_xg"]
        axg_opts = ["Away Team Pre-Match xG", "away_team_pre_match_xg", "away_pre_xg"]
        hxg = next((c for c in hxg_opts if c in out.columns), None)
        axg = next((c for c in axg_opts if c in out.columns), None)
        if hxg and axg:
            out["xg_diff_abs"] = (out[hxg] - out[axg]).abs()
            created.add("xg_diff_abs")

    # recent_xg_diff_abs — rolling FALLBACK from prematch xG (no match_date dependency)
    if "recent_xg_diff_abs" not in out.columns:
        hxg_opts = ["Home Team Pre-Match xG", "home_team_pre_match_xg", "home_pre_xg"]
        axg_opts = ["Away Team Pre-Match xG", "away_team_pre_match_xg", "away_pre_xg"]
        hxg = next((c for c in hxg_opts if c in out.columns), None)
        axg = next((c for c in axg_opts if c in out.columns), None)
        if hxg and axg and "home_team_name" in out.columns and "away_team_name" in out.columns:
            out["_hxg_roll5"] = (
                out.groupby("home_team_name")[hxg]
                   .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            out["_axg_roll5"] = (
                out.groupby("away_team_name")[axg]
                   .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
            )
            out["recent_xg_diff_abs"] = (out["_hxg_roll5"] - out["_axg_roll5"]).abs()
            out.drop(columns=["_hxg_roll5", "_axg_roll5"], inplace=True)
            created.add("recent_xg_diff_abs")

    # ---- press intensity rollups (index-safe; no match_date required) ----
    if "rolling5_home_press_intensity" not in out.columns and "home_press_intensity" in out.columns:
        out["rolling5_home_press_intensity"] = (
            out.groupby("home_team_name")["home_press_intensity"]
               .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
        )
        created.add("rolling5_home_press_intensity")

    if "rolling5_away_press_intensity" not in out.columns and "away_press_intensity" in out.columns:
        out["rolling5_away_press_intensity"] = (
            out.groupby("away_team_name")["away_press_intensity"]
               .transform(lambda s: s.shift(1).rolling(5, min_periods=1).mean())
        )
        created.add("rolling5_away_press_intensity")

    if "rolling5_press_intensity_diff" not in out.columns and \
       {"rolling5_home_press_intensity", "rolling5_away_press_intensity"}.issubset(out.columns):
        out["rolling5_press_intensity_diff"] = (
            out["rolling5_home_press_intensity"] - out["rolling5_away_press_intensity"]
        )
        created.add("rolling5_press_intensity_diff")

    # ---- market-derived implied probabilities (deterministic; no overround adj) ----
    def _inv(col):
        return 1.0 / out[col].replace(0, np.nan)

    if "btts_percentage_pre_match" not in out.columns and "odds_btts_yes" in out.columns:
        out["btts_percentage_pre_match"] = _inv("odds_btts_yes")
        created.add("btts_percentage_pre_match")

    if "over_15_percentage_pre_match" not in out.columns and "odds_ft_over15" in out.columns:
        out["over_15_percentage_pre_match"] = _inv("odds_ft_over15")
        created.add("over_15_percentage_pre_match")

    if "over_25_percentage_pre_match" not in out.columns and "odds_ft_over25" in out.columns:
        out["over_25_percentage_pre_match"] = _inv("odds_ft_over25")
        created.add("over_25_percentage_pre_match")

    if "over_35_percentage_pre_match" not in out.columns and "odds_ft_over35" in out.columns:
        out["over_35_percentage_pre_match"] = _inv("odds_ft_over35")
        created.add("over_35_percentage_pre_match")

    if "over_45_percentage_pre_match" not in out.columns and "odds_ft_over45" in out.columns:
        out["over_45_percentage_pre_match"] = _inv("odds_ft_over45")
        created.add("over_45_percentage_pre_match")

    if "odds_btts_no" in out.columns and "btts_no_percentage_pre_match" not in out.columns:
        out["btts_no_percentage_pre_match"] = _inv("odds_btts_no")
        created.add("btts_no_percentage_pre_match")

    # ---- odds-parity helpers (safe when odds present) ----
    if {"odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win"}.issubset(out.columns):
        imp_h = _inv("odds_ft_home_team_win")
        imp_d = _inv("odds_ft_draw")
        imp_a = _inv("odds_ft_away_team_win")
        if "draw_implied" not in out.columns:
            out["draw_implied"] = imp_d
            created.add("draw_implied")
        if "odds_parity" not in out.columns:
            out["odds_parity"] = (imp_h - imp_a).abs()
            created.add("odds_parity")
        if "odds_skew" not in out.columns:
            out["odds_skew"] = (imp_h + imp_a) / 2 - imp_d
            created.add("odds_skew")

        # 1X2 implied probability parity deltas
        if "implied_prob_diff" not in out.columns:
            # absolute home–away parity gap (smaller ⇒ more parity ⇒ draw-prone)
            out["implied_prob_diff"] = (imp_h - imp_a).abs()

        if "odds_diff" not in out.columns:
            # raw decimal odds gap for parity (home vs away)
            out["odds_diff"] = (
                out["odds_ft_home_team_win"] - out["odds_ft_away_team_win"]
            ).abs()

    # ---- h2h draw rate (expanding, leakage-safe, index-aligned) ----
    if "h2h_draw_rate" not in out.columns and {"home_team_name","away_team_name","FTR"}.issubset(out.columns):
        pair = out[["home_team_name","away_team_name"]].astype(str).apply(
            lambda r: "||".join(sorted([r.iloc[0], r.iloc[1]])), axis=1
        )
        y_draw = (out["FTR"] == 1).astype(float)
        grp = y_draw.groupby(pair)
        cum_sum = grp.cumsum().shift(1)     # prior draws
        counts  = grp.cumcount()            # prior matches count
        with np.errstate(divide="ignore", invalid="ignore"):
            h2h = cum_sum / counts.replace(0, np.nan)
        global_prior = y_draw.expanding().mean().shift(1)
        h2h = h2h.fillna(global_prior).fillna(y_draw.mean())
        out["h2h_draw_rate"] = h2h
        created.add("h2h_draw_rate")

    # ---- simple flags ----
    # pressed_vs_pressed: both teams low press-intensity (<= 40th pct) on rolling5
    if "pressed_vs_pressed" not in out.columns and \
       {"rolling5_home_press_intensity","rolling5_away_press_intensity"}.issubset(out.columns):
        thr = np.nanpercentile(
            pd.concat([out["rolling5_home_press_intensity"], out["rolling5_away_press_intensity"]]),
            40
        )
        out["pressed_vs_pressed"] = (
            (out["rolling5_home_press_intensity"] <= thr) &
            (out["rolling5_away_press_intensity"] <= thr)
        ).astype(int)
        created.add("pressed_vs_pressed")

    # both_slumping: both prematch PPG below shared median
    if "both_slumping" not in out.columns:
        hp = next((c for c in ["Pre-Match PPG (Home)", "home_ppg", "pre_match_home_ppg"] if c in out.columns), None)
        ap = next((c for c in ["Pre-Match PPG (Away)", "away_ppg", "pre_match_away_ppg"] if c in out.columns), None)
        if hp and ap:
            med = np.nanmedian(pd.concat([out[hp], out[ap]]))
            out["both_slumping"] = ((out[hp] <= med) & (out[ap] <= med)).astype(int)
            created.add("both_slumping")

    # tiny one-time audit of what we created this run
    global _DRAW_FEATURES_LOGGED
    if created and not _DRAW_FEATURES_LOGGED:
        try:
            keep = [c for c in PRESERVE_DRAW_COLS if c in out.columns]
            made = sorted(list(created & set(PRESERVE_DRAW_COLS)))
            print(f"🧪 draw-ready: created {made} | have {len(keep)}/{len(PRESERVE_DRAW_COLS)} core cols")
        except Exception:
            pass
        _DRAW_FEATURES_LOGGED = True
    # ---- team draw-form (rolling, leak-safe) ----
    if "home_draw_rate_rolling" not in out.columns and "FTR" in out.columns and "home_team_name" in out.columns:
        out["home_draw_rate_rolling"] = (
            (out["FTR"] == 1).astype(int)
            .groupby(out["home_team_name"])
            .transform(lambda s: s.shift(1).rolling(8, min_periods=1).mean())
        )

    if "away_draw_rate_rolling" not in out.columns and "FTR" in out.columns and "away_team_name" in out.columns:
        out["away_draw_rate_rolling"] = (
            (out["FTR"] == 1).astype(int)
            .groupby(out["away_team_name"])
            .transform(lambda s: s.shift(1).rolling(8, min_periods=1).mean())
        )

    if "team_draw_parity" not in out.columns and \
       {"home_draw_rate_rolling","away_draw_rate_rolling"}.issubset(out.columns):
        out["team_draw_parity"] = (out["home_draw_rate_rolling"] - out["away_draw_rate_rolling"]).abs()
            # ---- Overround-corrected implied probabilities (1X2) ----
    trio = {"odds_ft_home_team_win", "odds_ft_draw", "odds_ft_away_team_win"}
    if trio.issubset(out.columns):
        o = out[list(trio)].replace(0, np.nan)
        ip = 1.0 / o
        s = ip.sum(axis=1)
        with np.errstate(divide="ignore", invalid="ignore"):
            out["home_implied"] = ip["odds_ft_home_team_win"] / s
            out["draw_implied"] = ip["odds_ft_draw"] / s
            out["away_implied"] = ip["odds_ft_away_team_win"] / s

        # Parity helpers from corrected probs
        if "odds_parity" not in out.columns:
            out["odds_parity"] = (out["home_implied"] - out["away_implied"]).abs()
        if "odds_skew" not in out.columns:
            out["odds_skew"] = out["draw_implied"] - out[["home_implied","away_implied"]].max(axis=1)
        if "implied_prob_diff" not in out.columns:
            out["implied_prob_diff"] = (out["home_implied"] - out["away_implied"]).abs()
        if "odds_diff" not in out.columns:
            out["odds_diff"] = (out["odds_ft_home_team_win"] - out["odds_ft_away_team_win"]).abs()
                # ---- Parity bins (coarse buckets for tree models) ----
    try:
        if "ppg_diff" in out.columns and "ppg_diff_bin" not in out.columns:
            out["ppg_diff_bin"] = pd.cut(out["ppg_diff"].abs(),
                                         bins=[0,0.1,0.3,0.6,1.0,2.5],
                                         labels=False, include_lowest=True)
        if "xg_diff_abs" in out.columns and "xg_diff_abs_bin" not in out.columns:
            out["xg_diff_abs_bin"] = pd.cut(out["xg_diff_abs"],
                                            bins=[0,0.1,0.3,0.6,1.0,3.0],
                                            labels=False, include_lowest=True)
        if "odds_parity" in out.columns and "odds_parity_bin" not in out.columns:
            out["odds_parity_bin"] = pd.cut(out["odds_parity"],
                                            bins=[0,0.02,0.05,0.10,0.18,0.35],
                                            labels=False, include_lowest=True)
    except Exception:
        # bins are best-effort; never break the pipeline
        pass
    
        # ---- team draw-form (rolling, leak-safe) ----
    if "home_draw_rate_rolling" not in out.columns and "FTR" in out.columns and "home_team_name" in out.columns:
        out["home_draw_rate_rolling"] = (
            (out["FTR"] == 1).astype(int)
            .groupby(out["home_team_name"])
            .transform(lambda s: s.shift(1).rolling(8, min_periods=1).mean())
        )
    if "away_draw_rate_rolling" not in out.columns and "FTR" in out.columns and "away_team_name" in out.columns:
        out["away_draw_rate_rolling"] = (
            (out["FTR"] == 1).astype(int)
            .groupby(out["away_team_name"])
            .transform(lambda s: s.shift(1).rolling(8, min_periods=1).mean())
        )
    if "team_draw_parity" not in out.columns and \
       {"home_draw_rate_rolling","away_draw_rate_rolling"}.issubset(out.columns):
        out["team_draw_parity"] = (out["home_draw_rate_rolling"] - out["away_draw_rate_rolling"]).abs()
    return out
