def _league_tag(league_name: str) -> str:
    return str(league_name).replace(" ", "_")


def save_mix_params(league_name: str, params: dict, model_dir: str = MODEL_DIR):
    """
    LEGACY JSON writer disabled — delegates to YAML writer (<League>_mix.yaml).
    """
    return _write_mix_yaml(league_name, mix=params, model_dir=model_dir)


def save_market_thresholds(league_name: str, thr_tuple: tuple[float, float, float],
                           model_dir: str = MODEL_DIR):
    """
    Persist market thresholds to both JSON and CSV for backward compatibility.
    Returns (json_path, csv_path).
    """
    os.makedirs(model_dir, exist_ok=True)
    tag = _league_tag(league_name)
    out_json = os.path.join(model_dir, f"{tag}_market_thresholds.json")
    out_csv  = os.path.join(model_dir, f"{tag}_thresholds.csv")
    payload = {"draw": float(thr_tuple[0]),
               "home": float(thr_tuple[1]),
               "away": float(thr_tuple[2])}
    with open(out_json, "w") as fh:
        json.dump(payload, fh, indent=2)
    pd.DataFrame([payload]).to_csv(out_csv, index=False)
    print(f"💾  Saved thresholds → {out_json}  &  {out_csv}")
    return out_json, out_csv

def write_legacy_draw_threshold_json(league_name: str, model_dir: str = MODEL_DIR) -> str:
    """
    Bridge for older consumers: writes <LEAGUE>_draw_threshold.json
    from <LEAGUE>_mix.json and <LEAGUE>_market_thresholds.json.
    """
    import os, json
    tag = _league_tag(league_name)
    mix_path = os.path.join(model_dir, f"{tag}_mix.json")
    thr_path = os.path.join(model_dir, f"{tag}_market_thresholds.json")
    out_path = os.path.join(model_dir, f"{tag}_draw_threshold.json")
    try:
        with open(mix_path, "r") as fh:
            m = json.load(fh) or {}
        with open(thr_path, "r") as fh:
            t = json.load(fh) or {}
        payload = {
            "baseline_blend": float(m.get("alpha", 1.0)),
            "beta":           float(m.get("beta",  0.0)),
            "cap":            float(m.get("cap",   0.45)),
            "gamma":          float(m.get("gate_scale", m.get("gamma", 0.50))),
            "threshold":      float(t.get("draw",  0.30)),
        }
        with open(out_path, "w") as fh:
            json.dump(payload, fh, indent=2)
        if VERBOSE_MODELSTORE:
            print(f"💾  Saved legacy draw-threshold → {out_path}")
    except Exception:
        pass
    return out_path

# --- Compatibility shim: robust call to tune_mix_hyperparams ---
def _call_tmh_robust(*args, **kwargs):
    """
    Compatibility wrapper around tune_mix_hyperparams(...).
    Drops unknown kwargs (base_proba/implied*), tries kwargs call, then
    falls back to positional (y, home, away). Never raises.
    """
    # Drop legacy/unknown keys
    for _bad in ("base_proba", "implied_probs", "implied", "implied_val", "market_implied"):
        kwargs.pop(_bad, None)

    # First try keyword-style API (newer versions may accept n_trials/timeout)
    try:
        return tune_mix_hyperparams(**kwargs)
    except TypeError:
        pass
    except Exception:
        pass

    # Fallback: positional (y, home, away)
    y  = kwargs.get("y_val") if "y_val" in kwargs else (args[0] if len(args) > 0 else None)
    hp = kwargs.get("home_preds_val") if "home_preds_val" in kwargs else (args[1] if len(args) > 1 else None)
    ap = kwargs.get("away_preds_val") if "away_preds_val" in kwargs else (args[2] if len(args) > 2 else None)
    try:
        return tune_mix_hyperparams(y, hp, ap)
    except Exception:
        return {"alpha": 1.0, "beta": 0.0, "cap": 0.45, "gamma": 0.0}
def calibrate_ftr_mix_and_thresholds_for_league(league_name: str,
                                                csv_path: str,
                                                n_trials: int = 20,
                                                timeout: int = 60,
                                                model_root: str = "ModelStore"):
    """
    Calibrate FTR draw-mix (alpha/beta/cap/gamma) and the draw gate threshold.

    • Loads/engineers features on the provided CSV path.
    • Predicts base model probabilities and (if available) goal λ̂ (home/away).
    • Tunes mix params via _call_tmh_robust(...) when available; otherwise
      falls back to safe defaults.
    • Selects a draw decision threshold via grid search on validation data.
    • Saves <LEAGUE>_mix.json and <LEAGUE>_market_thresholds.json under ModelStore/.

    Returns: {"mix_json": <path>, "thresholds": {"draw": float}, "threshold_files": [json_path, csv_path]}
    """
    # --- Helper: robust wrapper for tune_mix_hyperparams (handles older signatures) ---
    def _call_tmh_robust(**kwargs):
        """Compatibility wrapper for tune_mix_hyperparams inside calibrator.
        Drops unknown kwargs (base_proba / implied*), tries kwargs call,
        then positional (y, home, away). Never raises."""
        # Drop legacy/unknown keys
        for _bad in ("base_proba", "implied_probs", "implied", "implied_val", "market_implied"):
            kwargs.pop(_bad, None)
    
        # Try keyword API first (newer function variants)
        try:
            return tune_mix_hyperparams(**kwargs)
        except TypeError:
            pass
        except Exception:
            pass
    
        # Fallback: positional (y, home, away)
        y  = kwargs.get("y_val")
        hp = kwargs.get("home_preds_val")
        ap = kwargs.get("away_preds_val")
        try:
            return tune_mix_hyperparams(y, hp, ap)
        except Exception:
            return {"alpha": 1.0, "beta": 0.0, "cap": 0.45, "gamma": 0.0}

    # --- Guaranteed fallback return payload (in case no earlier return executed) ---
    import os as _os, json as _json
    _loc = locals()
    _tag = str(_loc.get('league') or _loc.get('league_name') or _loc.get('league_str') or 'Unknown League').replace(' ', '_')
    model_root = _loc.get('model_root') or globals().get('MODEL_DIR', 'ModelStore')
    _mix_path = locals().get("mix_path") or _os.path.join("ModelStore", f"{_tag}_mix.json")
    _thr_json = locals().get("market_thr_json_path") or _os.path.join("ModelStore", f"{_tag}_market_thresholds.json")
    _thr_csv  = locals().get("threshold_csv_path") or _os.path.join("ModelStore", f"{_tag}_thresholds.csv")
    _thr_payload = locals().get("thr_dict") or locals().get("thresholds") or {}
    if not _thr_payload:
        try:
            with open(_thr_json, "r") as _fh:
                _thr_payload = _json.load(_fh) or {}
        except Exception:
            _thr_payload = {}
    return {"mix_json": _mix_path, "thresholds": _thr_payload, "threshold_files": (_thr_json, _thr_csv)}

