def _mix_yaml_paths(league_name: str):
    import os, re
    from pathlib import Path
    slug = re.sub(r"[^a-z0-9]+", "_", str(league_name).lower()).strip("_")
    base = Path(os.getenv("MODEL_DIR", str(PROJECT_ROOT / "ModelStore")))
    base.mkdir(parents=True, exist_ok=True)
    return base / f"{slug}_mix.yaml"

def save_mix_params(league_name: str, params: dict) -> str | None:
    """Write {'alpha','beta','cap','gate_scale',...} to YAML."""
    try:
        import yaml
        p = _mix_yaml_paths(league_name)
        with open(p, "w", encoding="utf-8") as fh:
            yaml.safe_dump({k: float(v) for k, v in params.items()}, fh, sort_keys=True)
        print(f"💾 Saved mix → {p}")
        return str(p)
    except Exception as e:
        print(f"⚠️  could not save mix yaml: {e}")
        return None

def load_mix_params(league_name: str) -> dict:
    """Load per-league mixer from <league>_mix.yaml.
    If FORCE_LOCKED and the league is present in LOCKED_FTR_MIX, return that.
    """
    # Short-circuit to locked values when requested
    try:
        if FORCE_LOCKED and league_name in LOCKED_FTR_MIX:
            locked = LOCKED_FTR_MIX[league_name]
            return {
                "alpha": float(locked.get("alpha", 1.0)),
                "beta":  float(locked.get("beta",  0.10)),
                "cap":   float(locked.get("cap",   0.45)),
                "gate_scale": float(locked.get("gate_scale", 0.60)),
            }
    except Exception:
        pass

    # YAML is the single source of truth
    try:
        import yaml, os
        p = _mix_yaml_paths(league_name)
        if os.path.exists(p):
            with open(p, "r", encoding="utf-8") as fh:
                d = yaml.safe_load(fh) or {}
            return {
                "alpha": float(d.get("alpha", 1.0)),
                "beta":  float(d.get("beta",  0.10)),
                "cap":   float(d.get("cap",   0.45)),
                "gate_scale": float(d.get("gate_scale", 0.60)),
            }
    except Exception:
        pass

    # Safe defaults if nothing persisted yet
    return {"alpha": 1.0, "beta": 0.10, "cap": 0.45, "gate_scale": 0.60}

