# Modernize CalibratedClassifierCV → _make_calibrator and cv='prefit' → cv=3
import re as _modernize_re
import builtins as _modernize_builtins
def _modernize_calibrator_codeblock(code):
    # Replace CalibratedClassifierCV( → _make_calibrator(
    code = _modernize_re.sub(
        r'CalibratedClassifierCV\(',
        r'_make_calibrator(',
        code
    )
    # Replace cv='prefit' (or cv="prefit") with cv=3
    code = _modernize_re.sub(
        r'cv\s*=\s*[\'"]prefit[\'"]',
        r'cv=3',
        code
    )
    return code
import sys as _modernize_sys
if __name__ != "__main__" and hasattr(_modernize_sys, "_getframe"):
    # Only patch in non-main context to avoid CLI issues
    _thisfile = __file__ if "__file__" in globals() else None
    if _thisfile:
        try:
            with open(_thisfile, "r", encoding="utf-8") as _f:
                _src = _f.read()
            _patched = _modernize_calibrator_codeblock(_src)
            if _patched != _src:
                # Compile and exec patched code in module's globals
                exec(compile(_patched, _thisfile, "exec"), globals())
        except Exception:
            pass
# --- One-shot doctor-all: force-scan Matches/ & ModelStore (ignore constants) -
if "_doctor_all" not in globals():
    def _doctor_all(*, verbose: bool = False) -> int:
        """
        Force-scan Matches/ directories and ModelStore/ artefacts to discover
        leagues without consulting constants. Then delegate to _doctor.
        Returns the total number of issues found.
        """
        import os, re, glob
        base_root = os.path.dirname(__file__)
        matches_dir = os.path.join(base_root, "Matches")
        model_dir = os.getenv("MODEL_DIR", os.path.join(base_root, "ModelStore"))
        leagues: set[str] = set()

        # 1) Scan Matches/<leagueTag>/
        try:
            for d in os.listdir(matches_dir):
                p = os.path.join(matches_dir, d)
                if os.path.isdir(p) and not d.startswith("."):
                    leagues.add(d)
        except Exception:
            pass

        # 2) Scan ModelStore for artefact-derived tags
        try:
            patterns = (
                os.path.join(model_dir, "*_draw_threshold.json"),
                os.path.join(model_dir, "*_mix.yaml"),
                os.path.join(model_dir, "*_home_goals_model.pkl"),
                os.path.join(model_dir, "*_away_goals_model.pkl"),
                os.path.join(model_dir, "*__draw_bundle.joblib"),
            )
            for pat in patterns:
                for f in glob.glob(pat):
                    name = os.path.basename(f)
                    # Handle __draw_bundle.joblib first
                    tag = re.sub(r"__draw_bundle\.joblib$", "", name)
                    # Handle *_mix.yaml / *_draw_threshold.json / goal-model pkls
                    tag = re.sub(r"(_draw_threshold\.json|_mix\.yaml|_home_goals_model\.pkl|_away_goals_model\.pkl)$", "", tag)
                    if tag and not tag.startswith("."):
                        leagues.add(tag)
        except Exception:
            pass

        if not leagues:
            print("ℹ️  doctor-all: found no leagues under Matches/ or ModelStore/.")
            return 0
        return _doctor(sorted(leagues), verbose=verbose)
#
# --- One-shot doctor: health checks & prioritized to-do list -----------------
if "_doctor" not in globals():
    def _doctor(leagues: list[str] | None = None, *, verbose: bool = False) -> int:
        """
        Run health checks over the given leagues (or an inferred active set) and
        print a prioritized to-do list for each league.
        Returns the total number of issues found.
        """
        import os, json
        issues_total = 0

        # Resolve MODEL_DIR and helper for tags/paths
        try:
            from constants import MODEL_DIR, LOCKED_FTR_MIX, LOCKED_THRESHOLDS, DRAW_THRESHOLD_MODE_PER_LEAGUE, HISTORICAL_DRAW_RATE
        except Exception:
            MODEL_DIR = os.getenv("MODEL_DIR", os.path.join(os.path.dirname(__file__), "ModelStore"))
            LOCKED_FTR_MIX = {}
            LOCKED_THRESHOLDS = {}
            DRAW_THRESHOLD_MODE_PER_LEAGUE = {}
            HISTORICAL_DRAW_RATE = {}

        def _tag(lg: str) -> str:
            return str(lg).replace(" ", "_")

        # Infer active leagues if none provided
        if not leagues:
            active = set()
            for dic in (LOCKED_FTR_MIX, LOCKED_THRESHOLDS, DRAW_THRESHOLD_MODE_PER_LEAGUE, HISTORICAL_DRAW_RATE):
                try:
                    active |= set(dic.keys())
                except Exception:
                    pass
            # Fallback: scan Matches/ for folders
            if not active:
                base = os.path.join(os.path.dirname(__file__), "Matches")
                try:
                    active |= {d for d in os.listdir(base) if os.path.isdir(os.path.join(base, d))}
                except Exception:
                    pass
            leagues = sorted(active)

        if not leagues:
            print("ℹ️  doctor: no leagues discovered; pass --league or set ACTIVE_LEAGUES env")
            return 0

        print("\n🩺 Doctor: health checks (draw JSON, mix YAML, goal models, locks)…\n")
        for lg in leagues:
            tag = _tag(lg)
            draw_json = os.path.join(MODEL_DIR, f"{tag}_draw_threshold.json")
            mix_yaml  = os.path.join(MODEL_DIR, f"{tag}_mix.yaml")
            goal_h    = os.path.join(MODEL_DIR, f"{tag}_home_goals_model.pkl")
            goal_a    = os.path.join(MODEL_DIR, f"{tag}_away_goals_model.pkl")

            missing = []
            warn    = []
            info    = []

            # 1) Learned draw JSON present?
            has_json = os.path.exists(draw_json)
            if not has_json:
                missing.append((1, f"No learned draw JSON → {draw_json}"))

            # 2) Mix YAML present?
            has_yaml = os.path.exists(mix_yaml)
            if not has_yaml:
                missing.append((2, f"No mix YAML → {mix_yaml}"))

            # 3) Goal models present?
            has_goal = os.path.exists(goal_h) and os.path.exists(goal_a)
            if not has_goal:
                warn.append((3, "Goal λ̂ models not found (home/away)"))

            # 4) Locks vs YAML conflict
            if lg in LOCKED_FTR_MIX and has_yaml:
                warn.append((4, "LOCKED_FTR_MIX exists but YAML present — set PREFER_YAML_OVER_LOCKS=1 (default)"))

            # 5) β in YAML over cap?
            try:
                if has_yaml:
                    import yaml  # type: ignore
                    with open(mix_yaml, "r", encoding="utf-8") as fh:
                        mix = yaml.safe_load(fh) or {}
                    b = float(mix.get("beta", 0.0))
                    if b > 0.20:
                        warn.append((5, f"YAML beta {b:.2f} > 0.20 cap — consider re-tuning"))
            except Exception:
                pass

            # 6) baseline_blend present in draw JSON?
            try:
                if has_json:
                    with open(draw_json, "r", encoding="utf-8") as fh:
                        js = json.load(fh) or {}
                    if "baseline_blend" not in js:
                        warn.append((6, "draw JSON missing baseline_blend — upgrade trainer and re-save"))
                    else:
                        info.append((9, f"baseline_blend α = {float(js.get('baseline_blend')):.2f}"))
            except Exception:
                pass

            # Prioritize and print
            bucket = sorted(missing + warn + info, key=lambda t: t[0])
            if bucket:
                issues_total += sum(1 for p, _ in bucket if p < 9)
                print(f"▶ {lg}")
                for _, msg in bucket:
                    print(f"   - {msg}")
                # Suggested commands
                cmds = []
                if not has_json:
                    cmds.append(f"python train_draw_classifier.py --league \"{lg}\" --data-dir Matches/{tag} --threshold-mode f1 --precision-target 0.60 --topk-pct 0.10")
                if not has_yaml:
                    cmds.append(f"python _baseline_ftr_pipeline.py --league \"{lg}\" --write-mix-only")
                cmds.append(f"python etl_press_intensity.py --match-dir Matches/{tag} --baseline-blend 0.70 --overwrite-intensity --debug-attach")
                cmds.append(f"python _baseline_ftr_pipeline.py --league \"{lg}\" --quick --export ./out")
                print("   → Next steps:")
                for c in cmds:
                    print(f"     $ {c}")
                print()
        print(f"Done. Total issues found: {issues_total}\n")
        return issues_total
# --- Self-check: effective mix vs YAML/LOCKED ---------------------------------
if "_selfcheck_mix" not in globals():
    def _selfcheck_mix(league_name: str) -> None:
        """Print and assert that effective mix (load_mix_params) matches YAML/LOCKED.
        Raises AssertionError on drift. Intended for CI/smoke."""
        import os as _os, math as _math
        # 1) Effective (what runtime will use)
        try:
            eff = load_mix_params(league_name)
        except Exception as _e:
            raise AssertionError(f"load_mix_params failed: {_e}")

        # 2) Expected: LOCKED when FORCE_LOCKED, else YAML (or safe defaults)
        src = None
        expected = None
        try:
            if FORCE_LOCKED and league_name in LOCKED_FTR_MIX:
                locked = LOCKED_FTR_MIX[league_name]
                expected = {
                    "alpha": float(locked.get("alpha", 1.0)),
                    "beta":  float(locked.get("beta",  0.10)),
                    "cap":   float(locked.get("cap",   0.45)),
                    "gate_scale": float(locked.get("gate_scale", 0.60)),
                }
                src = "LOCKED_FTR_MIX (FORCE_LOCKED=1)"
            else:
                import yaml
                p = _mix_yaml_paths(league_name)
                if _os.path.exists(p):
                    with open(p, "r", encoding="utf-8") as fh:
                        d = yaml.safe_load(fh) or {}
                    expected = {
                        "alpha": float(d.get("alpha", 1.0)),
                        "beta":  float(d.get("beta",  0.10)),
                        "cap":   float(d.get("cap",   0.45)),
                        "gate_scale": float(d.get("gate_scale", 0.60)),
                    }
                    src = p
                else:
                    expected = {"alpha": 1.0, "beta": 0.10, "cap": 0.45, "gate_scale": 0.60}
                    src = "defaults (no YAML/LOCKED)"
        except Exception as _e:
            raise AssertionError(f"expected mix resolution failed: {_e}")

        print(f"\n🧪 selfcheck-mix for {league_name}")
        print(f"   expected@{src}:    {expected}")
        print(f"   effective(runtime): {eff}")

        # 3) Assert equality within tight tolerance
        tol = 1e-9
        diffs = {}
        for k in ("alpha","beta","cap","gate_scale"):
            ev = float(expected.get(k, float("nan")))
            av = float(eff.get(k, float("nan")))
            if not (_math.isfinite(ev) and _math.isfinite(av) and abs(ev - av) <= tol):
                diffs[k] = (ev, av)
        if diffs:
            raise AssertionError(f"mix drift detected: {diffs}")
        print("✅ selfcheck-mix OK")    

# --- Compact argparse CLI for quick runs / scoring ---------------------------
if __name__ == "__main__":
    import sys as _sys
    # Avoid colliding with the earlier scan-missing block which already handled
    # that special mode when --scan-missing is present.
    if "--scan-missing" not in _sys.argv:
        import argparse as _argparse
        import os as _os
        parser = _argparse.ArgumentParser(
            prog="_baseline_ftr_pipeline.py",
            description="Quick runner for league FTR scoring and CSV scoring."
        )
        parser.add_argument("--league", "-l", type=str, help="League name (e.g., 'England Premier League')")
        parser.add_argument("--quick", action="store_true", help="Run quick pipeline for --league")
        parser.add_argument("--run", action="store_true", help="Run full pipeline wrapper for --league")
        parser.add_argument("--score", type=str, help="Score a CSV file or directory path for FTR")
        parser.add_argument("--doctor", action="store_true", help="Run health checks and print prioritized to-do list")
        parser.add_argument("--doctor-all", action="store_true", help="Force-scan Matches/ and ModelStore/ (ignore constants)")
        parser.add_argument("--print-mix", action="store_true", help="Print effective mix (post-cap) and exit")
        parser.add_argument("--selfcheck-mix", action="store_true",
                    help="Assert effective mix equals YAML/LOCKED for --league")
        parser.add_argument("--write-mix-only", action="store_true", help="Write <League>_mix.yaml without scoring")
        parser.add_argument("--export", type=str, default=None, help="Output directory for predictions CSV")
        parser.add_argument("--tail", type=int, default=None, help="Tail N rows when writing scored CSV")
        parser.add_argument("--verbose", action="store_true", help="Set VERBOSE_QUICK=1 for extra logs")
        parser.add_argument(
            "--setenv",
            action="append",
            default=[],
            metavar="KEY=VALUE",
            help="Set environment variables (can be passed multiple times)",
        )
        args = parser.parse_args()
        # Resolve league data directory (tolerant to spaces/underscores)
        data_dir, tried = _resolve_dir(args.league, getattr(args, "data_dir", None))
        if not data_dir:
            print("❌ League folder not found. Tried:\n  - " + "\n  - ".join(tried))
            print(f'💡 Tip: run with --data-dir "Matches/{args.league}" (quoted if it has spaces)')
            raise SystemExit(1)
        print(f"📂 Using data dir: {data_dir}")
        # Normalize arg for downstream usage
        args.data_dir = str(data_dir)

        if args.verbose:
            _os.environ["VERBOSE_QUICK"] = "1"
        # Apply any KEY=VALUE entries
        if args.setenv:
            for kv in args.setenv:
                try:
                    k, v = kv.split("=", 1)
                    _os.environ[str(k).strip()] = str(v)
                except Exception:
                    print(f"⚠️  --setenv ignored (bad format): {kv}")

        # Routing
        df_out = None
        if args.selfcheck_mix:
            if not args.league:
                parser.error("--selfcheck-mix requires --league")
            _selfcheck_mix(args.league)
            df_out = None
        elif args.doctor_all:
            _doctor_all(verbose=args.verbose)
            df_out = None
        elif args.doctor:
            leagues = [args.league] if args.league else None
            _doctor(leagues, verbose=args.verbose)
            df_out = None
        elif args.print_mix:
            if not args.league:
                parser.error("--print-mix requires --league")
            _print_mix(args.league)
            df_out = None
        elif args.write_mix_only:
            if not args.league:
                parser.error("--write-mix-only requires --league")
            _write_mix_yaml(args.league)
            df_out = None
        elif args.score:
            if not args.league:
                parser.error("--score requires --league to resolve per-league artefacts")
            df_out = score_ftr_csv(args.league, args.score, out_csv=args.export, tail=args.tail)
        elif args.quick or (args.league and not args.run):
            if not args.league:
                parser.error("--quick requires --league")
            df_out = run_league_quick(args.league, args.export)
        elif args.run:
            if not args.league:
                parser.error("--run requires --league")
            # Honor export directory via env (don’t pass unsupported kwarg)
            if args.export:
                try:
                    os.makedirs(args.export, exist_ok=True)
                    os.environ.setdefault("PREDICTION_REPORTS_DIR", args.export)
                    os.environ.setdefault("BANKER_REPORTS_DIR", args.export)
                    os.environ.setdefault("BANKER_WATERFALL_DIR", args.export)
                except Exception:
                    pass
            df_out = run_pipeline_for_league({"name": args.league}, {})
        else:
            parser.print_help()
            _sys.exit(2)

        # Friendly footer
        try:
            n = 0 if df_out is None else len(df_out)
            print(f"\n✔️  Done. Rows processed: {n}")
        except Exception:
            pass
        # --- OG: ensure the latest report function is bound (avoid stale defs on reload) ---
        try:
            globals()["_write_time_split_ftr_report"] = _write_time_split_ftr_report
        except Exception:
            pass
        # --- OG: ensure the latest report function is bound (avoid stale defs on reload) ---
        try:
            globals()["_write_time_split_ftr_report"] = _write_time_split_ftr_report
        except Exception:
            pass